  --HIS.02631.2016
  FUNCTION func_pedido_no_prazo_import(pReg_Filial IN integradora_comple.t_filial) RETURN BOOLEAN IS
    DENTRO_PRAZO VARCHAR2(1);
  BEGIN
    -- VALIDA O PRAZO DE IMPORTAÇÃO DO PEDIDO

    IF (pReg_Filial.IMPORTARPEDIDOFORAHORARIO = 'S') THEN
      RETURN TRUE;
    ELSE
      -- CONSULTA QUADRO HORÁRIO PARA VERIFICAR SE ESTÁ NO PRAZO OU NÃO
      SELECT
        CASE
          WHEN EXISTS(SELECT 1
                      FROM PCFILIAL F
                      WHERE F.CODIGO = pReg_Filial.codigo
                        AND (  (TO_CHAR(SYSDATE, 'HH24:MI:SS') BETWEEN TO_CHAR(F.HRINICIOEXPEDIENTE, 'HH24:MI:SS') AND
                                                                       TO_CHAR(F.HRFIMEXPEDIENTE, 'HH24:MI:SS') )
                               AND
                               (TO_CHAR(SYSDATE, 'HH24:MI:SS') NOT  BETWEEN TO_CHAR(F.HRINICIOALMOCO, 'HH24:MI:SS') AND
                                                                            TO_CHAR(F.HRFIMALMOCO, 'HH24:MI:SS') )
                            )) THEN 'S'
          ELSE 'N'
        END
        INTO DENTRO_PRAZO
      FROM DUAL;

      IF (DENTRO_PRAZO = 'S') THEN
        RETURN TRUE;
      ELSE
        RETURN FALSE;
      END IF;

    END IF;
  END func_pedido_no_prazo_import;

  PROCEDURE proc_bloqvenda
  (
    regfilial          IN integradora_comple.t_filial,
    p_regpedido        IN OUT integradora_comple.t_cabped
  ) is

   vnVLCREDDISPONIVELTOTAL PCCLIENT.LIMCRED%TYPE;
   VNCODMOTIVO                PCBLOQUEIOSPEDIDO.CODMOTIVO%TYPE;
	 VNCODMOTIVOBLOQUEIO        PCBLOQUEIOSPEDIDO.CODMOTBLOQUEIO%TYPE;
   VSMOTIVO                   PCBLOQUEIOSPEDIDO.MOTIVO%TYPE;
   VSPOSICAO                  PCBLOQUEIOSPEDIDO.STATUS%TYPE;
   VSCOMBOCONTINUO            VARCHAR2(1);
   VSTOTALPEDSEMBLOQ307       NUMBER;
  begin
     /*************************************************************************************
    *Responsável: Iran.Junior                                                           *
    *Data:        03/06/2016                                                            *
    *Solicitação: HIS.01567.2014                                                        *
    *Alteração:  Adicionado chamada da pkg_motivobloqueio para validar motivos          *
    *de bloqueios comun com processo da 316 e 336.                                      *
    *Os demais bloqueios acima são especificos do força de vendas e não foram alterados *
    *************************************************************************************
    *Responsável: Guilherme Freitas                                                     *
    *Data       : 20/12/2016                                                            *
    *Solicitação: 1420.141424.2016                                                      *
    *Alteração  : Até então, a chamada a package de bloqueio era feita, ainda não havia *
    *             ocorrido a inserção da PCPEDC, logo, não encontrava os dados do pedido*
    *             no momento da validação, não achando motivos válidos para bloquear o  *
    *             mesmo, fazendo com que o pedido fosse importado como liberado, quando *
    *             não deveria, ocasionando movimentação incorreta no estoque.           *
    *************************************************************************************/
     IF (p_regpedido.numpedorig <> 0) THEN

         DELETE FROM PCBLOQUEIOSPEDIDO
         WHERE CODMOTIVO = 3
         AND NUMPED = p_regpedido.Numped
         AND CODMOTBLOQUEIO IS NULL
         AND STATUS = 'L';

      END IF;

        integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog            := 'C';
        integradora_comple.vLog.MSG                := 'Validando limite de crédito disponível / motivos de bloqueio: ';

        PRC_LOG_INTEGRADORA(integradora_comple.vlog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        BEGIN
          vnVLCREDDISPONIVELTOTAL := PKG_LIMITECREDITO.RETORNA_LIMITE_CRED_DISPONIVEL(p_regpedido.codcli,
                                                                                      TRUE,
                                                                                      FALSE,
                                                                                      p_regpedido.codcli);
        EXCEPTION
          WHEN OTHERS THEN
            vnVLCREDDISPONIVELTOTAL := 0;
        END;

        integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog            := 'C';
        integradora_comple.vLog.MSG                := 'Valor limite de crédito encontrado: ' || vnVLCREDDISPONIVELTOTAL;
        integradora_comple.vLog.ptabela            := null;
        integradora_comple.vLog.PVENDA             := null;
        integradora_comple.vLog.PBASE              := null;

        PRC_LOG_INTEGRADORA(integradora_comple.vlog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        PKG_MOTIVOBLOQUEIO.VALIDAMOTIVOSBLOQUEIO(p_regpedido.Numped,
                                                 p_regpedido.codemitente,
                                                 2500);
        BEGIN
          SELECT CODMOTIVO, PCBLOQUEIOSPEDIDO.CODMOTBLOQUEIO, MOTIVO, STATUS
            INTO VNCODMOTIVO,VNCODMOTIVOBLOQUEIO,VSMOTIVO, VSPOSICAO
            FROM PCBLOQUEIOSPEDIDO
           WHERE PCBLOQUEIOSPEDIDO.NUMPED = p_regpedido.Numped
             AND STATUS = 'B'
             AND ROWNUM = 1;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vncodmotivo := 0;
            VSPOSICAO   := UPPER(TRIM(p_regpedido.POSICAO));
        END;

        BEGIN
          IF (regfilial.aceitadesctmkfv = 'S') THEN
             SELECT COUNT(NVL( CODMOTIVO, 1)) TOTMOT
              INTO VSTOTALPEDSEMBLOQ307
              FROM PCBLOQUEIOSPEDIDO
             WHERE PCBLOQUEIOSPEDIDO.NUMPED = p_regpedido.Numped
               AND STATUS = 'B'
               AND PCBLOQUEIOSPEDIDO.CODMOTBLOQUEIO IS NULL
               AND PCBLOQUEIOSPEDIDO.CODMOTIVO NOT IN (5, 7);
          ELSE
            SELECT COUNT(NVL( CODMOTIVO, 1)) TOTMOT
              INTO VSTOTALPEDSEMBLOQ307
              FROM PCBLOQUEIOSPEDIDO
             WHERE PCBLOQUEIOSPEDIDO.NUMPED = p_regpedido.Numped
               AND STATUS = 'B'
               AND PCBLOQUEIOSPEDIDO.CODMOTBLOQUEIO IS NULL
               AND PCBLOQUEIOSPEDIDO.CODMOTIVO <> 7;
          END IF;

        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            VSTOTALPEDSEMBLOQ307 := 0;
        END;

        FOR cBLOQUEIO in (SELECT NVL(CODMOTIVO, PCBLOQUEIOSPEDIDO.CODMOTBLOQUEIO) CODMOTIVO, MOTIVO, STATUS
                            FROM PCBLOQUEIOSPEDIDO
                           WHERE PCBLOQUEIOSPEDIDO.NUMPED = p_regpedido.Numped
                             AND CODMOTIVO <> 5) LOOP

            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.codusur,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             'Bloqueio ' || cBLOQUEIO.CODMOTIVO || ': ' || cBLOQUEIO.MOTIVO,
                             NULL,
                             null);

        END LOOP;

        IF (TRIM(VSPOSICAO) <> UPPER(TRIM(p_regpedido.POSICAO))) AND
           ( (NVL(VNCODMOTIVO, 0) <> 0) OR (NVL(VNCODMOTIVOBLOQUEIO, 0) <> 0) )
        THEN
          IF (integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'S') or (VSTOTALPEDSEMBLOQ307 = 0 )
          THEN

            UPDATE PCPEDI
               SET POSICAO = VSPOSICAO
             WHERE PCPEDI.NUMPED = p_regpedido.NUMPED;


            UPDATE PCPEDC
               SET POSICAO = VSPOSICAO, CODMOTIVO = VNCODMOTIVO, CODMOTBLOQUEIO = VNCODMOTIVOBLOQUEIO, MOTIVOPOSICAO = substr(VSMOTIVO,1,60)
             WHERE PCPEDC.NUMPED = p_regpedido.NUMPED;

            p_regpedido.posicao := VSPOSICAO;
          END IF;

        ELSIF TRIM(VSPOSICAO) = 'B' AND
              UPPER(TRIM(p_regpedido.POSICAO)) = 'P' AND
              (NVL(VNCODMOTIVO, 0) <> 0) THEN


            UPDATE PCPEDI
               SET POSICAO = VSPOSICAO
             WHERE PCPEDI.NUMPED = p_regpedido.NUMPED;


            UPDATE PCPEDC
               SET POSICAO = VSPOSICAO, CODMOTIVO = VNCODMOTIVO, CODMOTBLOQUEIO = VNCODMOTIVOBLOQUEIO , MOTIVOPOSICAO = substr(VSMOTIVO,1,60)
             WHERE PCPEDC.NUMPED = p_regpedido.NUMPED;


        END IF;

        IF (p_regpedido.numpedorig <> 0) THEN

          IF (p_regpedido.POSICAOORIG <> VSPOSICAO) THEN
              p_regpedido.valido := FALSE;
		          integradora_comple.proc_delitensped(p_regpedido, 'R');
              integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
              integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
              integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
              integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
              integradora_comple.vLog.TipoLog            := 'C';
              integradora_comple.vLog.MSG                := 'Posicao ped. princ.: '|| p_regpedido.POSICAOORIG || CHR(13) || ' Posicao ped. compl.: '
                                                  || VSPOSICAO || CHR(13) ||'. Pedido complementar não pode alterar posição do pedido principal.';
              integradora_comple.vLog.ptabela            := null;
              integradora_comple.vLog.PVENDA             := null;
              integradora_comple.vLog.PBASE              := null;

              PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

              integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.codusur,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             ' Posicao ped. princ.: '|| p_regpedido.POSICAOORIG || CHR(13) || ' Posicao ped. compl.: '
                                                  || VSPOSICAO || CHR(13) ||'. Pedido complementar não pode alterar posição do pedido principal.',
                             NULL,
                             null);

          END IF;

        END IF;

         IF TRIM(VSPOSICAO) = 'B' and
            ((integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'N') and
             (VSTOTALPEDSEMBLOQ307 > 0 )) THEN
                p_regpedido.valido := FALSE;
            integradora_comple.proc_delitensped(p_regpedido, 'R');

            integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
            integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
            integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
            integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
            integradora_comple.vLog.TipoLog            := 'C';
            integradora_comple.vLog.MSG                := 'Pedido com bloqueio e sistema não aceita pedido bloqueado (aceitavendabloq).';
            integradora_comple.vLog.ptabela            := null;
            integradora_comple.vLog.PVENDA             := null;
            integradora_comple.vLog.PBASE              := null;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.codusur,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             'Pedido com bloqueio e sistema não aceita pedido bloqueado (aceitavendabloq e tipoimportacaovenda).',
                             NULL,
                             null);
        end if;

        integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog            := 'C';
        integradora_comple.vLog.MSG                := 'Fim validação limite de crédito disponível / motivos de bloqueio: ';

        PRC_LOG_INTEGRADORA(integradora_comple.vlog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

  end;

  PROCEDURE proc_unlockpedidos IS
    PRAGMA AUTONOMOUS_TRANSACTION;
    VNCONTPED NUMBER;
  BEGIN

    VNCONTPED := integradora_comple.gvet_regpedido.COUNT;

    IF integradora_comple.gvet_regpedido.COUNT > 0 THEN

      FOR i IN 1 .. vncontped LOOP

        integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regpedido(i)
                                                     .numpedrca;
        integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i)
                                                     .CODUSUR;
        integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regpedido(i)
                                                     .CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regpedido(i)
                                                     .DTABERTURAPEDPALM;
        integradora_comple.vLog.MSG               := 'Efetuando UnLock do Pedido ';

        PRC_LOG_INTEGRADORA(integradora_comple.vLog,
                            (CASE WHEN
                             integradora_comple.vLog.MSG LIKE '%ORA-%' THEN
                             DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE
                             TO_CHAR($$PLSQL_LINE) END));

        UPDATE pcpedcfv c
           SET c.importado = 3, c.observacao_pc = c.observacao_pc
         WHERE c.numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
           AND c.codusur = integradora_comple.gvet_regpedido(i).codusur
           AND c.dtaberturapedpalm = integradora_comple.gvet_regpedido(i)
              .dtaberturapedpalm
           AND c.importado = 4;
      END LOOP;

    ELSE

      UPDATE pcpedcfv c
         SET c.importado = 3, c.observacao_pc = c.observacao_pc
       WHERE c.numpedrca = integradora_comple.vLog.NUMPEDRCA
         AND c.codusur = integradora_comple.vLog.CODUSUR
         AND c.dtaberturapedpalm = integradora_comple.vLog.DTABERTURAPEDPALM
         AND c.importado = 1;
    END IF;

    COMMIT;

  END proc_unlockpedidos;

  PROCEDURE proc_processarleitura
  (
    p_existerro   IN OUT BOOLEAN,
    p_tipoleitura IN NUMBER,
    p_datainicial IN DATE,
    p_datafinal   IN DATE,
    p_codfilial   IN VARCHAR2,
    p_tiporeg     IN NUMBER,
    p_codusur     IN NUMBER DEFAULT NULL,
    p_numpedrca   IN NUMBER DEFAULT NULL
  ) IS

    vblercabok         BOOLEAN;
    vbleritemok        BOOLEAN;
    vncontped          INTEGER;
    vncontitem         INTEGER;
    vncontorigempreco  INTEGER;
    vncontorigemcomiss INTEGER;
    vncontorigemdesc   INTEGER;
    vddatainicial      DATE;
    vddatafinal        DATE;
    viauxiliar         integer;

    vMensagem          VARCHAR2(4000);
    vValido            BOOLEAN;
	vCursorEstoque     integradora_comple.T_CURSOR_ESTOQUE_LOCK;

  BEGIN
    /*
       Campo IMPORTADO:
       Valor 0 = registro bloqueado.
       Valor 1 = registro liberado para leitura.
       Valor 2 = registro lido.
       Valor 3 = registro liberado para leitura novamente (rejeitado anteriormente).
    */

    -- Ajusta a faixa de datas conforme parametro.
    IF p_tipoleitura = 1
    THEN

      vddatainicial := TRUNC(SYSDATE) - 365;
      vddatafinal   := TRUNC(SYSDATE);

    ELSE

      vddatainicial := p_datainicial;
      vddatafinal   := p_datafinal;

    END IF;

    vncontped          := 0;
    vncontitem         := 0;
    vncontorigempreco  := 0;
    vncontorigemcomiss := 0;
    vncontorigemdesc   := 0;
    integradora_comple.vngdatainicio      := vddatainicial;
    integradora_comple.vngdatafim         := vddatafinal;

    --Pedidos
    IF p_tiporeg IS NULL
       OR p_tiporeg = 5
    THEN

     /* integradora_comple.proc_lockestoque(p_tipoleitura,
                                          p_datainicial,
                                          p_datafinal,
                                          p_codfilial,
                                          p_tiporeg,
                                          p_codusur,
                                          p_numpedrca,
                                          vMensagem,
                                          vValido,
                                          vCursorEstoque);*/
	  vValido := TRUE;
      if vValido = TRUE then

      FOR cr_pedcab IN (SELECT numpedrca,
                               codusur,
                               cgccli,
                               dtaberturapedpalm,
                               dtfechamentopedpalm,
                               numpedcli,
                               dtentrega,
                               codfilial,
                               NVL(NVl(codfilialnf,(SELECT CODFILIALNF
                                                      FROM PCCLIENT
                                                     WHERE codcli = PCPEDCFV.CODCLI )), codfilial) codfilialnf,
                               codfilialretira,
                               vlfrete,
                               codcob,
                               codplpag,
                               condvenda,
                               obs1,
                               obs2,
                               obsentrega1,
                               obsentrega2,
                               obsentrega3,
                               obsentrega4,
                               fretedespacho,
                               freteredespacho,
                               codfornecfrete,
                               prazo1 parcela1,
                               prazo2 parcela2,
                               prazo3 parcela3,
                               prazo4 parcela4,
                               prazo5 parcela5,
                               prazo6 parcela6,
                               prazo7 parcela7,
                               prazo8 parcela8,
                               prazo9 parcela9,
                               prazo10 parcela10,
                               prazo11 parcela11,
                               prazo12 parcela12,
                               origemped,
                               numpedorigem,
                               codclinf,
                               tipodocumento,
                               contaordem,
                               codcli,
                               codclitv8,
                               codplpagetico,
                               codplpaggenerico,
                               tipoprioridadeentrega,
                               localdesembaraco,
                               ufdesembaraco,
                               numpedtv1,
                               percdescabatimento,
                               codrota,
                               agrupamento,
                               codbnf,
                               custobonificacao,
                               codfornecbonific,
                               turnoentrega,
                               codendent,
                               vlentrada,
                               orcamento,
                               codendentcli,
                               pvendasemimposto, --os preços enviados estão sem imposto ?
                               codclirecebedor,
                               vldescabatimento,
                               numregiaobroker,
                               codusur2,
                               codusur3,
                               codusur4,
                               coalesce(vendaassistida, 'N') vendaassistida,
                               ROWNUM AS linha,
                               gerardadosnfpaulista,
                               NVL(precocompartilha, 'N') precocompartilha,
                               assinatura,
                               idparceiro,
                               uidregistro,
                               nvl(vendatriangular, 'N') vendatriangular,
                               condfinanc,
                               NVL(PAGCHEQUEMORADIA,'N') PAGCHEQUEMORADIA,
                               CODBREX,
                               codemitente,
                               NVL(gerabrinde,'S') gerabrinde,
                               descintermediador,
                               cnpjintermediador,
							   Opervendaexpindireta
                          FROM pcpedcfv
                         WHERE importado = p_tipoleitura
                           AND (NVL(trunc(dtinclusao),
                                    TRUNC(SYSDATE)) BETWEEN vddatainicial AND vddatafinal)
                           AND ((nvl(codfilial,
                                     '99') = nvl(p_codfilial,
                                                   '99') OR nvl(codfilial,
                                                                  '99') = '99') OR (p_codfilial = '99'))
                           AND nvl(tipofv,
                                   'FV') = 'FV'
                           AND (codusur = p_codusur OR p_codusur IS NULL)
                           AND (numpedrca = p_numpedrca OR p_numpedrca IS NULL)
                      ORDER BY numpedorigem DESC)
      LOOP
        BEGIN

          viauxiliar := 0;
          IF NVL(CR_PEDCAB.Numpedorigem,0) <> 0 THEN

            Select count(*) into viauxiliar
              from pcpedipcpedifv i
             where i.numpedrcafv = cr_pedcab.numpedrca
               --DDVENDAS-21600
               and ((cr_pedcab.vendaassistida = 'N' AND  i.codusur     = cr_pedcab.codusur) OR  (cr_pedcab.vendaassistida = 'S'))
			   --and i.codusur     = cr_pedcab.codusur
               and nvl(i.dtaberturapedpalmfv, cr_pedcab.dtaberturapedpalm) = cr_pedcab.dtaberturapedpalm;

          END IF;

          integradora_comple.gregpedido.numpedrca             := cr_pedcab.numpedrca;
          integradora_comple.gregpedido.codusur               := cr_pedcab.codusur;
          integradora_comple.gregpedido.cgccli                := cr_pedcab.cgccli;
          integradora_comple.gregpedido.dtaberturapedpalm     := cr_pedcab.dtaberturapedpalm;
          integradora_comple.gregpedido.dtfechamentopedpalm   := cr_pedcab.dtfechamentopedpalm;
          integradora_comple.gregpedido.numpedcli             := cr_pedcab.numpedcli;
          integradora_comple.gregpedido.dtentrega             := cr_pedcab.dtentrega;
          integradora_comple.gregpedido.codfilial             := nvl(cr_pedcab.codfilial,
                                                  integradora_comple.gregpcconsum.codfilialfv);
          integradora_comple.gregpedido.codfilialnf           := cr_pedcab.codfilialnf;
          integradora_comple.gregpedido.codfilialretira       := cr_pedcab.codfilialretira;
          integradora_comple.gregpedido.vlfrete               := NVL(cr_pedcab.vlfrete,0);
          integradora_comple.gregpedido.codcob                := UPPER(cr_pedcab.codcob);
          integradora_comple.gregpedido.codplpag              := cr_pedcab.codplpag;
          integradora_comple.gregpedido.condvenda             := cr_pedcab.condvenda;
          integradora_comple.gregpedido.obs1                  := cr_pedcab.obs1;
          integradora_comple.gregpedido.obs2                  := cr_pedcab.obs2;
          integradora_comple.gregpedido.obsentrega1           := cr_pedcab.obsentrega1;
          integradora_comple.gregpedido.obsentrega2           := cr_pedcab.obsentrega2;
          integradora_comple.gregpedido.obsentrega3           := cr_pedcab.obsentrega3;
          integradora_comple.gregpedido.obsentrega4           := cr_pedcab.obsentrega4;
          integradora_comple.gregpedido.fretedespacho         := cr_pedcab.fretedespacho;
          integradora_comple.gregpedido.freteredespacho       := cr_pedcab.freteredespacho;
          integradora_comple.gregpedido.codfornecfrete        := cr_pedcab.codfornecfrete;
          integradora_comple.gregpedido.parcela1              := cr_pedcab.parcela1;
          integradora_comple.gregpedido.parcela2              := cr_pedcab.parcela2;
          integradora_comple.gregpedido.parcela3              := cr_pedcab.parcela3;
          integradora_comple.gregpedido.parcela4              := cr_pedcab.parcela4;
          integradora_comple.gregpedido.parcela5              := cr_pedcab.parcela5;
          integradora_comple.gregpedido.parcela6              := cr_pedcab.parcela6;
          integradora_comple.gregpedido.parcela7              := cr_pedcab.parcela7;
          integradora_comple.gregpedido.parcela8              := cr_pedcab.parcela8;
          integradora_comple.gregpedido.parcela9              := cr_pedcab.parcela9;
          integradora_comple.gregpedido.parcela10             := cr_pedcab.parcela10;
          integradora_comple.gregpedido.parcela11             := cr_pedcab.parcela11;
          integradora_comple.gregpedido.parcela12             := cr_pedcab.parcela12;
          integradora_comple.gregpedido.origemped             := case when
                                                                  nvl(cr_pedcab.origemped,'F') = 'C'
                                                                  then 'F'
                                                                  else nvl(cr_pedcab.origemped,'F')
                                                                  end;
          integradora_comple.gregpedido.gerabrinde            := nvl(cr_pedcab.gerabrinde,'S');
          integradora_comple.gregpedido.numpedorig            := cr_pedcab.numpedorigem;
          integradora_comple.gregpedido.DATA                  := TRUNC(SYSDATE);
          integradora_comple.gregpedido.codclinf              := cr_pedcab.codclinf;
          integradora_comple.gregpedido.tipodocumento         := cr_pedcab.tipodocumento;
          integradora_comple.gregpedido.contaordem            := cr_pedcab.contaordem;
          integradora_comple.gregpedido.codcli                := cr_pedcab.codcli;
          integradora_comple.gregpedido.codclitv8             := cr_pedcab.codclitv8;
          integradora_comple.gregpedido.codplpagetico         := cr_pedcab.codplpagetico;
          integradora_comple.gregpedido.codplpaggenerico      := cr_pedcab.codplpaggenerico;
          integradora_comple.gregpedido.tipoprioridadeentrega := cr_pedcab.tipoprioridadeentrega;
          integradora_comple.gregpedido.localdesembaraco      := cr_pedcab.localdesembaraco;
          integradora_comple.gregpedido.ufdesembaraco         := cr_pedcab.ufdesembaraco;
          integradora_comple.gregpedido.numpedtv1             := case when
                                                                  cr_pedcab.condvenda = '5'
                                                                  then cr_pedcab.numpedtv1
                                                                  else ''
                                                                  end;
          integradora_comple.gregpedido.percdescabatimento    := cr_pedcab.percdescabatimento;
          integradora_comple.gregpedido.codrota               := cr_pedcab.codrota;
          integradora_comple.gregpedido.agrupamento           := cr_pedcab.agrupamento;
          integradora_comple.gregpedido.codbnf                := cr_pedcab.codbnf;
          integradora_comple.gregpedido.custobonificacao      := upper(cr_pedcab.custobonificacao);
          integradora_comple.gregpedido.codfornecbonific      := cr_pedcab.codfornecbonific;
          integradora_comple.gregpedido.turnoentrega          := cr_pedcab.turnoentrega;
          integradora_comple.gregpedido.codendent             := cr_pedcab.codendent;
          integradora_comple.gregpedido.vlentrada             := cr_pedcab.vlentrada;
          integradora_comple.gregpedido.orcamento             := nvl(cr_pedcab.orcamento,
                                                  'N');
          integradora_comple.gregpedido.codendentcli          := cr_pedcab.codendentcli;

          if(NVL(cr_pedcab.pvendasemimposto,'N') = 'N') then
           if(FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('TIPOENVIOFECPFV','99','M') = 'M')THEN
             integradora_comple.gregpedido.pvendasemimposto := 'N';
           ELSIF(FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('TIPOENVIOFECPFV','99','M') = 'A')THEN
             integradora_comple.gregpedido.pvendasemimposto := 'A';
           ELSE
             integradora_comple.gregpedido.pvendasemimposto := 'P';
           END IF;
          ELSE
            integradora_comple.gregpedido.pvendasemimposto      := nvl(cr_pedcab.pvendasemimposto,'N');
          END IF;

          integradora_comple.gregpedido.codclirecebedor       := cr_pedcab.codclirecebedor;
          integradora_comple.gregpedido.vldescabatimento      := cr_pedcab.vldescabatimento;
          integradora_comple.gregpedido.numregiaobroker       := cr_pedcab.numregiaobroker;
          integradora_comple.gregpedido.codusur2              := cr_pedcab.codusur2;
          integradora_comple.gregpedido.codusur3              := cr_pedcab.codusur3;
          integradora_comple.gregpedido.codusur4              := cr_pedcab.codusur4;
          integradora_comple.gregpedido.rotinalanc            := 'INTEGRADORA ' || integradora_comple.vsVersao;
          integradora_comple.gregpedido.vendaassistida        := cr_pedcab.vendaassistida;
          integradora_comple.gregpedido.gerardadosnfpaulista  := cr_pedcab.gerardadosnfpaulista;
          integradora_comple.gregpedido.precocompartilha      := cr_pedcab.PRECOCOMPARTILHA;
          integradora_comple.gregpedido.assinatura            := cr_pedcab.assinatura;
          integradora_comple.gregpedido.idparceiro            := cr_pedcab.idparceiro;
          integradora_comple.gregpedido.uidregistro           := cr_pedcab.uidregistro;
          integradora_comple.gregpedido.vendatriangular       := cr_pedcab.vendatriangular;
          integradora_comple.gregpedido.condfinanc            := cr_pedcab.condfinanc;
          integradora_comple.gregpedido.PAGCHEQUEMORADIA      := cr_pedcab.PAGCHEQUEMORADIA;
          integradora_comple.gregpedido.codbrex               := nvl(cr_pedcab.codbrex, 0);
          integradora_comple.gregpedido.codemitente           := nvl(cr_pedcab.codemitente, 8888);
          integradora_comple.gregpedido.descintermediador     := cr_pedcab.descintermediador;
          integradora_comple.gregpedido.cnpjintermediador     := cr_pedcab.cnpjintermediador;
		  integradora_comple.gregpedido.opervendaexpindireta  := cr_pedcab.opervendaexpindireta;

          IF NVL(integradora_comple.gregpedido.dtentrega,
                 TRUNC(SYSDATE)) < TRUNC(SYSDATE)
          THEN
            integradora_comple.gregpedido.dtentrega := TRUNC(SYSDATE);
          END IF;

          begin
            select pcsuperv.codsupervisor
                 , pcsuperv.codgerente
              into integradora_comple.gregpedido.codsupervisor
                 , integradora_comple.gregpedido.codgerente
              from pcsuperv
                 , pcusuari
             where pcusuari.codsupervisor = pcsuperv.codsupervisor
               and pcusuari.codusur = cr_pedcab.codusur;
          exception
          when others then
            null;
          end;

          vblercabok := TRUE;

          IF viauxiliar > 0 then

            integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gregpedido.numpedrca;
            integradora_comple.vLog.CODUSUR           := integradora_comple.gregpedido.codusur;
            integradora_comple.vLog.CGCCLI            := integradora_comple.gregpedido.cgccli;
            integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gregpedido.dtaberturapedpalm;
            integradora_comple.vLog.TIPOLOG           := 'G';
            integradora_comple.vLog.MSG               := 'Já existe pedido importado anteriormente. Favor consultar pedido no Sistema.';

            PRC_LOG_INTEGRADORA(integradora_comple.vLog,
                                (CASE WHEN
                                 integradora_comple.vLog.MSG LIKE '%ORA-%' THEN
                                 DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE
                                 TO_CHAR($$PLSQL_LINE) END));

            p_existerro := TRUE;
            vblercabok  := FALSE;

            integradora_comple.proc_registralog(NULL,
                                                cr_pedcab.numpedrca,
                                                NULL,
                                                NULL,
                                                NULL,
                                                NULL,
                                                NULL,
                                                NULL,
                                                NULL,
                                                cr_pedcab.codusur,
                                                cr_pedcab.dtaberturapedpalm,
                                                NULL,
                                                '2',
                                                'Já existe pedido importado anteriormente. Favor consultar pedido no Sistema.',
                                                NULL,
                                                NULL);

            exit;
          end if;

          /**************************************************************************
          *BLOQUEIA O PEDIDO PRA NÃO SER PROCESSADO POR OUTRA CHAMADA DA INTEGRADORA*
          **************************************************************************/
          vblercabok := integradora_comple.func_lockpedido(cr_pedcab.numpedrca, cr_pedcab.codusur, cr_pedcab.dtaberturapedpalm, cr_pedcab.cgccli, p_tipoleitura);
          ---------------------------------------------------------------------------
          --Desdodbrar os itens do pedido, conforme a filial retira que irá atender
          if (paramfilial.obtercomovarchar2('ATRIBUIRFILIALRETIRAAUTOMATICOFV', cr_pedcab.codfilial) = 'S') and
             (paramfilial.obtercomovarchar2('CON_USACHAVETRIPLAPCPEDI') = 'S') THEN
             integradora_comple.PROCURAR_ESTOQUE(cr_pedcab.numpedrca, cr_pedcab.cgccli, cr_pedcab.codusur);
          END IF;

          IF vblercabok and viauxiliar = 0
          THEN
            vncontped := vncontped + 1;
            integradora_comple.gvet_regpedido(vncontped) := integradora_comple.gregpedido;

            FOR cr_pedcorp IN (SELECT numpedrca,
                                      cgccli,
                                      codusur,
                                      dtaberturapedpalm,
                                      codprod,
                                      numseq,
                                      qt,
                                      pvenda,
                                      codauxiliar,
                                      codfilialretira,
                                      unidade_frios,
                                      politicaprioritaria,
                                      codcombo,
                                      sugestao,
                                      tipoentrega,
                                      ROWNUM AS linha,
                                      nvl(bonific,'N') bonific, --HIS.05072.2014
                                      vlbasepartdest,
                                      aliqfcp,
                                      aliqinternadest,
                                      vlfcppart,
                                      vlicmspartdest,
                                      vlicmspart,
                                      usaunidademaster,
                                      coddescontosimulador,
                                      devolucaocarcaca, --HIS.03804.2016
                                      VLDESCCARCACA, --HIS.03804.2016
                                      tipocombo,
                                      nvl(MOVIMENTACONTACORRENTERCA, 'S') movimentacontacorrenterca, --HIS.01896.2017
                                      numpedcli,
                                      numitemped,
                                      coddesconto,
                                      dtentrega
                                 FROM pcpedifv
                                WHERE numpedrca = cr_pedcab.numpedrca
                                  AND cgccli = cr_pedcab.cgccli
                                  --AND codusur = cr_pedcab.codusur (VEN-963)
                                  AND dtaberturapedpalm = cr_pedcab.dtaberturapedpalm
                                  order by numseq)
            LOOP
              BEGIN


                integradora_comple.gregitem.numpedrca           := cr_pedcorp.numpedrca;
                integradora_comple.gregitem.codusur             := cr_pedcorp.codusur;
                integradora_comple.gregitem.cgccli              := cr_pedcorp.cgccli;
                integradora_comple.gregitem.dtaberturapedpalm   := cr_pedcorp.dtaberturapedpalm;
                integradora_comple.gregitem.codprod             := cr_pedcorp.codprod;
                integradora_comple.gregitem.numseq              := cr_pedcorp.numseq;
                integradora_comple.gregitem.numseqfv            := cr_pedcorp.numseq;
                integradora_comple.gregitem.qt                  := cr_pedcorp.qt;
                integradora_comple.gregitem.pvenda              := cr_pedcorp.pvenda;
                integradora_comple.gregitem.pvendaanterior      := cr_pedcorp.pvenda;
                integradora_comple.gregitem.codfilialretira     := cr_pedcorp.codfilialretira;
                integradora_comple.gregitem.codauxiliar         := cr_pedcorp.codauxiliar;
                integradora_comple.gregitem.numpedorig          := integradora_comple.gregpedido.numpedorig;
                integradora_comple.gregitem.unidadevenda        := upper(TRIM(cr_pedcorp.unidade_frios));
                integradora_comple.gregitem.politicaprioritaria := nvl(cr_pedcorp.politicaprioritaria, 'N');
                integradora_comple.gregitem.coddescontofv       := nvl(cr_pedcorp.coddesconto, 0);
                /* ICMS PARTILHA */
                integradora_comple.gregitem.vlbasepartdest      := nvl(cr_pedcorp.vlbasepartdest,0);
                integradora_comple.gregitem.aliqfcp             := nvl(cr_pedcorp.aliqfcp,0);
                integradora_comple.gregitem.aliqinternadest     := nvl(cr_pedcorp.aliqinternadest,0);
                integradora_comple.gregitem.vlfcppart           := nvl(cr_pedcorp.vlfcppart,0);
                integradora_comple.gregitem.vlicmspartdest      := nvl(cr_pedcorp.vlicmspartdest,0);
                integradora_comple.gregitem.vlicmspart          := nvl(cr_pedcorp.vlicmspart,0);
                integradora_comple.gregitem.usaunidademaster    := nvl(cr_pedcorp.usaunidademaster, 'N');
                integradora_comple.gregitem.devolucaocarcaca    := nvl(cr_pedcorp.devolucaocarcaca, 'N'); --HIS.03804.2016
                integradora_comple.gregitem.vldesccarcaca       := cr_pedcorp.vldesccarcaca;              --HIS.03804.2016
                integradora_comple.gregitem.tipocombo           := cr_pedcorp.tipocombo;
                integradora_comple.gregitem.numpedcli           := cr_pedcorp.numpedcli;
                integradora_comple.gregitem.numitemped          := cr_pedcorp.numitemped;

                /* ICMS PARTILHA */

                integradora_comple.gregitem.movimentacontacorrenterca := cr_pedcorp.MOVIMENTACONTACORRENTERCA; --HIS.01896.2017

                 /******************************************
                *Solicitação: 3013.100359.2015
                *Responsável: Rafael Soares
                *Data       : 17/09/2015
                *Alteração:   Integradora não deve realizar nenhuma validação de combo na importação
                *             importação de pedidos TV5
                *****************************************/
                IF cr_pedcab.condvenda = 5
                THEN
                    integradora_comple.gregitem.codcombo            := NULL;
                ELSE
                    integradora_comple.gregitem.codcombo            := cr_pedcorp.codcombo;
                END IF;
                integradora_comple.gregitem.sugestao            := cr_pedcorp.sugestao;
                integradora_comple.gregitem.tipoentrega         := cr_pedcorp.tipoentrega;
                IF (cr_pedcab.condvenda = 7) and cr_pedcorp.tipoentrega IN ('EN', 'EF')
                THEN
                    integradora_comple.gregitem.dtentrega           := nvl(cr_pedcorp.Dtentrega,cr_pedcab.dtentrega);
                END IF;                
                vbleritemok                  := TRUE;

                -----------------------------------------------------------
                --Autor: Rodrigo Santos
                --Solicitação: HIS.05072.2014
                --Data: 12/12/2014
                --Descrição: Implementação referente a item BNF no pedido TV1.

                integradora_comple.gregitem.bonific := cr_pedcorp.bonific;
                -----------------------------------------------------------

                -----------------------------------------------------------
                --Autor: Guilherme Freitas
                --Solicitação: HIS.00698.2015
                --Data: 28/06/2016
                --Descrição: Implementação do desconto de simulador.

                integradora_comple.gregitem.coddescontosimulador := cr_pedcorp.CODDESCONTOSIMULADOR;
                ------------------------------------------------------------


                IF vbleritemok = TRUE
                THEN
                  vncontitem := vncontitem + 1;
                  integradora_comple.gvet_regitem(vncontitem) := integradora_comple.gregitem;
                  -- incrementar contador de itens do pedido atual
                  integradora_comple.gvet_regpedido(vncontped).numitens := NVL(integradora_comple.gvet_regpedido(vncontped).numitens,
                                                            0) + 1;

                  --origempreco
                  vncontorigempreco := vncontorigempreco + 1;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).codprod := integradora_comple.gregitem.codprod;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).data := integradora_comple.gvet_regpedido(vncontped).data;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).origemped := integradora_comple.gvet_regpedido(vncontped).origemped;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).codemitente := cr_pedcab.codemitente;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).codfilial := integradora_comple.gvet_regpedido(vncontped).codfilial;
                  integradora_comple.gvet_regorigempreco(vncontorigempreco).usatributporuf := 'N';


                  --origemcomiss
                  vncontorigemcomiss := vncontorigemcomiss + 1;
                  integradora_comple.gvet_regorigemcomiss(vncontorigemcomiss).codprod := integradora_comple.gregitem.codprod;
                  integradora_comple.gvet_regorigemcomiss(vncontorigemcomiss).origemped := integradora_comple.gvet_regpedido(vncontped).origemped;
                  integradora_comple.gvet_regorigemcomiss(vncontorigemcomiss).codauxiliar := integradora_comple.gregitem.codauxiliar;
                  integradora_comple.gvet_regorigemcomiss(vncontorigemcomiss).codfilial := integradora_comple.gvet_regpedido(vncontped).codfilial;
                  integradora_comple.gvet_regorigemcomiss(vncontorigemcomiss).codusur := integradora_comple.gvet_regpedido(vncontped).codusur;

                  --origemdesc
                  vncontorigemdesc := vncontorigemdesc + 1;
                  integradora_comple.gvet_regorigemdesc(vncontorigemdesc).codprod := integradora_comple.gregitem.codprod;
                  integradora_comple.gvet_regorigemdesc(vncontorigemdesc).origemped := integradora_comple.gvet_regpedido(vncontped).origemped;
                  integradora_comple.gvet_regorigemdesc(vncontorigemdesc).codauxiliar := integradora_comple.gregitem.codauxiliar;


                END IF;
              EXCEPTION
                WHEN OTHERS THEN
                  integradora_comple.vLog.NUMPEDRCA         := cr_pedcorp.numpedrca;
                  integradora_comple.vLog.CODUSUR           := cr_pedcorp.CODUSUR;
                  integradora_comple.vLog.CGCCLI            := cr_pedcorp.CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM := cr_pedcorp.DTABERTURAPEDPALM;
                  integradora_comple.vLog.TIPOLOG           := 'G';
                  integradora_comple.vLog.MSG               := 'ERRO AO LER ITEM DO PEDIDO' || SQLCODE || '-' || SQLERRM || ';';

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  integradora_comple.proc_registralog(NULL,
                                   cr_pedcorp.numpedrca,
                                   cr_pedcorp.codprod,
                                   cr_pedcorp.numseq,
                                   cr_pedcorp.codauxiliar,
                                   cr_pedcorp.cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   cr_pedcorp.codusur,
                                   cr_pedcorp.dtaberturapedpalm,
                                   NULL,
                                   '3',
                                   'ERRO AO LER ITEM DO PEDIDO#' || SQLCODE || '-' || ';' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                                   cr_pedcorp.linha,
                                   NULL);
              END;
            END LOOP;
          END IF;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.vLog.NUMPEDRCA         := cr_pedcab.numpedrca;
            integradora_comple.vLog.CODUSUR           := cr_pedcab.CODUSUR;
            integradora_comple.vLog.CGCCLI            := cr_pedcab.CGCCLI;
            integradora_comple.vLog.DTABERTURAPEDPALM := cr_pedcab.DTABERTURAPEDPALM;
            integradora_comple.vLog.TIPOLOG           := 'G';
            integradora_comple.vLog.MSG               := 'ERRO AO LER PEDIDO' || SQLCODE || '-' || SQLERRM;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

            integradora_comple.proc_registralog(NULL,
                             cr_pedcab.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             cr_pedcab.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             cr_pedcab.codusur,
                             cr_pedcab.dtaberturapedpalm,
                             NULL,
                             '2',
                             'ERRO AO LER PEDIDO#' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                             cr_pedcab.linha,
                             NULL);
        END;
      END LOOP;
	  END IF;
	  --Fim bloqueio estoque para importar
    END IF;
    --fim pedidos


  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.vLog.NUMPEDRCA         := NULL;
      integradora_comple.vLog.CODUSUR           := NULL;
      integradora_comple.vLog.CGCCLI            := NULL;
      integradora_comple.vLog.DTABERTURAPEDPALM := NULL;
      integradora_comple.vLog.TipoLog           := 'G';
      integradora_comple.vLog.MSG               := 'ERRO AO LER PEDIDOS' || SQLCODE || '-' || ';' || SQLERRM;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      p_existerro := TRUE;
      integradora_comple.proc_registralog(NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       '1',
                       'ERRO AO LER PEDIDOS;' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       NULL);
  END proc_processarleitura;

  PROCEDURE proc_pcparamfilial
  (
    p_codfilial IN pcfilial.codigo%TYPE,
    p_nome      IN pcparamfilial.nome%TYPE,
    p_padrao    IN pcparamfilial.valor%TYPE,
    p_valor     OUT pcparamfilial.valor%TYPE
  ) IS

    vsnome pcparamfilial.nome%TYPE;

  BEGIN

    vsnome := upper(TRIM(p_nome));


    BEGIN
      SELECT nvl(p.valor,
                 p_padrao)
        INTO p_valor
        FROM pcparamfilial p
       WHERE upper(TRIM(p.nome)) = vsnome
         AND p.codfilial = p_codfilial;
    EXCEPTION

      WHEN no_Data_found THEN

        BEGIN

          SELECT nvl(p.valor,
                     p_padrao)
            INTO p_valor
            FROM pcparamfilial p
           WHERE upper(TRIM(p.nome)) = vsnome
             AND p.codfilial = '99';
        EXCEPTION
          WHEN no_data_found THEN

            p_valor := p_padrao;

        END;

      WHEN OTHERS THEN
        p_valor := p_padrao;

    END;



  END proc_pcparamfilial;

