    THEN
      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;

      vsmensagem := vsmensagem || vschar || vsmensagem_rest || ';';

      IF p_regfilial.tipoimportacaovenda = 'RI'
      THEN
        p_regitem.valido        := FALSE;
        p_regorigempreco.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'RP'
      THEN
        p_regpedido.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'BP'
      THEN
        p_Regpedido.posicao := 'B';

        IF length(p_regpedido.log) <= 3000
           OR p_regpedido.log IS NULL
        THEN
          p_regpedido.log := p_regpedido.log || CHR(13) || vsmensagem_rest;
        END IF;

        PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,20,substr(vsmensagem_rest,1,200),'C');

        p_regpedido.motivoposicao := substr(vsmensagem_rest,
                                            1,
                                            45) || 'Codprod :' || p_regitem.codprod;

      END IF;

    END IF;

    ----------------------------------------------------------------------

    --tarefa 145246
    IF p_regfilial.utilizavendaporembalagem = 'S'
