        THEN
          p_regitem.valido        := FALSE;
          p_regorigempreco.valido := FALSE;
        ELSIF p_regfilial.tipoimportacaovenda = 'RP'
        THEN
          p_regpedido.valido := FALSE;
        ELSIF p_regfilial.tipoimportacaovenda = 'BP'
        THEN
          p_Regpedido.posicao := 'B';

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || 'Código EAN13, EAN8 ou DUN14 do produto é inválido ou não existe.' || ';';

          p_regpedido.motivoposicao := substr(vsmensagem,1,50);
          PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,20,substr(vsmensagem,1,200),'C');

        END IF;

      ELSE

        SELECT COUNT(*)
          INTO vicontador
          FROM pcembalagem p
         WHERE codprod = p_regitem.codprod
           AND codfilial = p_regpedido.codfilial
           AND codauxiliar = p_regitem.codauxiliar;

        IF vicontador = 0
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || 'PRODUTO NAO ENCONTRADO COM ESTE CODAUXILIAR' || ';';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;
          ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
            p_regpedido.valido := FALSE;
          END IF;

        END IF;

        -- SE A EMBALAGEM NÃO FOR PERMITIDA NO FV, DEVO REJEITAR A IMPORTAÇÃO DO PRODUTO.
        SELECT COUNT(*)
          INTO vicontador
          FROM pcembalagem p
         WHERE codprod = p_regitem.codprod
           AND codfilial = p_regpedido.codfilial
           AND codauxiliar = p_regitem.codauxiliar
           AND P.ENVIAFV = 'S';

        IF vicontador = 0
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || 'EMBALAGEM INFORMADA NÃO PERMITIDA NO FORÇA DE VENDAS' || ';';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;
          ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
            p_regpedido.valido := FALSE;
         END IF;

        END IF;


      END IF;

    END IF;

    IF p_regproduto.tipomerc = 'CB'
