                 --   round(NVL(pctabpr.pvendasemimposto, 0),integradora_comple.gregpcconsum.numcasasdecvenda),
                 --   round(NVL(pctabpr.pvendaatacsemimposto, 0),integradora_comple.gregpcconsum.numcasasdecvenda)
                 nvl(pctabpr.vlst,0),
                 nvl(pctabpr.custoprecific, 0),
                 nvl(pctribut.AGREGADESCST1, 'N'),
                 NVL(PCTRIBUT.APLICAACRESPFJURIDICA,'N')APLICAACRESPFJURIDICA,
                 nvl(pctribut.PERACRESCISMOSIMPNAC,0),
                 nvl(pctribut.codicmtabsimpnasc,0),
                 NVL(PCPRODUT.CUSTOREPZFM,PCPRODUT.CUSTOREP) PTABELAFABRICAZFM,
                 PCTRIBUT.CODICMDIFER,
                 PCTABPR.Vlipi,
                 NVL(pcest.custofinsemst,0),
                 nvl(pctribut.UTILIZAMOTORCALCULO, 'N') UTILIZAMOTORCALCULO,
                 NVL(PCTABPR.PERDESCFOB,0),
                 COALESCE(PCTRIBUT.PERCACRESCBENFFIS,0 ) PERCACRESCBENFFIS,
                 NVL(PCTABPR.PERCACRESCIMOFRETE, 0) PERCACRESCIMOFRETE,
                 NVL(PCTABPR.PERCDESCSIMPLESNAC,0)
            INTO p_regprecos
            FROM pctabpr,
                 pctribut,
                 pcest,
                 pcprodut,
                 pctribut vt
          -- WHERE pctabpr.codst = pctribut.codst(+)
           WHERE PCTABPR.CODST = VT.CODST(+)
             AND NVL(DECODE(P_REGPEDIDO.VENDATRIANGULAR,
                            'S',
                             VT.CODFIGVENDATRIANGULAR,
                             VT.CODST), VT.CODST) = PCTRIBUT.CODST
             AND pcest.codprod = pctabpr.codprod(+)
             AND pcest.codprod = p_regitem.codprod
             AND p_regregiao.numregiao = pctabpr.numregiao(+)
             AND pcest.codfilial = decode(p_regfilial.origemcustofilialretira,
                                          'V',
                                          p_regpedido.codfilial,
                                          p_regitem.codfilialretira)
                 AND pcprodut.codprod  = pcest.codprod           --HIS.00185.2015
                 AND  pcprodut.codprod = pctabpr.codprod;        --HIS.00185.2015
        EXCEPTION
          WHEN OTHERS THEN
            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;

            vsmensagem       := vsmensagem || vschar || 'Erro ao buscar preco do produto#;' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';';
            p_regitem.valido := FALSE;
        END;
       END IF;
      END IF;
    ELSE
      --não é cesta

      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog           := 'I';
      integradora_comple.vLog.MSG               := 'Buscando dados de tributação de produto normal.';

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      IF p_regfilial.utilizavendaporembalagem = 'S'
      THEN

        vnPOFERTA := 0;
         vnPOFERTAATAC := 0;
        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAOFERTAEMBALAGEM', '99', 'N') = 'S' THEN
          SELECT NVL(MIN(POFERTA), 0) AS POFERTA, NVL(MIN(POFERTAATAC), 0) POFERTAATAC
            INTO vnPOFERTA, vnPOFERTAATAC
            FROM (SELECT POFERTA, NULL AS POFERTAATAC
                    FROM PCEMBALAGEM E
                   WHERE E.CODPROD = P_REGITEM.codprod
                     AND E.CODAUXILIAR = P_REGITEM.codauxiliar
                     AND E.CODFILIAL = P_REGPEDIDO.codfilial
                     AND E.DTOFERTAINI <= TRUNC(SYSDATE)
                     AND E.DTOFERTAFIM >= TRUNC(SYSDATE)
                  UNION ALL
                  SELECT NULL, E.POFERTAATAC
                    FROM PCEMBALAGEM E
                   WHERE E.CODPROD = P_REGITEM.codprod
                     AND E.CODAUXILIAR = P_REGITEM.codauxiliar
                     AND E.CODFILIAL = P_REGPEDIDO.codfilial
                     AND E.DTOFERTAATACINI <= TRUNC(SYSDATE)
                     AND E.DTOFERTAATACFIM >= TRUNC(SYSDATE)
                  UNION ALL
                  SELECT I.VLOFERTA POFERTA, I.VLOFERTAATAC POFERTAATAC
                    FROM PCOFERTAPROGRAMADAI I, PCOFERTAPROGRAMADAC C
                   WHERE I.CODOFERTA = C.CODOFERTA
                     AND C.DTCANCEL IS NULL
                     AND I.CODAUXILIAR = P_REGITEM.codauxiliar
                     AND I.CODFILIAL = P_REGPEDIDO.codfilial
                     AND C.DTINICIAL <= TRUNC(SYSDATE)
                     AND C.DTFINAL >= TRUNC(SYSDATE));
        END IF;

        --tributacao por estado
        IF nvl(integradora_comple.gregpcconsum.usatributacaoporuf,
               'N') = 'S'
        THEN

          p_regorigempreco.usatributporuf := 'S';

          IF p_regpedido.codfilialnf IS NULL
          THEN

            IF p_regcliente.codfilialnf IS NULL
            THEN

              vscodfilialnf := p_regpedido.codfilial;
            ELSE

              vscodfilialnf := p_regcliente.codfilialnf;
            END IF;
          ELSE

            vscodfilialnf := p_regpedido.codfilialnf;
          END IF;


          SELECT COUNT(*)
            INTO vicontador
            FROM pctabtrib p
           WHERE p.codprod = p_Regitem.codprod
             AND p.codfilialnf = vscodfilialnf
             AND p.ufdestino = nvl(vsUfEnt, p_Regcliente.estent);

          IF vicontador = 0
          THEN
            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;
            vsmensagem := vsmensagem || vschar || 'NÃO ENCONTRADA TRIBUTAÇÃO POR ESTADO;';

            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;

          ELSE

            SELECT p.codst
              INTO vncodst
              FROM pctabtrib p
             WHERE p.codprod = p_Regitem.codprod
               AND p.codfilialnf = vscodfilialnf
               AND p.ufdestino = nvl(vsUfEnt, p_Regcliente.estent)
               AND rownum = 1;

