                     nvl(pctabpr.vlst,0),
                     nvl(pctabpr.custoprecific,0),
                     nvl(pctribut.AGREGADESCST1, 'N'),
                     NVL(PCTRIBUT.APLICAACRESPFJURIDICA,'N')APLICAACRESPFJURIDICA,
                     nvl(pctribut.PERACRESCISMOSIMPNAC,0),
                     nvl(pctribut.codicmtabsimpnasc,0),
                     0 PTABELAFABRICAZFM,
                     PCTRIBUT.CODICMDIFER,
                     PCTABPR.Vlipi,
                     NVL(pcest.custofinsemst,0),
                     nvl(pctribut.UTILIZAMOTORCALCULO, 'N') UTILIZAMOTORCALCULO,
                     NVL(PCTABPR.PERDESCFOB,0),
                     COALESCE(PCTRIBUT.PERCACRESCBENFFIS,0 ) PERCACRESCBENFFIS,
                     NVL(PCTABPR.PERCACRESCIMOFRETE, 0) PERCACRESCIMOFRETE,
                     NVL(PCTABPR.PERCDESCSIMPLESNAC,0)
                INTO p_regprecos
                FROM pctabpr,
                     pctribut,
                     pcest,
                     pcembalagem,
                     pcprodut,
                     pctribut vt
               --WHERE pctribut.codst = vncodst
               WHERE VT.CODST = VNCODST
                 AND NVL(DECODE(P_REGPEDIDO.VENDATRIANGULAR,
                                'S',
                                VT.CODFIGVENDATRIANGULAR,
                                VT.CODST), VT.CODST) = PCTRIBUT.CODST
                 AND pctabpr.codprod = p_regitem.codprod
                 AND pcest.codprod = p_regitem.codprod
                 AND pctabpr.numregiao = p_regregiao.numregiao
                 AND pcest.codfilial = decode(p_regfilial.origemcustofilialretira,
                                              'V',
                                              p_regpedido.codfilial,
                                              p_regitem.codfilialretira)
                 AND pcembalagem.codprod = p_regitem.codprod
                 AND pcprodut.codprod = p_regitem.codprod
                 AND pcembalagem.codauxiliar = p_regitem.codauxiliar
                 AND pcembalagem.codfilial = p_regpedido.codfilial;
            EXCEPTION
              WHEN OTHERS THEN
                IF vsmensagem IS NOT NULL
                THEN
                  vschar := '#';
                ELSE
                  vschar := NULL;
                END IF;
                vsmensagem              := vsmensagem || vschar || 'ERRO AO BUSCAR PRECO DO PRODUTO#;' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';';
                p_regitem.valido        := FALSE;
                p_regorigempreco.valido := FALSE;
            END;
           END IF;

            IF nvl(p_apenasvalida,
                   'N') = 'N'
            THEN

              p_regitem.pvenda := round(p_regitem.pvenda / p_regprecos.qtunit,
                                        6);
            END IF;

            p_regitem.qt := p_regitem.qt * p_regprecos.qtunit;

          END IF;

          --não usa tributação por estado
        ELSE
          -- busca as informacoes da tabela de preco.

         IF p_regitem.valido = TRUE
         THEN
          BEGIN
            SELECT NVL(pctribut.aliqicms1,
                       0),
                   NVL(pctribut.aliqicms2,
                       0),
                   NVL(pctribut.codicmtab,
                       0),
                   pctabpr.codst,
                   NVL(pcest.custocont,
                       0),
                   NVL(pcest.custofin,
                       0),
                   NVL(pcest.custoreal,
                       0),
                   NVL(pcest.custorep,
                       0),
                   NVL(pcest.custoultent,
                       0),
                   NVL(pctabpr.excluido,
                       'N'),
                   NVL(pctribut.iva,
                       0),
                   NVL(pctribut.pauta,
                       0),
                   NVL(pctribut.peracrescismopf,
                       0),
                   NVL(pctabpr.perdescautor,
                       0),
                   NVL(pctribut.perdesccusto,
                       0),
                   NVL(pctabpr.perdescmax,
                       0),
                   NVL(pctabpr.perdescmaxesp,
                       0),
                   pctribut.perdestab,
                   NVL(pctabpr.precominimovenda,
                       0),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda, least(vnPOFERTA, pctabpr.pvenda)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda1, least(vnPOFERTA, pctabpr.pvenda1)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda2, least(vnPOFERTA, pctabpr.pvenda2)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda3, least(vnPOFERTA, pctabpr.pvenda3)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda4, least(vnPOFERTA, pctabpr.pvenda4)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda5, least(vnPOFERTA, pctabpr.pvenda5)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda6, least(vnPOFERTA, pctabpr.pvenda6)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   (round(nvl(decode(vnPOFERTA, 0, pctabpr.pvenda7, least(vnPOFERTA, pctabpr.pvenda7)),
                              0),
                          6) * decode(nvl(pcembalagem.fatorpreco,
                                                                       1),
                                                                   0,
                                                                   1,
                                                                   nvl(pcembalagem.fatorpreco,
                                                                       1))),
                   NVL(pctabpr.qtdescautor,
                       0),
                   NVL(pctribut.aplicaacrescpjisenta,
                       'N'),
                   NVL(pctribut.percbaseredst,
                       0),
                   nvl(pctribut.tipocalculognre,
                       'P'),
                   NVL(pctribut.ivafonte,
                       0),
                   NVL(pctribut.aliqicms1fonte,
                       0),
                   NVL(pctribut.aliqicms2fonte,
                       0),
                   NVL(pctribut.percbaseredstfonte,
                       0),
                   nvl(pctribut.percbasered,
                       0),
                   nvl(pctribut.perbaserednrpa,
                       0),
                   nvl(pctribut.percbaseredconsumidor,
                       0),
                   nvl(pctribut.utilizapercbaseredpf,
                       'N'),
                   nvl(pcest.valorultent,0),
                   nvl(pctribut.usavalorultentbasest,
                       'N'),
                   nvl(pctribut.usavalorultentbasest2,
                       'N'),
                   NVL(pctribut.codicmtabpf,
                       0),
                   nvl(pctribut.perdescsuframa,
                       0),
                   nvl(pctribut.perdescicmisencao,
                       0),
                   pctabpr.descontafrete,
                   nvl(pctribut.percdescpis,
                       0),
                   nvl(pctribut.percdesccofins,
                       0),
                   nvl(pctribut.perdescrepasse,
                       0),
                   nvl(pctabpr.precomaxconsum,
                       0),
                   nvl(pcembalagem.qtunit,
                       1),
                   decode(nvl(pcembalagem.fatorpreco,
                              1),
                          0,
                          1,
                          nvl(pcembalagem.fatorpreco,
                              1)),
                   DECODE(p_regfilial.PRECOPOREMBALAGEM, 'S',  nvl(PCEMBALAGEM.qtminimaatacado, 0), nvl(PCPRODUT.QTMINIMAATACADO,0)),
                   decode(vnPOFERTAATAC, 0,
                   (decode(nvl(pcembalagem.pvendaatac,
                               0),
                           0,
                           nvl(pcembalagem.pvenda,
                               0),
                           nvl(pcembalagem.pvendaatac,
                               0)) * decode(nvl(pcembalagem.fatorpreco,
                                                 1),
                                             0,
                                             1,
                                             nvl(pcembalagem.fatorpreco,
                                                 1))), vnPOFERTAATAC),
                   (nvl(decode(vnPOFERTA, 0, pcembalagem.pvenda, least(vnPOFERTA, pcembalagem.pvenda)),
                        0) * decode(nvl(pcembalagem.fatorpreco,
                                         1),
                                     0,
                                     1,
                                     nvl(pcembalagem.fatorpreco,
                                         1))),
                   (nvl(pcembalagem.poferta,
                        0) * decode(nvl(pcembalagem.fatorpreco,
                                         1),
                                     0,
                                     1,
                                     nvl(pcembalagem.fatorpreco,
                                         1))),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac1, least(vnPOFERTA, pctabpr.pvendaatac1)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac2, least(vnPOFERTA, pctabpr.pvendaatac2)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac3, least(vnPOFERTA, pctabpr.pvendaatac3)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac4, least(vnPOFERTA, pctabpr.pvendaatac4)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac5, least(vnPOFERTA, pctabpr.pvendaatac5)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac6, least(vnPOFERTA, pctabpr.pvendaatac6)),
                             0),
                         6),
                   round(NVL(decode(vnPOFERTA, 0, pctabpr.pvendaatac7, least(vnPOFERTA, pctabpr.pvendaatac7)),
                             0),
                         6),
                   pcembalagem.dtofertaini,
                   pcembalagem.dtofertafim,
                   pcembalagem.dtofertaatacini,
                   pcembalagem.dtofertaatacfim,
                   nvl(pcembalagem.pofertaatac,
                       0),
                   nvl(pctribut.mostrarpvendasemst,
                       integradora_comple.gregpcconsum.mostrarpvendasemst),
                   nvl(pctribut.usapmcbasest,
                       'N'),
                   nvl(pcest.custonfsemst,
                       nvl(pcest.valorultent,
                           0)),
                   nvl(pctribut.percredpvendasimplesnac,
                       0),
                   nvl(pcest.vlstultent,
                       0),
                   nvl(pctribut.percdifaliquotas,
                       0),
                   nvl(pcest.custonfsemstguiaultent,
                       0),
                   nvl(pcest.ivaultent,
                       0),
                   nvl(pcest.aliqicms1ultent,
                       0),
                   nvl(pcest.aliqicms2ultent,
                       0),
                   nvl(pcest.redbaseivaultent,
                       100),
                   nvl(pcest.percicmsfretefobstultent,
                       0),
                   nvl(pcest.vlfreteconhecultent,
                       0),
                   nvl(pcest.percaliqextguiaultent,
                       0),
                   nvl(pcest.baseicmsultent,
