                   nvl(pctribut.usaaliqicmssimplesnacional,
                       'N'),
                   nvl(pctribut.aliqstsimplesnacional,
                       0),
                   nvl(pctribut.agregaripicalculost,
                       'N'),
                   pctabpr.precofab,
                   pcembalagem.pcomint1,
                   pcembalagem.pcomext1,
                   pcembalagem.pcomrep1,
                   nvl(pctribut.usavlultentmediobasest,
                       'N'),
                   nvl(pctabpr.vlultentmes,
                       0),
                   round(NVL(pctabpr.pvendasemimposto1,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto2,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto3,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto4,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto5,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto6,
                             0),
                         6),
                   round(NVL(pctabpr.pvendasemimposto7,
                             0),
                         6),
                   nvl(pctribut.percbasestrj,
                       0),
                   round(NVL(pctabpr.pvendaatacsemimposto1,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto2,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto3,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto4,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto5,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto6,
                             0),
                         6),
                   round(NVL(pctabpr.pvendaatacsemimposto7,
                             0),
                         6), --,
                   --round(NVL(pctabpr.pvendasemimposto, 0),integradora_comple.gregpcconsum.numcasasdecvenda),
                   --round(NVL(pctabpr.pvendaatacsemimposto, 0),integradora_comple.gregpcconsum.numcasasdecvenda)
                   nvl(pctabpr.vlst,0),
                   nvl(pctabpr.custoprecific,0),
                   nvl(pctribut.AGREGADESCST1, 'N'),
                   NVL(PCTRIBUT.APLICAACRESPFJURIDICA,'N')APLICAACRESPFJURIDICA,
                   nvl(pctribut.PERACRESCISMOSIMPNAC,0),
                   nvl(pctribut.codicmtabsimpnasc,0),
                   0 PTABELAFABRICAZFM,
                   PCTRIBUT.CODICMDIFER,
                   PCTABPR.Vlipi,
                   NVL(pcest.custofinsemst,0),
                   nvl(pctribut.UTILIZAMOTORCALCULO, 'N') UTILIZAMOTORCALCULO,
                   NVL(PCTABPR.PERDESCFOB,0),
                   COALESCE(PCTRIBUT.PERCACRESCBENFFIS,0 ) PERCACRESCBENFFIS,
                   NVL(PCTABPR.PERCACRESCIMOFRETE, 0) PERCACRESCIMOFRETE,
                   NVL(PCTABPR.PERCDESCSIMPLESNAC,0)
              INTO p_regprecos
              FROM pctabpr,
                   pctribut,
                   pcest,
                   pcembalagem,
                   pcprodut,
                   pctribut vt
             --WHERE pctabpr.codst = pctribut.codst
             WHERE PCTABPR.CODST = VT.CODST
               AND NVL(DECODE(P_REGPEDIDO.VENDATRIANGULAR,
                              'S',
                              VT.CODFIGVENDATRIANGULAR,
                              VT.CODST), VT.CODST) = PCTRIBUT.CODST
               AND pctabpr.codprod = p_regitem.codprod
               AND pcest.codprod = p_regitem.codprod
               AND pctabpr.numregiao = p_regregiao.numregiao
               AND pcest.codfilial = decode(p_regfilial.origemcustofilialretira,
                                            'V',
                                            p_regpedido.codfilial,
                                            p_regitem.codfilialretira)
               AND pcembalagem.codprod = p_regitem.codprod
               AND pcprodut.codprod = p_regitem.codprod
               AND pcembalagem.codauxiliar = p_regitem.codauxiliar
               AND pcembalagem.codfilial = p_regpedido.codfilial;

          EXCEPTION
            WHEN OTHERS THEN
              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;
              vsmensagem              := vsmensagem || vschar || 'ERRO AO BUSCAR PRECO DO PRODUTO#;' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';';
              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;
          END;
         END IF;

          IF nvl(p_apenasvalida,
                 'N') = 'N'
          THEN

            p_regitem.pvenda := round(p_regitem.pvenda / p_regprecos.qtunit,
                                      6);
          END IF;

          p_regitem.qt := p_regitem.qt * p_regprecos.qtunit;

        END IF;

        --não usa venda por embalagem
      ELSE

        --tributacao por estado
        IF nvl(integradora_comple.gregpcconsum.usatributacaoporuf,
               'N') = 'S'
        THEN

          p_regorigempreco.usatributporuf := 'S';

          IF p_regpedido.codfilialnf IS NULL
          THEN

            IF p_regcliente.codfilialnf IS NULL
            THEN

              vscodfilialnf := p_regpedido.codfilial;
            ELSE

              vscodfilialnf := p_regcliente.codfilialnf;
            END IF;
          ELSE

            vscodfilialnf := p_regpedido.codfilialnf;
          END IF;

          SELECT COUNT(*)
            INTO vicontador
            FROM pctabtrib p
           WHERE p.codprod = p_Regitem.codprod
             AND p.codfilialnf = vscodfilialnf
             AND p.ufdestino = nvl(vsUfEnt, p_Regcliente.estent);

          IF vicontador = 0
          THEN
            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;
            vsmensagem := vsmensagem || vschar || 'NÃO ENCONTRADA TRIBUTAÇÃO POR ESTADO;';

            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;

          ELSE

            SELECT p.codst
              INTO vncodst
              FROM pctabtrib p
             WHERE p.codprod = p_Regitem.codprod
               AND p.codfilialnf = vscodfilialnf
               AND p.ufdestino = nvl(vsUfEnt, p_Regcliente.estent)
               AND rownum = 1;

            -- busca as informacoes da tabela de preco.
           IF p_regitem.valido = TRUE
           THEN
            BEGIN
              SELECT nvl(pctribut.aliqicms1,
                         0),
                     nvl(pctribut.aliqicms2,
                         0),
                     nvl(pctribut.codicmtab,
                         0),
                     NVL(pctribut.codst, vncodst),
                     nvl(pcest.custocont,
                         0),
                     nvl(pcest.custofin,
                         0),
                     nvl(pcest.custoreal,
                         0),
                     nvl(pcest.custorep,
                         0),
                     nvl(pcest.custoultent,
                         0),
                     nvl(pctabpr.excluido,
                         'N'),
                     nvl(pctribut.iva,
                         0),
                     nvl(pctribut.pauta,
                         0),
                     nvl(pctribut.peracrescismopf,
                         0),
                     nvl(pctabpr.perdescautor,
                         0),
                     nvl(pctribut.perdesccusto,
                         0),
                     nvl(pctabpr.perdescmax,
                         0),
                     nvl(pctabpr.perdescmaxesp,
                         0),
                     pctribut.perdestab,
                     nvl(pctabpr.precominimovenda,
                         0),
                     round(NVL(pctabpr.pvenda,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda1,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda2,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda3,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda4,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda5,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda6,
                               0),
                           6),
                     round(NVL(pctabpr.pvenda7,
                               0),
                           6),
                     nvl(pctabpr.qtdescautor,
                         0),
                     nvl(pctribut.aplicaacrescpjisenta,
                         'N'),
                     nvl(pctribut.percbaseredst,
                         0),
                     nvl(pctribut.tipocalculognre,
                         'P'),
                     NVL(pctribut.ivafonte,
                         0),
                     NVL(pctribut.aliqicms1fonte,
                         0),
                     NVL(pctribut.aliqicms2fonte,
                         0),
                     NVL(pctribut.percbaseredstfonte,
                         0),
                     nvl(pctribut.percbasered,
                         0),
                     nvl(pctribut.perbaserednrpa,
                         0),
                     nvl(pctribut.percbaseredconsumidor,
                         0),
                     nvl(pctribut.utilizapercbaseredpf,
                         'N'),
                     nvl(pcest.valorultent,0),
                     nvl(pctribut.usavalorultentbasest,
                         'N'),
                     nvl(pctribut.usavalorultentbasest2,
                         'N'),
                     NVL(pctribut.codicmtabpf,
                         0),
                     nvl(pctribut.perdescsuframa,
                         0),
                     nvl(pctribut.perdescicmisencao,
                         0),
                     pctabpr.descontafrete,
                     nvl(pctribut.percdescpis,
                         0),
                     nvl(pctribut.percdesccofins,
                         0),
                     nvl(pctribut.perdescrepasse,
                         0),
                     nvl(pctabpr.precomaxconsum,
                         0),
                     1,
                     1,
                     DECODE (( SELECT COUNT (*)
                             FROM pcprodfilial
                             WHERE codprod = pcprodut.codprod
                             AND codfilial = pcest.codfilial)
                            ,0, DECODE (NVL (pcprodut.qtminimaatacado, 0)
                            ,0, 1
                            ,pcprodut.qtminimaatacado
