                            ,NVL ((SELECT qtminimaatacado
                                   FROM pcprodfilial
                                   WHERE codprod = pcprodut.codprod
                                   AND codfilial = pcest.codfilial)
                            ,DECODE (NVL (pcprodut.qtminimaatacado, 0)
                            ,0, 1
