              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;
          END;
         END IF;
        END IF;

      END IF;

      --tarefa 132437

      SELECT COUNT(*)
        INTO vicotarca
        FROM pcprodusur p
       WHERE p.datainicio <= trunc(SYSDATE)
         AND p.datafim >= trunc(SYSDATE)
         AND p.codprod = p_regitem.codprod
         AND (p.numregiao = p_regregiao.numregiao OR p.numregiao IS NULL)
         AND p.codusur = coalesce(p_regitem.codusur, P_REGPEDIDO.CODUSUR)
         AND p.tipocota = 'U';

      IF vicotarca > 0
      THEN

        vbvalidocotarca := funcoesvendas.verificarcotarca(p_Regitem.codprod,
                                                          coalesce(p_regitem.codusur, P_REGPEDIDO.CODUSUR),
                                                          p_Regitem.qt,
                                                          p_regregiao.numregiao,
                                                          vsmensagemcotarca);

        IF vbvalidocotarca = FALSE
        THEN
          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem       := vsmensagem || vschar || vsmensagemcotarca;
          p_regitem.valido := FALSE;
        END IF;

      END IF;

      SELECT COUNT(*)
        INTO vicotacli
        FROM pcprodusur p
       WHERE p.datainicio <= trunc(SYSDATE)
         AND p.datafim >= trunc(SYSDATE)
         AND p.codprod = p_regitem.codprod
         AND (p.numregiao = p_regregiao.numregiao OR p.numregiao IS NULL)
         AND p.codusur IS NULL
         AND p.codcli = p_regpedido.codcli
         AND p.tipocota = 'C';

      IF vicotacli > 0
      THEN

        vbvalidocotacli := funcoesvendas.verificarcotacliente(p_Regitem.codprod,
                                                              p_regpedido.codcli,
                                                              p_Regitem.qt,
                                                              p_regregiao.numregiao,
                                                              vsmensagemcotacli);

        IF vbvalidocotacli = FALSE
        THEN
          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem       := vsmensagem || vschar || vsmensagemcotacli;
          p_regitem.valido := FALSE;
        END IF;

      END IF;


      p_regitem.qtpecas := NULL;

      IF (p_regproduto.tipoestoque = 'FR') and
         (((FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAFRIOSEMBALAGEM', p_regpedido.codfilial, 'N') = 'S') AND
            p_regfilial.utilizavendaporembalagem = 'S') OR
          (p_regfilial.utilizavendaporembalagem = 'N'))

      THEN


        vnqt := p_Regitem.qt;

        IF upper(TRIM(p_regitem.unidadevenda)) = upper(TRIM(p_Regproduto.unidademaster))
        THEN

          p_regitem.qt       := vnqt * p_regproduto.pesobrutomaster;
          p_regitem.qtcx     := vnqt;
          p_regitem.qtpecas  := NULL;
          p_regprecos.qtunit := 1;
		  vsMultiplicouPeso := 'S';
        ELSIF (upper(TRIM(p_regitem.unidadevenda)) = 'PC')
        THEN
          p_regitem.qt       := vnqt * p_regproduto.pesopeca;
          p_regitem.qtpecas  := vnqt;
          p_regitem.qtcx     := NULL;
          p_regprecos.qtunit := 1;
		  vsMultiplicouPeso := 'S';

        END IF;


        IF (p_regfilial.ARREDONDAQTEMBALFRIOS = 'S') AND
           ((upper(TRIM(p_regitem.unidadevenda)) = upper(TRIM(p_Regproduto.unidademaster))) OR
            ((p_regfilial.utilizavendaporembalagem = 'S') AND UPPER(TRIM(p_regproduto.unidade)) = 'CX'))
        THEN

          P_REGITEM.QTCX    := ROUND(P_REGITEM.QTCX);
          P_REGITEM.QTPECAS := ROUND(P_REGITEM.QTPECAS);
          P_REGITEM.QT      := ROUND(P_REGITEM.QT);

          IF P_REGITEM.QT <= 0 THEN
            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;

            vsmensagem := vsmensagem || vschar || 'FILIAL DO PEDIDO ESTÁ PARAMETRIZADO PARA ARREDONDAR QUANTIDADE DE FRIOS. QUANTIDADE ARREDONDADA = 0';
            P_REGITEM.VALIDO := FALSE;
          END IF;
        END IF;

      END IF; --fim 132437

      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog           := 'I';
      integradora_comple.vLog.MSG               := 'Iniciando validação da Restrição de Venda, rotina 391, para o produto: ' || p_regitem.codprod;

     IF nvl(P_REGPEDIDO.NUMPEDORIG,0) = 0
       THEN
      BEGIN
        SELECT SUM(TOTAL_TEMP)
          INTO VNVLATEND_TEMP
          FROM (SELECT SUM(ROUND((CASE
                                   WHEN (T.tipoestoque = 'FR') and
                                        ((                        (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAFRIOSEMBALAGEM',
                                                                              p_regpedido.codfilial,
                                                                              'N') = 'S') AND
                                        p_regfilial.utilizavendaporembalagem = 'S') OR
                                        (p_regfilial.utilizavendaporembalagem = 'N')) THEN

                                    CASE
                                      WHEN upper(TRIM(I.UNIDADE_FRIOS)) =
                                           upper(TRIM(T.unidademaster)) THEN
                                       I.qt * T.pesobrutomaster
                                      WHEN (upper(TRIM(I.UNIDADE_FRIOS)) = 'PC') THEN
                                       I.qt * T.pesopeca
                                    END

                                   WHEN (
                                        ((p_regfilial.ARREDONDAQTEMBALFRIOS = 'S') AND (T.tipoestoque = 'FR')) AND
                                        ((upper(TRIM(I.UNIDADE_FRIOS)) =
                                        upper(TRIM(T.unidademaster))) OR
                                        ((p_regfilial.utilizavendaporembalagem = 'S') AND
                                        UPPER(TRIM(T.unidade)) = 'CX'))
                                        ) THEN

                                    ROUND(I.QT)
                                   ELSE
                                    I.qt
                                 END * I.pvenda), 2)) AS TOTAL_TEMP, I.NUMPEDRCA
                  FROM PCPEDIFV I, PCPRODUT T
                 WHERE I.NUMPEDRCA = p_regitem.numpedrca
                   AND I.CODPROD = T.CODPROD
                   AND I.CODUSUR =
                       coalesce(p_regitem.codusur, p_regpedido.codusur)
                   AND I.CGCCLI = p_regpedido.cgccli
                   AND I.DTABERTURAPEDPALM = p_regpedido.dtaberturapedpalm
                 GROUP BY I.QT, I.PVENDA, I.NUMPEDRCA);

        vbRetornoRest := funcoesvendas.validarrestricaovenda(p_regitem.CODPROD,
                                                             p_regregiao.numregiao,
                                                             p_regpedido.CODCLI,
                                                             p_regpedido.CODUSUR,
                                                             p_regproduto.CODFORNEC,
                                                             p_regcliente.CODPRACA,
                                                             p_regproduto.CLASSE,
                                                             p_regcliente.CODATV1,
                                                             p_regrca.CODSUPERVISOR,
                                                             vsmensagem_restricao,
                                                             p_regpedido.CODFILIAL,
                                                             p_regpedido.CONDVENDA,
                                                             p_regpedido.FRETEDESPACHO,
                                                             p_regpedido.ORIGEMPED,
                                                             p_regitem.CODAUXILIAR,
                                                             p_regpedido.CODPLPAG,
                                                             p_regpedido.CODCOB,
                                                             p_regproduto.CODMARCA,
                                                             VNVLATEND_TEMP);
        IF vbRetornoRest = FALSE THEN
          IF vsmensagem IS NOT NULL THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || vsmensagem_restricao || ';';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;
          ELSIF p_regfilial.tipoimportacaovenda = 'RP' THEN
            p_regpedido.valido := FALSE;
          ELSIF p_regfilial.tipoimportacaovenda = 'BP' THEN
            p_Regpedido.posicao := 'B';

            IF length(p_regpedido.log) <= 3000 OR p_regpedido.log IS NULL THEN
              p_regpedido.log := p_regpedido.log || CHR(13) ||
                                 vsmensagem_restricao;
            END IF;

            PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,
                                            20,
                                            substr(vsmensagem_restricao,1,200),
                                            'C');

            p_regpedido.motivoposicao := substr(vsmensagem_rest, 1, 45) ||
                                         'Codprod :' || p_regitem.codprod;

          END IF;
        END IF;
      END;
     END IF;

      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog           := 'I';
      integradora_comple.vLog.MSG               := 'Iniciando definição do preço de tabela para o item ' || p_regitem.codprod;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      IF p_regfilial.PRECOPOREMBALAGEM = 'S'
         AND p_regfilial.utilizavendaporembalagem = 'S'
      THEN

        p_regorigemdesc.pembalagem := 'S';

        --Varejo
        IF p_regfilial.tipoprecificacao <> 'A'
        THEN
          IF p_regprecos.qtminimaatacado > 1
          THEN
            IF p_regitem.qt >= p_regprecos.qtminimaatacado
            THEN
              p_regproduto.ptabela           := nvl(p_regprecos.pvendaatac,
                                                    p_regprecos.pvendaemb) / p_regprecos.qtunit;
              p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendaatac,
                                                    p_regprecos.pvenda) / p_regprecos.qtunit;
            ELSE
              p_regproduto.ptabela           := p_regprecos.pvendaemb / p_regprecos.qtunit;
              p_regproduto.ptabelasemimposto := p_regprecos.pvenda / p_regprecos.qtunit;
            END IF;
          ELSE
            p_regproduto.ptabela           := p_regprecos.pvendaemb / p_regprecos.qtunit;
            p_regproduto.ptabelasemimposto := p_regprecos.pvenda / p_regprecos.qtunit;
          END IF;
          --Atacado
        ELSE
          p_regproduto.ptabela           := nvl(p_regprecos.pvendaatac,
                                                p_regprecos.pvendaemb) / p_regprecos.qtunit;
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendaatac,
                                                p_regprecos.pvenda) / p_regprecos.qtunit;

        END IF;

        -- MyShop
        p_regitem.ptabelaatac := nvl(p_regprecos.pvendaatac,
                                     p_regprecos.pvendaemb) / p_regprecos.qtunit;
        p_regitem.ptabelavar  := p_regprecos.pvendaemb / p_regprecos.qtunit;


        --tarefa 70944 verificar poferta como preco minimo
        IF (p_regprecos.poferta > 0)
           AND trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND p_regprecos.dtofertafim
        THEN

            IF p_regitem.qt < case p_regprecos.qtminimaatacado when 0 then 999999 else p_regprecos.qtminimaatacado end
          THEN
            p_regproduto.ptabela := p_regprecos.poferta / P_REGPRECOS.qtunit;

          END IF;
        END IF;

        IF p_regfilial.tipoprecificacao <> 'A'
        THEN
          IF (p_regprecos.poferta > 0)
             AND (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND p_regprecos.dtofertafim)
          THEN
            IF p_regitem.qt < case p_regprecos.qtminimaatacado when 0 then 999999 else p_regprecos.qtminimaatacado end
            THEN
              p_regproduto.ptabela := p_regprecos.poferta / P_REGPRECOS.QTUNIT;
              --myshop
              p_regitem.ptabelavar := p_regprecos.poferta / P_REGPRECOS.qtunit;

            END IF;
          END IF;
        ELSE
          IF (p_regprecos.pofertaatac > 0)
             AND (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaatacini AND p_regprecos.dtofertaatacfim)
          THEN
            IF p_regitem.qt >= p_regprecos.qtminimaatacado
            THEN
              p_regproduto.ptabela := p_regprecos.pofertaatac / P_REGPRECOS.QTUNIT;
              --myshop
              p_regitem.ptabelaatac := p_regprecos.poferta / P_REGPRECOS.qtunit;

            END IF;
          END IF;
        END IF;


        IF (nvl(p_regproduto.ptabela,0) = 0)
           and (P_REGPEDIDO.CONDVENDA <> 10)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;
          vsmensagem := vsmensagem || vschar || 'PRECO DE TABELA ZERADO;';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
             p_regitem.valido        := FALSE;
             p_regorigempreco.valido := FALSE;
           ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
             p_regpedido.valido := FALSE;
          END IF;
        END IF;

      ELSE

         /**********************************************************
        *Soticitação: HIS.00185.2015
        *Responsável: Rafael Soares
        *Data       : 15/09/2015
        *Alteração  : Ajustado package para utilizar o preço de tabela conforme o parametro TIPOPRECIFICACAO
        ***********************************************************/


        if ((p_regfilial.tipoprecificacao = 'P') OR
           (p_regfilial.tipoprecificacao = 'A' AND p_regitem.qt >= p_regprecos.qtminimaatacado) OR --HIS.00185.2015
           (p_regfilial.tipoprecificacao = 'V' AND (p_regitem.qt < p_regprecos.qtminimaatacado OR NVL(p_regprecos.qtminimaatacado,0) = 0)))--HIS.00185.2015
         THEN
          IF p_regitem.numpr = 1
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda1;
          ELSIF p_regitem.numpr = 2
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda2;
          ELSIF p_regitem.numpr = 3
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda3;
          ELSIF p_regitem.numpr = 4
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda4;
          ELSIF p_regitem.numpr = 5
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda5;
          ELSIF p_regitem.numpr = 6
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda6;
          ELSIF p_regitem.numpr = 7
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda7;
          END IF;
        ELSIF ((p_regfilial.tipoprecificacao = 'A' AND p_regitem.qt < p_regprecos.qtminimaatacado) OR--HIS.00185.2015
              (p_regfilial.tipoprecificacao = 'V' AND p_regitem.qt >= p_regprecos.qtminimaatacado))--HIS.00185.2015
        THEN
          IF p_regitem.numpr = 1
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac1;
          ELSIF p_regitem.numpr = 2
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac2;
          ELSIF p_regitem.numpr = 3
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac3;
          ELSIF p_regitem.numpr = 4
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac4;
          ELSIF p_regitem.numpr = 5
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac5;
          ELSIF p_regitem.numpr = 6
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac6;
          ELSIF p_regitem.numpr = 7
          THEN
            p_regproduto.ptabela := p_regprecos.pvendaatac7;
          END IF;
        ELSE
          IF p_regitem.numpr = 1
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda1;
          ELSIF p_regitem.numpr = 2
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda2;
          ELSIF p_regitem.numpr = 3
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda3;
          ELSIF p_regitem.numpr = 4
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda4;
          ELSIF p_regitem.numpr = 5
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda5;
          ELSIF p_regitem.numpr = 6
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda6;
          ELSIF p_regitem.numpr = 7
          THEN
            p_regproduto.ptabela := p_regprecos.pvenda7;
          END IF;

        END IF;


        IF (nvl(p_regproduto.ptabela,0) = 0)
             and (P_REGPEDIDO.CONDVENDA <> 10)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;
          vsmensagem := vsmensagem || vschar || 'PRECO DE TABELA ZERADO;';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
             p_regitem.valido        := FALSE;
             p_regorigempreco.valido := FALSE;
          ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
             p_regpedido.valido := FALSE;
          END IF;

        END IF;

        -- verifica precos sem imposto da 201
        IF p_regitem.numpr = 1
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto1, p_regprecos.pvenda1);
        ELSIF p_regitem.numpr = 2
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto2, p_regprecos.pvenda2);
        ELSIF p_regitem.numpr = 3
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto3, p_regprecos.pvenda3);
        ELSIF p_regitem.numpr = 4
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto4, p_regprecos.pvenda4);
        ELSIF p_regitem.numpr = 5
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto5, p_regprecos.pvenda5);
        ELSIF p_regitem.numpr = 6
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto6, p_regprecos.pvenda6);
        ELSIF p_regitem.numpr = 7
        THEN
          p_regproduto.ptabelasemimposto := nvl(p_regprecos.pvendasemimposto7, p_regprecos.pvenda7);
        END IF;

      END IF;

    END IF;


    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
    integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
    integradora_comple.vLog.TipoLog           := 'I';
    integradora_comple.vLog.MSG               := 'Fim Definição Preço Tabela Produto ' || p_regitem.codprod;
    integradora_comple.vLog.PTABELA           := p_regproduto.ptabela;


    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    p_regitem.geragnre_cnpjcliente := NULL;

    -- 160801
    IF p_regprecos.tipocalculognre = 'P'
       AND p_regprecos.pagtonomedocliente = 'S'
    THEN

      p_regitem.geragnre_cnpjcliente := 'S';

    END IF;


    p_regorigemdesc.ptabela := p_regproduto.ptabela;

    IF p_apenasvalida = 'S'
    THEN

      p_regitem.pvenda := p_regproduto.ptabela;

    END IF;


    --199697
    IF p_regcliente.ACEITAVENDAFRACAO = 'S'
       AND p_regcliente.VALIDARMULTIPLOVENDA = 'S'
    THEN

      IF p_regproduto.multiplo = 0
      THEN

        IF p_regproduto.aceitavendafracao = 'M'
        THEN

          IF (p_regitem.qt / 0.5) <> trunc(p_regitem.qt / 0.5)
          THEN

            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;

            p_regitem.qt := trunc(p_regitem.qt / 0.5) * 0.5;

            IF p_regitem.qt > 0
            THEN

              vsmensagem := vsmensagem || vschar || 'Produto so pode ser vendido fracionado de 0.5 ' || CHR(13) || 'Quantidade pedida alterada para :' || p_regitem.qt || ';';
            ELSE

              vsmensagem := vsmensagem || vschar || 'Produto so pode ser vendido fracionado de 0.5 : ' || CHR(13) || 'Item será cortado por não atingir fracionamento;';

              IF p_regfilial.tipoimportacaovenda = 'RI' THEN
                 p_regitem.valido        := FALSE;
                 p_regorigempreco.valido := FALSE;
              ELSE
                 p_regpedido.valido := FALSE;
              END IF;

            END IF;

          END IF;

        ELSIF p_regproduto.aceitavendafracao = 'N'
              AND p_regitem.qt <> trunc(p_regitem.qt)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || 'Produto nao pode ser vendido fracionado ;';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
             p_regitem.valido        := FALSE;
             p_regorigempreco.valido := FALSE;
          ELSE
             p_regpedido.valido := FALSE;
          END IF;

        END IF;

      END IF;

    ELSE

      IF (p_regitem.qt <> trunc(p_regitem.qt)) and (p_regcliente.ACEITAVENDAFRACAO = 'N')
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Cliente nao aceita venda fracionada ;';

        IF p_regfilial.tipoimportacaovenda = 'RI' THEN
          p_regitem.valido        := FALSE;
          p_regorigempreco.valido := FALSE;
        ELSE
          p_regpedido.valido := FALSE;
        END IF;

      END IF;

    END IF;


    -- tarefa 134170
    IF (p_regcliente.VALIDARMULTIPLOVENDA = 'S')
      AND(
         (not(p_regpedido.condvenda in (5, 11)) and ((vsChecarMultiploVendaBNF = 'S') and (vsItemTV1BNF = 'F'))) or
         (not(p_regpedido.condvenda in (5, 11)) and (not(vsItemTV1BNF = 'F'))) or
         ((p_regpedido.condvenda in (5, 11)) and (vsItemTV1BNF = 'F'))
         )
    THEN

      IF p_regproduto.multiplo <> 0
      THEN

        IF (p_regitem.qt / p_regproduto.multiplo) <> trunc(p_regitem.qt / p_regproduto.multiplo)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          p_regitem.qt := trunc(p_regitem.qt / p_regproduto.multiplo) * p_regproduto.multiplo;

          IF p_regitem.qt > 0
          THEN

            vsmensagem := vsmensagem || vschar || 'Produto so pode ser vendido multiplo de : ' || p_regproduto.multiplo || CHR(13) || 'Quantidade pedida alterada para :' || p_regitem.qt || ';';
          ELSE

            vsmensagem := vsmensagem || vschar || 'Produto so pode ser vendido multiplo de : ' || p_regproduto.multiplo || CHR(13) || 'Item será cortado por não atingir multiplo;';

            IF p_regfilial.tipoimportacaovenda in ('BP', 'RI') THEN
              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;
            ELSE
              p_regpedido.valido := FALSE;
            END IF;

          END IF;

        END IF;
      END IF;

    END IF;

    IF p_regitem.usaunidademaster = 'S'    THEN
      BEGIN
        SELECT P.QTUNITCX
          INTO qtunidademaster
          FROM PCPRODUT P
         WHERE P.CODPROD = P_REGITEM.codprod;

      IF qtunidademaster <> 0
      THEN

        IF (p_regitem.qt / qtunidademaster) <> trunc(p_regitem.qt / qtunidademaster)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem := vsmensagem || vschar || 'Produto so pode ser vendido na unidade master: ' || qtunidademaster || CHR(13) ||
                        'Item será cortado por não atingir multiplo;';

          IF p_regfilial.tipoimportacaovenda = 'RI' THEN
             p_regitem.valido        := FALSE;
             p_regorigempreco.valido := FALSE;
          ELSE
             p_regpedido.valido := FALSE;
          END IF;

        END IF;
      END IF;

      EXCEPTION
        WHEN OTHERS THEN
          vnmultiplo := nvl(vnmultiplo, 1);
      END;



    END IF;

    IF vnQTMAXPEDVENDA > 0
    THEN

      IF NVL(p_regpedido.numpedorig,0) > 0
	    THEN
		BEGIN

		  SELECT SUM(I.QT)
		  INTO VNQTITEM_PEDORIG
		  FROM PCPEDI I, PCPEDC C
		  WHERE C.NUMPED = I.NUMPED
		  AND C.NUMPEDRCA = P_REGPEDIDO.NUMPEDORIG
		  AND I.CODPROD = P_REGITEM.CODPROD;

		EXCEPTION
		  WHEN OTHERS THEN
		    VNQTITEM_PEDORIG := 0;
		END;
      END IF;

      IF (p_regitem.qt + VNQTITEM_PEDORIG)  > vnQTMAXPEDVENDA
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Produto nao pode ser vendido na# Quantidade :' || p_regitem.qt || '#' || 'Quantidade maxima : ' || vnQTMAXPEDVENDA || ';';

        IF p_regfilial.tipoimportacaovenda = 'RI'
        THEN
          p_regitem.valido        := FALSE;
          p_regorigempreco.valido := FALSE;
        ELSIF p_regfilial.tipoimportacaovenda = 'RP'
        THEN
          p_regpedido.valido := FALSE;
        ELSIF p_regfilial.tipoimportacaovenda = 'BP'
        THEN
          p_Regpedido.posicao := 'B';

          IF length(p_regpedido.log) <= 3000
             OR p_regpedido.log IS NULL
          THEN
            p_regpedido.log := p_regpedido.log || CHR(13) || 'Produto nao pode ser vendido nesta quantidade. Quantidade maxima :' || vnQTMAXPEDVENDA || ';';
          END IF;
          PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,20,substr('Produto nao pode ser vendido nesta quantidade :' || p_regitem.codprod,1,200),'C');

          p_regpedido.motivoposicao := substr('Produto nao pode ser vendido nesta quantidade :' || p_regitem.codprod,1,60);

        END IF;


      END IF;
    END IF;

    p_regitem.vlrepasse := NULL;
    p_regitem.vloutros  := NULL;
    p_regitem.vlbonific := NULL;

    IF p_regpedido.origemped = 'R'
    THEN
      IF integradora_comple.gregpcconsum.abatefretevendabalcao = 'S'
         AND p_regprecos.descontafrete = 'S'
      THEN
        p_regorigempreco.TIPOFRETE := '1';
        p_regorigempreco.PERCFRETE := p_regregiao.perfrete;
      END IF;

      IF integradora_comple.gregpcconsum.abatefretevendabalcao = 'S'
      THEN
        vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela/(1 + (p_regregiao.perfrete/100 +  nvl(p_regprecos.PERCACRESCIMOFRETE,0)/100));
        p_regproduto.ptabela :=  p_regproduto.ptabela/(1 + (p_regregiao.perfrete/100 + nvl(p_regprecos.PERCACRESCIMOFRETE,0)/100));
      END IF;

      Select nvl(f.percacrescimobalcao,integradora_comple.gregpcconsum.percacrescimobalcao)
        into integradora_comple.gregpcconsum.percacrescimobalcao
        from pcfilial f
       where f.codigo = p_regfilial.codigo;

      IF nvl(integradora_comple.gregpcconsum.percacrescimobalcao,
             0) <> 0
      THEN
        p_regorigempreco.PERCACRESCBALCAO := integradora_comple.gregpcconsum.percacrescimobalcao;
      END IF;

    END IF;

    -- Melhorar dados OrigemPreço
    IF p_regpedido.origemped = 'T'
    THEN
      p_regorigempreco.PERCACRESCIMOTELEMARKETING := p_regfilial.PERCACRESCIMOTELEMARKETING;
    END IF;

    -- verifica se produto esta excluido na regiao
    IF p_regprecos.excluido = 'S'
    THEN

      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;
      vsmensagem := vsmensagem || vschar || 'PRODUTO EXCLUIDO DA REGIAO ;';

      p_regitem.valido        := FALSE;
      p_regorigempreco.valido := FALSE;

    END IF;


    IF p_regprecos.custofin = 0
    THEN

      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;
      vsmensagem := vsmensagem || vschar || 'PRODUTO SEM CUSTO FINANCEIRO;';

      IF p_regfilial.tipoimportacaovenda = 'RI'
      THEN
        p_regitem.valido        := FALSE;
        p_regorigempreco.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'RP'
      THEN
        p_regpedido.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'BP'
      THEN
        p_Regpedido.posicao := 'B';
      END IF;

    ELSE
      p_regitem.custofinest := p_regprecos.custofin;
    END IF;

    -- produto sem custo real
    IF p_regprecos.custoreal = 0
    THEN
      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;
      vsmensagem := vsmensagem || vschar || 'PRODUTO SEM CUSTO REAL;';

      IF p_regfilial.tipoimportacaovenda = 'RI'
      THEN
        p_regitem.valido        := FALSE;
        p_regorigempreco.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'RP'
      THEN
        p_regpedido.valido := FALSE;
      ELSIF p_regfilial.tipoimportacaovenda = 'BP'
      THEN
        p_Regpedido.posicao := 'B';
      END IF;

    END IF;

    -- produto sem custo real + crédito de icm
    IF p_regprecos.custorep = 0
    THEN

      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;
      vsmensagem := vsmensagem || vschar || 'PRODUTO SEM CUSTO REPOSICAO;';

      p_regitem.valido        := FALSE;
      p_regorigempreco.valido := FALSE;

    END IF;

    if p_regpedido.vendatriangular = 'S' THEN
      BEGIN
        SELECT PCTRIBUT.CODFIGVENDATRIANGULAR
          INTO P_REGORIGEMPRECO.CODFIGVENDATRIANGULAR
          FROM PCTRIBUT
         WHERE CODST = vncodst;

        P_REGITEM.CODFIGVENDATRIANGULAR := P_REGORIGEMPRECO.CODFIGVENDATRIANGULAR;

      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    END IF;


    --tarefa 130781
    IF p_regfilial.utilizacontrolemedicamentos = 'N'
       AND p_regfilial.precoporembalagem = 'N'
       AND p_regitem.cesta = 'N'
       and (P_REGPEDIDO.CONDVENDA <> 10)
    THEN
      -- verifica produto com preco 0 (zero)
      IF (p_regprecos.pvenda <= 0)
         OR (p_regprecos.pvenda1 <= 0)
         OR (p_regprecos.pvenda2 <= 0)
         OR (p_regprecos.pvenda3 <= 0)
         OR (p_regprecos.pvenda4 <= 0)
         OR (p_regprecos.pvenda5 <= 0)
         OR (p_regprecos.pvenda6 <= 0)
         OR (p_regprecos.pvenda7 <= 0)
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;
        vsmensagem := vsmensagem || vschar || 'PRECO DE TABELA ZERADO;';

        IF p_regfilial.tipoimportacaovenda = 'RI' THEN
           p_regitem.valido        := FALSE;
           p_regorigempreco.valido := FALSE;
         ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
           p_regpedido.valido := FALSE;
        END IF;

        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.MSG               := 'Produto sem Preço de Tabela';

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


      END IF;
    END IF;

    -- tratamento com relacao ao preco e descontos
    IF p_regitem.valido = TRUE
    THEN


      --tarefa 128635
      IF p_regitem.cesta = 'S'
      THEN
        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog           := 'I';
        integradora_comple.vLog.MSG               := 'Definindo preço de tabela para produto CB. CODPROD ' || p_regitem.codprod;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        --com impostos
        funcoesvendas.buscarprecocestabasica(p_regpedido.numped,
                                             p_regitem.codprod,
                                             p_regregiao.numregiao,
                                             p_regitem.numpr,
                                             vbecesta,
                                             vnptabelacesta,
                                             vsmensagemcesta,
                                             p_regfilial.utilizavendaporembalagem,
                                             p_regfilial.precoporembalagem,
                                             p_regfilial.tipoprecificacao,
                                             p_regpedido.codfilial,
                                             p_regitem.qt,
                                             'S',
                                             p_regpedido.codfilialnf,
                                             P_REGCLIENTE.CODCLI,
                                             p_regpedido.codplpag,
                                             p_regpedido.condvenda);



        --sem impostos
        funcoesvendas.buscarprecocestabasica(p_regpedido.numped,
                                             p_regitem.codprod,
                                             p_regregiao.numregiao,
                                             p_regitem.numpr,
                                             vbecesta,
                                             vnptabelacestasemimposto,
                                             vsmensagemcesta,
                                             p_regfilial.utilizavendaporembalagem,
                                             p_regfilial.precoporembalagem,
                                             p_regfilial.tipoprecificacao,
                                             p_regpedido.codfilial,
                                             p_regitem.qt,
                                             'S',
                                             p_regpedido.codfilialnf,
                                             P_REGCLIENTE.CODCLI,
                                             p_regpedido.codplpag,
                                             p_regpedido.condvenda);

        IF vbecesta = FALSE
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem       := vsmensagem || vschar || ' Nao encontrado cadastro como cesta';
          p_regitem.valido := FALSE;

        ELSE
          p_regproduto.ptabela           := nvl(vnptabelacesta,0);
          p_regproduto.ptabelasemimposto := vnptabelacestasemimposto;
          p_regitem.pbaserca             := vnptabelacesta;
          p_regitem.pvenda1              := vnptabelacesta;

          --myshop
          p_regitem.ptabelaatac := vnptabelacesta;
          p_regitem.ptabelavar  := vnptabelacesta;


          proc_validaitenscesta(p_regitem,
                                p_regorigempreco,
                                p_regproduto,
                                p_regpedido,
                                p_regfilial,
                                p_regregiao,
                                p_regcliente,
                                p_regprecos,
                                vsmensagemitenscesta,
                                vbvalidoprecofixocesta,
                                NVL(integradora_comple.func_calcularperdescitem(p_regproduto.ptabela, p_regitem.pvenda), 0));

          IF vbvalidoprecofixocesta = TRUE
          THEN
            p_regproduto.ptabelasemimposto := p_regproduto.ptabela;

          END IF;

          integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
          integradora_comple.vLog.CODUSUR            := P_REGPEDIDO.CODUSUR;
          integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
          integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
          integradora_comple.vLog.TipoLog            := 'I';
          integradora_comple.vLog.MSG                := 'Definido preço de tabela para produto CB. CODPROD ' || p_regitem.codprod;
          integradora_comple.vLog.ptabela            := p_regproduto.ptabela;
          integradora_comple.vLog.PTABELA_SEMIMPOSTO := p_regproduto.ptabelasemimposto;

          PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        END IF;

        IF TRIM(vsmensagemcesta) IS NOT NULL
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem       := vsmensagem || vschar || vsmensagemcesta;
          p_regitem.valido := FALSE;

        END IF;

        IF TRIM(vsmensagemitenscesta) IS NOT NULL
        THEN
		      IF (vsmensagemitenscesta LIKE '%kit aberto%') THEN
             p_regpedido.valido := FALSE;
          END IF;

          IF (vsmensagemitenscesta LIKE '%Preco sem Imposto(vnprecosemimposto)%') THEN
            IF p_regfilial.tipoimportacaovenda = 'RI' THEN
               p_regitem.valido        := FALSE;
               p_regorigempreco.valido := FALSE;
            ELSE
              p_regpedido.valido := FALSE;

            END IF;

          END IF;

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;

          vsmensagem       := vsmensagem || vschar || vsmensagemitenscesta;
          p_regitem.valido := FALSE;

        END IF;

      END IF;

      p_regorigempreco.PORIGINAL := p_regproduto.ptabela;
      p_regitem.poriginal        := p_regproduto.ptabela;
      p_regitem.pvendabase       := p_regproduto.ptabela;

      IF (p_regpedido.condvenda = 11) AND
         (p_regitem.tipoTV11 = 'R')
      THEN

        p_regitem.qt := p_regitem.qt * (-1);

        IF integradora_comple.gregpcconsum.USATROCACOMPRECOVENDA = 'N' THEN
          p_regitem.pvenda     := p_regprecos.custofin;
          p_regitem.pbaserca   := NULL;
          p_regitem.ptabela    := p_regprecos.custofin;
          p_regproduto.ptabela := p_regprecos.custofin;
        END IF;

      END IF;

      -- Verificar variáveis nullas
      vtITEM_PRECOS.pvenda   := nvl(vtITEM_PRECOS.pvenda, p_regitem.pvenda);
      vtITEM_PRECOS.ptabela  := round(nvl(vtITEM_PRECOS.ptabela, p_regproduto.ptabela), integradora_comple.gregpcconsum.numcasasdecvenda);
      vtITEM_PRECOS.pbaserca := round(nvl(vtITEM_PRECOS.pbaserca, p_regitem.pbaserca), integradora_comple.gregpcconsum.numcasasdecvenda);
      -----------------------------

      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'I';
      integradora_comple.vLog.MSG                := 'Iniciando validações de preço do produto ' || p_regitem.codprod;
      /** PRECOS **/
      integradora_comple.vLog.ptabela            := vtITEM_PRECOS.ptabela;
      integradora_comple.vLog.PTABELA_SEMIMPOSTO := vtITEM_PRECOS.ptabela_semimpostos;
      integradora_comple.vLog.PVENDA             := vtITEM_PRECOS.pvenda;
      integradora_comple.vLog.PVENDA_SEMIMPOSTO  := vtITEM_PRECOS.pvenda_semimpostos;
      integradora_comple.vLog.PBASE              := vtITEM_PRECOS.pbaserca;
      integradora_comple.vLog.PBASE_SEMIMPOSTO   := vtITEM_PRECOS.pbaserca_semimpostos;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      vsufEnt := integradora_comple.func_retornaUfEntEnd(P_REGPEDIDO.CODENDENTCLI,
                                                         P_REGCLIENTE.CODCLI);


      -- 0.003634.2017 Validar se é preço fixo, caso seja, setar o PTABELA
      vsmensagemprecofixo := NULL;

      IF nvl(vsItemTV1BNF,'N') = 'S' THEN
        vnCondvenda := 5;
      ELSE
        vnCondvenda := p_regpedido.condvenda;
      END IF;

      IF (p_regitem.cesta = 'N') OR
         (p_regitem.cesta = 'S' AND vbvalidoprecofixocesta = FALSE) AND
         (p_apenasvalida = 'N'  AND p_regfilial.precoporembalagem = 'N')
      THEN

        vbvalidoprecofixo := funcoesvendas.validarpoliticaprecofixo(p_regitem.codprod,
                                                                    p_regpedido.DATA,
                                                                    p_regregiao.numregiao,
                                                                    p_regpedido.codcli,
                                                                    vnCondvenda,
                                                                    --p_regpedido.condvenda,
                                                                    p_regpedido.codplpag,
                                                                    p_regproduto.ptabela,
                                                                    integradora_comple.gregpcconsum.validapvendabonific,
                                                                    integradora_comple.gregpcconsum.utilizapercfinprecoprom,
                                                                    0,--p_regitem.pertxfim, Acréscimo de plano de pagamento já é aplicado abaixo
                                                                    p_regitem.numdias,
                                                                    p_regcliente.codcliprinc,
                                                                    p_regproduto.codprodprinc,
                                                                    p_regcliente.codpraca,
                                                                    coalesce(p_regitem.codusur, p_regpedido.CODUSUR),
                                                                    p_regrca.codsupervisor,
                                                                    NULL,
                                                                    p_regpedido.origemped,
                                                                    p_regcliente.codatv1,
                                                                    vddtfim,
                                                                    vsmensagemprecofixo,
                                                                    vnprecofixo,
                                                                    p_regpedido.codfilial,
                                                                    p_regfilial.validarprecovendatv20,
                                                                    p_regfilial.broker,
                                                                    p_regfilial.utilizavendaporembalagem,
                                                                    p_regfilial.precoporembalagem,
                                                                    p_regitem.codauxiliar,
                                                                    vConsideraPrecoSemImposto);
        BEGIN
          SELECT NVL(P.Precofixo, 'N'), NVL(P.Precofixo, 'N')
            INTO vPrecoFixo, vPrecoFixoOrigem --HIS.02857.2014
            FROM PCPRODUT P
           WHERE P.CODPROD = p_regitem.codprod;
        EXCEPTION
          WHEN OTHERS THEN
            vPrecoFixo    := 'N';
        END;


        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAOFERTAEMBALAGEM', '99', 'N') = 'N' OR
           (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAOFERTAEMBALAGEM', '99', 'N') = 'S' AND
            vnprecofixo < vtITEM_PRECOS.ptabela) THEN

          if (vsmensagemprecofixo is NULL) then
           vConsideraPrecoSemImposto := NVL(vConsideraPrecoSemImposto, 'N');
          else
           vConsideraPrecoSemImposto := NVL(vConsideraPrecoSemImposto, 'S');
          end if;

          IF vbvalidoprecofixo OR vPrecoFixo    = 'S'
          THEN
            vtITEM_PRECOS.ptabela   := vnprecofixo;
            vtITEM_PRECOS.pbaserca  := vnprecofixo;
            vPrecoFixo              := 'S';
            p_regorigempreco.origempreco := 10;
            p_regorigempreco.poriginal := vnprecofixo;
            p_regorigempreco.codprecofixo := vsmensagemprecofixo;
            p_regitem.codprecofixo := vsmensagemprecofixo;

            IF nvl(vConsideraPrecoSemImposto, 'N') = 'S' THEN
               p_regprecos.vlst := 0;
            ELSE
               p_regprecos.vlst := 1;
            END IF;

            IF (P_REGPRECOS.qtunit <> trunc(P_REGPRECOS.qtunit)) and
               (p_regfilial.utilizavendaporembalagem = 'S')
            THEN
                vtITEM_PRECOS.ptabela := ROUND(ROUND(vtITEM_PRECOS.ptabela * P_REGPRECOS.qtunit, integradora_comple.gregpcconsum.numcasasdecvenda)/
                                         (P_REGPRECOS.qtunit), integradora_comple.gregpcconsum.numcasasdecvenda);
                vtITEM_PRECOS.pbaserca := ROUND(ROUND(vtITEM_PRECOS.pbaserca * P_REGPRECOS.qtunit, integradora_comple.gregpcconsum.numcasasdecvenda)/
                                         (P_REGPRECOS.qtunit), integradora_comple.gregpcconsum.numcasasdecvenda);
            END IF;

            IF NVL(P_REGITEM.codprecofixo,0) > 0 THEN
              BEGIN
               SELECT NVL(APLICADESCONTOSIMPLES, 'S')
                 INTO VSAPLICADESCONTOSIMPLES
                 FROM PCPRECOPROM
                WHERE CODPRECOPROM = P_REGITEM.codprecofixo;
              EXCEPTION
               WHEN OTHERS THEN
                VSAPLICADESCONTOSIMPLES    := 'S';
              END;
            END IF;

           END IF;
        END IF;

        -- Fim Verifica Preço Fixo
      vJaCalculouptabela_semimpostos := 'N';
      vbClienteIsentoSt              := FERRAMENTAS.VERIFICAR_ISENTOST(p_regcliente.codcli,
                                                                       p_regitem.codprod,
                                                                       p_regprecos.codst) = 'S';

        IF p_regitem.cesta = 'N'
           OR (p_regitem.cesta = 'S' AND vbvalidoprecofixocesta = FALSE)
        THEN

          -------------------------------------DESCONTOS DE PLANO DE PAGAMENTO------------------------------------------
          IF (vPrecoFixo <> 'S' or integradora_comple.gregpcconsum.UTILIZAPERCFINPRECOPROM = 'S')
          THEN
            -- aplica taxa financeira do plano de pagamento

            --vtITEM_PRECOS.pvenda   := vtITEM_PRECOS.pvenda * (1 + (p_regitem.pertxfim / 100));
            vtITEM_PRECOS.ptabela  := vtITEM_PRECOS.ptabela * (1 + (p_regitem.pertxfim / 100));
            vtITEM_PRECOS.pbaserca := vtITEM_PRECOS.pbaserca * (1 + (p_regitem.pertxfim / 100)); --LLima 11/07/2014
            p_regitem.poriginal  := vtITEM_PRECOS.ptabela;

            --myshop
            p_regitem.ptabelaatac := (p_regitem.ptabelaatac * (1 + (p_regitem.pertxfim / 100)));
            p_regitem.ptabelavar  := (p_regitem.ptabelavar * (1 + (p_regitem.pertxfim / 100)));

          END IF;

          IF (p_regplpag.formaparcelamento = 'V') AND (p_regpedido.percplpag IS NOT NULL) and (vPrecoFixo <> 'S' or integradora_comple.gregpcconsum.UTILIZAPERCFINPRECOPROM = 'S')
          THEN

            -- Na versão 23 o PVENDA também sofria o acréscimo caso o plano de pagamento fosse variável, mantido na versão 26 --------
            vtITEM_PRECOS.pvenda   := round(vtITEM_PRECOS.pvenda * (1 + (p_regpedido.percplpag / 100)),integradora_comple.gregpcconsum.numcasasdecvenda);
            p_regitem.pvenda       := round(p_regitem.pvenda * (1 + (p_regpedido.percplpag / 100)),integradora_comple.gregpcconsum.numcasasdecvenda);
            --------------------------------------------------------------------------------------------------------------------------

            vtITEM_PRECOS.ptabela  := round(vtITEM_PRECOS.ptabela * (1 + (p_regpedido.percplpag / 100)),integradora_comple.gregpcconsum.numcasasdecvenda);
            vtITEM_PRECOS.pbaserca := round(vtITEM_PRECOS.pbaserca * (1 + (p_regpedido.percplpag / 100)),integradora_comple.gregpcconsum.numcasasdecvenda);
            p_regitem.poriginal  := vtITEM_PRECOS.ptabela;

          END IF;
          ------------------------------------FIM DESCONTOS DE PLANO DE PAGAMENTO------------------------------------------
      END IF;

      ---------------------------------------------------DESCONTO POR ATIVIDADE---------------------------------------------------
       BEGIN
          SELECT NVL(pcativi.percdesc,
                     0)
            INTO vnperdescativ
            FROM pcativi,
                 pcclient
           WHERE pcclient.codcli = p_regcliente.codcli
             AND pcclient.codatv1 = pcativi.codativ;
        EXCEPTION
          WHEN OTHERS THEN
            vnperdescativ := 0;
        END;

        IF (vnperdescativ <> 0) and (not vbvalidoprecofixocesta) and (vPrecoFixo <> 'S')
        THEN
          vtITEM_PRECOS.ptabela  := (vtITEM_PRECOS.ptabela + (vtITEM_PRECOS.ptabela * vnperdescativ / 100));
          --vtITEM_PRECOS.ptabela_semimpostos := (vtITEM_PRECOS.ptabela_semimpostos+ (vtITEM_PRECOS.ptabela_semimpostos * vnperdescativ / 100));


          p_regorigempreco.PERCRAMOATIV   := vnperdescativ;
          p_regorigemdesc.percdescpcativi := vnperdescativ;


          -- MyShop
          p_regitem.ptabelaatac := (p_regitem.ptabelaatac + (p_regitem.ptabelaatac * vnperdescativ / 100));
          p_regitem.ptabelavar  := (p_regitem.ptabelavar + (p_regitem.ptabelavar * vnperdescativ / 100));

        END IF;
        ---------------------------------------------------FIM DESCONTO POR ATIVIDADE---------------------------------------------------

        ---------------------------------------------------DESCONTO FOB DA 201----------------------------------------------------------

        IF (p_regprecos.PERDESCFOB > 0) AND (p_regpedido.fretedespacho = 'F') and (vPrecoFixo <> 'S') THEN
                vtITEM_PRECOS.ptabela  := vtITEM_PRECOS.ptabela * (1 - (p_regprecos.PERDESCFOB / 100));
                vtITEM_PRECOS.pbaserca := vtITEM_PRECOS.pbaserca * (1 - (p_regprecos.PERDESCFOB / 100));
                p_regitem.poriginal  := vtITEM_PRECOS.ptabela;
        END IF;

        ---------------------------------------------------FIM DESCONTO FOB 201---------------------------------------------------------

       IF (p_regfilial.tipoprecificacao = 'A' OR p_regfilial.tipoprecificacao = 'V') or
         (p_regfilial.utilizavendaporembalagem = 'S' AND p_regfilial.precoporembalagem = 'S')
        THEN
           p_regitem.poriginal := p_regprecos.pvenda1;
       End if;

        IF ((p_regprecos.vlst > 0) and
          ((p_regcliente.calculast = 'N') or
           (vbClienteIsentoSt)))  THEN

           vsRetiraImposto201 := RetirarImposto201(vPrecoFixo,
                                                   vConsideraPrecoSemImposto,
                                                   p_regpedido.codfilial,p_regcliente.simplesnacional,
                                                   p_regprecos.percredpvendasimplesnac);

          SELECT VALORSEMIMPOSTO, MSG
            INTO vtITEM_PRECOS.ptabela_semimpostos, VSMSGRETORNO_PSEMIMPOSTO
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_PVENDA_SEM_IMPOSTO(p_regfilial.codigo,
                                                                p_regpedido.codfilialnf,
                                                                p_regitem.codfilialretira,
                                                                p_regcliente.codcli,
                                                                p_regpedido.codplpag,
                                                                p_regitem.codprod,
                                                                p_regitem.codauxiliar,
                                                                p_regpedido.condvenda,
                                                                'N',
                                                                p_regprecos.vlst, --1,
                                                                0,
                                                                vtITEM_PRECOS.ptabela,
                                                                vsRetiraImposto201,
                                                                'S',
                                                                vsItemTV1BNF,
                                                                vsmensagemprecofixo,--0,
                                                                NULL,
                                                                'N',
                                                                'N',
                                                                'N',
                                                                'N',
                                                                0,
                                                                p_regpedido.VendaTriangular,
                                                                'I',
                                                                p_regpedido.codbnf,
                                                                p_regpedido.codendentcli,
                                                                p_regpedido.tipodocumento));
          IF VSMSGRETORNO_PSEMIMPOSTO <> 'OK' THEN
            IF vsmensagem IS NOT NULL THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;

            vsmensagem := vsmensagem || vschar ||
                          '2(PSI): Item ' || p_regitem.codprod || ' retornou com Preco de Sem Imposto(vtITEM_PRECOS.ptabela_semimpostos) nulo ou zerado. ' || chr(13) ||
                          VSMSGRETORNO_PSEMIMPOSTO;
            raise ERRO_VALIDARPRECONULOOUZERADO;
          END IF;

          SELECT VALORIPI
            INTO vtITEM_PRECOS.vlipi_ptabela
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_IPI(p_regfilial.codigo,
                                                 p_regpedido.codfilialnf,
                                                 p_regitem.codfilialretira,
                                                 p_regcliente.codcli,
                                                 p_regitem.codprod,
                                                 p_regitem.codauxiliar,
                                                 p_regpedido.condvenda,
                                                 'N',
                                                 vtITEM_PRECOS.ptabela_semimpostos,
