                                                                  vtITEM_PRECOS.ptabela_semimpostos,
                                                                  p_regpedido.VendaTriangular,
                                                                  'I',
                                                                  p_regpedido.codbnf,
                                                                  p_regpedido.codendentcli,
                                                                  p_regpedido.tipodocumento,
                                                                  'N',
                                                                  p_regpedido.contaordem,
                                                                  ticmspartilha.VLICMSPARTREM,
                                                                  vsRetiraFecp));

            IF VSMSGRETORNO_PSEMIMPOSTO <> 'OK' THEN
              IF vsmensagem IS NOT NULL THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar ||
                    '(PSI - Preço Fixo): Item ' || p_regitem.codprod || ' retornou com Preco de Sem Imposto(vtITEM_PRECOS.pvenda_semimpostos) nulo ou zerado. ' || chr(13) ||
                     VSMSGRETORNO_PSEMIMPOSTO;
              raise ERRO_VALIDARPRECONULOOUZERADO;
            END IF;
           END IF;
          END IF;

          IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',p_regpedido.codfilial,'N') = 'S')
            AND (nvl(p_regcliente.simplesnacional,'N') = 'S')
            AND NOT(NVL(p_regitem.codprecofixo,0) > 0 and VSAPLICADESCONTOSIMPLES = 'N')
          THEN
            --PVENDA
            /*SELECT VALOR_REDUCAO_SIMPLES_NACIONAL
             INTO  vtITEM_PRECOS.vlredsimplesnac_pvenda
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(p_regfilial.codigo,
                                                                    p_regpedido.codfilialnf,
                                                                    p_regitem.codfilialretira,
                                                                    p_regcliente.codcli,
                                                                    p_regpedido.codplpag,
                                                                    p_regitem.codprod,
                                                                    p_regitem.codauxiliar,
                                                                    p_regpedido.condvenda,
                                                                    'N',
                                                                    vtITEM_PRECOS.pvenda_semimpostos,
                                                                    vtITEM_PRECOS.pvenda_semimpostos
                                                                    ));

            vtITEM_PRECOS.pvenda_semimpostos := vtITEM_PRECOS.pvenda_semimpostos - vtITEM_PRECOS.vlredsimplesnac_pvenda; */

            vtITEM_PRECOS.vlredsimplesnac_pvenda := vtITEM_PRECOS.vlredsimplesnac_ptabela;
            vtITEM_PRECOS.pvenda_semimpostos := vtITEM_PRECOS.pvenda_semimpostos - vtITEM_PRECOS.vlredsimplesnac_pvenda;

          ELSIF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',p_regpedido.codfilial,'N') = 'N')
            AND (nvl(p_regcliente.simplesnacional,'N') = 'S')
            THEN

            SELECT VALORIPI
              INTO vtITEM_PRECOS.vlipi_ptabela
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_IPI(p_regfilial.codigo,
                                               p_regpedido.codfilialnf,
                                               p_regitem.codfilialretira,
                                               p_regcliente.codcli,
                                               p_regitem.codprod,
                                               p_regitem.codauxiliar,
                                               p_regpedido.condvenda,
                                               'N',
                                               vtITEM_PRECOS.ptabela_semimpostos,
                                               p_regpedido.vendatriangular,
                                               p_regpedido.codendentcli,
                                               'N',--transferencia
                                               'N',--transferenciaVirtual
                                               'N',
                                               'F',
                                               null,
                                               'I',
                                               p_regpedido.codbnf,
                                               'N',
                                               p_regpedido.tipodocumento --VEN-1315
                                              ));

            SELECT BASEST,ST, VLRFECP, ALIQFECP
              INTO vtITEM_PRECOS.basest_ptabela,vtITEM_PRECOS.vlst_ptabela, vtITEM_PRECOS.VLFECP,
                   p_regitem.AliqFECP
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_ST(p_regfilial.codigo,
                                                  p_regpedido.codfilialnf,
                                                  p_regitem.codfilialretira,
                                                  p_regcliente.codcli,
                                                  p_regpedido.codplpag,
                                                  p_regitem.codprod,
                                                  p_regitem.codauxiliar,
                                                  p_regpedido.condvenda,
                                                  'N',
                                                  vtITEM_PRECOS.ptabela_semimpostos,
                                                  0,
                                                  vsItemTV1BNF,
                                                  0,
                                                  0,
                                                  0,
                                                  NULL,
                                                  'S',
                                                  'N',
                                                  'T',
                                                  'N',
                                                  0,
                                                  'N',
                                                  0,
                                                  p_regpedido.vendatriangular,
                                                  'I',
                                                  p_regpedido.codbnf,
                                                  p_regpedido.codendentcli,
                                                  'N',
                                                  p_regpedido.tipodocumento, --VEN-1315
                                                  'N',
                                                  p_regpedido.contaordem,
                                                  ticmspartilha.VLICMSPARTREM
                                                  ));

            IF p_regprecos.tipocalculognre <> 'C' THEN
               if (p_regpedido.pvendasemimposto = 'A') then --Não deve somar o FECP ao preço de tabela
                  vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela_semimpostos + vtITEM_PRECOS.vlipi_ptabela + vtITEM_PRECOS.vlst_ptabela;
               else
                  vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela_semimpostos + vtITEM_PRECOS.vlipi_ptabela + vtITEM_PRECOS.vlst_ptabela + vtITEM_PRECOS.VLFECP;
               end if;
            ELSE
               vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela_semimpostos + vtITEM_PRECOS.vlipi_ptabela;
            END IF;


            --PVENDA
            SELECT VALOR_REDUCAO_SIMPLES_NACIONAL
             INTO  vtITEM_PRECOS.vlredsimplesnac_pvenda
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(p_regfilial.codigo,
                                                                    p_regpedido.codfilialnf,
                                                                    p_regitem.codfilialretira,
                                                                    p_regcliente.codcli,
                                                                    p_regpedido.codplpag,
                                                                    p_regitem.codprod,
                                                                    p_regitem.codauxiliar,
                                                                    p_regpedido.condvenda,
                                                                    'N',
                                                                    vtITEM_PRECOS.ptabela_semimpostos,
                                                                    vtITEM_PRECOS.ptabela_semimpostos
                                                                    ));

            vtITEM_PRECOS.pvenda_semimpostos := vtITEM_PRECOS.pvenda_semimpostos - vtITEM_PRECOS.vlredsimplesnac_pvenda;

            if nvl(p_regprecos.percredpvendasimplesnac, 0) > 0 then
              p_regitem.iva   := p_regprecos.iva * (p_regprecos.percredpvendasimplesnac/100);
              p_regprecos.iva := p_regitem.iva;
            end if;

          END IF;

          T_PCPEDC.CODCLI := p_regpedido.CODCLI;
          T_PCPEDC.CODFILIAL := P_REGPEDIDO.codfilial;
          T_PCPEDC.CODFILIALNF := P_REGPEDIDO.codfilialnf;
          T_PCPEDC.CONDVENDA := P_REGPEDIDO.condvenda;
          T_PCPEDC.CODBNF := P_REGPEDIDO.codbnf;
          T_PCPEDC.CODCLINF := P_REGPEDIDO.codclinf;
          T_PCPEDC.VENDATRIANGULAR := P_REGPEDIDO.VENDATRIANGULAR;
          T_PCPEDC.CONTAORDEM  := P_REGPEDIDO.contaordem;
          T_PCPEDC.CODCOB := P_REGPEDIDO.codcob;
          T_PCPEDC.USACFOPVENDANATV10 := P_REGPEDIDO.USACFOPVENDANATV10;
		  T_PCPEDC.OPERVENDAEXPINDIRETA := P_REGPEDIDO.opervendaexpindireta;

          T_PCPEDI.BONIFIC := P_REGITEM.bonific;
          T_PCPEDI.VLDESCSUFRAMA := P_REGITEM.vldescsuframa;
          T_PCPEDI.VLDESCICMISENCAO := P_REGITEM.vldescicmisencao;
          T_PCPEDI.PVENDA := P_REGITEM.PVENDA;
          T_PCPEDI.CODST  := p_regprecos.CODST;
          T_PCPEDI.CODPROD := P_REGITEM.CODPROD;

          FERRAMENTAS.DEFINIRCODFISCAL(T_PCPEDC, T_PCPEDI, VNCODFISCAL, VNSITTRIBUT, vsmensagemcodfiscal);
          vsmensagem := vsmensagem || ' ' ||  vsmensagemcodfiscal;
          p_regitem.vssittribut := VNSITTRIBUT;
		  p_regitem.codfiscal := vncodfiscal;

          pkg_fwpc_fiscal.icmspartilha_calcular_1_5(nvl(p_regpedido.codfilialnf,p_regpedido.codfilial),
                                                   nvl(p_regpedido.codclinf,p_regpedido.codcli),
                                                   '',
                                                   vsufEnt,
                                                   p_regpedido.data,
                                                   vtITEM_PRECOS.pvenda_semimpostos,
                                                   p_regprecos.codst,
                                                   p_regitem.codprod,
                                                   VNCODFISCAL,
                                                   VNSITTRIBUT,
                                                   VSRETORNOPartilha,
                                                   vnCodMSGPartilha,
                                                   vsMSGPartilha);

		  if vnCodMSGPartilha = 0 then
            tICMSPARTILHA := func_prepararRetXMLPartilha(VSRETORNOPartilha);
			vnPerDesc := integradora_comple.func_calcularperdescitem(vtITEM_PRECOS.ptabela_semimpostos,
                                            vtITEM_PRECOS.pvenda_semimpostos);
          end if;

          IF vnCodMSGPartilha not in (0,4,5,11) and (P_REGPEDIDO.CONDVENDA <> 10) then
            p_regitem.valido := false;

            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             p_regitem.codprod,
                             p_regitem.numseq,
                             NULL,
                             p_Regitem.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.CODUSUR,
                             p_regitem.dtaberturapedpalm,
                             NULL,
                             '3',
                             'Erro ao calcular partilha de ICMS. Código: ' || to_char(vnCodMSGPartilha) || ' ' || vsMSGPartilha,
                             NULL,
                             p_regitem.numseqfv);
           ELSE
             IF p_regpedido.precocompartilha = 'N' THEN
               vtITEM_PRECOS.pvenda_semimpostos := vtITEM_PRECOS.pvenda_semimpostos + nvl(tICMSPARTILHA.VLICMSPART,0);
             END IF;
           end if;

              -----------------------------------------------


          SELECT VALORIPI
            INTO  vtITEM_PRECOS.vlipi_pvenda
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_IPI(p_regfilial.codigo,
                                                 p_regpedido.codfilialnf,
                                                 p_regitem.codfilialretira,
                                                 p_regcliente.codcli,
                                                 p_regitem.codprod,
                                                 p_regitem.codauxiliar,
                                                 p_regpedido.condvenda,
                                                 'N',
                                                 vtITEM_PRECOS.pvenda_semimpostos,
                                                 p_regpedido.vendatriangular,
                                                 p_regpedido.codendentcli,
                                                 'N',--transferencia
                                                 'N',--transferenciaVirtual
                                                 'N',
                                                 'F',
                                                 vtITEM_PRECOS.ptabela_semimpostos,
                                                 'I',
                                                 p_regpedido.codbnf,
                                                 'S',
                                               p_regpedido.tipodocumento --VEN-1315
                                                ));

          SELECT BASEST,ST, VLRFECP, ALIQFECP
            INTO  vtITEM_PRECOS.basest_pvenda,vtITEM_PRECOS.vlst_pvenda, vtITEM_PRECOS.VLFECP,
                  p_regitem.AliqFECP
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_ST(p_regfilial.codigo,
                                                p_regpedido.codfilialnf,
                                                p_regitem.codfilialretira,
                                                p_regcliente.codcli,
                                                p_regpedido.codplpag,
                                                p_regitem.codprod,
                                                p_regitem.codauxiliar,
                                                p_regpedido.condvenda,
                                                'N',
                                                vtITEM_PRECOS.pvenda_semimpostos,
                                                0,
                                                vsItemTV1BNF,
                                                0,
                                                0,
                                                0,
                                                NULL,
                                                'S',
                                                'N',
                                                'T',
                                                'N',
                                                0,
                                                'N',
                                                vtITEM_PRECOS.ptabela_semimpostos,
                                                p_regpedido.vendatriangular,
                                                'I',
                                                p_regpedido.codbnf,
                                                p_regpedido.codendentcli,
                                                'S',
                                                p_regpedido.tipodocumento, --VEN-1315
                                                'N',
                                                p_regpedido.contaordem,
                                                ticmspartilha.VLICMSPARTREM
                                                ));

          IF p_regprecos.tipocalculognre <> 'C' THEN
             vtITEM_PRECOS.pvenda := vtITEM_PRECOS.pvenda_semimpostos + vtITEM_PRECOS.vlipi_pvenda + vtITEM_PRECOS.vlst_pvenda + NVL(vtITEM_PRECOS.VLFECP, 0);
          ELSE
             vtITEM_PRECOS.pvenda := vtITEM_PRECOS.pvenda_semimpostos + vtITEM_PRECOS.vlipi_pvenda;
          END IF;

        END IF;

        integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog            := 'I';
        integradora_comple.vLog.MSG                := 'Calculado preço de venda com e sem impostos do produto ' || p_regitem.codprod;
        /** PRECOS **/
        integradora_comple.vLog.ptabela            := vtITEM_PRECOS.ptabela;
        integradora_comple.vLog.PTABELA_SEMIMPOSTO := vtITEM_PRECOS.ptabela_semimpostos;
        integradora_comple.vLog.PVENDA             := vtITEM_PRECOS.pvenda;
        integradora_comple.vLog.PVENDA_SEMIMPOSTO  := vtITEM_PRECOS.pvenda_semimpostos;
        integradora_comple.vLog.PBASE              := vtITEM_PRECOS.pbaserca;
        integradora_comple.vLog.PBASE_SEMIMPOSTO   := vtITEM_PRECOS.pbaserca_semimpostos;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));



        p_regitem.vlbasepartdest           := tICMSPARTILHA.vlbasepartdest;
        p_regitem.aliqfcp                   := tICMSPARTILHA.aliqfcp;
        p_regitem.vlfcppart                 := tICMSPARTILHA.vlfcppart;
        p_regitem.vlicmspartdest           := tICMSPARTILHA.vlicmspartdest;
        p_regitem.vlicmspart               := tICMSPARTILHA.vlicmspart;
        p_regitem.vlicmsdifaliqpart        := tICMSPARTILHA.VLICMSDIFALIQ;
        p_regitem.percbaseredpart          := tICMSPARTILHA.PERCBASERED;
        p_regitem.percprovpart             := tICMSPARTILHA.percprovpart;
        p_regitem.vlicmspartrem             := tICMSPARTILHA.vlicmspartrem;
        p_regitem.aliqinternadest          := tICMSPARTILHA.aliqinternadest;
        p_regitem.AliqInterOrigPart        := tICMSPARTILHA.ALIQINTERESTADUAL;
        p_regorigempreco.vlicmspart        := tICMSPARTILHA.vlicmspart;
        p_regorigempreco.VLICMSDIFALIQPART := tICMSPARTILHA.VLICMSDIFALIQ;

        pkg_fwpc_fiscal.icmspartilha_calcular_1_5(nvl(p_regpedido.codfilialnf,p_regpedido.codfilial),
                                                   nvl(p_regpedido.codclinf,p_regpedido.codcli),
                                                   '',
                                                   vsufEnt,
                                                   p_regpedido.data,
                                                   vtITEM_PRECOS.pvenda_semimpostos,
                                                   p_regprecos.codst,
                                                   p_regitem.codprod,
                                                   VNCODFISCAL,
                                                   VNSITTRIBUT,
                                                   VSRETORNOPartilha,
                                                   vnCodMSGPartilha,
                                                   vsMSGPartilha);

		if vnCodMSGPartilha = 0 then
			tICMSPARTILHA := func_prepararRetXMLPartilha(VSRETORNOPartilha);
		end if;

        p_regitem.VLICMSPARTPTABELA        := tICMSPARTILHA.vlicmspart;


        vnPerDesc := integradora_comple.func_calcularperdescitem(vtITEM_PRECOS.ptabela_semimpostos,
                                              vtITEM_PRECOS.pvenda_semimpostos);

        vtITEM_PRECOS.pbaserca := p_regdesconto.pbaserca;
        vtITEM_PRECOS.pbaserca := nvl(nvl(p_regitem.pbaserca, vtITEM_PRECOS.pbaserca), vtITEM_PRECOS.ptabela);

        --vtITEM_PRECOS.pbaserca := nvl(p_regitem.pbaserca, vtITEM_PRECOS.ptabela);

		pkg_fwpc_fiscal.icmspartilha_calcular_1_5(nvl(p_regpedido.codfilialnf,p_regpedido.codfilial),
                                                   nvl(p_regpedido.codclinf,p_regpedido.codcli),
                                                   '',
                                                   vsufEnt,
                                                   p_regpedido.data,
                                                   nvl(vtITEM_PRECOS.pbaserca_semimpostos, vtITEM_PRECOS.ptabela_semimpostos),
                                                   p_regprecos.codst,
                                                   p_regitem.codprod,
                                                   VNCODFISCAL,
                                                   VNSITTRIBUT,
                                                   VSRETORNOPartilha,
                                                   vnCodMSGPartilha,
                                                   vsMSGPartilha);

		if vnCodMSGPartilha = 0 then
			tICMSPARTILHA := func_prepararRetXMLPartilha(VSRETORNOPartilha);
		end if;

        p_regitem.VLICMSPARTPBASERCA        := tICMSPARTILHA.vlicmspart;

        integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TipoLog            := 'I';
        integradora_comple.vLog.MSG                := 'Definido o PBASERCA para o produto ' || p_regitem.codprod;
        /** PRECOS **/
        integradora_comple.vLog.ptabela            := vtITEM_PRECOS.ptabela;
        integradora_comple.vLog.PTABELA_SEMIMPOSTO := vtITEM_PRECOS.ptabela_semimpostos;
        integradora_comple.vLog.PVENDA             := vtITEM_PRECOS.pvenda;
        integradora_comple.vLog.PVENDA_SEMIMPOSTO  := vtITEM_PRECOS.pvenda_semimpostos;
        integradora_comple.vLog.PBASE              := vtITEM_PRECOS.pbaserca;
        integradora_comple.vLog.PBASE_SEMIMPOSTO   := vtITEM_PRECOS.pbaserca_semimpostos;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));



      ELSE
        vtITEM_PRECOS.pvenda_semimpostos := vtITEM_PRECOS.pvenda ;
      END IF; -- END IF (p_regitem.cesta = 'N') OR       (p_regitem.cesta = 'S' AND vbvalidoprecofixocesta = FALSE) AND (p_apenasvalida = 'N'  AND p_regfilial.precoporembalagem = 'N')

	       ---------------------------Diferencial de ALiquotas------------------------------
      if (p_regcliente.isentodifaliquotas = 'N') and
         (nvl(p_regprecos.PERCDIFALIQUOTAS,0) > 0) then

		  DECLARE
			vnPVALORDIFALIQUOTA NUMBER := 0;
		  BEGIN
			vnPVALORDIFALIQUOTA := nvl(Round((vtITEM_PRECOS.ptabela_semimpostos  * (p_regprecos.PERCDIFALIQUOTAS / 100)),
												integradora_comple.gregpcconsum.numcasasdecvenda),0);

			vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela + vnPVALORDIFALIQUOTA;


			vnPVALORDIFALIQUOTA   := nvl(Round((vtITEM_PRECOS.pbaserca_semimpostos  * (p_regprecos.PERCDIFALIQUOTAS / 100)),
												integradora_comple.gregpcconsum.numcasasdecvenda),0);

			vtITEM_PRECOS.pbaserca := vtITEM_PRECOS.pbaserca + vnPVALORDIFALIQUOTA;


			vnPVALORDIFALIQUOTA   := nvl(Round((vtITEM_PRECOS.pvenda_semimpostos  * (p_regprecos.PERCDIFALIQUOTAS / 100)),
												integradora_comple.gregpcconsum.numcasasdecvenda),0);

			vtITEM_PRECOS.pvenda := vtITEM_PRECOS.pvenda + vnPVALORDIFALIQUOTA;

			p_regitem.vldifaliquotas := vnPVALORDIFALIQUOTA;
			p_regitem.basedifaliquotas := ROUND(vtITEM_PRECOS.pvenda_semimpostos,integradora_comple.gregpcconsum.numcasasdecvenda);
		  END;
	  END IF;

      -----------------------------------------------DESCONTO DE SIMPLES NACIONAL COM PARAMETRO "USADESCSIMPLESNAC = S" ---------------------------------------------------

         IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',p_regpedido.codfilial,'N') = 'S')
            AND (nvl(p_regcliente.simplesnacional,'N') = 'S')
            AND NOT(NVL(p_regitem.codprecofixo,0) > 0 and VSAPLICADESCONTOSIMPLES = 'N')
          THEN
            --PBASERCA
            SELECT VALOR_REDUCAO_SIMPLES_NACIONAL
             INTO  vtITEM_PRECOS.vlredsimplesnac_pbaserca
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(p_regfilial.codigo,
                                                                    p_regpedido.codfilialnf,
                                                                    p_regitem.codfilialretira,
                                                                    p_regcliente.codcli,
                                                                    p_regpedido.codplpag,
                                                                    p_regitem.codprod,
                                                                    p_regitem.codauxiliar,
                                                                    p_regpedido.condvenda,
                                                                    'N',
                                                                    vtITEM_PRECOS.pbaserca,
                                                                    vtITEM_PRECOS.pbaserca
                                                                    ));

            vtITEM_PRECOS.pbaserca := vtITEM_PRECOS.pbaserca - vtITEM_PRECOS.vlredsimplesnac_pbaserca;




          END IF;

      -----------------------------------------------FIM DESCONTO DE SIMPLES NACIONAL---------------------------------------------------

      -----------------------------------------------DESCONTO DE BALCAO RESERVA---------------------------------------------------
      --SOLICITAÇÃO 2337.098165.2014
      IF (p_regpedido.origemped = 'R') AND (nvl(integradora_comple.gregpcconsum.percacrescimobalcao,0) <> 0)
      THEN
        vtITEM_PRECOS.ptabela   := vtITEM_PRECOS.ptabela * (1 + (integradora_comple.gregpcconsum.percacrescimobalcao / 100));
        vtITEM_PRECOS.pbaserca  := vtITEM_PRECOS.pbaserca * (1 + (integradora_comple.gregpcconsum.percacrescimobalcao / 100));
      END IF;
      ----------------------------------------------------------------------------------------------------------------------------

       --------------------------------------------------VALIDAÇÃO Itens sem filial 99 TV10--------------------------------------------------------
       if (P_REGPEDIDO.CONDVENDA = 10)  and
         (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('RESTPRODTV10FIL99','99','N') = 'S')and
         (p_Regitem.valido = TRUE)
       then
        BEGIN
         SELECT NVL(CODFILIAL, '')CODFILIAL
         INTO vsProdFilial
           FROM PCPRODUT
        WHERE codprod = p_regitem.codprod;
        exception
          when no_data_found then
            vsProdFilial := '';
        end;

        if(vsProdFilial <> '99')then
            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;

            vsmensagem := vsmensagem || vschar || 'Produto com filial diferente de 99, não é permitido em pedido TV10, (parametro 3845 na rotina 132)';

            p_regitem.valido        := FALSE;
            p_regorigempreco.valido := FALSE;
        end IF;
      end IF;
      --------------------------------------------------FIM VALIDAÇÃO Itens sem filial 99 TV10--------------------------------------------------------
      IF p_Regitem.valido = TRUE
      THEN


        ------------------------PEGA O PREÇO DE REFERENTE A PEDIDO DE TRANSFERENCIA---------------------------
        IF p_regpedido.condvenda IN (10, 13) AND NOT (p_regpedido.condvenda = 13 AND P_REGCLIENTE.TIPOCUSTOMANIF = 'P')
        THEN

        vsTIPOCUSTO := CASE P_REGPEDIDO.CONDVENDA
                         WHEN 10 THEN
                           p_regcliente.tipocustotransf
                         WHEN 13 THEN
                           P_REGCLIENTE.TIPOCUSTOMANIF
                       END;

          --Se TIPOCUSTOTRANSF.AsString = 'P' ->  usa preço de venda
          --Custo Reposição - > default
          IF vsTIPOCUSTO = 'E'
          THEN
            vtITEM_PRECOS.ptabela  := p_regprecos.custorep;

            IF nvl(p_regprecos.custorep,0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem custorep, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;



            END IF;

            --Custo Real
          ELSIF vsTIPOCUSTO = 'R'
          THEN
            vtITEM_PRECOS.ptabela  := p_regprecos.custoreal;

            IF nvl(p_regprecos.custoreal,
                   0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem custoreal, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;


            END IF;


            --Custo Contábil
          ELSIF vsTIPOCUSTO = 'C'
          THEN
            vtITEM_PRECOS.ptabela  := p_regprecos.custocont;


            IF nvl(p_regprecos.custocont,
                   0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem custocont, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;


            END IF;

            --Custo Financeiro
          ELSIF vsTIPOCUSTO = 'F'
          THEN
            vtITEM_PRECOS.ptabela := p_regprecos.custofin;

            IF nvl(p_regprecos.custofin,
                   0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem custofin, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;


            END IF;

            --Custo Última Entrada
          ELSIF vsTIPOCUSTO = 'U'
          THEN
            vtITEM_PRECOS.ptabela  := p_regprecos.custoultent;

            IF nvl(p_regprecos.custoultent,
                   0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem custoultent, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;

            END IF;

          --Valor Última Entrada
          ELSIF vsTIPOCUSTO = 'V'
          THEN
            vtITEM_PRECOS.ptabela := p_regprecos.valorultent;

            IF nvl(p_regprecos.valorultent,
                   0) = 0
            THEN

              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem := vsmensagem || vschar || 'Produto sem valorultent, necessario para pedido tipo '||p_regpedido.condvenda;-- 10';

              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;

            END IF;

          END IF;

          SELECT perdesccustotransf
            INTO VNperdesccustotransf
            FROM PCTRIBUT
           WHERE CODST =  p_regprecos.codst;

          if (VNperdesccustotransf > 0) then
             vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela  * (1 - (NVL(VNperdesccustotransf,0) / 100));
          end if;

          if (paramfilial.obtercomovarchar2('USARTRIBTRANSFVENDA10', p_regpedido.codfilial) = 'S')
            and NVL(p_regcliente.peracrestransf,0) > 0 then
             vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela  * (1 + (NVL(p_regcliente.peracrestransf,0) / 100));
          end if;

          SELECT VALORSEMIMPOSTO, MSG
            INTO vtITEM_PRECOS.ptabela_semimpostos, VSMSGRETORNO_PSEMIMPOSTO
            FROM TABLE(PKG_TRIBUTACAO.CALCULAR_PVENDA_SEM_IMPOSTO(p_regfilial.codigo,
                                                                  p_regpedido.codfilialnf,
                                                                  p_regitem.codfilialretira,
                                                                  p_regcliente.codcli,
                                                                  p_regpedido.codplpag,
                                                                  p_regitem.codprod,
                                                                  p_regitem.codauxiliar,
                                                                  p_regpedido.condvenda,
                                                                  'N',
                                                                  case
                                                                    when p_regpedido.condvenda = 10 and vsTIPOCUSTO = 'P' and
                                                                         nvl(p_regprecos.vlst, 0) > 0 then
                                                                     p_regprecos.vlst
                                                                    else
                                                                     0
                                                                  end, -- DDVENDAS-12141
                                                                  0,
                                                                  vtITEM_PRECOS.ptabela,
                                                                  vsRetiraImposto201,
                                                                  'S',
                                                                  vsItemTV1BNF,
                                                                  vsmensagemprecofixo, --0,
                                                                  NULL,
                                                                  'N',
                                                                  'N',
                                                                  'N',
                                                                  'N',
                                                                  0,
                                                                  p_regpedido.VendaTriangular,
                                                                  'I',
                                                                  p_regpedido.codbnf,
                                                                  p_regpedido.codendentcli,
                                                                  p_regpedido.tipodocumento));

          IF VSMSGRETORNO_PSEMIMPOSTO <> 'OK' THEN
            IF vsmensagem IS NOT NULL THEN
             vschar := '#';
            ELSE
             vschar := NULL;
            END IF;

            vsmensagem := vsmensagem || vschar ||
                          '4(PSI): Item ' || p_regitem.codprod || ' retornou com Preco de Sem Imposto(vtITEM_PRECOS.ptabela_semimpostos) nulo ou zerado. ' || chr(13) ||
                          VSMSGRETORNO_PSEMIMPOSTO;
			       raise ERRO_VALIDARPRECONULOOUZERADO;

          END IF;

          SELECT VALORIPI
            INTO vtITEM_PRECOS.vlipi_ptabela
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_IPI(p_regfilial.codigo,
                                                 p_regpedido.codfilialnf,
                                                 p_regitem.codfilialretira,
                                                 p_regcliente.codcli,
                                                 p_regitem.codprod,
                                                 p_regitem.codauxiliar,
                                                 p_regpedido.condvenda,
                                                 'N',
                                                 vtITEM_PRECOS.ptabela_semimpostos,
                                                 p_regpedido.vendatriangular,
                                                 p_regpedido.codendentcli,
                                                 'N',--transferencia
                                                 'N',--transferenciaVirtual
                                                 'N',
                                                 'F',
                                                 null,
                                                 'I',
                                                 p_regpedido.codbnf,
                                                 'S',
                                               p_regpedido.tipodocumento --VEN-1315
                                                ));

          SELECT BASEST,ST, VLRFECP, ALIQFECP
            INTO vtITEM_PRECOS.basest_ptabela,vtITEM_PRECOS.vlst_ptabela, vtITEM_PRECOS.VLFECP,
                 p_regitem.AliqFECP
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_ST(p_regfilial.codigo,
                                                p_regpedido.codfilialnf,
                                                p_regitem.codfilialretira,
                                                p_regcliente.codcli,
                                                p_regpedido.codplpag,
                                                p_regitem.codprod,
                                                p_regitem.codauxiliar,
                                                p_regpedido.condvenda,
                                                'N',
                                                vtITEM_PRECOS.ptabela_semimpostos,
                                                0,
                                                vsItemTV1BNF,
                                                0,
                                                0,
                                                0,
                                                NULL,
                                                'S',
                                                'N',
                                                'T',
                                                'N',
                                                0,
                                                'N',
                                                0,
                                                p_regpedido.vendatriangular,
                                                'I',
                                                p_regpedido.codbnf,
                                                p_regpedido.codendentcli,
                                                'S',
                                                p_regpedido.tipodocumento, --VEN-1315
                                                'N',
                                                p_regpedido.contaordem,
                                                ticmspartilha.VLICMSPARTREM
                                                ));


          IF p_regprecos.tipocalculognre <> 'C' THEN

              IF (NVL(p_regpedido.pvendasemimposto,'P') in('N','P'))   THEN
                 vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela_semimpostos +
                                          NVL(vtITEM_PRECOS.vlipi_ptabela,0) +
                                          NVL(vtITEM_PRECOS.vlst_ptabela,0) +
                                          NVL(vtITEM_PRECOS.VLFECP, 0);
              END IF;

          ELSE
            vtITEM_PRECOS.ptabela := vtITEM_PRECOS.ptabela_semimpostos + vtITEM_PRECOS.vlipi_ptabela;
          END IF;

          IF P_REGPEDIDO.CONDVENDA = 10 THEN
            IF vsTIPOCUSTO <> 'P' THEN
              vtITEM_PRECOS.pvenda := vtITEM_PRECOS.ptabela  * (1 + (p_regregiao.perfrete/100));
              vtITEM_PRECOS.pvenda_semimpostos :=   vtITEM_PRECOS.ptabela_semimpostos * (1 + (p_regregiao.perfrete/100));
            ELSE
             vtITEM_PRECOS.pvenda := vtITEM_PRECOS.ptabela;
             vtITEM_PRECOS.pvenda_semimpostos :=   vtITEM_PRECOS.ptabela_semimpostos;
            END IF;
          END IF;
          IF (nvl(vtITEM_PRECOS.ptabela,0) = 0)
          THEN

            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;
            vsmensagem := vsmensagem || vschar || 'PRECO DE TABELA ZERADO;';

            IF p_regfilial.tipoimportacaovenda = 'RI' THEN
              p_regitem.valido        := FALSE;
              p_regorigempreco.valido := FALSE;
            ELSIF p_regfilial.tipoimportacaovenda IN ('RP', 'BP') THEN
              p_regpedido.valido := FALSE;
            END IF;

          END IF;

        END IF;
        ------------------------FIM PEGA O PREÇO DE REFERENTE A PEDIDO DE TRANSFERENCIA---------------------------


        IF p_regitem.cesta = 'N'
           OR (p_regitem.cesta = 'S' AND vbvalidoprecofixocesta = FALSE)
        THEN
			IF p_regfilial.utilizavendaporembalagem = 'S' THEN
				BEGIN
				--Busca o fator de conversao do produto na pcembalagem
				select nvl(pcembalagem.qtunit,1) into fatorCoversaoEmbalagem
					from pcembalagem
					where pcembalagem.codprod = p_regitem.codprod
					and pcembalagem.codfilial = p_regfilial.codigo;
				EXCEPTION
					WHEN OTHERS THEN
					fatorCoversaoEmbalagem := 1;
				END;

				--O preco de venda do item quando a filial utiliza venda por embalagem
				-- é o preço total do produto dividido pelo fator de conversão.
				p_regitem.pvenda1 := (p_regprecos.pvenda1/fatorCoversaoEmbalagem);

			ELSE
				--Se a filial não utiliza venda por embalagem o preço de venda é o preço total do produto
				p_regitem.pvenda1 := p_regprecos.pvenda1;
			END IF;
		-------------------------------------ACRESCIMO/DESCONTO BENEFICIO FISCAL-----------------------------------------
          IF (p_regcliente.POSSUIBENFFISCAL = 'S') THEN
            vtITEM_PRECOS.ptabela  := (vtITEM_PRECOS.ptabela * (1 - (p_regprecos.PERCACRESCBENFFIS/100)));
            vtITEM_PRECOS.pbaserca := (vtITEM_PRECOS.pbaserca * (1 - (p_regprecos.PERCACRESCBENFFIS/100)));

            p_regorigempreco.PERCACRESCBENFFIS := p_regprecos.PERCACRESCBENFFIS;
          END IF;
          -------------------------------------ACRESCIMO/DESCONTO BENEFICIO FISCAL-----------------------------------------

          -------------------------------------ACRESCIMO DE SIMPLES NACIONAL------------------------------------------
          IF( p_regcliente.tipoempresa = 'SN')and (p_regprecos.PERACRESCISMOSIMPNAC > 0)then

            vtITEM_PRECOS.ptabela := (vtITEM_PRECOS.ptabela + (vtITEM_PRECOS.ptabela * p_regprecos.PERACRESCISMOSIMPNAC / 100));
            vtITEM_PRECOS.pbaserca := (vtITEM_PRECOS.pbaserca + (vtITEM_PRECOS.pbaserca * p_regprecos.PERACRESCISMOSIMPNAC / 100));

            p_regorigempreco.PERACRESCISMOSIMPNAC := p_regprecos.PERACRESCISMOSIMPNAC;
            --p_regorigemdesc.peracrespf    := p_regprecos.PERACRESCISMOSIMPNAC;

            --myshop
            p_regitem.ptabelaatac := (p_regitem.ptabelaatac + (p_regitem.ptabelaatac * p_regprecos.PERACRESCISMOSIMPNAC / 100));
            p_regitem.ptabelavar  := (p_regitem.ptabelavar + (p_regitem.ptabelavar * p_regprecos.PERACRESCISMOSIMPNAC / 100));

          ELSE
            -------------------------------------ACRESCIMO DE PESSOA FÍSICA------------------------------------------
            /*
              Autor      : Iran Junior
              Solicitação: HIS.01672.2016
              Data       : 21/06/2016
              Descrição  : Adicionado condição abaixo para contemplar o cenario
              descrito na historia:HIS.01672.2016
              Não aplicar acréscimo de Pessoa Física quando for Pessoa Jurídica,
              não contribuinte e consumidor final
            */


           vbAplicaPJURICONSF := 'N';
           vbValidaPJIsentoIEcomoPF := nvl(integradora_comple.gregpcconsum.consideraisentoscomopf,'N');

           IF(p_regprecos.APLICAACRESPFJURIDICA = 'S' AND
              p_regcliente.contribuinte = 'N' AND
            p_regcliente.consumidorfinal = 'S' AND
            p_regcliente.tipofj = 'J') THEN

            vbAplicaPJURICONSF := 'S';

           END IF;

           IF (
             not(p_regpedido.condvenda in (8, 10)) and ((p_regcliente.tipofj = 'J') and
              (p_regcliente.contribuinte = 'N') and
              (p_regcliente.consumidorfinal = 'S' )) and (vbAplicaPJURICONSF = 'N') and
              (vbValidaPJIsentoIEcomoPF = 'N')) then
               p_regprecos.peracrescismopf := 0;
          END IF;

            vbpessoafisica := (FERRAMENTAS.VERIFICAR_FJ(p_regpedido.codcli) = 'PESSOA FISICA');

          IF ((p_regpedido.condvenda <> 3 AND p_regpedido.condvenda <> 6 AND p_regpedido.condvenda <> 12)
             OR (integradora_comple.gregpcconsum.aplicaacrescpftv3 = 'S'))  AND p_regitem.cesta = 'N'
            THEN
              IF integradora_comple.gregpcconsum.acrescimopfcomie = 'S'
              THEN
                IF ((p_regprecos.APLICAACRESCPJISENTA = 'S') AND ((p_regcliente.IEENT = 'ISENTA') OR (p_regcliente.IEENT = 'ISENTO'))) OR
                   (vbpessoafisica)
                THEN

                  vtITEM_PRECOS.ptabela := (vtITEM_PRECOS.ptabela + (vtITEM_PRECOS.ptabela * p_regprecos.peracrescismopf / 100));
                  vtITEM_PRECOS.pbaserca := (vtITEM_PRECOS.pbaserca + (vtITEM_PRECOS.pbaserca * p_regprecos.peracrescismopf / 100));

                  vtITEM_PRECOS.ptabela  := ROUND(vtITEM_PRECOS.ptabela, integradora_comple.gregpcconsum.numcasasdecvenda);
                  vtITEM_PRECOS.pbaserca := ROUND( vtITEM_PRECOS.pbaserca, integradora_comple.gregpcconsum.numcasasdecvenda);

                  p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
                  p_regorigemdesc.peracrespf    := p_regprecos.peracrescismopf;

                  --myshop
                  p_regitem.ptabelaatac := (p_regitem.ptabelaatac + (p_regitem.ptabelaatac * p_regprecos.peracrescismopf / 100));
                  p_regitem.ptabelavar  := (p_regitem.ptabelavar + (p_regitem.ptabelavar * p_regprecos.peracrescismopf / 100));

                  IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('ACRESPERCPESSOAFISICA',p_regpedido.codfilial,'N') = 'N') THEN
                    p_regprecos.precominimovenda := (p_regprecos.precominimovenda + (p_regprecos.precominimovenda * p_regprecos.peracrescismopf / 100));
                  END IF;

                END IF;
              ELSE
                IF ((p_Regprecos.APLICAACRESCPJISENTA = 'S') AND ((p_regcliente.IEENT = 'ISENTA') OR (p_regcliente.IEENT = 'ISENTO'))) OR
                   (vbpessoafisica and ((p_regcliente.IEENT = 'ISENTA') OR (p_regcliente.IEENT = 'ISENTO')))
                THEN

                  vtITEM_PRECOS.ptabela := (vtITEM_PRECOS.ptabela + (vtITEM_PRECOS.ptabela * p_regprecos.peracrescismopf / 100));
                  vtITEM_PRECOS.pbaserca := (vtITEM_PRECOS.pbaserca + (vtITEM_PRECOS.pbaserca * p_regprecos.peracrescismopf / 100));

                  vtITEM_PRECOS.ptabela  := ROUND(vtITEM_PRECOS.ptabela, integradora_comple.gregpcconsum.numcasasdecvenda);
                  vtITEM_PRECOS.pbaserca := ROUND( vtITEM_PRECOS.pbaserca, integradora_comple.gregpcconsum.numcasasdecvenda);

                  p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
                  p_regorigemdesc.peracrespf    := p_regprecos.peracrescismopf;

                  --myshop
                  p_regitem.ptabelaatac := (p_regitem.ptabelaatac + (p_regitem.ptabelaatac * p_regprecos.peracrescismopf / 100));
                  p_regitem.ptabelavar  := (p_regitem.ptabelavar + (p_regitem.ptabelavar * p_regprecos.peracrescismopf / 100));

                  IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('ACRESPERCPESSOAFISICA',p_regpedido.codfilial,'N') = 'N') THEN
                    p_regprecos.precominimovenda := (p_regprecos.precominimovenda + (p_regprecos.precominimovenda * p_regprecos.peracrescismopf / 100));
                  END IF;

                END IF;
              END IF;
            END IF;
            -------------------------------------FIM ACRESCIMO DE PESSOA FÍSICA------------------------------------------
          END IF; -- p_regitem.cesta = 'N' OR (p_regitem.cesta = 'S' AND vbvalidoprecofixocesta = FALSE)
        END IF;
        ------------------------------------- FIM ACRESCIMO DE SIMPLES NACIONAL------------------------------------------

        -----------------------------------------------DESCONTO DE SIMPLES NACIONAL COM PARAMETRO "USADESCSIMPLESNAC = N" ---------------------------------------------------
        IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',p_regpedido.codfilial,'N') = 'N')
          AND (nvl(p_regcliente.simplesnacional,'N') = 'S')
          AND (p_regpedido.pvendasemimposto <> 'S')
        THEN

          --PTABELA
          SELECT VALORSEMIMPOSTO, MSG
            INTO  vtITEM_PRECOS.ptabela_semimpostos, VSMSGRETORNO_PSEMIMPOSTO
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_PVENDA_SEM_IMPOSTO(p_regfilial.codigo,
                                                                p_regpedido.codfilialnf,
                                                                p_regitem.codfilialretira,
                                                                p_regcliente.codcli,
                                                                p_regpedido.codplpag,
                                                                p_regitem.codprod,
                                                                p_regitem.codauxiliar,
                                                                p_regpedido.condvenda,
                                                                'N',
                                                                1,
                                                                0,
                                                                vtITEM_PRECOS.ptabela,
                                                                'N',
                                                                'P',
                                                                'N',
                                                                0,
                                                                NULL,
                                                                'N',
                                                                'N',
                                                                'N',
                                                                'N',
                                                                0,
                                                                p_regpedido.VendaTriangular,
                                                                'I',
                                                                p_regpedido.codbnf,
                                                                p_regpedido.codendentcli,
                                                                p_regpedido.tipodocumento,
                                                                'N',
                                                                p_regpedido.contaordem,
                                                                ticmspartilha.VLICMSPARTREM));

          IF VSMSGRETORNO_PSEMIMPOSTO <> 'OK' THEN
            IF vsmensagem IS NOT NULL THEN
             vschar := '#';
            ELSE
             vschar := NULL;
            END IF;

            vsmensagem := vsmensagem || vschar ||
                          '5(PSI): Item ' || p_regitem.codprod || ' retornou com Preco de Sem Imposto(vtITEM_PRECOS.ptabela_semimpostos) nulo ou zerado. ' || chr(13) ||
                          VSMSGRETORNO_PSEMIMPOSTO;
			      raise ERRO_VALIDARPRECONULOOUZERADO;
          END IF;

          SELECT VALOR_REDUCAO_SIMPLES_NACIONAL,NOVO_PRECO_SIMPLES_NACIONAL
            INTO  vtITEM_PRECOS.vlredsimplesnac_ptabela, vtITEM_PRECOS.ptabela
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(p_regfilial.codigo,
                                                                  p_regpedido.codfilialnf,
                                                                  p_regitem.codfilialretira,
                                                                  p_regcliente.codcli,
                                                                  p_regpedido.codplpag,
                                                                  p_regitem.codprod,
                                                                  p_regitem.codauxiliar,
                                                                  p_regpedido.condvenda,
                                                                  'N',
                                                                  vtITEM_PRECOS.ptabela_semimpostos,
                                                                  vtITEM_PRECOS.ptabela
                                                                  ));

          vtITEM_PRECOS.vlredsimplesnac_pvenda := vtITEM_PRECOS.vlredsimplesnac_ptabela;
          vtITEM_PRECOS.pvenda := vtITEM_PRECOS.pvenda - vtITEM_PRECOS.vlredsimplesnac_pvenda;

           /* DDVENDAS-22006:
          Ponto alterado para que a Integradora não recalcule o desconto do Simples Nacional sobre o
          Preço de Venda já calculado anteriormente e persista o valor do Preço de Tabela calculado acima,
          para que o comportamento fique igual ao da 316, nesta modalidade de
          Desconto do Simples (Rotina 514).
          */

          --PVENDA
          SELECT NVL(NOVO_PRECO_SIMPLES_NACIONAL, 0)
            INTO  vtITEM_PRECOS.pvenda
          FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(p_regfilial.codigo,
                                                                  p_regpedido.codfilialnf,
                                                                  p_regitem.codfilialretira,
                                                                  p_regcliente.codcli,
                                                                  p_regpedido.codplpag,
                                                                  p_regitem.codprod,
                                                                  p_regitem.codauxiliar,
                                                                  p_regpedido.condvenda,
                                                                  'N',
                                                                  vtITEM_PRECOS.pvenda_semimpostos,
                                                                  vtITEM_PRECOS.pvenda
                                                                  ));


          if nvl(p_regprecos.percredpvendasimplesnac, 0) > 0 then
            p_regitem.iva   := p_regprecos.iva * (p_regprecos.percredpvendasimplesnac/100);
