        END IF;

        integradora_comple.gvet_regitenscesta(i).pvenda :=  vnpvendasemimposto + vnVlIpi + vnST + VLFECP_PVENDA;


        IF vsmensagem_stfonte IS NOT NULL
        THEN
          integradora_comple.proc_registralog(p_regpedido.numped,
                           p_regpedido.numpedrca,
                           p_regitem.codprod,
                           p_regitem.numseq,
                           p_regitem.codauxiliar,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           p_regpedido.CODUSUR,
                           p_regpedido.dtaberturapedpalm,
                           NULL,
                           '3',
                           vsmensagem_stfonte,
                           NULL,
                           p_regitem.numseqfv);
        END IF;

        IF (integradora_comple.gvet_regitenscesta(i).st = 0)
           AND (vnSTFONTE <> 0)
        THEN

          integradora_comple.gvet_regitenscesta(i).st := vnSTFONTE;

          integradora_comple.gvet_regitenscesta(i).PVENDA := Round(integradora_comple.gvet_regitenscesta(i).PVENDA + vnSTFONTE,
                                                integradora_comple.gregpcconsum.numcasasdecvenda);


          integradora_comple.gvet_regitenscesta(i).PTABELA := Round(integradora_comple.gvet_regitenscesta(i).PTABELA + vnSTFONTE,
                                                 integradora_comple.gregpcconsum.numcasasdecvenda);

          integradora_comple.gvet_regitenscesta(i).IVA := integradora_comple.gvet_regitenscesta(i).ivafonte;

          integradora_comple.gvet_regitenscesta(i).PAUTA := 0;

          integradora_comple.gvet_regitenscesta(i).ALIQICMS1 := integradora_comple.gvet_regitenscesta(i).aliqicms1fonte;

          integradora_comple.gvet_regitenscesta(i).ALIQICMS2 := integradora_comple.gvet_regitenscesta(i).aliqicms2fonte;

          integradora_comple.gvet_regitenscesta(i).PERCBASEREDST := integradora_comple.gvet_regitenscesta(i).percbaseredst;

          integradora_comple.gvet_regitenscesta(i).PERCBASEREDSTFONTE := integradora_comple.gvet_regitenscesta(i).PERCBASEREDSTFONTE;
        END IF;


        IF integradora_comple.gvet_regitenscesta(i).codicmtabpf IS NULL
        THEN
          vbcodicmtabpf := TRUE;
        ELSE
          vbcodicmtabpf := FALSE;
        END IF;

        -- busca percentual de comissao
        vsmensagem_comiss := NULL;


        SELECT COUNT(*)
          INTO vicont
          FROM pctabcomiss p;

        IF vicont <> 0
        THEN
          vbUsaPcTabComiss := TRUE;
        ELSE
          vbUsaPcTabComiss := FALSE;
        END IF;

        SELECT COUNT(*)
          INTO vicont
          FROM pccomissaousur p;

        IF vicont <> 0
        THEN
          vbUsaPcComissaoUsur := TRUE;
        ELSE
          vbUsaPcComissaoUsur := FALSE;
        END IF;


        SELECT COUNT(*)
          INTO vicont
          FROM pccomissaoplpag p;

        IF vicont <> 0
        THEN
          vbUsaPcComissaoplpag := TRUE;
        ELSE
          vbUsaPCComissaoPlPag := FALSE;
        END IF;


        SELECT COUNT(*)
          INTO vicont
          FROM pccomissaoregiao p;

        IF vicont <> 0
        THEN
          vbUsaPcComissaoregiao := TRUE;
        ELSE
          vbUsaPcComissaoregiao := FALSE;
        END IF;

        IF p_regfilial.broker = 'S'
        THEN
          vbUsaPCComissaofilial := TRUE;
        ELSE
          vbUsaPCComissaofilial := FALSE;
        END IF;

        BEGIN

        if p_regpedido.condvenda not in (4, 5, 8, 10, 13, 11, 20) or
           (p_regpedido.condvenda = 9 and ferramentas.F_BUSCARPARAMETRO_ALFA('CON_CALCULACOMISSTV9',p_regpedido.codfilial, 'N') = 'S')
        then

          integradora_comple.gvet_regitenscesta(i).percom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido(p_regregiao.numregiao,
                                                                                      vnperluc,
                                                                                      ROUND(vPerDescCesta, 2),
                                                                                      vbUsaPcTabComiss,
                                                                                      vbUsaPcComissaoUsur,
                                                                                      vbUsaPCComissaoPlPag,
                                                                                      vbUsaPCComissaoRegiao,
                                                                                      vbUsaPCComissaofilial,
                                                                                      integradora_comple.gregpcconsum.usacomissaoporrca,
                                                                                      integradora_comple.gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                                                                      integradora_comple.gregpcconsum.usacomissaoporcliente,
                                                                                      integradora_comple.gregpcconsum.USACOMISSAOPORLINHAPROD,
                                                                                      integradora_comple.gregpcconsum.comissaorcatipovenda,
                                                                                      p_regrca.tipovend,
                                                                                      p_regrca.percent,
                                                                                      p_regrca.percent2,
                                                                                      integradora_comple.gvet_regitenscesta(i).codprodmp,
                                                                                      integradora_comple.gvet_regitenscesta(i).pcomint1,
                                                                                      integradora_comple.gvet_regitenscesta(i).PCOMEXT1,
                                                                                      integradora_comple.gvet_regitenscesta(i).PCOMREP1,
                                                                                      integradora_comple.gvet_regitenscesta(i).codlinhaprod,
                                                                                      integradora_comple.gvet_regitenscesta(i).tipocomissao,
                                                                                      integradora_comple.gvet_regitenscesta(i).codepto,
                                                                                      integradora_comple.gvet_regitenscesta(i).codsec,
                                                                                      integradora_comple.gvet_regitenscesta(i).classe,
                                                                                      p_regitem.tipovenda,
                                                                                      p_regitem.codplpag,
                                                                                      p_regpedido.data,
                                                                                      p_regpedido.codfilial,
                                                                                      coalesce(p_regitem.codusur, p_regpedido.CODUSUR),
                                                                                      p_regfilial.considerarcomissaozero,
                                                                                      p_regfilial.tipoavaliacaocomissao,
                                                                                      p_regcliente.percomcli,
                                                                                      p_regcliente.codcli,
                                                                                      NULL,
                                                                                      vncodcomis,
                                                                                      vscodrotinacomis,
                                                                                      vsLetraComiss,
                                                                                      vsmensagem_comiss,
                                                                                      integradora_comple.gvet_regitenscesta(i).codauxiliar,
                                                                                      NULL, --regprecos.pcomint1_emb,
                                                                                      NULL, --regprecos.PCOMEXT1_emb,
                                                                                      NULL, --regprecos.PCOMREP1_emb,
                                                                                      p_regfilial.utilizavendaporembalagem,
                                                                                      integradora_comple.gvet_regitenscesta(i).ptabela,
                                                                                      integradora_comple.gvet_regitenscesta(i).pvenda,
                                                                                      integradora_comple.gregpcconsum.numcasasdecvenda);
        end if;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             p_regitem.codprod,
                             p_regitem.numseq,
                             p_regitem.codauxiliar,
                             NULL,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.CODUSUR,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '3',
                             vsmensagem_comiss,
                             NULL,
                             p_regitem.numseqfv);
        END;

        IF nvl(integradora_comple.gregpcconsum.incluircomissaocmvvenda,
               'S') = 'N'
        THEN
          vnpercom := 0;
        ELSE
          vnpercom := integradora_comple.gvet_regitenscesta(i).percom;
        END IF;

        BEGIN
          SELECT CodIcmDifer
            into vnCodIcmDifer
            FROM PCTRIBUT
           WHERE PCTRIBUT.CODST = integradora_comple.gvet_regitenscesta(i).codst;
        EXCEPTION
          WHEN OTHERS THEN
            vnCodIcmDifer := 0;
        END;
        --53 parâmetros
        funcoesvendas.calcularCMV(p_regfilial.impostocomissaorca,
                                  integradora_comple.gregpcconsum.aplicarindicecmv,
                                  integradora_comple.gregpcconsum.INCLUIRCOMISSAOCMVVENDA,
                                  nvl(integradora_comple.gregpcconsum.txvenda,0),
                                  p_regcliente.tipofj,
                                  p_regcliente.utilizaiesimplificada,
                                  p_regcliente.ieent,
                                  integradora_comple.gvet_regitenscesta(i).freteespecial,
                                  p_regregiao.PERFRETETERCEIROS,
                                  p_regregiao.PERFRETEESPECIAL,
                                  integradora_comple.gvet_regitenscesta(i).vlcustofin,
                                  integradora_comple.gvet_regitenscesta(i).vlcustoreal,
                                  integradora_comple.gvet_regitenscesta(i).perdesccusto,
                                  integradora_comple.gvet_regitenscesta(i).codicmtab,
                                  vbcodicmtabpf,
                                  integradora_comple.gvet_regitenscesta(i).codicmtabpf,
                                  p_regpedido.percvenda,
                                  integradora_comple.gvet_regitenscesta(i).pvenda,
                                  vnPERCOM,
                                  integradora_comple.gvet_regitenscesta(i).ST,
                                  0,
                                  0,
								  0,
                                  p_regcliente.contribuinte,
                                  0,
                                  0, --nvl(integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA,0),
                                  p_regcliente.consumidorfinal,
                                  nvl(integradora_comple.gregpcconsum.consideraisentoscomopf,'N'),
                                  integradora_comple.gvet_regitenscesta(i).perfretecmv,
                                  integradora_comple.gvet_regitenscesta(i).CUSTOFINEST,
                                  integradora_comple.gvet_regitenscesta(i).txvenda,
                                  integradora_comple.gvet_regitenscesta(i).perdesccusto,
                                  integradora_comple.gvet_regitenscesta(i).CODICMTAB,
                                  integradora_comple.gvet_regitenscesta(i).VLCUSTOREAL,
                                  integradora_comple.gvet_regitenscesta(i).VLCUSTOFIN,
                                  integradora_comple.gvet_regitenscesta(i).VLDESCCUSTOCMV,
                                  p_regcliente.codcli,
                                  integradora_comple.gvet_regitenscesta(i).custoprecific,
                                  false,
                                  false,
                                  integradora_comple.gvet_regitenscesta(i).codst,
                                  0,
                                  integradora_comple.gvet_regitenscesta(i).codicmtabsimpnasc,
                                  0,
                                  nvl(p_regitem.codfilialretira, p_regfilial.codigo),
                                  vnCodIcmDifer,
                                  0,
                                  0,
                                  0,
								  0,
								  p_regpedido.numped,
								  p_regitem.numseq,
								  p_regitem.codprod);

        vPerDescCesta := ROUND(vPerDescCesta,
                           integradora_comple.gregpcconsum.numcasasdecvenda);

        vnperluc := ((integradora_comple.gvet_regitenscesta(i).pvenda - integradora_comple.gvet_regitenscesta(i).vlcustofin) / integradora_comple.gvet_regitenscesta(i).pvenda) * 100;


        IF p_regpedido.orcamento = 'S'
        THEN

          INSERT INTO pcorcavendaicesta
            (numorca,
             numped,
             codprod,
             numseq,
             codauxiliar,
             codprodmp,
             qtmp,
             pvenda,
             ptabela,
             pbaserca,
             baseicst,
             st,
             stclientegnre,
             percipi,
             vlipi,
             perciss,
             vliss,
             vldescsuframa,
             vlcustofin,
             vlcustoreal,
             vlcustorep,
             vlcustocont,
             vldesccustocmv,
             codst,
             percom,
             perdesctab,
             iva,
             aliqicms1,
             aliqicms2,
             pauta,
             percbasered,
             custofinest,
             percbaseredstfonte,
             percbaseredst,
             perdesccusto,
             codicmtab,
             txvenda,
             perfretecmv,
             vlbasepartdest,
             aliqfcp,
             aliqinternadest,
             vlfcppart,
             vlicmspartdest,
             vlicmspart,
             VLICMSDIFALIQPART,
             PERCBASEREDPART,
             PERCPROVPART,
             VLICMSPARTREM,
             ALIQINTERORIGPART,
             VLFECP,
             ALIQICMSFECP,
             VLBASEFCPST
             )
          VALUES
            (p_regpedido.numped,
             p_regpedido.numped,
             p_regitem.codprod,
             p_regitem.numseq,
             integradora_comple.gvet_regitenscesta(i).codauxiliar,
             integradora_comple.gvet_regitenscesta(i).codprodmp,
             integradora_comple.gvet_regitenscesta(i).qt,
             integradora_comple.gvet_regitenscesta(i).pvenda,
             integradora_comple.gvet_regitenscesta(i).ptabela,
             integradora_comple.gvet_regitenscesta(i).ptabela,
             integradora_comple.gvet_regitenscesta(i).baseicst,
             integradora_comple.gvet_regitenscesta(i).st,
             NULL, --integradora_comple.gvet_regitenscesta(i).stclientegnre,
             nvl(percipi,0), --integradora_comple.gvet_regitenscesta(i).percipi,
             integradora_comple.gvet_regitenscesta(i).vlipi,
             NULL, --integradora_comple.gvet_regitenscesta(i).perciss,
             NULL, --integradora_comple.gvet_regitenscesta(i).vliss,
             NULL, --integradora_comple.gvet_regitenscesta(i).vldescsuframa,
             integradora_comple.gvet_regitenscesta(i).vlcustofin,
             integradora_comple.gvet_regitenscesta(i).vlcustoreal,
             integradora_comple.gvet_regitenscesta(i).custorep,
             integradora_comple.gvet_regitenscesta(i).custocont,
             integradora_comple.gvet_regitenscesta(i).vldesccustocmv,
             integradora_comple.gvet_regitenscesta(i).codst,
             integradora_comple.gvet_regitenscesta(i).percom,
             NULL, --integradora_comple.gvet_regitenscesta(i).perdesctab,
             integradora_comple.gvet_regitenscesta(i).iva,
             integradora_comple.gvet_regitenscesta(i).aliqicms1,
             integradora_comple.gvet_regitenscesta(i).aliqicms2,
             integradora_comple.gvet_regitenscesta(i).pauta,
             integradora_comple.gvet_regitenscesta(i).percbasered,
             integradora_comple.gvet_regitenscesta(i).custofinest,
             integradora_comple.gvet_regitenscesta(i).percbaseredstfonte,
             integradora_comple.gvet_regitenscesta(i).percbaseredst,
             integradora_comple.gvet_regitenscesta(i).perdesccusto,
             integradora_comple.gvet_regitenscesta(i).codicmtab,
             integradora_comple.gvet_regitenscesta(i).txvenda,
             integradora_comple.gvet_regitenscesta(i).perfretecmv,
             integradora_comple.gvet_regitenscesta(i).vlbasepartdest,
             integradora_comple.gvet_regitenscesta(i).aliqfcp,
             integradora_comple.gvet_regitenscesta(i).aliqinternadest,
             integradora_comple.gvet_regitenscesta(i).vlfcppart,
             integradora_comple.gvet_regitenscesta(i).vlicmspartdest,
             integradora_comple.gvet_regitenscesta(i).vlicmspart,
             integradora_comple.gvet_regitenscesta(i).VLICMSDIFALIQPART,
             integradora_comple.gvet_regitenscesta(i).PERCBASEREDPART,
             integradora_comple.gvet_regitenscesta(i).PERCPROVPART,
             integradora_comple.gvet_regitenscesta(i).VLICMSPARTREM,
             integradora_comple.gvet_regitenscesta(i).ALIQINTERORIGPART,
             integradora_comple.gvet_regitenscesta(i).VLFECP,
             integradora_comple.gvet_regitenscesta(i).ALIQICMSFECP,
             integradora_comple.gvet_regitenscesta(i).VLBASEFCPST
             );


        ELSE


          INSERT INTO pcpedicesta
            (numped,
             codprod,
             numseq,
             codprodmp,
             qtmp,
             pvenda,
             ptabela,
             pbaserca,
             st,
             vlcustofin,
             vlcustoreal,
             percom,
             baseicst,
             aliqicms1,
             aliqicms2,
             percbaseredst,
             iva,
             pauta,
             percbaseredstfonte,
             percbasered,
             codst,
             vlcustorep,
             vlcustocont,
             custofinest,
             perdesccusto,
             codicmtab,
             perfretecmv,
             txvenda,
             vldesccustocmv,
             codauxiliar,
             vlbasepartdest,
             aliqfcp,
             aliqinternadest,
             vlfcppart,
             vlicmspartdest,
             vlicmspart,
             VLICMSDIFALIQPART,
             PERCBASEREDPART,
             PERCPROVPART,
             VLICMSPARTREM,
             ALIQINTERORIGPART,
             CODFISCAL,
             SITTRIBUT,
             VLIPI,
             PERCIPI,
             VLFECP,
             ALIQICMSFECP,
             VLBASEFCPST,
             PERDESCTAB
             )
          VALUES
            (p_regpedido.numped,
             p_regitem.codprod,
             p_regitem.numseq,
             integradora_comple.gvet_regitenscesta(i).codprodmp,
             integradora_comple.gvet_regitenscesta(i).qt,
             round(integradora_comple.gvet_regitenscesta(i).pvenda,integradora_comple.gregpcconsum.numcasasdecvenda),
             round(integradora_comple.gvet_regitenscesta(i).ptabela,integradora_comple.gregpcconsum.numcasasdecvenda),
             round(nvl(integradora_comple.gvet_regitenscesta(i).pbaserca, integradora_comple.gvet_regitenscesta(i).ptabela),
                   integradora_comple.gregpcconsum.numcasasdecvenda),
             integradora_comple.gvet_regitenscesta(i).st,
             integradora_comple.gvet_regitenscesta(i).vlcustofin,
             integradora_comple.gvet_regitenscesta(i).vlcustoreal,
             nvl(integradora_comple.gvet_regitenscesta(i).percom,0),
             integradora_comple.gvet_regitenscesta(i).baseicst,
             integradora_comple.gvet_regitenscesta(i).aliqicms1,
             integradora_comple.gvet_regitenscesta(i).aliqicms2,
             integradora_comple.gvet_regitenscesta(i).percbaseredst,
             integradora_comple.gvet_regitenscesta(i).iva,
             integradora_comple.gvet_regitenscesta(i).pauta,
             integradora_comple.gvet_regitenscesta(i).percbaseredstfonte,
             integradora_comple.gvet_regitenscesta(i).percbasered,
             integradora_comple.gvet_regitenscesta(i).codst,
             integradora_comple.gvet_regitenscesta(i).custorep,
             integradora_comple.gvet_regitenscesta(i).custocont,
             integradora_comple.gvet_regitenscesta(i).custofinest,
             integradora_comple.gvet_regitenscesta(i).perdesccusto,
             integradora_comple.gvet_regitenscesta(i).codicmtab,
             integradora_comple.gvet_regitenscesta(i).perfretecmv,
             integradora_comple.gvet_regitenscesta(i).txvenda,
             integradora_comple.gvet_regitenscesta(i).vldesccustocmv,
             integradora_comple.gvet_regitenscesta(i).codauxiliar,
             integradora_comple.gvet_regitenscesta(i).vlbasepartdest,
             integradora_comple.gvet_regitenscesta(i).aliqfcp,
             integradora_comple.gvet_regitenscesta(i).aliqinternadest,
             integradora_comple.gvet_regitenscesta(i).vlfcppart,
             integradora_comple.gvet_regitenscesta(i).vlicmspartdest,
             integradora_comple.gvet_regitenscesta(i).vlicmspart,
             integradora_comple.gvet_regitenscesta(i).VLICMSDIFALIQPART,
             integradora_comple.gvet_regitenscesta(i).PERCBASEREDPART,
             integradora_comple.gvet_regitenscesta(i).PERCPROVPART,
             integradora_comple.gvet_regitenscesta(i).VLICMSPARTREM,
             integradora_comple.gvet_regitenscesta(i).ALIQINTERORIGPART,
             VNCODFISCAL,
             VNSITTRIBUT,
             integradora_comple.gvet_regitenscesta(i).vlipi,
             nvl(percipi,0),
             integradora_comple.gvet_regitenscesta(i).VLFECP,
             integradora_comple.gvet_regitenscesta(i).ALIQICMSFECP,
             integradora_comple.gvet_regitenscesta(i).VLBASEFCPST,
             vPerDescCesta
             );

        END IF;
      END IF;
    END LOOP;

    pnSOMAVLDESCSUFRAMA           := vnSOMAVLDESCSUFRAMA;
    pnSOMAVLDESCICMISENCAO    := vnSOMAVLDESCICMISENCAO;
    pnSOMAVLDESCREDUCAOCOFINS := vnSOMAVLDESCREDUCAOCOFINS;
    pnSOMAVLDESCREDUCAOPIS    := vnSOMAVLDESCREDUCAOPIS;

    RETURN TRUE;
  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regitem.codprod,
                       p_regitem.numseq,
                       p_regitem.codauxiliar,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_regpedido.dtaberturapedpalm,
                       NULL,
                       '3',
                       'Problemas na gravacao o item de cesta ' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       p_regitem.numseqfv);


      RETURN FALSE;
  END func_inseriritemcesta;

  procedure gravar_pcorigempreco(p_regorigempreco  IN integradora_comple.t_origempreco,
                                p_regitem         IN integradora_comple.t_itemped)
  is
  begin
    BEGIN
      INSERT INTO pcorigempreco
        (numped, --1
         tipobroker, --2
         codprod, --3
         numseq, --4
         usatributporuf, --5
         origempreco, --6
         colunapreco, --7
         tipofrete, --8
