         dtfimautor, --26
         dtiniciodescflex, --27
         dtfimdescflex, --28
         dtiniciodescvolume, --29
         dtfimdescvolume, --30
         dtiniciodescptabela, --31
         dtfimdescptabela, --32
         dtiniciooferta, --33
         dtfimoferta, --34
