  FUNCTION func_inseriritempedido
  (
    p_regpedido       IN integradora_comple.t_cabped,
    p_regitem         IN integradora_comple.t_itemped,
    p_regprecos       IN integradora_comple.t_precosetributacao,
    p_regproduto      IN integradora_comple.t_produto,
    p_regorigempreco  IN integradora_comple.t_origempreco,
    p_regorigemcomiss IN integradora_comple.t_origemcomiss,
    p_regorigemdesc   IN integradora_comple.t_origemdesc,
    p_regrca          IN integradora_comple.t_rca,
    p_regcliente      IN integradora_comple.t_clientepedido,
    p_regfilial       IN integradora_comple.t_filial,
    p_Regregiao       IN integradora_comple.t_regiaocliente
  )

   RETURN BOOLEAN IS

    vbvalido BOOLEAN;

    vnvlcustofin  pcpedi.vlcustofin%TYPE;
    vnvlcustoreal pcpedi.vlcustoreal%TYPE;
    vnvlcustorep  pcpedi.vlcustorep%TYPE;
    vncustofinest pcpedi.custofinest%TYPE;
    vnvlcustocont pcpedi.vlcustocont%TYPE;
    vnpercom      pcpedi.percom%TYPE;
    vlpvendacesta pcpedi.pvenda%TYPE;
    vlpbasercacesta pcpedi.pvenda%TYPE;
    vlptabelacesta pcpedi.pvenda%TYPE;
    vlstcesta     pcpedi.st%TYPE;
    vlipicesta     pcpedi.vlipi%TYPE;
    vnPBONIFIC    NUMBER;

    /* ICMS PARTILHA */
    vnVLBASEPARTDEST    pcpedi.VLBASEPARTDEST%type;
    vnALIQFCP           pcpedi.ALIQFCP%type;
    vnALIQINTERNADEST   pcpedi.ALIQINTERNADEST%type;
    vnVLFCPPART         pcpedi.VLFCPPART%type;
    vnVLICMSPARTDEST    pcpedi.VLICMSPARTDEST%type;
    vnVLICMSPART        pcpedi.VLICMSPART%type;
    vnVLICMSDIFALIQPART pcpedi.VLICMSDIFALIQPART%type;
    vnPERCBASEREDPART   pcpedi.PERCBASEREDPART%type;
    vnPERCPROVPART      pcpedi.PERCPROVPART%type;
    vnVLICMSPARTREM     pcpedi.VLICMSPARTREM%type;
    vnALIQINTERORIGPART PCPEDI.ALIQINTERORIGPART%TYPE;
    vnNUMPEDRCAFV       PCPEDIPCPEDIFV.NUMPEDRCAFV%TYPE;
    vnSOMAVLDESCSUFRAMA      pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCICMISENCAO    pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCREDUCAOCOFINS pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCREDUCAOPIS    pcpedi.Vldescsuframa%type;
    vnVLFECP                  pcpedi.VLFECP%TYPE;
    vnALIQICMSFECP            pcpedi.ALIQICMSFECP%TYPE;
    vnVLBASEFCPST             pcpedi.VLBASEFCPST%TYPE;

  BEGIN

    CASE
      WHEN (p_regpedido.condvenda in (5,11))
        OR ((p_regpedido.condvenda = 1)
        AND (p_regitem.bonific <> 'N')) THEN

        vnPBONIFIC := p_regitem.pvenda;

      ELSE
        vnPBONIFIC := 0;
    END CASE;

    IF p_regitem.cesta = 'S'
    THEN

      vbvalido := func_inseriritemcesta(p_regrca,
                                        p_regcliente,
                                        p_regitem,
                                        p_regpedido,
                                        p_regregiao,
                                        p_regfilial,
                                        vnSOMAVLDESCSUFRAMA,
                                        vnSOMAVLDESCICMISENCAO,
                                        vnSOMAVLDESCREDUCAOCOFINS,
                                        vnSOMAVLDESCREDUCAOPIS);

      if not vbvalido then

        integradora_comple.proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         p_regproduto.codprod,
                         p_regitem.numseq,
                         p_regitem.codauxiliar,
                         p_regpedido.cgccli,
                         NULL,
                         NULL,
                         NULL,
                         p_regpedido.CODUSUR,
                         p_regpedido.dtaberturapedpalm,
                         NULL,
                         '3',
                         'Erro ao inserir itens da cesta',
                         NULL,
                         p_regitem.numseqfv);

        return false;

      end if;

    END IF;

    INSERT INTO pcpedi
      (codcli, --1
       codicmtab, --2
       codprod, --3
       codst, --4
       codusur, --5
       DATA, --6
       numped, --7
       numseq, --8
       percom, --9
       perdesc, --10
       posicao, --11
       ptabela, --12
       pvenda, --13
       qt, --14
       qtfalta, --15
       st, --16
       stclientegnre, --17
       vlcustocont, --18
       vlcustofin, --19
       vlcustoreal, --20
       vlcustorep, --21
       pbaserca, --22
       pvendabase, --23
       iva, --24
       pauta, --25
       aliqicms1, --26
       aliqicms2, --27
       percbaseredst, --28
       percbaseredstfonte, --29
       baseicst, --30
       perfretecmv, --31
       custofinest, --32
       txvenda, --33
