       vldesccustocmv, --35
       letracomiss, --36
       vlipi, --37
       percipi, --38
       vldescsuframa, --39
       vldescicmisencao, --40
       perdescisentoicms, --41
       vlverbacmv, --42
       pvenda1, --43
       percdescpis, --44
       percdesccofins, --45
       vldescreducaopis, --46
       vldescreducaocofins, --47
       codauxiliar, --48
       qtpecas, --49
       qtcx, --50
       vlrepasse, --51
       vlbonific, --52
       perbonific, --53
       vloutros, --54
       perdesccom, --55
       vldesccom, --56
       qtunitemb, --57
       vlredpvendasimplesna, --58
       vlredcmvsimplesnac, --59
       codfilialretira, --60
