       aliqfcp,           --85
       aliqinternadest,   --86
       vlfcppart,         --87
       vlicmspartdest,    --88
       vlicmspart,        --89
       VLICMSDIFALIQPART, --90
       PERCBASEREDPART,   --91
       PERCPROVPART,       --92
       VLICMSPARTREM,     --93
       ALIQINTERORIGPART, --94
       usaunidademaster,  --95
       coddescontosimulador, --96
       CODFIGVENDATRIANGULAR, --97
       PTABELAFABRICAZFM,     --98
       ORIGMERCTRIB,           --99
       codfiscal,              --100
       vlipiptabela,           --101
       stptabela,              --102
       devolucaocarcaca,       --103
       vldesccarcaca,          --104
       unidade,                --105
       tipocombo,              --106
       CODEMITENTEITEMPEDIDO,  --107
       sittribut,              --108
       vlbasefcpst,            --109
       aliqicmsfecp,           --110
       VLFECP,                 --111
       UTILIZOUMOTORCALCULO,   --112
       codprecofixo,           --113
       codprecocesta,          --114
       NUMPEDCLI,              --115
	     VLICMSPARTPTABELA,      --116
	     VLICMSPARTPBASERCA,      --117
	     vldifaliquotas,         --118
       basedifaliquotas,       --119
       numitemped,              --120
	   vlverbacmvcli,           --121
       dtentrega                --122
              )
    VALUES
      (p_regpedido.codcli, --1
       p_regitem.codicmtab, --2
       p_regitem.codprod, --3
       p_regprecos.codst, --4
       coalesce(p_regitem.codusur, p_regpedido.CODUSUR), --5
       p_regpedido.data, --6
       p_regpedido.numped, --7
       p_regitem.numseq, --8
       nvl(p_regitem.percom,0), --9
       integradora_comple.func_calcularperdescitem(round(p_regitem.ptabela, integradora_comple.gregpcconsum.numcasasdecvenda)
                                                  ,round(p_regitem.pvenda, integradora_comple.gregpcconsum.numcasasdecvenda)),--p_regitem.perdesc, --10
       'L',--p_regpedido.posicao, --11
       round(p_regitem.ptabela, integradora_comple.gregpcconsum.numcasasdecvenda), --12
       round(p_regitem.pvenda, integradora_comple.gregpcconsum.numcasasdecvenda), --13
       p_regitem.qt, --14
       p_regitem.qtfalta,--0, --15
       p_regitem.st, --16
       p_regitem.stclientegnre, --17
       nvl(p_regPRECOS.custocont,0), --18
       decode(p_regpedido.condvenda,
              4,
              0,
              decode(p_regfilial.tipobroker,
                     'MAB',DECODE(p_regpedido.ORIGEMPED,'K',
                     nvl(p_regprecos.precofab,
                         p_regitem.vlcustofin),nvl(p_regitem.vlcustofin,0)),
                     nvl(p_regitem.vlcustofin,0))), --19
       decode(p_regpedido.condvenda,
              4,
              0,
              decode(p_regfilial.tipobroker,
                     'MAB',DECODE(p_regpedido.ORIGEMPED,'K',
                     nvl(p_regprecos.precofab,
                         p_regitem.vlcustoreal),nvl(p_regitem.vlcustoreal,0)),
                     nvl(p_regitem.vlcustoreal,0))), --20
       p_regprecos.custorep, --21
       round(p_regitem.pbaserca, integradora_comple.gregpcconsum.numcasasdecvenda), --22
       p_regitem.pvendabase, --23
       decode(p_regitem.origemst, 'F', p_regprecos.ivafonte, 'N', p_regprecos.iva, 0),--24
       p_regitem.pauta,--25
       decode(p_regitem.origemst, 'F', p_regprecos.aliqicms1fonte, 'N', p_regprecos.aliqicms1, 0), --26
       decode(p_regitem.origemst, 'F', p_regprecos.aliqicms2fonte, 'N', p_regprecos.aliqicms2, 0), --27
       p_regitem.percbaseredst, --28
       p_regitem.percbaseredstfonte, --29
       p_regitem.baseicst, --30
       p_regitem.perfretecmv, --31
       p_regitem.custofinest, --32
       p_regitem.txvenda, --33
       p_regitem.perdesccusto, --34
       p_regitem.vldesccustocmv, --35
       p_regitem.letracomiss, --36
       p_regitem.vlipi, --37
       p_regitem.percipi, --38
       case when p_regitem.cesta = 'S' then vnSOMAVLDESCSUFRAMA else p_regitem.vldescsuframa end, --39
       case when p_regitem.cesta = 'S' then vnSOMAVLDESCICMISENCAO else p_regitem.vldescicmisencao end, --40
       p_regitem.perdescisentoicms, --41
       p_regitem.vlverbacmv, --42
       p_regitem.pvenda1, --43
       p_regitem.percdescpis, --44
       p_regitem.percdesccofins, --45
       case when p_regitem.cesta = 'S' then vnSOMAVLDESCREDUCAOPIS else p_regitem.vldescreducaopis end, --46
       case when p_regitem.cesta = 'S' then vnSOMAVLDESCREDUCAOCOFINS else p_regitem.vldescreducaocofins end, --47
       p_regitem.codauxiliar, --48
       p_Regitem.qtpecas, --49
       p_regitem.qtcx, --50
       p_Regitem.vlrepasse, --51
       vnPBONIFIC, --52
       p_regitem.perbonific, --53
       p_regitem.vloutros, --54
       p_regitem.perdesccom, --55
       p_regitem.vldesccom, --56
       p_regprecos.qtunit, --57
