       p_Regitem.vlredcmvsimplesnac, --59
       p_regitem.codfilialretira, --60
       p_regitem.poriginal, --61
       p_regitem.precomaxconsum, --62
       p_regitem.descprecofab, --63
       p_regitem.politicaprioritaria, --64
       p_regitem.codcombo, --65
       /*decode(p_regitem.codcombo,
              NULL,
              'S',
              'N'),*/
       p_regitem.movimentacontacorrenterca, --66 HIS.01896.2017
       p_Regitem.pvendaanterior, --67
       '2596', --68
       p_regitem.coddesconto, --69
       p_regpedido.percdescabatimento, --70
       p_regitem.geragnre_cnpjcliente, --71
       p_regitem.sugestao, --72
       p_regitem.tipoentrega, --73
       p_regitem.percom2, --74
       p_regitem.percom3, --75
       p_regitem.percom4, --76
       0, --77
       vnPBONIFIC, --78
       nvl(p_regitem.bonific,'N'), --79
       p_regitem.percredaliqipi, --80
       p_regitem.coddescontobaserca, -- 81
       p_regitem.perdescpauta, --82
       p_regitem.origemst, --83
       p_regitem.vlbasepartdest,    --84
       p_regitem.aliqfcp,           --85
       p_regitem.aliqinternadest,   --86
       p_regitem.vlfcppart,         --87
       p_regitem.vlicmspartdest,    --88
       p_regitem.vlicmspart,        --89
       p_regitem.VLICMSDIFALIQPART, --90
       p_regitem.PERCBASEREDPART,   --91
