       p_regitem.AliqFECP,               --110
       p_regitem.VLFECP,                 --111
       p_regprecos.UTILIZAMOTORCALCULO,  --112
       p_regitem.codprecofixo,           --113
       p_regitem.codprecocesta,          --114
       p_regitem.NUMPEDCLI,              --115
	     p_regitem.VLICMSPARTPTABELA,      --116
	     p_regitem.VLICMSPARTPBASERCA,     --117
	     p_regitem.vldifaliquotas,         --118
       p_regitem.basedifaliquotas,       --119
       p_regitem.numitemped,             --120
	   p_regitem.vlverbacmvcli,          --121
       p_regitem.dtentrega             --122
       );
    

    BEGIN
      SELECT NUMPEDRCAFV
        INTO vnNUMPEDRCAFV
        FROM PCPEDIPCPEDIFV
       WHERE NUMPEDRCAFV = p_regpedido.numpedrca
         AND CODUSURFV = COALESCE(p_regitem.codusur, p_regpedido.CODUSUR)
         AND DTABERTURAPEDPALMFV = p_regpedido.dtaberturapedpalm
         AND CODPRODFV = p_regitem.codprod
         AND NUMSEQFV = p_regitem.numseqfv
         AND CGCCLIFV = p_regpedido.cgccli;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        INSERT INTO pcpedipcpedifv
          (numpedrcafv,
           codusurfv,
           dtaberturapedpalmfv,
           codprodfv,
           numseqfv,
           numped,
           codprod,
           codusur,
           numseq,
           cgcclifv,
           codcli)
        VALUES
          (p_regpedido.numpedrca,
           coalesce(p_regitem.codusur, p_regpedido.CODUSUR),
           p_regpedido.dtaberturapedpalm,
           p_regitem.codprod,
           p_regitem.numseqfv,
           p_regpedido.numped,
           p_regitem.codprod,
           coalesce(p_regitem.codusur, p_regpedido.CODUSUR),
           p_regitem.numseq,
           p_regpedido.cgccli,
           p_regpedido.codcli);
    END;

    gravar_pcorigempreco(p_regorigempreco,
                         p_regitem);


    BEGIN

      INSERT INTO pcorigemcomis
        (numped, -- 1
         origemped, -- 2
         codprod, -- 3
         codauxiliar, -- 4
         numseq, -- 5
         codfilial, -- 6
         numregiao, -- 7
         percom, -- 8
         perdesc, -- 9
         codusur, -- 10
         codcli, -- 11
         codcob, -- 12
         codplpag, -- 13
         codrotinacomis, -- 14
         codcomis, -- 15
         tipocomissao, -- 16
         tipovend, -- 17
         tipovenda, -- 18
         codlinhaprod, -- 19
         tipoavaliacaocomissao, -- 20
         ordemavaliacaocomissaorca, -- 21
         usacomissaoporrca, -- 22
         usacomissaoporcliente, -- 23
         usacomissaoporlinhaprod, -- 24
         comissaorcatipovenda, -- 25
         considerarcomissaozero -- 26
         )
      VALUES
        (p_regorigemcomiss.numped, -- 1
         p_regorigemcomiss.origemped, -- 2
         p_regorigemcomiss.codprod, -- 3
         p_regorigemcomiss.codauxiliar, -- 4
         p_regorigemcomiss.numseq, -- 5
         p_regorigemcomiss.codfilial, -- 6
         p_regorigemcomiss.numregiao, -- 7
         p_regorigemcomiss.percom, -- 8
         p_regorigemcomiss.perdesc, -- 9
         coalesce(p_regitem.codusur, p_regpedido.CODUSUR), -- 10
         p_regorigemcomiss.codcli, -- 11
         p_regorigemcomiss.codcob, -- 12
         p_regorigemcomiss.codplpag, -- 13
         p_regorigemcomiss.codrotinacomis, -- 14
         p_regorigemcomiss.codcomis, -- 15
         p_regorigemcomiss.tipocomissao, -- 16
         p_regorigemcomiss.tipovend, -- 17
         p_regorigemcomiss.tipovenda, -- 18
         p_regorigemcomiss.codlinhaprod, -- 19
         p_regorigemcomiss.tipoavaliacaocomissao, -- 20
         p_regorigemcomiss.ordemavaliacaocomissaorca, -- 21
         p_regorigemcomiss.usacomissaoporrca, -- 22
         p_regorigemcomiss.usacomissaoporcliente, -- 23
         p_regorigemcomiss.usacomissaoporlinhaprod, -- 24
         p_regorigemcomiss.comissaorcatipovenda, -- 25
         p_regorigemcomiss.considerarcomissaozero -- 26
         );
    EXCEPTION
      WHEN OTHERS THEN
        integradora_comple.proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         p_regproduto.codprod,
                         p_regitem.numseq,
                         p_regitem.codauxiliar,
                         p_regpedido.cgccli,
                         NULL,
                         NULL,
                         NULL,
                         p_regpedido.CODUSUR,
                         p_regpedido.dtaberturapedpalm,
                         NULL,
                         '3',
                         'Erro ao inserir origem comissão: ' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                         NULL,
                         p_regitem.numseqfv);



    END;


    IF p_regitem.cesta = 'S'
    THEN

      SELECT SUM(p.qtmp * vlcustofin),
             SUM(p.qtmp * vlcustoreal),
             SUM(p.qtmp * vlcustorep),
             SUM(p.qtmp * custofinest),
             SUM(p.qtmp * vlcustocont),
             AVG(percom),
             sum(p.qtmp * pvenda),
             sum(p.qtmp * PTABELA),
             sum(p.qtmp * pbaserca),
             sum(p.qtmp * st),
             sum(p.qtmp * vlipi),
             sum(p.qtmp * vlicmspart),  --1
             sum(p.qtmp * VLBASEPARTDEST), --2
             AVG(ALIQFCP), --3
             AVG(ALIQINTERNADEST), --4
             sum(p.qtmp * VLFCPPART), --5
             sum(p.qtmp * VLICMSPARTDEST), --6
             sum(p.qtmp * VLICMSPART), --7
             sum(p.qtmp * VLICMSDIFALIQPART), --8
             AVG(PERCBASEREDPART), --9
             AVG(PERCPROVPART),  --10
             sum(p.qtmp * vlicmspartrem), --11
             AVG(ALIQINTERORIGPART), --12
             SUM(p.qtmp * nvl(VLFECP,0)),      --13
             AVG(nvl(ALIQICMSFECP,0)) ,        --14
             SUM(p.qtmp * nvl(VLBASEFCPST,0))  --15
        INTO vnvlcustofin,
             vnvlcustoreal,
             vnvlcustorep,
             vncustofinest,
             vnvlcustocont,
             vnpercom,
             vlpvendacesta,
             vlptabelacesta,
             vlpbasercacesta,
             vlstcesta,
             vlipicesta,
             vnvlicmspart,  --1
             vnVLBASEPARTDEST, --2
             vnALIQFCP, --3
             vnALIQINTERNADEST, --4
             vnVLFCPPART, --5
             vnVLICMSPARTDEST, --6
             vnVLICMSPART, --7
             vnVLICMSDIFALIQPART, --8
             vnPERCBASEREDPART, --9
             vnPERCPROVPART,         --10
             vnVLICMSPARTREM, --11
             vnALIQINTERORIGPART, --12
             vnVLFECP,             --13
             vnALIQICMSFECP,       --14
             vnVLBASEFCPST         --15
        FROM pcpedicesta p
       WHERE numped = p_Regpedido.numped
         AND codprod = p_regitem.codprod
         AND numseq = p_Regitem.numseq;

      UPDATE pcpedi
         SET vlcustofin        = vnvlcustofin,
             vlcustoreal       = vnvlcustoreal,
             vlcustorep        = vnvlcustorep,
             vlcustocont       = vnvlcustocont,
             custofinest       = vncustofinest,
             pvenda            = vlpvendacesta,
             ptabela           = vlptabelacesta,
             pbaserca          = vlpbasercacesta,
             st                = vlstcesta,
             vlipi               = vlipicesta,
             vlbasepartdest    = vnvlbasepartdest,
             aliqfcp           = vnaliqfcp,
             aliqinternadest   = vnaliqinternadest,
             vlfcppart         = vnvlfcppart,
             vlicmspartdest    = vnvlicmspartdest,
             vlicmspart        = vnvlicmspart,
             vlicmsdifaliqpart = vnvlicmsdifaliqpart,
             percbaseredpart   = vnpercbaseredpart,
             percprovpart      = vnpercprovpart,
             vlicmspartrem     = vnVLICMSPARTREM,
             ALIQINTERORIGPART = vnALIQINTERORIGPART,
             VLFECP            = vnVLFECP,
             ALIQICMSFECP      = vnALIQICMSFECP,
             VLBASEFCPST       = vnVLBASEFCPST

       WHERE numped = p_Regpedido.numped
         AND codprod = p_regitem.codprod
         AND numseq = p_Regitem.numseq;

     UPDATE pcorigempreco
         SET
             vlicmspartilha        = vnvlicmspart,
             vlicmsdifaliqpart = vnvlicmsdifaliqpart,
             VLFECP            = vnVLFECP

       WHERE numped = p_Regpedido.numped
         AND codprod = p_regitem.codprod
         AND numseq = p_Regitem.numseq;

    ELSE

      vbvalido := TRUE;
    END IF;

    if p_regitem.devolucaocarcaca = 'S' then
      integradora_comple.proc_movimenta_inservivel(p_regpedido, p_regcliente, p_regitem);
    end if;

    RETURN vbvalido;

  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'I';
      integradora_comple.vLog.MSG                := 'Erro no insert da PCPEDI do produto ' || p_regitem.codprod || chr(13) ||
                                 'Msg Original: ' || SQLCODE || ' - ' || SQLERRM;
      /** PRECOS **/
      integradora_comple.vLog.ptabela            := p_regitem.ptabela;
      integradora_comple.vLog.PVENDA             := p_regitem.pvenda;
      integradora_comple.vLog.PBASE              := p_regitem.pbaserca;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regproduto.codprod,
                       p_regitem.numseq,
                       p_regitem.codauxiliar,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_regpedido.dtaberturapedpalm,
                       NULL,
                       '3',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       p_regitem.numseqfv);
      RETURN FALSE;
  END func_inseriritempedido;


  FUNCTION func_inseriritemorcamento
  (
    p_regpedido       IN integradora_comple.t_cabped,
    p_regitem         IN integradora_comple.t_itemped,
    p_regprecos       IN integradora_comple.t_precosetributacao,
    p_regproduto      IN integradora_comple.t_produto,
    p_regrca          IN integradora_comple.t_rca,
    p_regcliente      IN integradora_comple.t_clientepedido,
    p_regfilial       IN integradora_comple.t_filial,
    p_Regregiao       IN integradora_comple.t_regiaocliente,
    p_regorigempreco  IN integradora_comple.t_origempreco
  )

   RETURN BOOLEAN IS

    vbvalido BOOLEAN;

    vnvlcustofin        pcpedi.vlcustofin%TYPE;
    vnvlcustoreal       pcpedi.vlcustoreal%TYPE;
    vnvlcustorep        pcpedi.vlcustorep%TYPE;
    vncustofinest       pcpedi.custofinest%TYPE;
    vnvlcustocont       pcpedi.vlcustocont%TYPE;

    /* ICMS PARTILHA */
    vnVLBASEPARTDEST    pcpedi.VLBASEPARTDEST%type;
    vnALIQFCP           pcpedi.ALIQFCP%type;
    vnALIQINTERNADEST   pcpedi.ALIQINTERNADEST%type;
    vnVLFCPPART         pcpedi.VLFCPPART%type;
    vnVLICMSPARTDEST    pcpedi.VLICMSPARTDEST%type;
    vnVLICMSPART        pcpedi.VLICMSPART%type;
    vnVLICMSDIFALIQPART pcpedi.VLICMSDIFALIQPART%type;
    vnPERCBASEREDPART   pcpedi.PERCBASEREDPART%type;
    vnPERCPROVPART      pcpedi.PERCPROVPART%type;
    vnVLICMSPARTREM     pcpedi.VLICMSPARTREM%type;
    vnSOMAVLDESCSUFRAMA      pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCICMISENCAO    pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCREDUCAOCOFINS pcpedi.Vldescsuframa%type;
    vnSOMAVLDESCREDUCAOPIS    pcpedi.Vldescsuframa%type;

  BEGIN

    INSERT INTO PCORCAVENDAI
      (numorca, --1
       data, --2
       codcli, --3
       codprod, --4
       codusur, --5
       qt, --6
       pvenda, --7
       ptabela, --8
       numcar, --9
       posicao, --10
       st, --11
       vlcustofin, --12
       vlcustoreal, --13
       percom, --14
       perdesc, --15
       qtfalta, --16
       numseq, --17
       pvendabase, --18
       codst, --19
       iva, --20
       aliqicms1, --21
       aliqicms2, --22
       pauta, --23
       percbasered, --24
       vldescfin, --25
       custofinest, --26
       perfretecmv, --27
       percbaseredst, --28
       percbaseredstfonte, --29
       perciss, --30
       vliss, --31
       percipi, --32
       vlipi, --33
       codauxiliar, --34
       vldescicmisencao, --35
       vlrepasse, --36
       codfilialretira, --37
       percvenda, --38
       vldescpissuframa, --39
       poriginal, --40
       vlcustocont, --41
       vlcustorep, --42
       pbaserca, --43
       pesobruto, --44
       vlverbacmv, --45
       numverbarebcmv, --46
       qtcx, --47
       qtpecas, --48
       perdesccusto, --49
       txvenda, --50
       codicmtab, --51
       perdescisentoicms, --52
       pvenda1, --53
       geragnre_cnpjcliente, --54
       vldifaliquotas, --55
       basedifaliquotas, --56
       percdifaliquotas, --57
       tipoentrega, --58
       pvendaanterior, --59
       vldesccustocmv, --60
       vldescsuframa, --61
       stclientegnre, --62
       baseicst, --63
       letracomiss, --64
       qtunitemb, --65
       codcombo, --66
       vlredpvendasimplesna, --67
       vlredcmvsimplesnac, --68
       perdescpauta, --69
       vlbasepartdest,    --70
       aliqfcp,           --71
       aliqinternadest,   --72
       vlfcppart,         --73
       vlicmspartdest,    --74
       vlicmspart,        --75
       VLICMSDIFALIQPART, --76
       PERCBASEREDPART,   --77
       PERCPROVPART,      --78
       VLICMSPARTREM,     --79
       ALIQINTERORIGPART, --80
       PTABELAFABRICAZFM, --81
       ORIGMERCTRIB,      --82
       vlbasefcpst,       --83
       aliqicmsfecp,      --84
       VLFECP,            --85
       numpedcli,         --86
       numitemped         --87
       )
    VALUES
      (p_regpedido.numped, --1
       p_regpedido.data, --2
       p_regpedido.codcli, --3
       p_regitem.codprod, --4
       coalesce(p_regitem.codusur, p_regpedido.CODUSUR), --5
       p_regitem.qt, --6
       p_regitem.pvenda, --7
       p_regitem.ptabela, --8
       0, --9
       p_regpedido.posicao, --10
       p_regitem.st, --11
       p_regitem.vlcustofin, --12
       p_regitem.vlcustoreal, --13
       p_regitem.percom, --14
       p_regitem.perdesc, --15
       0, --16
       p_regitem.numseq, --17
       p_regitem.pvendabase, --18
       p_regprecos.codst, --19
       decode(p_regitem.origemst, 'F', p_regprecos.ivafonte, 'N', p_regprecos.iva, 0),--20
       decode(p_regitem.origemst, 'F', p_regprecos.aliqicms1fonte, 'N', p_regprecos.aliqicms1, 0), --21
       decode(p_regitem.origemst, 'F', p_regprecos.aliqicms2fonte, 'N', p_regprecos.aliqicms2, 0), --22
       p_regitem.pauta, --23
       NULL, --24
       NULL, --25
       p_regitem.custofinest, --26
       p_regitem.perfretecmv, --27
       p_regitem.percbaseredst, --28
       p_regitem.percbaseredstfonte, --29
       NULL, --30
       NULL, --31
       p_regitem.percipi, --32
       p_regitem.vlipi, --33
       p_regitem.codauxiliar, --34
       p_regitem.vldescicmisencao, --35
       p_regitem.vlrepasse, --36
       p_regitem.codfilialretira, --37
       NULL, --38
       NULL, --39
       p_regitem.poriginal, --40
       p_regitem.vlcustocont, --41
       p_regitem.vlcustorep, --42
       p_regitem.pbaserca, --43
       NULL, --44
       NULL, --45
       NULL, --46
       p_regitem.qtcx, --47
       p_regitem.qtpecas, --48
       p_regitem.perdesccusto, --49
       p_regitem.txvenda, --50
       p_regitem.codicmtab, --51
       p_regitem.perdescisentoicms, --52
       p_regitem.pvenda1, --53
       p_regitem.geragnre_cnpjcliente, --54
       NULL, --55
       NULL, --56
       p_regprecos.percdifaliquotas, --57
       p_regitem.tipoentrega, --58
       p_regitem.pvendaanterior, --59
       p_regitem.vldesccustocmv, --60
       p_regitem.vldescsuframa, --61
       p_regitem.stclientegnre, --62
       p_regitem.baseicst, --63
       p_regitem.letracomiss, --64
       p_regprecos.qtunit, --65
       p_regitem.codcombo, --66
       p_regitem.vlredpvendasimplesna, --67
       p_regitem.vlredcmvsimplesnac, --68
       p_regitem.perdescpauta,--69
       p_regitem.vlbasepartdest,    --70
       p_regitem.aliqfcp,           --71
       p_regitem.aliqinternadest,   --72
       p_regitem.vlfcppart,         --73
       p_regitem.vlicmspartdest,    --74
       p_regitem.vlicmspart,        --75
       p_regitem.VLICMSDIFALIQPART, --76
       p_regitem.PERCBASEREDPART,   --77
       p_regitem.PERCPROVPART,      --78
       p_regitem.VLICMSPARTREM,     --79
       p_regitem.ALIQINTERORIGPART, --80
       p_regitem.PTABELAFABRICAZFM, --81
       P_REGITEM.ORIGMERCTRIB,      --82
       p_regitem.BaseFECP,          --83
       p_regitem.AliqFECP,          --84
       p_regitem.VLFECP,            --85
       p_regitem.numpedcli,         --86
       p_regitem.numitemped         --87
       );

    gravar_pcorigempreco(p_regorigempreco,
                         p_regitem);


    IF p_regitem.cesta = 'S'
    THEN

      vbvalido := func_inseriritemcesta(p_regrca,
                                        p_regcliente,
                                        p_regitem,
                                        p_regpedido,
                                        p_regregiao,
                                        p_regfilial,
                                        vnSOMAVLDESCSUFRAMA,
                                        vnSOMAVLDESCICMISENCAO,
                                        vnSOMAVLDESCREDUCAOCOFINS,
                                        vnSOMAVLDESCREDUCAOPIS);
      SELECT SUM(p.qtmp * vlcustofin),
             SUM(p.qtmp * vlcustoreal),
             SUM(p.qtmp * vlcustorep),
             SUM(p.qtmp * custofinest),
             SUM(p.qtmp * vlcustocont),
             sum(p.qtmp * vlicmspart),  --1
             sum(p.qtmp * VLBASEPARTDEST), --2
             sum(ALIQFCP), --3
             sum(ALIQINTERNADEST), --4
             sum(p.qtmp * VLFCPPART), --5
             sum(p.qtmp * VLICMSPARTDEST), --6
             sum(p.qtmp * VLICMSPART), --7
             sum(p.qtmp * VLICMSDIFALIQPART), --8
             sum(PERCBASEREDPART), --9
             sum(PERCPROVPART),  --10
             sum(p.qtmp * vlicmspartrem) --11
        INTO vnvlcustofin,
             vnvlcustoreal,
             vnvlcustorep,
             vncustofinest,
             vnvlcustocont,
             vnvlicmspart,  --1
             vnVLBASEPARTDEST, --2
             vnALIQFCP, --3
             vnALIQINTERNADEST, --4
             vnVLFCPPART, --5
             vnVLICMSPARTDEST, --6
             vnVLICMSPART, --7
             vnVLICMSDIFALIQPART, --8
             vnPERCBASEREDPART, --9
             vnPERCPROVPART,         --10
             vnVLICMSPARTREM --11
        FROM pcorcavendaicesta p
       WHERE numorca = p_Regpedido.numped
         AND codprod = p_regitem.codprod
         AND numseq = p_Regitem.numseq;

      UPDATE pcorcavendai
         SET vlcustofin        = vnvlcustofin,
             vlcustoreal       = vnvlcustoreal,
             vlcustorep        = vnvlcustorep,
             vlcustocont       = vnvlcustocont,
             custofinest       = vncustofinest,
             vlbasepartdest    = vnvlbasepartdest,
             aliqfcp           = vnaliqfcp,
             aliqinternadest   = vnaliqinternadest,
             vlfcppart         = vnvlfcppart,
             vlicmspartdest    = vnvlicmspartdest,
             vlicmspart        = vnvlicmspart,
             vlicmsdifaliqpart = vnvlicmsdifaliqpart,
             percbaseredpart   = vnpercbaseredpart,
             percprovpart      = vnpercprovpart,
             vlicmspartrem     = vnVLICMSPARTREM,
             VLDESCSUFRAMA     =  case when p_regitem.cesta = 'S' then vnSOMAVLDESCSUFRAMA else p_regitem.vldescsuframa end,
             VLDESCICMISENCAO  = case when p_regitem.cesta = 'S' then vnSOMAVLDESCICMISENCAO else p_regitem.vldescicmisencao end,
             VLDESCREDUCAOCOFINS = case when p_regitem.cesta = 'S' then vnSOMAVLDESCREDUCAOPIS else p_regitem.vldescreducaocofins  end,
             VLDESCREDUCAOPIS = case when p_regitem.cesta = 'S' then vnSOMAVLDESCREDUCAOCOFINS else p_regitem.vldescreducaopis end
       WHERE numorca = p_Regpedido.numped
         AND codprod = p_regitem.codprod
         AND numseq = p_Regitem.numseq;



    ELSE

      vbvalido := TRUE;


    END IF;


    IF vbvalido = TRUE
    THEN

      RETURN TRUE;
    ELSE
      RETURN FALSE;
    END IF;




  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'I';
      integradora_comple.vLog.MSG                := 'Erro insert PCORCAVENDAI. Produto ' || p_regitem.codprod || chr(13) ||
                                 'Msg Original: ' || SQLCODE || ' - ' || SQLERRM;
      /** PRECOS **/
      integradora_comple.vLog.ptabela            := p_regitem.ptabela;
      integradora_comple.vLog.PVENDA             := p_regitem.pvenda;
      integradora_comple.vLog.PBASE              := p_regitem.pbaserca;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regproduto.codprod,
                       p_regitem.numseq,
                       p_regitem.codauxiliar,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_regpedido.dtaberturapedpalm,
                       NULL,
                       '3',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       p_regitem.numseqfv);
      RETURN FALSE;
  END func_inseriritemorcamento;


  FUNCTION func_inserircabpedido
  (
    p_regpedido        IN integradora_comple.t_cabped,
    p_regplpag         IN integradora_comple.t_planodepagamento,
    p_regrca           IN integradora_comple.t_rca,
    p_regcliente       IN integradora_comple.t_clientepedido,
    p_regregiao        IN integradora_comple.t_regiaocliente,
    P_REGFILIAL        IN integradora_comple.T_FILIAL,
    p_contitensvalidos IN NUMBER,
    p_vltotped         IN NUMBER,
    p_vlatend          IN NUMBER,
    p_vltottab         IN NUMBER,
    p_totpesoped       IN NUMBER,
    p_totvolumeped     IN NUMBER,
    p_vlcustocontped   IN NUMBER,
    p_vlcustofinped    IN NUMBER,
    p_vlcustorealped   IN NUMBER,
    p_vlcustorepped    IN NUMBER,
    p_vlverbacmv       IN NUMBER,
    p_vlverbacmvcli    IN NUMBER

  ) RETURN BOOLEAN IS

    vnperdescped NUMBER;

    at_vlatend     pcpedc.vlatend%TYPE;
    at_vltabela    pcpedc.vltabela%TYPE;
    at_numitens    pcpedc.numitens%TYPE;
    at_vltotal     pcpedc.vltotal%TYPE;
    at_vlcustofin  pcpedc.vlcustofin%TYPE;
    at_vlcustorep  pcpedc.vlcustorep%TYPE;
    at_vlverbacmv  pcpedc.vlverbacmv%TYPE;
    at_vlverbacmvcli  pcpedc.vlverbacmv%TYPE;
    at_vlcustoreal pcpedc.vlcustoreal%TYPE;
    at_vlcustocont pcpedc.vlcustocont%TYPE;
    at_totpeso     pcpedc.totpeso%TYPE;
    at_totvolume   pcpedc.totvolume%TYPE;

    vsmensagematurota VARCHAR2(1000);
    vbjustvalida      BOOLEAN;

    --HIS.05072.2014
    vnTOTAL_BNF       NUMBER := 0;

  BEGIN

    IF p_vltottab <> 0
    THEN
      vnperdescped := ROUND((((p_vltottab - p_vlatend/*p_vltotped*/) / p_vltottab) * 100),
                            integradora_comple.gregpcconsum.numcasasdecvenda);
    ELSE
      vnperdescped := 0;
    END IF;

    BEGIN
      SELECT NVL(SUM(NVL(pcpedi.qt, 0) * NVL(pcpedi.pbonific, 0)),0)
        INTO vnTOTAL_BNF
        FROM pcpedi
       WHERE numped = p_regpedido.numped
         AND nvl(bonific,'N') <> 'N';
    EXCEPTION
      WHEN OTHERS THEN
        vnTOTAL_BNF := 0;
    END;

    IF nvl(p_regpedido.numpedorig,0) = 0
    THEN
      INSERT INTO pcpedc
        (codcli, --1
         codcob, --2
         coddistrib, --3
         codemitente, --4
         codfilial, --5
         codfilialnf, --6
         codplpag, --7
         codpraca, --8
         codsupervisor, --9
         codusur, --10
         condvenda, --11
         DATA, --12
         dtentrega, --13
         hora, --14
         minuto, --15
         numcar, --16
         numitens, --17
         numped, --18
         numpedcli, --19
         numpedrca, --20
         obs1, --21
         obs2, --22
         obsentrega1, --23
         obsentrega2, --24
         operacao, --25
         origemped, --26
         percvenda, --27
         perdesc, --28
         posicao, --29
         prazo1, --30
         prazo2, --31
         prazo3, --32
         prazo4, --33
         prazo5, --34
         prazo6, --35
         prazo7, --36
         prazo8, --37
         prazo9, --38
         prazo10, --39
         prazo11, --40
         prazo12, --41
         prazomedio, --42
         tipovenda, --43
         totpeso, --44
         totvolume, --45
         vlatend, --46
         vlcustocont, --47
         vlcustofin, --48
         vlcustoreal, --49
         vlcustorep, --50
         vltabela, --51
         vltotal, --52
         dtaberturapedpalm, --53
         dtfechamentopedpalm, --54
         numregiao, --55
         usaintegracaowms, --56
         usacredrca, --57
         usadebcredrca, --58
         bonificaltdebcredrca, --59
         trocaaltdebcredrca, --60
         crmaltdebcredrca, --61
         brokeraltdebcredrca, --62
         tipomovccrca, --63
         vlfrete, --64
         codfornecfrete, --65
         fretedespacho, --66
         freteredespacho, --67
         broker, --68
         tipodocumento, --69
         codclinf, --70
         contaordem, --71
         codmotivo, --72
         motivoposicao, --73
         log, --74
         codclitv8, --75
         codplpagetico, --76
         codplpaggenerico, --77
         tipoprioridadeentrega, --78
         localdesembaraco, --79
         ufdesembaraco, --80
         numpedtv1, --81
         agrupamento, --82
         codbnf, --83
         custobonificacao, --84
         codfornecbonific, --85
         turnoentrega, --86
         codendent, --87
         vlentrada, --88
         codendentcli, --89
