         codestabelecimento, --91
         numtabela, --92
         obsentrega3, --93
         obsentrega4, --94
         codmotbloqueio, --95
         utilizavendaporembalagem, --96
         codusur2, --97
         codusur3, --98
         codusur4, --99
         vlbonific, --100 tarefa: 663.123945.2014
         rotinalanc, --101
         vendaassistida, --102
         gerardadosnfpaulista, --103
         assinatura,--104
         idparceiro,--105
         uidregistro, --106
         vendatriangular,--107
         condfinanc, -- 108
         PAGCHEQUEMORADIA, --109
         USACFOPVENDANATV10, --110
         CODBREX, --111
         codclirecebedor, --112
         codgerente, --113
         tipocontacorrente, --114
         vlverbacmv, --115
         vlverbacmvcli, --116
         descintermediador, --117
         cnpjintermediador, -- 118,
		 opervendaexpindireta, --119
		 BLOQUEIOSUPPLIER
         )
      VALUES
        (p_regpedido.codcli, --1
         p_regpedido.codcob, --2
         NVL(p_regpedido.CODDISTRIB, p_regrca.coddistrib), --3
         p_regpedido.codemitente, --4
         p_regpedido.codfilial, --5
         p_regpedido.codfilialnf, --6
         p_regpedido.codplpag, --7
         p_regcliente.codpraca, --8
         p_regrca.codsupervisor, --9
         p_regrca.codusur, --10
         p_regpedido.condvenda, --11
         p_regpedido.data, --12
         NVL(p_regpedido.dtentrega,
             p_regpedido.data), -- 13
         TO_NUMBER(TO_CHAR(SYSDATE,
                           'HH24')), --14
         TO_NUMBER(TO_CHAR(SYSDATE,
                           'MI')), --15
         0, --16
         p_contitensvalidos, --17
         p_regpedido.numped, --18
         p_regpedido.numpedcli, --19
         p_regpedido.numpedrca, --20
         p_regpedido.obs1, --21
         p_regpedido.obs2, --22
         nvl(p_regpedido.obsentrega1,
             p_regcliente.obsentrega1), --23
         nvl(p_regpedido.obsentrega2,
             p_regcliente.obsentrega2), --24
         'N', --25
         p_regpedido.origemped, --26
         p_regpedido.percvenda, --27
         vnperdescped, --28
         p_regpedido.posicao, --29
         p_regplpag.prazo1, --30
         p_regplpag.prazo2, --31
         p_regplpag.prazo3, --32
         p_regplpag.prazo4, --33
         p_regplpag.prazo5, --34
         p_regplpag.prazo6, --35
         p_regplpag.prazo7, --36
         p_regplpag.prazo8, --37
         p_regplpag.prazo9, --38
         p_regplpag.prazo10, --39
         p_regplpag.prazo11, --40
         p_regplpag.prazo12, --41
         p_regpedido.prazomedio, --42
         p_regplpag.tipovenda, --43
         p_totpesoped, --44
         p_totvolumeped, --45
         -------------------------------------
         p_vlatend, --46
         -------------------------------------
         p_vlcustocontped, --47
         decode(p_regpedido.condvenda,
                20,
                0,
                p_vlcustofinped), --48
         decode(p_regpedido.condvenda,
                20,
                0,
                p_vlcustorealped), --49
         decode(p_regpedido.condvenda,
                20,
                0,
                p_vlcustorepped), --50
         decode(p_regpedido.condvenda,
