         p_regpedido.trocaaltdebcredrca, --60
         p_Regpedido.crmaltdebcredrca, --61
         p_Regpedido.brokeraltdebcredrca, --62
         p_Regpedido.tipomovccrca, --63
         p_regpedido.vlfrete, --64
         p_regpedido.codfornecfrete, --65
         nvl(p_regpedido.fretedespacho,
             p_regcliente.fretedespacho), --66
         p_regpedido.freteredespacho, --67
         P_REGFILIAL.broker, --68
         p_regpedido.tipodocumento, --69
         p_regpedido.codclinf, --70
         p_regpedido.contaordem, --71
         p_regpedido.codmotivo, --72
         p_Regpedido.motivoposicao, --73
         p_regpedido.log, --74
         p_regpedido.codclitv8, --75
         p_regpedido.codplpagetico, --76
         p_regpedido.codplpaggenerico, --77
         p_regpedido.tipoprioridadeentrega, --78
         p_Regpedido.localdesembaraco, --79
         p_regpedido.ufdesembaraco, --80
         p_regpedido.numpedtv1, --81
         p_regpedido.agrupamento, --82
         p_regpedido.codbnf, --83
         p_regpedido.custobonificacao, --84
         p_regpedido.codfornecbonific, --85
         p_regpedido.turnoentrega, --86
         p_regpedido.codendent, --87
         p_regpedido.vlentrada, --88
         p_regpedido.codendentcli, --89
         p_regpedido.vldescabatimento, --90
         p_regregiao.codestabelecimento, --91
         p_regpedido.numtabela, --92
         nvl(p_regpedido.obsentrega3,
             p_regcliente.obsentrega3), --93
         nvl(p_regpedido.obsentrega4,
             p_regcliente.obsentrega4), --94
         p_regpedido.codmotbloqueio, --95
         p_regfilial.utilizavendaporembalagem, --96
         p_regpedido.codusur2, --97
         p_regpedido.codusur3, --98
         p_regpedido.codusur4, --99
         -------------------------------------
         vnTOTAL_BNF, --100
         -------------------------------------
         p_regpedido.rotinalanc, --101
         p_regpedido.vendaassistida, --102
         p_regpedido.gerardadosnfpaulista, --103
         p_regpedido.assinatura,--104
         p_regpedido.idparceiro,--105
         p_regpedido.uidregistro, --106
         P_REGPEDIDO.VENDATRIANGULAR,--107
         p_regpedido.condfinanc, --108
         p_regpedido.PAGCHEQUEMORADIA, --109
         P_REGPEDIDO.USACFOPVENDANATV10, --110
         p_regpedido.codbrex, --111
         p_regpedido.codclirecebedor, --112
         p_regrca.codgerente, --113
         decode(NVL(p_regpedido.tipocontacorrente,'X'), 'X', paramfilial.obtercomovarchar2('TIPOCONTACORRENTEFV'), NVL(p_regpedido.tipocontacorrente, 'R')), --114
         p_vlverbacmv, --115
         p_vlverbacmvcli, --116
         p_regpedido.descintermediador, --117
         p_regpedido.cnpjintermediador, --118
		 p_regpedido.opervendaexpindireta, --119
		 DECODE(p_regpedido.CODCOB, 'SUPP', 'S', 'N')
         );

       IF p_regpedido.CODCOB = 'SUPP' THEN
         VENDAS.INSERIR_PCFILAMAISNEGLOG(p_regpedido.numped,p_regpedido.codfilial);
         VENDAS.INSERIR_PCFILAMAISNEGENVIO(p_regpedido.numped,p_regpedido.codfilial,'1');
       END IF;

      IF p_regpedido.condvenda = 13
         AND p_Regpedido.codcli IN (1, 2, 3) --clientes consumidor final
      THEN

        INSERT INTO pcvendaconsum
          (numped,
           cliente,
           cgcent,
           enderent,
           municent,
           estent,
           cepent,
           ieent)
        VALUES
          (p_regpedido.numped,
           p_regcliente.cliente,
           p_regcliente.cgcent,
           p_regcliente.enderent,
           p_regcliente.municent,
           p_regcliente.estent,
           p_regcliente.cepent,
           p_regcliente.ieent);

      END IF;

      -- Gravando a mesma posição do cabeçalho
      UPDATE PCPEDI
         SET POSICAO = p_regpedido.posicao
       WHERE NUMPED  = p_regpedido.numped;

    ELSE

      SELECT SUM(ROUND(NVL(pcpedi.pvenda,
                     0) * NVL(pcpedi.qt,
                              0), 2)), --1
             SUM(ROUND(NVL(pcpedi.ptabela,
                     0) * NVL(pcpedi.qt,
                              0), 2)), --2
             COUNT(*), --3
             SUM(Round((NVL(pcpedi.qt,
                      0) + NVL(pcpedi.qtfalta,
                                0)) * NVL(pcpedi.pvenda,
                                          0), 2)), --4
             SUM(NVL(pcpedi.vlcustofin,
                     0) * NVL(pcpedi.qt,
                              0)), --5
             SUM(NVL(pcpedi.vlcustorep,
                     0) * NVL(pcpedi.qt,
                              0)), --6
             SUM(NVL(pcpedi.vlcustoreal,
                     0) * NVL(pcpedi.qt,
                              0)), --7
             SUM(NVL(pcpedi.vlcustocont,
                     0) * NVL(pcpedi.qt,
                              0)), --8
             SUM(NVL(pcprodut.pesobruto,
                     0) * NVL(pcpedi.qt,
                              0)), --9
             SUM(NVL(pcprodut.volume,
                     0) * NVL(pcpedi.qt,
                              0)), --10
             SUM(NVL(pcpedi.vlverbacmv,
                     0) * NVL(pcpedi.qt,
                              0)),  --11
             SUM(NVL(pcpedi.vlverbacmvcli,
                     0) * NVL(pcpedi.qt,
                              0))  --12
        INTO at_vlatend, --1
             at_vltabela, --2
             at_numitens, --3
             at_vltotal, --4
             at_vlcustofin, --5
             at_vlcustorep, --6
             at_vlcustoreal, --7
             at_vlcustocont, --8
             at_totpeso, --9
             at_totvolume, --10
             at_vlverbacmv, --11
             at_vlverbacmvcli --12
        FROM pcpedi,
             pcprodut
       WHERE pcpedi.numped = p_regpedido.numped
         AND pcpedi.codprod = pcprodut.codprod
		 AND PCPEDI.QT > 0;
      UPDATE pcpedc
         SET vlatend     = decode(p_Regpedido.condvenda,
                                  5,
                                  0,
                                  decode(p_Regpedido.condvenda,
                                         20,
                                         0,
                                         at_vlatend)),
             vltabela    = decode(p_Regpedido.condvenda,
                                  20,
                                  0,
                                  at_vltabela),
             numitens    = at_numitens,
             vltotal     = at_vltotal, -- foi descomentado pois não totalizava o pedido quando tinha complemento.
             vlcustofin  = decode(p_Regpedido.condvenda,
                                  20,
                                  0,
                                  at_vlcustofin),
             vlcustorep  = decode(p_Regpedido.condvenda,
                                  20,
                                  0,
                                  at_vlcustorep),
             vlcustoreal = decode(p_Regpedido.condvenda,
                                  20,
                                  0,
                                  at_vlcustoreal),
             vlcustocont = at_vlcustocont,
             totpeso     = at_totpeso,
             totvolume   = at_totvolume,
             vlverbacmvcli =at_vlverbacmvcli,
             vlverbacmv  = at_vlverbacmv
       WHERE numped = p_regpedido.numped;

    END IF;



    RETURN TRUE;

  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'C';
      integradora_comple.vLog.MSG                := 'Erro ao inserir cabeçalho do pedido ' || p_regpedido.numped || chr(13) ||
                                 'Msg BD: ' || SQLCODE || ' - '|| SQLERRM;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_Regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       null);
      RETURN FALSE;

  END func_inserircabpedido;


  FUNCTION func_inserirorcamento
