       substr(p_regcliente.cliente,1,60), --56
       p_regcliente.cgcent, --57
       p_regcliente.enderent, --58
       p_regcliente.bairroent, --59
       p_regcliente.estent, --60
       p_regcliente.telent, --61
       p_regcliente.ieent, --62
       p_regcliente.codatv1, --63
       p_regcliente.municent, --64
       p_regpedido.codfilialnf, --65
       (trunc(SYSDATE) + nvl(integradora_comple.gregpcconsum.prazovalidadeorcamento,
                             0)), --66
       p_vlcustocontped, --67
       p_vlcustorepped, --68
       p_regpedido.origemped, --69
       p_regregiao.numregiao, --70
       p_regpedido.log, --71
       p_regfilial.usaintegracaowms, --72
       NULL, --73
       p_regpedido.codmotivo, --74
       p_regfilial.broker, --75
       substr(p_regpedido.motivoposicao,
              1,
              50), --76
       NULL, --77
       p_regpedido.tipoprioridadeentrega, --78
       p_regpedido.codplpagetico, --79
       p_regpedido.codplpaggenerico, --80
       p_regpedido.codendentcli --81
       );




    RETURN TRUE;

  EXCEPTION
    WHEN OTHERS THEN
      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'C';
      integradora_comple.vLog.MSG                := 'Erro ao inserir orçamento de venda. ' || p_regpedido.numped || chr(13) ||
                                 'Msg.: ' || SQLCODE || ' - ' || SQLERRM;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_Regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       null);
      RETURN FALSE;

  END func_inserirorcamento;


  PROCEDURE proc_validacaofinalcabposcorte
  (
    p_regpedido        IN OUT integradora_comple.t_cabped,
    p_regplpag         IN integradora_comple.t_planodepagamento,
    p_Regrca           IN integradora_comple.t_rca,
    p_vltotped         IN NUMBER,
    p_vlatendped       IN NUMBER,
    p_contitensvalidos IN NUMBER
  ) IS

    vsmensagem      VARCHAR2(32767);
    vsmensagem_rest varchar2(1000);
    vschar          VARCHAR2(1) DEFAULT '#';
    vs_movest       varchar2(10);
    msgest          varchar2(1000);

    vbvalido        BOOLEAN;
    vnvlfalta       NUMBER;
    vsmotivoposicao pcpedc.motivoposicao%TYPE;

    VNCODMOTIVO                PCBLOQUEIOSPEDIDO.CODMOTIVO%TYPE;
    VSMOTIVO                   PCBLOQUEIOSPEDIDO.MOTIVO%TYPE;

    vsMsgTemp                  VARCHAR2(1000);
    vsTipoImportacao           varchar2(2);
    vsRetornoRest              BOOLEAN;
    vncontitensvalidos         NUMBER;

  BEGIN

    vsmensagem      := NULL;
    vbvalido        := TRUE;
    vsmotivoposicao := NULL;
    vncodmotivo     := NULL;
    vncontitensvalidos := p_contitensvalidos;


    SELECT nvl(p_vltotped,
               0) - nvl(p_vlatendped,
                        0)
      INTO vnvlfalta
      FROM dual;

    --tarefa 211580
    IF p_vltotped > integradora_comple.gregpcconsum.vlmaxvenda
       AND nvl(integradora_comple.gregpcconsum.vlmaxvenda,
               0) > 0
    THEN

      IF integradora_comple.gregpcconsum.aceitavendabloq = 'S'
      THEN
        p_regpedido.posicao       := 'B';
        p_regpedido.codmotivo     := 4;
        p_regpedido.motivoposicao := substr('Pedido excede valor maximo por pedido.',1,60);
        PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped, 22,p_regpedido.motivoposicao, 'C');
      ELSE
        p_regpedido.valido := FALSE;
      END IF;

      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;

      vsmensagem := vsmensagem || vschar || 'Valor do pedido de(' || p_vltotped || ') execede o valor maximo estipulado por pedido (' || integradora_comple.gregpcconsum.vlmaxvenda || ' ).';


    END IF;

    --Por rca
    IF nvl(p_Regrca.vlvendaminped,
           0) > 0
    THEN

      IF p_vlatendped < nvl(p_Regrca.vlvendaminped,
                            0)
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Valor do pedido (' || p_vlatendped || ') Valor da falta (' || vnvlfalta;
        vsmensagem := vsmensagem || ') menor que o#' || ';';
        vsmensagem := vsmensagem || 'mínimo permitido para o RCA: ' || p_regrca.vlvendaminped || ';';

        p_regpedido.valido        := FALSE;
        vsmotivoposicao := 'Valor do pedido menor que minimo para o RCA';
        vncodmotivo     := 8;

      END IF;

    END IF;

    --Por Plano de Pagamento
    IF p_regplpag.vlminpedido > 0
    THEN
      IF p_vlatendped < p_regplpag.vlminpedido
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Valor do pedido (' || p_vlatendped || ') Valor da falta (' || vnvlfalta;
        vsmensagem := vsmensagem || ') menor que o#' || ';';
        vsmensagem := vsmensagem || 'mínimo permitido para o Plano de Pagamento: ' || p_regplpag.vlminpedido || ';';

        IF (ferramentas.F_BUSCARPARAMETRO_ALFA('TIPOIMPORTACAOVENDA', p_regpedido.codfilial, 'N') <> 'BP')
        THEN
           p_regpedido.valido        := FALSE;
        END IF;

        vsmotivoposicao := 'Valor do pedido menor que o minimo para Plano de Pagamento';
        vncodmotivo     := 10;

      END IF;

    END IF;


    IF p_contitensvalidos < p_regplpag.numitensminimo
    THEN

      IF vsmensagem IS NOT NULL
      THEN
        vschar := '#';
      ELSE
        vschar := NULL;
      END IF;

      vsmensagem := vsmensagem || vschar || 'Numero de itens (' || p_contitensvalidos || ') menor que o#';
      vsmensagem := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpag.codplpag || ';';
      p_regpedido.valido   := FALSE;



    END IF;

    IF p_regpedido.origemped <> 'R'
       OR (p_regpedido.origemped = 'R' AND ferramentas.F_BUSCARPARAMETRO_ALFA('CON_VALIDAVLMINVENDABALCAO', p_regpedido.codfilial, 'N') = 'S')
    THEN

      IF p_regpedido.condvenda IN (1, 7, 13)
         AND ferramentas.F_BUSCARPARAMETRO_NUM('VLMINVENDAFV', p_regpedido.codfilial, 0) > 0
      THEN

        IF p_vlatendped < ferramentas.F_BUSCARPARAMETRO_NUM('VLMINVENDAFV', p_regpedido.codfilial, 0)
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;
          vsmensagem := vsmensagem || vschar || 'Valor do pedido (' || p_vlatendped || ') Valor da falta (' || vnvlfalta;
          vsmensagem := vsmensagem || ') menor que o#' || ';';
          vsmensagem := vsmensagem || 'mínimo permitido para a Filial: ' || ferramentas.F_BUSCARPARAMETRO_NUM('VLMINVENDAFV', p_regpedido.codfilial, 0) || ';';

          p_regpedido.valido        := FALSE;
          vsmotivoposicao := 'Valor do Pedido menor que o minimo para a Filial';
          vncodmotivo     := 11;
        END IF;


      END IF;

    END IF;

   /*********  HIS.02142.2016  ***********/
   SELECT VENDAS.VALIDA_VLR_LIM_VENDA_MEI(p_regpedido.codcli,
                                          p_vlatendped)
     INTO vsMsgTemp
     FROM DUAL;

   IF UPPER(VSMSGTEMP) <> 'OK' THEN
     vsmensagem := vsmensagem || vschar || VSMSGTEMP;
     p_regpedido.valido   := FALSE;
   END IF;

   vsTipoImportacao := FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('TIPOIMPORTACAOVENDA', P_REGPEDIDO.CODFILIAL, 'RI');

   IF nvl(P_REGPEDIDO.NUMPEDORIG,0) = 0
     THEN
   BEGIN
     FOR DADOS IN (SELECT I.CODPROD,
                            V.NUMSEQFV,
                            I.NUMSEQ,
                            C.NUMREGIAO,
                            C.CODCLI,
                            C.CODUSUR,
                            T.CODFORNEC,
                            (SELECT CODPRACA
                               FROM PCCLIENT
                              WHERE CODCLI = C.CODCLI) CODPRACA,
                            T.CLASSE,
                            (SELECT CODATV1 FROM PCCLIENT WHERE CODCLI = C.CODCLI) CODATV1,
                            C.CODSUPERVISOR,
                            C.CODFILIAL,
                            C.CONDVENDA,
                            C.FRETEDESPACHO,
                            C.ORIGEMPED,
                            I.CODAUXILIAR,
                            C.CODPLPAG,
                            C.CODCOB,
                            T.CODMARCA,
                            CASE
                              WHEN C.CONDVENDA IN (4, 5, 8, 11, 20) THEN
                               CASE
                                 WHEN C.VLATEND >= C.VLTOTAL THEN
                                  C.VLATEND
                                 ELSE
                                  C.VLTOTAL
                               END
                              ELSE
                               C.VLATEND
                            END VLATEND
                       FROM PCPEDI I, PCPEDIPCPEDIFV V, PCPEDC C, PCPRODUT T
                      WHERE V.NUMPED = I.NUMPED
                        AND V.NUMSEQ = I.NUMSEQ
                        AND V.CODPROD = I.CODPROD
                        AND V.NUMPED = C.NUMPED
                        AND V.NUMPEDRCAFV = C.NUMPEDRCA
                        AND V.CODPROD = T.CODPROD
                        AND I.NUMPED = C.NUMPED
                        AND I.CODPROD = T.CODPROD
                        AND C.NUMPED = P_REGPEDIDO.NUMPED)

      LOOP

       integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
       integradora_comple.vLog.CODUSUR           := P_REGPEDIDO.CODUSUR;
       integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
       integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
       integradora_comple.vLog.TipoLog           := 'I';
       integradora_comple.vLog.MSG               := 'Validando restrição de venda APOS CORTE. Codprod: ' ||
                                                      DADOS.CODPROD || ';';

       PRC_LOG_INTEGRADORA(integradora_comple.vLog,
                           (CASE WHEN
                            integradora_comple.vLog.MSG LIKE '%ORA-%' THEN
                            DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE
                            TO_CHAR($$PLSQL_LINE) END));

       vsRetornoRest := funcoesvendas.validarrestricaovenda(DADOS.CODPROD,
                                              DADOS.NUMREGIAO,
                                              DADOS.CODCLI,
                                              DADOS.CODUSUR,
                                              DADOS.CODFORNEC,
                                              DADOS.CODPRACA,
                                              DADOS.CLASSE,
                                              DADOS.CODATV1,
                                              DADOS.CODSUPERVISOR,
                                              vsmensagem_rest,
                                              DADOS.CODFILIAL,
                                              DADOS.CONDVENDA,
                                              DADOS.FRETEDESPACHO,
                                              DADOS.ORIGEMPED,
                                              DADOS.CODAUXILIAR,
                                              DADOS.CODPLPAG,
                                              DADOS.CODCOB,
                                              DADOS.CODMARCA,
                                              DADOS.VLATEND);
         IF vsRetornoRest = FALSE THEN
           IF vsmensagem IS NOT NULL THEN
             vschar := '#';
           ELSE
             vschar := NULL;
           END IF;

          vsmensagem := vsmensagem || vschar || vsmensagem_rest || ';';

          IF vsTipoImportacao in ('RI', 'RP') THEN
             p_regpedido.valido := FALSE;
             vncontitensvalidos := 0;
             integradora_comple.proc_registralog(p_regpedido.numped,
                                                 p_regpedido.numpedrca,
                                                 DADOS.CODPROD,
                                                 DADOS.NUMSEQ,
                                                 NULL,
                                                 p_regpedido.cgccli,
                                                 NULL,
                                                 NULL,
                                                 NULL,
                                                 P_REGPEDIDO.CODUSUR,
                                                 p_regpedido.dtaberturapedpalm,
                                                 NULL,
                                                 '3',
                                                 vsmensagem_rest,
                                                 NULL,
                                                 DADOS.NUMSEQFV);

           ELSIF vsTipoImportacao = 'BP' THEN
             p_Regpedido.posicao := 'B';

             IF length(p_regpedido.log) <= 3000 OR p_regpedido.log IS NULL THEN
               p_regpedido.log := p_regpedido.log || CHR(13) || vsmensagem_rest;
             END IF;

             PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,
                                             20,
                                             substr(vsmensagem_rest,1,200),
                                             'C');

             p_regpedido.motivoposicao := substr(vsmensagem_rest, 1, 45) ||
                                          'Codprod :' || DADOS.CODPROD;

           END IF;

         END IF;

     END LOOP;

   EXCEPTION
     WHEN OTHERS THEN
       p_regpedido.valido := FALSE;
       vsmensagem         := vsmensagem || vschar ||
                             ' Erro ao validar Restrição de Venda após Corte: ' ||
                             SQLCODE || '-' || SQLERRM || '-' ||
                             DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';';

       integradora_comple.proc_registralog(p_regpedido.numped,
                                           p_regpedido.numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           p_regpedido.cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           p_regpedido.CODUSUR,
                                           p_Regpedido.dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           SQLCODE || '-' || SQLERRM || '-' ||
                                           DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                           NULL,
                                           null);

      END;
   END IF;

    -- registra log
    IF (vsmensagem IS NOT NULL)
    THEN
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       (case when vsmensagem_rest is not null
                                           and vncontitensvalidos = 0 then
                                           'Nenhum item gravado.'
                                           else
                                             vsmensagem
                                             end),
                       NULL,
                       null);
    END IF;

  EXCEPTION
    WHEN OTHERS THEN
      p_regpedido.valido := FALSE;
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                       NULL,
                       null);

  END proc_validacaofinalcabposcorte;

  PROCEDURE proc_verificaCorte
  (
    p_regpedido  IN OUT integradora_comple.t_cabped,
    p_regitem    IN OUT integradora_comple.t_itemped,
    p_regfilial  IN integradora_comple.t_filial,
    p_regcliente IN integradora_comple.t_clientepedido,
    p_qtunitemb  IN number
  ) IS

   vbfazreservaestoque BOOLEAN;
   vsfazreservaestoque VARCHAR2(3);
   vnqtpedido          NUMBER;
   vnqtdisponivel      NUMBER;
   vnqtdisponivel_cont NUMBER;
   vnqtatend           NUMBER;
   vnqtfalta           NUMBER;
   vicont              NUMBER;
   vncodcertific       pccertific.codcertific%TYPE;
   --vnqtunit            number;
   vbValidouEstoque    BOOLEAN;
   vsItemTV1BNF        VARCHAR2(1);

   CURSOR cr_estoque(p_numpedrca         pcpedifv.numpedrca%type
                    ,p_codusur           pcpedifv.codusur%type
                    ,p_dtaberturapedpalm pcpedifv.dtaberturapedpalm%type) IS
    SELECT pcest.codprod,
           pcest.qtreserv,
           pcest.qtbloqueada,
           pcest.qtpendente,
           -----------------
           nvl(pcprodut.pesoliq,0) pesoliq,
           -----------------
           p_regitem.qt,
           pcpedifv.numseq,
           pcpedifv.codauxiliar,
           p_qtunitemb qtunitemb,
           pcpedifv.codfilialretira,
           -----------------
           est_disp.qtestger,
           est_disp.qtest,
           est_disp.qtdisp,
           est_disp.qtdisp_cont,
           -----------------
           pcprodut.tipomerc
      FROM pcest,
           TABLE(VENDAS.ESTOQUE_DISPONIVEL(pcest.codprod, pcest.codfilial)) est_disp,
           pcpedifv,
           pcprodut
     WHERE pcest.codprod              = est_disp.codprod(+)
       AND pcest.codfilial            = est_disp.codfilial(+)
       AND pcest.codprod              = pcprodut.codprod
       AND pcest.codprod              = pcpedifv.codprod
       AND pcest.codfilial            = p_regitem.codfilialretira
       AND pcpedifv.numpedrca         = p_numpedrca
       AND pcpedifv.codusur           = p_codusur
       AND pcpedifv.dtaberturapedpalm = p_dtaberturapedpalm
       AND pcpedifv.codprod           = p_regitem.codprod
       AND pcpedifv.numseq            = p_regitem.numseqfv;

  PROCEDURE validar_qtdisp(p_codprod    IN NUMBER,
                             p_qtdisp     IN OUT NUMBER,
                             p_qtdispcont IN OUT NUMBER,
                             p_qtunitemb  IN NUMBER)
    IS
      vnmultiplo               pcprodut.multiplo%TYPE;
      vnmultiplo_prod          pcprodut.multiplo%TYPE;
      vschecarmultiplovendabnf pcprodut.checarmultiplovendabnf%TYPE;
      vsaceitavendafracao_prod pcprodut.aceitavendafracao%TYPE;
      vsaceitavendafracao      pcprodfilial.aceitavendafracao%TYPE;
      --vnqtunitemb              pcpedi.qtunitemb%TYPE;
    BEGIN

      BEGIN
        SELECT nvl(pcprodfilial.multiplo,0),
               aceitavendafracao
          INTO vnmultiplo,
               vsaceitavendafracao
          FROM pcprodfilial
         WHERE codfilial = p_regpedido.codfilial
           AND codprod = p_codprod;
      EXCEPTION
        WHEN OTHERS THEN
          vnmultiplo          := 0;
          vsaceitavendafracao := NULL;
      END;

      BEGIN
        SELECT nvl(multiplo,0),
               pcprodut.checarmultiplovendabnf,
               pcprodut.aceitavendafracao
          INTO vnmultiplo_prod,
               vschecarmultiplovendabnf,
               vsaceitavendafracao_prod
          FROM pcprodut
         WHERE codprod = p_codprod;
      EXCEPTION
        WHEN OTHERS THEN
          vnmultiplo_prod          := 0;
          vsaceitavendafracao_prod := NULL;
      END;

      IF vsaceitavendafracao IS NOT NULL
      THEN
        vsaceitavendafracao_prod := vsaceitavendafracao;
      END IF;

      -- Validação por embalagem
      IF p_Regfilial.utilizavendaporembalagem = 'S'
      THEN
        IF vsaceitavendafracao_prod = 'S' THEN
          p_qtdisp     := round((p_qtdisp),6);
          p_qtdispcont := round((p_qtdispcont),6);
		elsif (vsaceitavendafracao_prod = 'M') and
                     (((p_qtdisp < 1) and (p_qtdisp > 0))
                     or ((p_qtdispcont < 1) and (p_qtdispcont > 0)) ) THEN
            p_qtdisp     := (round((p_qtdisp / vnmultiplo_prod),6)) * vnmultiplo_prod;
            p_qtdispcont := (round((p_qtdispcont / vnmultiplo_prod),6)) * vnmultiplo_prod;
        else
          p_qtdisp     := trunc(round((p_qtdisp / p_qtunitemb),6)) * p_qtunitemb;
          p_qtdispcont := trunc(round((p_qtdispcont / p_qtunitemb),6)) * p_qtunitemb;
        end if;
      END IF;

      -- Validação meia embalagem
      IF p_regcliente.ACEITAVENDAFRACAO = 'S'
         AND p_regcliente.VALIDARMULTIPLOVENDA = 'S'
      THEN

        IF vnmultiplo_prod = 0
        THEN

          IF vsaceitavendafracao_prod = 'M'
          THEN
            p_qtdisp     := trunc(round((p_qtdisp / 0.5),6)) * 0.5;
            p_qtdispcont := trunc(round((p_qtdispcont / 0.5),6)) * 0.5;
          END IF;
        END IF;

      ELSE

        p_qtdisp     := round((p_qtdisp),6);
        p_qtdispcont := round((p_qtdispcont),6);

      END IF;

      IF (p_regitem.bonific <> 'N'
        AND (p_regitem.bonific IN ('F', 'S'))) THEN
        vsItemTV1BNF := 'F';
      ELSE
        vsItemTV1BNF := 'N';
      END IF;

      -- Validação múltiplo
      IF (p_regcliente.VALIDARMULTIPLOVENDA = 'S')
       AND(
         (not(p_regpedido.condvenda in (5, 11)) and ((vsChecarMultiploVendaBNF = 'S') and (vsItemTV1BNF = 'F'))) or
         (not(p_regpedido.condvenda in (5, 11)) and (not(vsItemTV1BNF = 'F'))) or
         ((p_regpedido.condvenda in (5, 11)) and (vsItemTV1BNF = 'F'))
         )
      THEN

        IF nvl(vnmultiplo,0) <> 0
        THEN
          vnmultiplo_prod := vnmultiplo;
        END IF;

        IF vnmultiplo_prod <> 0
        THEN
          IF vsaceitavendafracao_prod = 'S' THEN
            p_qtdisp     := round((p_qtdisp),6);
            p_qtdispcont := round((p_qtdispcont),6);
		  elsif (vsaceitavendafracao_prod = 'M') and
                     (((p_qtdisp < 1) and (p_qtdisp > 0))
                     or ((p_qtdispcont < 1) and (p_qtdispcont > 0)) ) THEN
            p_qtdisp     := (round((p_qtdisp / vnmultiplo_prod),6)) * vnmultiplo_prod;
            p_qtdispcont := (round((p_qtdispcont / vnmultiplo_prod),6)) * vnmultiplo_prod;
          else
            p_qtdisp     := trunc(round((p_qtdisp / vnmultiplo_prod),6)) * vnmultiplo_prod;
            p_qtdispcont := trunc(round((p_qtdispcont / vnmultiplo_prod),6)) * vnmultiplo_prod;
          end if;
        END IF;
      END IF;

    END validar_qtdisp;

 BEGIN
                                                                         -- 7431.108773.2017
   IF (((integradora_comple.gregpcconsum.liberarpedidopendente = 'N') OR p_regpedido.posicaoorig in ('P','B')) AND
        (p_regpedido.posicao IN ('P','B')))
    THEN
      vbfazreservaestoque := FALSE;
    ELSE
      CASE
        WHEN (p_regpedido.posicao IN ('L','M')) THEN
          vbfazreservaestoque := TRUE;
        WHEN (p_regpedido.posicao = 'P' OR (p_regpedido.posicao = 'B' and FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VERIFICAESTOQUEPEDBLOQUEADO', p_regpedido.codfilial,'N') = 'S')) THEN
          vbfazreservaestoque := TRUE;
          p_regpedido.posicao := 'L';
        ELSE
          vbfazreservaestoque := FALSE;
      END CASE;

    /*
    Autor      : Rafael Braga
    Solicitação: 2550.098053.2016
    Data       : 12/09/2016
    Descrição  : Gravando log se irá ou não reservar estoque.
    */
     vsfazreservaestoque := CASE
                              WHEN vbfazreservaestoque THEN
                               'SIM'
                              ELSE
                               'NAO'
                            END;

     INSERT INTO pclogfv
       (arquivo,
        codcli,
        DATA,
        motivo,
        numped,
        numpedcli,
        numpedrca,
        status)
     VALUES
       ('PCPEDCFV/PCPEDIFV',
        p_regpedido.codcli,
        SYSDATE,
        'Reserva Estoque: ' || vsfazreservaestoque || ' Posição: ' || p_regpedido.posicao,
        p_regpedido.numped,
        NULL,
        p_regpedido.numpedrca,
        'N');

    END IF;
    ----------------------------------------------------------------------------------------------------------------------------------------------

    vbValidouEstoque := FALSE;

    FOR cr_pcest IN cr_estoque(p_regpedido.numpedrca, coalesce(p_regitem.codusur, p_regpedido.CODUSUR), p_regpedido.dtaberturapedpalm)
    LOOP
      vbValidouEstoque := TRUE;

      IF vbfazreservaestoque
      THEN
        --Assumir a qtde disponível retornada pela função "VENDAS.ESTOQUE_DISPONIVEL"
        vnqtdisponivel := greatest(nvl(cr_pcest.QTDISP,0),0);
        vnqtdisponivel_cont := greatest(nvl(cr_pcest.QTDISP_CONT,0),0);

        -- Subtrai da quantidade disponível o já calculado no pedido corrente

         -----------------------------------------------------------
        --Autor:Rafael Soares
        --Solicitação: 630.026700.2016
        --Data: 21/03/2016
        --Descrição:  Quando o produto possui o mesmo item duas vezes, com venda por embalagem e fator de conversão maior que 0
        --            ,  ao importa-los, deve ser levado em conta o fator de conversão da embalagem para dar a baixa no estoque disponível
        -----------------------------------------------------------
        IF p_Regfilial.utilizavendaporembalagem = 'S'
        THEN
           select nvl(sum(pcpedifv.qt * nvl (pcembalagem.qtunit,1)) ,0) into vnqtpedido
            from pcpedifv, pcpedcfv, pcembalagem
           where pcpedifv.numpedrca         = p_regpedido.numpedrca
             and pcpedifv.dtaberturapedpalm = p_regpedido.dtaberturapedpalm
             and pcpedifv.codprod           = cr_pcest.codprod
             and pcpedifv.cgccli            = p_regpedido.cgccli
             and pcpedifv.numseq            < cr_pcest.numseq
             and pcpedifv.numpedrca         = pcpedcfv.numpedrca
             and pcpedifv.codusur           = pcpedcfv.codusur --(VEN-963)
             and pcpedifv.codprod           = pcembalagem.codprod
             and pcpedcfv.codfilial         = pcembalagem.codfilial
             and pcpedifv.codauxiliar       = pcembalagem.codauxiliar
             and pcpedifv.dtaberturapedpalm = pcpedcfv.dtaberturapedpalm
             and pcpedifv.cgccli            = pcpedcfv.cgccli;
        ELSE
          select nvl(sum(pcpedifv.qt),0) into vnqtpedido
            from pcpedifv
           where pcpedifv.numpedrca         = p_regpedido.numpedrca
             and pcpedifv.dtaberturapedpalm = p_regpedido.dtaberturapedpalm
             and pcpedifv.codprod           = cr_pcest.codprod
             and pcpedifv.cgccli            = p_regpedido.cgccli
             and pcpedifv.numseq            < cr_pcest.numseq;
        END IF;

        vnqtdisponivel := greatest(vnqtdisponivel - vnqtpedido,0);
        --Fazer as demais validações(multiplo, aceita fração, checar multiplo na venda bnf, etc)
        --sobre a qtde disponível encontrada
        validar_qtdisp(cr_pcest.codprod,
                       vnqtdisponivel,
                       vnqtdisponivel_cont,
                       cr_pcest.qtunitemb);
        -----------------------Quantidade disponível ENCONTRADA!---------------------

        --Caso NÃO haja estoque suficiente do item corrente
        IF   --------------------------------------------------------------------------------------
             --Validação de estoque contábil
             (((p_regfilial.verificaestoquecont = 'S' AND p_regfilial.con_verificaestoquecont = 'S') and (cr_pcest.tipomerc <> 'CB')
              AND vnqtdisponivel_cont < cr_pcest.qt)
          OR --------------------------------------------------------------------------------------
             --Validação de estoque gerencial
             --((p_regfilial.verificaestoquecont = 'N' OR p_regfilial.con_verificaestoquecont = 'N')
              --AND vnqtdisponivel < cr_pcest.qt)
              (vnqtdisponivel < cr_pcest.qt))
             --------------------------------------------------------------------------------------
        THEN


          IF (NVL(p_regfilial.aceitavendasemestfv,'N') = 'S') and p_regpedido.posicao <> 'B'
          THEN
             p_regpedido.posicao := 'P';
             p_regpedido.motivoposicao := 'PRODUTO SEM ESTOQUE';
          END IF;
          
          IF (p_regpedido.condvenda = 7) and (p_regitem.tipoentrega = 'EF') 
          THEN
             p_regpedido.posicao := 'P';
             p_regpedido.motivoposicao := 'PRODUTO SEM ESTOQUE';
          END IF;          

            IF ((p_regfilial.verificaestoquecont = 'S' AND p_regfilial.con_verificaestoquecont = 'S') AND (vnqtdisponivel_cont < cr_pcest.qt) and (cr_pcest.tipomerc <> 'CB'))
            THEN
              vnqtatend := least(vnqtdisponivel_cont, vnqtdisponivel);
              vnqtfalta := greatest(cr_pcest.qt - least(vnqtdisponivel_cont, vnqtdisponivel), 0);
            ELSE
              vnqtatend := vnqtdisponivel;
              vnqtfalta := greatest(cr_pcest.qt - vnqtdisponivel, 0);
            END IF;

            -- DDVENDAS-3842
            IF ((NVL(p_regfilial.aceitavendasemestfv,'N') = 'S') and
               (p_regpedido.origemped = 'R' and integradora_comple.gregpcconsum.aceitavendabalcaoestneg = 'S'))
            THEN
              p_regpedido.posicao := 'L';
              vnqtatend := p_regitem.qt;
              vnqtfalta := 0;
             END IF;

            p_regitem.qtfalta := vnqtfalta;

         END IF;

      END IF;
      ------------------------------------------------
      SELECT COUNT(*)
        INTO vicont
        FROM pccertific
       WHERE codprod = cr_pcest.codprod
         AND pccertific.dtinicio <= trunc(SYSDATE)
         AND pccertific.dtvenc >= trunc(SYSDATE);

      vncodcertific := NULL;

      IF vicont <> 0
      THEN

        SELECT codcertific
          INTO vncodcertific
          FROM pccertific
         WHERE codprod = cr_pcest.codprod
           AND pccertific.dtinicio <= trunc(SYSDATE)
           AND pccertific.dtvenc >= trunc(SYSDATE)
           AND rownum = 1;

        UPDATE pcpedi
           SET codcertific = vncodcertific
         WHERE codprod = cr_pcest.codprod
           AND numped = p_regpedido.numped
           AND numseq = cr_pcest.numseq
           AND (codauxiliar = cr_pcest.codauxiliar OR codauxiliar IS NULL);

        UPDATE pccertific
           SET pccertific.pesoutilizado = nvl(pesoutilizado,0) + (nvl(cr_pcest.pesoliq,0) * cr_pcest.qt)
         WHERE codprod = cr_pcest.codprod
           AND pccertific.dtinicio <= trunc(SYSDATE)
           AND pccertific.dtvenc >= trunc(SYSDATE)
           AND rownum = 1;
        ------------------------------------------------
      END IF;

    END LOOP;

    integradora_comple.vLog.MSG := 'Validou estoque: "' || (CASE WHEN vbValidouEstoque THEN 'Sim' ELSE 'Não' END) || '"' || ' CodProd: ' || p_regitem.codprod || ' Numseq: ' || p_regitem.numseqfv || ' CodFilialRetira: ' || p_regitem.codfilialretira;
    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

  END;

  PROCEDURE reservarestoque(p_regpedido IN integradora_comple.t_cabped)
    IS
    ex_movest exception;
    vs_movest  varchar2(100);
    msgest    varchar2(1000);
    vncodprod   pcest.codprod%type;
    BEGIN

      FOR itens IN
      (SELECT pcpedi.codprod, codfilialretira, qt, pcpedi.numseq, pcpedi.posicao
         FROM pcpedi INNER JOIN pcpedipcpedifv
                             ON pcpedipcpedifv.numped = pcpedi.numped
                            AND pcpedipcpedifv.numseq = pcpedi.numseq
                            AND pcpedipcpedifv.codprod = pcpedi.codprod
        WHERE pcpedi.numped              = p_regpedido.numped
          AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca)
      LOOP

        IF itens.posicao not in ('P', 'B') THEN
           integradora_comple.vLog.MSG  := 'Incluir estoque RESERVADO codprod.: ' || itens.codprod;
           vs_movest := pkg_estoque.RESERVA_INCLUIR(p_regpedido.numped, itens.codprod, itens.numseq, true, 'IN', msgest);
        ELSE
           integradora_comple.vLog.MSG  := 'Incluir estoque PENDENTE codprod.: ' || itens.codprod;
           vs_movest := pkg_estoque.PENDENTE_INCLUIR(p_regpedido.numped, itens.codprod, itens.numseq, true, 'IN', msgest);
        END IF;

        integradora_comple.vLog.NUMPEDRCA :=  p_regpedido.numpedrca;
        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        IF vs_movest = 'N' THEN
           RAISE ex_movest;
        END IF;

      END LOOP;

    EXCEPTION
      WHEN ex_movest THEN
         integradora_comple.vLog.MSG := 'Erro: Não foi possível movimentar o estoque. Menssagem PKG_ESTOQUE: "' || chr(13) || msgest || '"';
         PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
         RAISE_APPLICATION_ERROR(-20000, integradora_comple.vLog.MSG);

      WHEN OTHERS THEN
         integradora_comple.vLog.MSG := 'Erro: Não foi possível movimentar o estoque. Falha ao executar a função: reservarestoque"';
         PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
         RAISE_APPLICATION_ERROR(-20000, integradora_comple.vLog.MSG);
    END reservarestoque;


  PROCEDURE proc_gravaestoque
  (
    p_regpedido  IN OUT integradora_comple.t_cabped,
    p_numseq     IN NUMBER,
    p_regfilial  IN integradora_comple.t_filial,
    --p_regcliente IN t_clientepedido,
    p_regrca     IN integradora_comple.t_rca,
    p_regplpag   IN integradora_comple.t_planodepagamento,
    vnvlatend    OUT NUMBER,
    vntotpeso    OUT NUMBER,
    vntotvolume  OUT NUMBER,
    p_vltotped   IN NUMBER
  ) IS
    -------------------------------------------------------------------------------------------
    CURSOR cr_estoque(p_numped pcpedi.numped%TYPE) IS
    SELECT pcest.codprod,
           pcest.qtreserv,
           pcest.qtbloqueada,
           pcest.qtpendente,
           -----------------
           nvl(pcprodut.pesoliq,0) pesoliq,
           -----------------
           pcpedi.qt,
           pcpedi.numseq,
           pcpedi.codauxiliar,
           nvl(pcpedi.qtunitemb,1) qtunitemb,
           pcpedi.codfilialretira,
           -----------------
           est_disp.qtestger,
           est_disp.qtest,
           est_disp.qtdisp,
           est_disp.qtdisp_cont
           -----------------
      FROM pcest,
           TABLE(VENDAS.ESTOQUE_DISPONIVEL(pcest.codprod, pcest.codfilial)) est_disp,
           pcpedi,
           pcprodut,
           pcpedipcpedifv
     WHERE pcest.codprod = est_disp.codprod(+)
       AND pcest.codfilial = est_disp.codfilial(+)
       AND pcest.codprod = pcprodut.codprod
       AND pcest.codprod = pcpedi.codprod
       AND pcest.codfilial = pcpedi.codfilialretira
       AND pcpedi.numped = p_numped
       AND pcpedipcpedifv.numped  = pcpedi.numped
       AND pcpedipcpedifv.codprod = pcpedi.codprod
       AND pcpedipcpedifv.numseq  = pcpedi.numseq
       AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca;
    -------------------------------------------------------------------------------------------
    --vnqtdisponivel      NUMBER;
    --vnqtatend           NUMBER;
    --vnqtfalta           NUMBER;
    vnvltabela          NUMBER;
    vnvltotal           NUMBER;
    vnvlcustofin        NUMBER;
    vnvlcustoreal       NUMBER;
    vnvlcustorep        NUMBER;
    vnvlcustocont       NUMBER;
    vnvlverbacmv        NUMBER;
    vnvlverbacmvcli     NUMBER;
    vnnumitens          NUMBER;
    vnsomafalta         NUMBER;
    vbfazreservaestoque BOOLEAN;
    --vnqtdisponivel_cont NUMBER;
    vnnumseq            NUMBER;
    --vnqtminautoservico  NUMBER;
    vicont              NUMBER;
    vncodcertific       pccertific.codcertific%TYPE;
    --vnqttotprod         NUMBER;

    vnqttotatendida     NUMBER;


    vbHOUVEFALTA        BOOLEAN;
    vbrejeitapedido     BOOLEAN;
    vs_movest  varchar2(100);
    msgest    varchar2(1000);
    vsVerificaEstoquePedBloqueado VARCHAR2(2);
    vbIntegradoraGerouFalta BOOLEAN := FALSE;
    vbJahExistePCFalta BOOLEAN := FALSE;

    -------------------------------------------------------------
    --vsPOSICAO_PED            VARCHAR2(1);

  /*-----------------------------------I M P O R T A N T E ! ! !-----------------------------------
  Objetivo do método: Efetuar todas as validações relacionadas a estoque sobre todos os itens do pedido.
  Documentação:
      Parâmetros lidos:
        a) 1303 - Liberar pedido pendente automaticamente (CON_LIBERARPEDIDOPENDENTE)
           Descrição: Define se o sistema irá liberar o pedido automaticamente ao gravá-lo.
           Comportamento: Quando marcado como "Não", todos os pedidos irão cair na posição "P"endente,
                          caso contrário, o sistema irá fazer as demais validações de estoque para
                          liberação do pedido.
        b) 2548 - Aceita Venda sem Estoque FV (ACEITAVENDASEMESTFV)
           Descrição: Caso o parâmetro 1303 esteja marcado como "Sim", irá determinar a maneira de
                      validar o estoque dos itens.
           Comportamento: Conforme selecionado a seguir:
                          "N" - NÃO: Irá alterar a quantidade pedida do item para o disponível em estoque,
                          gerando falta do restante.
                          "RP" - REJEITAR PEDIDO: Irá rejeitar a gravação do pedido caso haja falta de qualquer
                          um dos itens.
                          "S" - SIM: Irá gravar o pedido na posição "P"endente, em caso de falta em um dos itens.
        c) 2373 - Verificar estoque no momento da venda (VERIFICAESTOQUECONT)
           Descrição: Este parâmetro faz o estoque disponível ter como base o estoque contábil e não o gerencial.
           Comportamento: Quando marcado como "Sim" o estoque disponível a ser comparado com a quantidade
                          solicitada terá como base o estoque contábil (PCEST.QTEST), fazendo todas as demais
                          ponderações sobre seu total da mesma forma que seria realizado com o estoque gerencial(PCEST.QTESTGER).

  -----------------------------------------------------------------------------------------------*/
  BEGIN

    vbrejeitapedido := FALSE;
    vbHOUVEFALTA := FALSE;

    vsVerificaEstoquePedBloqueado := FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VERIFICAESTOQUEPEDBLOQUEADO', p_regpedido.codfilial,'N');

    /*Ponto de validação de Falta */
    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
    integradora_comple.vLog.TIPOLOG           := 'G';
    integradora_comple.vLog.MSG               := ' Ponto 1: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                 ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                 ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                 ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                 ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                 ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;


    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    IF ((integradora_comple.gregpcconsum.liberarpedidopendente = 'N') OR p_regpedido.posicaoorig in ('P','B'))
       AND (p_regpedido.posicao IN ('P','B'))
    THEN
      vbfazreservaestoque := FALSE;
      -- p_regpedido.posicao := 'P'; -- Comentado por alterar a posição do pedido indevidamente Tarefa: 1020.031354.2015


      integradora_comple.vLog.NUMPEDRCA          := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR            := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI             := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM  := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TipoLog            := 'C';
      integradora_comple.vLog.MSG                :=  case p_regpedido.posicao
                                                       when 'P' then 'Pedido gravado como "Pendente" devido parâmetro 1303;'
                                                       else 'Pedido gravado como "BLOQUEADO"' end;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      /*Ponto de validação de Falta */
      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TIPOLOG           := 'G';
      integradora_comple.vLog.MSG               := ' Ponto 2: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                   ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                   ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                   ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                   ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                   ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    ELSE

      CASE
        WHEN (p_regpedido.posicao IN ('L','M')) THEN
          vbfazreservaestoque := TRUE;
        WHEN (p_regpedido.posicao IN ('P', 'B')) THEN
          vbfazreservaestoque := TRUE;
        ELSE
          vbfazreservaestoque := FALSE;
      END CASE;

      vbrejeitapedido := (NVL(p_regfilial.aceitavendasemestfv,'N') = 'RP');

      /*Ponto de validação de Falta */
      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TIPOLOG           := 'G';
      integradora_comple.vLog.MSG               := ' Ponto 3: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                   ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                   ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                   ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                   ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                   ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    END IF;

    --vnnumseq := 0;
    /*Ponto de validação de Falta */
    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
    integradora_comple.vLog.TIPOLOG           := 'G';
    integradora_comple.vLog.MSG               := ' Ponto 4: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                 ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                 ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                 ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                 ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                 ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    ----------------------------------------------------------------------------------------------------------------------------------------------
    FOR cr_pcest IN cr_estoque(p_regpedido.numped)
    LOOP



      IF vbfazreservaestoque
      THEN
        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TIPOLOG           := 'G';
        integradora_comple.vLog.MSG               := 'vbfazreservaestoque = true; codprod = '|| cr_pcest.codprod || '; qtestger = ' ||cr_pcest.qtestger|| '; qtest = ' ||cr_pcest.qtest|| '; qtdisp = '||cr_pcest.qtdisp||'; qtdisp_cont = '|| cr_pcest.qtdisp_cont;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

         SELECT COUNT(*)
         INTO vicont
           FROM PCPEDI INNER JOIN PCPEDIPCPEDIFV
                               ON PCPEDIPCPEDIFV.NUMPED = PCPEDI.Numped
                              AND PCPEDIPCPEDIFV.numseq = pcpedi.numseq
                              AND pcpedipcpedifv.codprod      = pcpedi.codprod
           WHERE pcpedi.numped = p_regpedido.numped
             AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca
             AND pcpedi.codprod = cr_pcest.codprod
             AND pcpedi.numseq = cr_pcest.numseq
             AND (pcpedi.codauxiliar = cr_pcest.codauxiliar OR pcpedi.codauxiliar IS NULL)
             AND NVL(pcpedi.qtfalta ,0) > 0;

         IF vicont > 0 then
           vbHOUVEFALTA := TRUE;
         end if;

      ELSE

        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TIPOLOG           := 'G';
        integradora_comple.vLog.MSG               := 'vbfazreservaestoque = false; qtestger = ' ||cr_pcest.qtestger|| '; qtest = ' ||cr_pcest.qtest|| '; qtdisp = '||cr_pcest.qtdisp||'; qtdisp_cont = '|| cr_pcest.qtdisp_cont;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

         vbHOUVEFALTA := TRUE;
      END IF;

      /*Ponto de validação de Falta */
      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TIPOLOG           := 'G';
      integradora_comple.vLog.MSG               := ' Ponto 5(Por Produto): ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                   ' Produto: ' || cr_pcest.codprod || 'Numseq: ' || cr_pcest.numseq ||
                                                   ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                   ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                   ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                   ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                   ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

      ------------------------------------------------
      SELECT COUNT(*)
        INTO vicont
        FROM pccertific
       WHERE codprod = cr_pcest.codprod
         AND pccertific.dtinicio <= trunc(SYSDATE)
         AND pccertific.dtvenc >= trunc(SYSDATE);

      vncodcertific := NULL;

      IF vicont <> 0
      THEN

        SELECT codcertific
          INTO vncodcertific
          FROM pccertific
         WHERE codprod = cr_pcest.codprod
           AND pccertific.dtinicio <= trunc(SYSDATE)
           AND pccertific.dtvenc >= trunc(SYSDATE)
           AND rownum = 1;

        UPDATE pcpedi
           SET codcertific = vncodcertific
         WHERE codprod = cr_pcest.codprod
           AND numped = p_regpedido.numped
           AND numseq = cr_pcest.numseq
           AND (codauxiliar = cr_pcest.codauxiliar OR codauxiliar IS NULL);

        UPDATE pccertific
           SET pccertific.pesoutilizado = nvl(pesoutilizado,0) + (nvl(cr_pcest.pesoliq,0) * cr_pcest.qt)
         WHERE codprod = cr_pcest.codprod
           AND pccertific.dtinicio <= trunc(SYSDATE)
           AND pccertific.dtvenc >= trunc(SYSDATE)
           AND rownum = 1;
        ------------------------------------------------
      END IF;

    END LOOP;

    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
    integradora_comple.vLog.TIPOLOG           := 'G';
    integradora_comple.vLog.MSG               := 'p_regpedido.posicao = '||p_regpedido.posicao|| '; p_regpedido.posicaoorig = '||p_regpedido.posicaoorig;

    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    ------------------  E S T O Q U E ------------------
    IF vbfazreservaestoque
    THEN


      IF vbHOUVEFALTA
      THEN

        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TIPOLOG           := 'G';
        integradora_comple.vLog.MSG               := 'Houve falta vbHOUVEFALTA = true; aceitavendasemestfv = '|| NVL(p_regfilial.aceitavendasemestfv,'N');

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

        /*Ponto de validação de Falta */
        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TIPOLOG           := 'G';
        integradora_comple.vLog.MSG               := ' Ponto 6: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                     ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                     ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                     ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                     ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                     ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


        CASE NVL(p_regfilial.aceitavendasemestfv,'N')
          WHEN 'S' THEN


            IF p_regpedido.posicao <> 'B' THEN
               p_regpedido.posicao := 'P';
            END IF;

            BEGIN
              FOR itens IN (SELECT pcpedi.codprod,
                                   pcpedi.numseq,
                                   pcpedi.codauxiliar,
                                   pcpedi.qtfalta,
                                   pcpedi.qt,
                                   pcpedi.codfilialretira,
                                   pcpedi.pvenda,
                                   pcpedipcpedifv.numseqfv,
                                   pcpedi.codusur
                              FROM pcpedi
                             inner join pcpedipcpedifv
                                on pcpedipcpedifv.numped = pcpedi.numped
                               and pcpedipcpedifv.numseq = pcpedi.numseq
                               and pcpedipcpedifv.codprod = pcpedi.codprod
                             WHERE pcpedi.numped = p_regpedido.numped
                               AND pcpedipcpedifv.numpedrcafv =
                                   p_regpedido.numpedrca
                               AND nvl(pcpedi.qtfalta, 0) > 0) LOOP

                integradora_comple.proc_registralog(p_regpedido.numped,
                                                    p_regpedido.numpedrca,
                                                    itens.codprod,
                                                    itens.numseq,
                                                    itens.codauxiliar,
                                                    p_regpedido.cgccli,
                                                    NULL,
                                                    NULL,
                                                    NULL,
                                                    p_regpedido.CODUSUR,
                                                    p_regpedido.dtaberturapedpalm,
                                                    NULL,
                                                    '3',
                                                    'Qt. Pedida: ' ||
                                                    (itens.qt) ||
                                                    '#Qt. Atendida: ' ||
                                                    (itens.qt -
                                                    nvl(itens.qtfalta, 0)) ||
                                                    '#Qt. Falta: ' ||
                                                    nvl(itens.qtfalta, 0) || ';' ||
                                                    chr(10) ||
                                                    'Item importado sem geracao de falta. Motivo: Parametro 2548 = S.' || ';',
                                                    NULL,
                                                    itens.numseqfv);

                integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
                integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
                integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
                integradora_comple.vLog.TIPOLOG           := 'G';
                integradora_comple.vLog.MSG               := 'Qt. Pedida: ' ||
                                                             (itens.qt) ||
                                                             '#Qt. Atendida: ' ||
                                                             (itens.qt -
                                                             itens.qtfalta) ||
                                                             '#Qt. Falta: ' ||
                                                             nvl(itens.qtfalta,
                                                                 0) || ';' ||
                                                             chr(10) ||
                                                             'Item importado sem geracao de falta. Motivo: Parametro 2548 = S.' || ';';

                PRC_LOG_INTEGRADORA(integradora_comple.vLog,
                                    (CASE WHEN
                                     integradora_comple.vLog.MSG LIKE '%ORA-%' THEN
                                     DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE
                                     TO_CHAR($$PLSQL_LINE) END));
              END LOOP;
            END;

            UPDATE PCPEDI
               SET QTFALTA = 0
             WHERE NUMPED = p_regpedido.numped;

           -- reservarestoque(p_regpedido);

            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.CODUSUR,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             'Pedido gravado como "Pendente" devido falta de estoque;',
                             NULL,
                             null);


          WHEN 'RP' THEN


            --Rejeita o pedido caso o parametro aceitavendasemestfv = RP
            FOR itens IN (SELECT pcpedi.codprod,
                                 pcpedi.numseq,
                                 pcpedi.codauxiliar,
                                 pcpedi.qt,
                                 pcpedi.qtfalta
                            FROM pcpedi INNER JOIN pcpedipcpedifv
                                                ON pcpedipcpedifv.numped = pcpedi.numped
                                               AND pcpedipcpedifv.numseq = pcpedi.numseq
                                               AND pcpedipcpedifv.codprod = pcpedi.codprod
                           WHERE pcpedi.numped = p_regpedido.numped
                             AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca)
            LOOP
              IF nvl(itens.qtfalta,0) > 0
              THEN
                integradora_comple.proc_registralog(p_regpedido.numped,
                                 p_regpedido.numpedrca,
                                 itens.codprod,
                                 itens.numseq,
                                 itens.codauxiliar,
                                 p_regpedido.cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 p_regpedido.CODUSUR,
                                 p_regpedido.dtaberturapedpalm,
                                 NULL,
                                 '3',
                                 'Produto sem estoque no momento da importação!;' || 'Qt Disponivel : ' || (itens.qt - nvl(itens.qtfalta,0)) || ' Qt Pedida : ' || (itens.qt) || ';',
                                 NULL,
                                 null);

              END IF;

              integradora_comple.proc_pcpedimov(p_regpedido, itens.codprod, itens.numseq, 0, 'N');

            END LOOP;


            DELETE FROM pcpedc
             WHERE numped = p_regpedido.numped;


            p_regpedido.valido := FALSE;


            integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.codusur,
                             p_Regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             'Pedido rejeitado. #Existe item sem estoque. De acordo com parametro aceitavendasemestfv.;',
                             NULL,
                             null);


          ELSE

            /*Ponto de validação de Falta */
            integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
            integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
            integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
            integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
            integradora_comple.vLog.TIPOLOG           := 'G';
            integradora_comple.vLog.MSG               := ' Ponto 7: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                         ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                         ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                         ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                         ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                         ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

            IF (p_regpedido.posicao <> 'B') or
               (p_regpedido.posicao = 'B' and FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VERIFICAESTOQUEPEDBLOQUEADO', p_regpedido.codfilial,'N') = 'S') THEN

              IF p_regpedido.posicao = 'P'
              THEN
                p_regpedido.posicao := 'L';
              END IF;


              SELECT SUM(nvl(qt,0)-nvl(qtfalta,0))
                INTO vnqttotatendida
                FROM pcpedi inner join pcpedipcpedifv
                                    on pcpedipcpedifv.numped = pcpedi.numped
                                   and pcpedipcpedifv.numseq = pcpedi.numseq
                                   and pcpedipcpedifv.codprod = pcpedi.codprod
               WHERE pcpedi.numped = p_regpedido.numped
                 AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca;

              IF (vnqttotatendida > 0)
              THEN

                FOR itens IN
                (SELECT pcpedi.codprod, pcpedi.codauxiliar, pcpedi.numseq, pcpedi.pvenda,
                        pcpedi.codfilialretira, pcpedi.qt, pcpedi.qtfalta, pcpedipcpedifv.numseqfv, pcpedi.codusur
                   FROM pcpedi inner join pcpedipcpedifv
                                       on pcpedi.numped = pcpedipcpedifv.numped
                                      and pcpedi.numseq = pcpedipcpedifv.numseq
                                      and pcpedi.codprod = pcpedipcpedifv.codprod
                  WHERE pcpedi.numped = p_regpedido.numped
                    AND pcpedipcpedifv.numpedrcafv = p_regpedido.numpedrca
                    AND nvl(qtfalta,0) > 0)
                LOOP


                  UPDATE pcest
                     SET pcest.qtvendaperdida = NVL(pcest.qtvendaperdida,0) + nvl(itens.qtfalta,0)
                   WHERE pcest.codfilial = itens.codfilialretira
                     AND pcest.codprod = itens.codprod;

                  integradora_comple.proc_pcpedimov(p_regpedido, itens.codprod, itens.numseq, (itens.qt - itens.qtfalta),'N');
				  integradora_comple.pro_insereMensagemFalta(p_regpedido.CODUSUR, p_regpedido.NUMPED, p_regpedido.CODCLI,
				                     nvl(itens.codfilialretira, p_regpedido.codfilial), itens.codprod, itens.numseq, itens.codauxiliar,
				                     nvl(itens.qtfalta,0), itens.pvenda);

                  if integradora_comple.func_existepcfalta(p_regpedido.numped,
                                                           itens.codprod,
                                                           itens.numseq) then
                  /*Ponto de validação de Falta - A Integradora somente gera PCFALTA caso passe por aqui.
                  No log, deve existir os pontos . */

                    vbJahExistePCFalta := TRUE;

                    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
                    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
                    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
                    integradora_comple.vLog.TIPOLOG           := 'G';
                    integradora_comple.vLog.MSG               := ' Ponto 8: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                                 ' Já Existe PCFALTA? ' || CASE WHEN vbJahExistePCFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                                 ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                                 ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                                 ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;

                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                    UPDATE PCFALTA
                       set codcli    = p_regpedido.codcli,
                           codfilial = itens.codfilialretira,
                           codusur   = nvl(itens.codusur, p_regpedido.CODUSUR),
                           data      = TRUNC(SYSDATE),
                           pvenda    = itens.pvenda,
                           qt        = itens.qtfalta
                    where numped     = p_regpedido.numped
                      and numseq     = itens.numseq
                      and codprod    = itens.codprod;
                  else

                    vbIntegradoraGerouFalta := TRUE;
                    /*Ponto de validação de Falta*/
                    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
                    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
                    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
                    integradora_comple.vLog.TIPOLOG           := 'G';
                    integradora_comple.vLog.MSG               := ' Ponto 9: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                                 ' Já Existe PCFALTA? ' || CASE WHEN vbJahExistePCFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                                 ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                                 ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                                 ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;
                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                    INSERT INTO pcfalta
                      (codcli,
                       codfilial,
                       codprod,
                       codusur,
                       DATA,
                       numseq,
                       pvenda,
                       qt,
                       numped)
                    VALUES
                      (p_regpedido.codcli,
                       itens.codfilialretira,
                       itens.codprod,
                       nvl(itens.codusur, p_regpedido.CODUSUR),
                       TRUNC(SYSDATE),
                       itens.numseq,
                       itens.pvenda,
                       itens.qtfalta,
                       p_regpedido.numped);

                    /*Ponto de validação de Falta*/
                    integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
                    integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
                    integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
                    integradora_comple.vLog.TIPOLOG           := 'G';
                    integradora_comple.vLog.MSG               := ' Ponto 10: ' || 'Houve Falta? ' || CASE WHEN vbHOUVEFALTA THEN 'S' ELSE 'N' END ||
                                                                 ' Já Existe PCFALTA? ' || CASE WHEN vbJahExistePCFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Integradora Gerou Falta? ' || CASE WHEN vbIntegradoraGerouFalta THEN 'S' ELSE 'N' END ||
                                                                 ' Faz Reserva de Estoque? ' || CASE WHEN vbfazreservaestoque THEN 'S' ELSE 'N' END ||
                                                                 ' Aceita Venda sem Estoque FV? ' || (NVL(p_regfilial.aceitavendasemestfv,'N')) ||
                                                                 ' Liberar Ped.Pendente(P.1303): ' || (integradora_comple.gregpcconsum.liberarpedidopendente) ||
                                                                 ' Verif.Est.Ped.Bloq(P.3804): ' || vsVerificaEstoquePedBloqueado;
                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  end if;

                  integradora_comple.proc_registralog(p_regpedido.numped,
                                   p_regpedido.numpedrca,
                                   itens.codprod,
                                   itens.numseq,
                                   itens.codauxiliar,
                                   p_Regpedido.cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   p_regpedido.CODUSUR,
                                   p_regpedido.dtaberturapedpalm,
                                   NULL,
                                   '3',
                                   'Qt. Pedida: ' || (itens.qt) || '#Qt. Atendida: ' || (itens.qt - itens.qtfalta) || ';',
                                   NULL,
                                   itens.numseqfv);

                  integradora_comple.proc_pcpedimov(p_regpedido, itens.codprod, itens.numseq, (itens.qt - itens.qtfalta),'N');

                END LOOP;

              ELSE

                integradora_comple.proc_delitensped(p_regpedido, 'N');


                integradora_comple.proc_registralog(p_regpedido.numped,
                               p_regpedido.numpedrca,
                               NULL,
                               NULL,
                               NULL,
                               p_regpedido.cgccli,
                               NULL,
                               NULL,
                               NULL,
                               p_regpedido.CODUSUR,
                               p_Regpedido.dtaberturapedpalm,
                               NULL,
                               '2',
                               'Pedido rejeitado. #Falta integral.;',
                               NULL,
                               null);

                p_regpedido.valido := FALSE;

              END IF;
           ELSE
              UPDATE PCPEDI
              SET QTFALTA = 0
              WHERE NUMPED = p_regpedido.numped;

              integradora_comple.proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.CODUSUR,
                             p_regpedido.dtaberturapedpalm,
                             NULL,
                             '2',
                             'Pedido gravado como "Bloqueado";',
                             NULL,
                             null);
           END IF;

        END CASE;


      ELSE

        integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
        integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
        integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
        integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
        integradora_comple.vLog.TIPOLOG           := 'G';
        integradora_comple.vLog.MSG               := 'Não houve falta vbHOUVEFALTA = false';

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


        null;
        --reservarestoque(p_regpedido);

      END IF;--vbHOUVEFALTA


    ELSE
      integradora_comple.vLog.NUMPEDRCA         := p_regpedido.numpedrca;
      integradora_comple.vLog.CODUSUR           := p_regpedido.CODUSUR;
      integradora_comple.vLog.CGCCLI            := p_regpedido.CGCCLI;
      integradora_comple.vLog.DTABERTURAPEDPALM := p_regpedido.DTABERTURAPEDPALM;
      integradora_comple.vLog.TIPOLOG           := 'G';
      integradora_comple.vLog.MSG               := 'vbfazreservaestoque = false';

      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
      null;
     -- reservarestoque(p_regpedido);

    END IF;
    ------------------------------------------------------------------------------------

    IF p_regpedido.valido = TRUE
    THEN

      SELECT SUM(Round( NVL(pcpedi.qt,
                     0) * NVL(pcpedi.ptabela,
                              0), 2)) vltabela,
             SUM(DECODE(NVL(pcpedi.bonific, 'N'), 'F', 0, 'S', 0,
                          Round(pcpedi.qt * pcpedi.pvenda, 2))) vlatend,
             SUM(Round((NVL(pcpedi.qt,
                      0) + NVL(pcpedi.qtfalta,
                                0)) * NVL(pcpedi.pvenda,
                                          0), 2)) vltotal,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlcustofin,
                              0)) vlcustofin,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlcustoreal,
                              0)) vlcustoreal,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlcustorep,
                              0)) vlcustorep,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlcustocont,
                              0)) vlcustocont,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcprodut.pesobruto,
                              0)) totpeso,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcprodut.volume,
                              0)) totvolume,
             COUNT(*) numitens,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlverbacmv,
                              0)) vlverbacmv,
             SUM(NVL(pcpedi.qt,
                     0) * NVL(pcpedi.vlverbacmvcli,
                              0)) vlverbacmvcli
        INTO vnvltabela,
             vnvlatend,
             vnvltotal,
             vnvlcustofin,
             vnvlcustoreal,
             vnvlcustorep,
             vnvlcustocont,
             vntotpeso,
             vntotvolume,
             vnnumitens,
             vnvlverbacmv,
             vnvlverbacmvcli
        FROM pcpedi,
             pcprodut
       WHERE pcpedi.numped = p_regpedido.numped
         AND pcpedi.codprod = pcprodut.codprod
		 AND pcpedi.QT > 0;

      -- Somar corte total de item
      vnsomafalta := 0;

      SELECT NVL(SUM(NVL(pcfalta.qt,0) * NVL(pcfalta.pvenda,0)),0)
        INTO vnsomafalta
        FROM pcfalta
       WHERE pcfalta.numped = p_regpedido.numped
         AND pcfalta.codprod NOT IN (SELECT pcpedi.codprod
                                       FROM pcpedi
                                      WHERE pcpedi.numped = p_regpedido.numped);

      IF vnnumitens > 0
      THEN

        UPDATE pcpedi
           SET pcpedi.posicao = p_regpedido.posicao
         WHERE pcpedi.numped = p_regpedido.numped;

        UPDATE pcpedc
           SET pcpedc.posicao     = p_regpedido.posicao,
               pcpedc.vltabela    = decode(p_regpedido.condvenda,
                                           20,
                                           0,
                                           vnvltabela),
               pcpedc.vlatend     = decode(p_regpedido.condvenda,
                                           5,
                                           0,
                                           decode(p_regpedido.condvenda,
                                                  20,
                                                  0,
                                                  vnvlatend + NVL(VLFRETE, 0))),
               pcpedc.vlcustofin  = decode(p_regpedido.condvenda,
                                           20,
                                           0,
                                           vnvlcustofin),
               pcpedc.vlcustoreal = decode(p_regpedido.condvenda,
                                           20,
                                           0,
                                           vnvlcustoreal),
               pcpedc.vlcustorep  = decode(p_regpedido.condvenda,
                                           20,
                                           0,
                                           vnvlcustorep),
               pcpedc.vlcustocont = vnvlcustocont,
               pcpedc.totpeso     = vntotpeso,
               pcpedc.totvolume   = vntotvolume,
               pcpedc.numitens    = vnnumitens,
               pcpedc.vlverbacmv  = vnvlverbacmv,
               pcpedc.vlverbacmvcli = vnvlverbacmvcli
         WHERE pcpedc.numped = p_regpedido.numped;

      ELSE

        p_regpedido.valido := FALSE;

        integradora_comple.proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         NULL,
                         NULL,
                         NULL,
                         p_regpedido.cgccli,
                         NULL,
                         NULL,
                         NULL,
                         p_regpedido.CODUSUR,
                         p_Regpedido.dtaberturapedpalm,
                         NULL,
                         '2',
                         'Pedido rejeitado. #Itens sem estoque;',
                         NULL,
                         null);
      END IF;

    END IF;

  EXCEPTION
    WHEN OTHERS THEN
      p_regpedido.valido := FALSE;
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_Regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_regpedido.dtaberturapedpalm,
                       NULL,
                       '1',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                       NULL,
                       null);

      -- rollback;

      IF nvl(p_regpedido.numpedorig,
             0) = 0
      THEN

        integradora_comple.proc_delitensped(p_regpedido, 'S');

      END IF;

  END proc_gravaestoque;

  PROCEDURE proc_validacaofinalcab
  (
    p_regpedido        IN OUT integradora_comple.t_cabped,
    p_regcliente       IN integradora_comple.t_clientepedido,
    p_regplpag         IN OUT integradora_comple.t_planodepagamento,
    p_regplpagetico    IN integradora_comple.t_plpagetico,
    p_regplpaggenerico IN integradora_comple.t_plpaggenerico,
    --p_regcob           IN t_pccob,
    p_regfilial        IN integradora_comple.t_filial,
    --p_regrca           IN t_rca,
    p_contitensvalidos IN NUMBER,
    p_vltotped         IN OUT NUMBER,
    --p_vltotped_ant     IN NUMBER,
    p_vltottab         IN NUMBER,
    p_vlcustofin       IN NUMBER
  ) IS

    vsmensagem         VARCHAR2(32767);
    vschar             VARCHAR2(1) DEFAULT '#';
    --vnsaldodisponivel  NUMBER;
    --vnnumeroparcelas   INTEGER;
    --vnvalorparcela     NUMBER;
    vsmensagem_vendapf VARCHAR2(1000);
    vnvlminpedido      pccob.vlminpedido%TYPE;
    vnvlpedido         NUMBER;
    vnVLATEND          NUMBER;
    qtITENS            NUMBER;

    vncontitenseticos       NUMBER;
    vncontitensgenericos    NUMBER;
    vncontitensoutros       NUMBER;
    vnvltotitensgenericos   NUMBER;
    vnvltotitenseticos      NUMBER;
    vnvltotitensoutros      NUMBER;
    vnvltotvendabonificmes  NUMBER := 0;
    vnperdesctot   NUMBER(18,6);
    vicontparc     NUMBER;
    vnvlminvendabk NUMBER(18,6);
    vnperluc       NUMBER(18,6);

    vnVLBONIFIC    NUMBER;

    --HIS.02660.2015
    vsPodeComprar  VARCHAR2(1);
    vsMsgTemp      VARCHAR2(1000);
    vnQtdTemp      NUMBER(18,6);

    vnvendatriangular number;
    vnqtitens         number;

    vnTOTALBONIFIC_           number;
    vnTOTALVENDA_             number;
    --vnCUSTOFIN_               number;

    vpermitirvendainterestadualpf PCPARAMFILIAL.Valor%type;
    vpermitirvendaestadualpfcomie PCPARAMFILIAL.Valor%type;
    vpermitirvendaestadualpfsemie PCPARAMFILIAL.Valor%type;
    vUf PCFILIAL.UF%type;
    vnsaldodisponivel_LimCred     number;
	vsCLIENTEMAISNEGOCIOS  PCCLIENT.CLIENTEMAISNEGOCIOS%TYPE;
  BEGIN

    vsmensagem := NULL;

    if (p_regpedido.numpedorig > 0) then
      select nvl(vlatend,0) + p_vltotped
        into p_vltotped
        from pcpedc
       where numped =  p_regpedido.numped;
    end if;

    if (ferramentas.F_BUSCARPARAMETRO_ALFA('FIL_USAESTOQUEDEPFECHADO',
                                              p_regpedido.codfilial,
                                              'N') = 'S')  then

      -- Validar VENDATRIANGULAR
      select count(*) into vnvendatriangular
        from pcpedi i
       where i.numped = p_regpedido.numped
         and ferramentas.F_BUSCARPARAMETRO_ALFA('USADEPTERCEIRO',
                                                i.codfilialretira,
                                                'N') = 'S';
      if vnvendatriangular > 0 then

        p_regpedido.vendatriangular := 'S';

        select count(*) into vnqtitens
          from pcpedi i
         where i.numped = p_regpedido.numped;

        if vnvendatriangular <> vnqtitens then
          p_regpedido.valido := FALSE;

          IF vsmensagem IS NULL
          THEN

            vsmensagem := 'Não é permitido mais de uma filial retira para o pedido caso alguma delas esteja com o parâmetro USADEPTERCEIRO marcado como SIM';

          ELSE

            vsmensagem := vsmensagem || CHR(13) || 'Não é permitido mais de uma filial retira para o pedido caso alguma delas esteja com o parâmetro USADEPTERCEIRO marcado como SIM';

          END IF;
        end if;
      end if;
    end if;

    --tarefa 147989
    IF p_regplpag.formaparcelamento = 'V'
       AND p_regpedido.numpedorig = 0
    THEN

      SELECT COUNT(*)
        INTO vicontparc
        FROM pcpedcvcto
       WHERE numped = p_regpedido.numped;


      IF p_vltotped / vicontparc < p_regplpag.vlminparcela
      THEN


        IF vsmensagem IS NULL
        THEN

          vsmensagem := 'Valor da Parcela do pedido : ' || round(p_vltotped / vicontparc,
                                                                 2) || ' menor que o permitido : ' || p_regplpag.vlminparcela;

        ELSE

          vsmensagem := vsmensagem || CHR(13) || 'Valor da Parcela do pedido : ' || round(p_vltotped / vicontparc,
                                                                                          2) || ' menor que o permitido : ' || p_regplpag.vlminparcela;

        END IF;

      END IF;

    END IF;

    SELECT SUM(qt * nvl(pbonific,0))
      INTO vnVLBONIFIC
      FROM pcpedi
     WHERE numped = p_regpedido.numped
       AND nvl(bonific,'N') <> 'N';

    IF ((p_regpedido.condvenda = 5) OR (nvl(vnVLBONIFIC,0) > 0))
       AND p_regfilial.vlmaxvendabonificmes > 0
    THEN

      BEGIN
        SELECT SUM(round(nvl(pcpedi.qt,
                             0) * nvl(pcpedi.pbonific,
                                      0),
                         2))
          INTO vnvltotvendabonificmes
          FROM pcpedi,
               pcpedc
         WHERE pcpedc.numped = pcpedi.numped
           AND pcpedc.dtcancel IS NULL
           AND to_char(pcpedc.data,
                       'mm/yyyy') = to_char(trunc(SYSDATE),
                                            'mm/yyyy')
           AND pcpedc.codfilial = p_regpedido.codfilial
           AND (pcpedc.condvenda IN (5, 11) OR nvl(pcpedi.bonific,'N') <> 'N')
           AND pcpedc.numped <> p_regpedido.numped;
      EXCEPTION
        WHEN OTHERS THEN
          vnvltotvendabonificmes := 0;
      END;


      IF nvl(vnVLBONIFIC,
             0) + nvl(vnvltotvendabonificmes,
                      0) > p_regfilial.vlmaxvendabonificmes
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'O valor de vendas bonificadas realizadas (' ||
                      vnvltotvendabonificmes || ' )#';
        vsmensagem := vsmensagem || 'ultrapassa o limite parametrizado para o mês (' || p_regfilial.vlmaxvendabonificmes || ' );';

        p_regpedido.valido := FALSE;


      END IF;


    END IF;

    --tarefa 142808
    IF p_regpedido.condvenda NOT IN (4, 5, 8)
    THEN

      IF nvl(p_regfilial.permaxdescvenda,
             0) > 0
      THEN

        IF p_vltottab <> 0
        THEN
          vnperdesctot := ROUND((((p_vltottab - p_vltotped) / p_vltottab) * 100),
                                integradora_comple.gregpcconsum.numcasasdecvenda);
        ELSE
          vnperdesctot := 0;
        END IF;

        IF vnperdesctot > nvl(p_regfilial.permaxdescvenda,
                              0)
        THEN
          if FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('ACEITABLOQPEDACIMADESCMAXIMOMEDIO', p_regfilial.codigo, 'N') = 'N' THEN
             IF vsmensagem IS NOT NULL THEN
                vschar := '#';
             ELSE
                vschar := NULL;
             END IF;
             vsmensagem := vsmensagem || vschar ||
                           'Percentual médio de desconto do pedido (' ||
                           vnperdesctot || ') maior que o máximo cadastrado por filial: ' ||
                           nvl(p_regfilial.permaxdescvenda,0);
             p_regpedido.valido := FALSE;
          ELSE
            p_regpedido.posicao := 'B';
            p_regpedido.codmotivo := 24;
            p_regpedido.motivoposicao := '%desc.médio do pedido (' ||
                                          vnperdesctot ||
                                          ') e sup.máx.permitido.';
          end if;
        END IF;

      ELSE
        IF nvl(integradora_comple.gregpcconsum.permaxdescvenda,
               0) > 0
        THEN


          IF p_vltottab <> 0
          THEN
            vnperdesctot := ROUND((((p_vltottab - p_vltotped) / p_vltottab) * 100),
                                  integradora_comple.gregpcconsum.numcasasdecvenda);
          ELSE
            vnperdesctot := 0;
          END IF;

          IF vnperdesctot > nvl(integradora_comple.gregpcconsum.permaxdescvenda,
                                0)
          THEN

            IF vsmensagem IS NOT NULL
            THEN
              vschar := '#';
            ELSE
              vschar := NULL;
            END IF;
            vsmensagem := vsmensagem || vschar || 'Percentual médio de desconto do pedido (' || vnperdesctot || ') maior que o#';
            vsmensagem := vsmensagem || 'máximo cadastrado para a empresa: ' || nvl(integradora_comple.gregpcconsum.permaxdescvenda,
                                                                                    0) || ';';

            p_regpedido.valido := FALSE;

          END IF;

        END IF;

      END IF;
    END IF;

    IF p_regfilial.utilizacontrolemedicamentos = 'S'
       AND p_regcliente.utilizaplpagmedicamento = 'S'
    THEN


      SELECT COUNT(*),
             SUM(pcpedi.qt * pcpedi.pvenda)
        INTO vncontitenseticos,
             vnvltotitenseticos
        FROM pcpedi,
             pcprodut
       WHERE numped = p_Regpedido.numped
         AND pcpedi.codprod = pcprodut.codprod
         AND pcprodut.grupofaturamento = 'E';

      SELECT COUNT(*),
             SUM(pcpedi.qt * pcpedi.pvenda)
        INTO vncontitensgenericos,
             vnvltotitensgenericos
        FROM pcpedi,
             pcprodut
       WHERE numped = p_Regpedido.numped
         AND pcpedi.codprod = pcprodut.codprod
         AND pcprodut.grupofaturamento IN ('G', 'S');

      SELECT COUNT(*),
             SUM(pcpedi.qt * pcpedi.pvenda)
        INTO vncontitensoutros,
             vnvltotitensoutros
        FROM pcpedi,
             pcprodut
       WHERE numped = p_Regpedido.numped
         AND pcpedi.codprod = pcprodut.codprod
         AND pcprodut.grupofaturamento NOT IN ('E', 'G', 'S');

      IF p_regplpagetico.numdias <= p_regplpaggenerico.numdias
      THEN
        vncontitenseticos  := nvl(vncontitenseticos,
                                  0) + nvl(vncontitensoutros,
                                           0);
        vnvltotitenseticos := nvl(vnvltotitenseticos,
                                  0) + nvl(vnvltotitensoutros,
                                           0);
      ELSE
        vncontitensgenericos  := nvl(vncontitensgenericos,
                                     0) + nvl(vncontitensoutros,
                                              0);
        vnvltotitensgenericos := nvl(vnvltotitensgenericos,
                                     0) + nvl(vnvltotitensoutros,
                                              0);
      END IF;



      IF vncontitenseticos <> 0
         AND vncontitenseticos < p_regplpagetico.numitensminimo
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem         := vsmensagem || vschar || 'Numero de itens de medicamentos Eticos(' || vncontitenseticos || ') menor que o#';
        vsmensagem         := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpagetico.codplpag || ';';
        p_regpedido.valido := FALSE;
      END IF;

      IF vnvltotitenseticos <> 0
         AND vnvltotitenseticos < p_regplpagetico.vlminpedido
      THEN


        p_regpedido.valido := FALSE;


        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Valor de itens de medicamentos Eticos do pedido (' || vnvltotitenseticos || ') menor que o#';
        vsmensagem := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpagetico.codplpag || ';';


      END IF;

      IF vncontitensgenericos <> 0
         AND vncontitensgenericos < p_regplpaggenerico.numitensminimo
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem         := vsmensagem || vschar || 'Numero de itens de medicamentos Genericos(' || vncontitensgenericos || ') menor que o#';
        vsmensagem         := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpaggenerico.codplpag || ';';
        p_regpedido.valido := FALSE;
      END IF;

      IF vnvltotitensgenericos <> 0
         AND vnvltotitensgenericos < p_regplpaggenerico.vlminpedido
      THEN


        p_regpedido.valido := FALSE;


        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Valor de itens de medicamentos Genericos do pedido (' || vnvltotitensgenericos || ') menor que o#';
        vsmensagem := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpaggenerico.codplpag || ';';


      END IF;





    ELSE

      IF p_contitensvalidos < p_regplpag.numitensminimo
      THEN

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem         := vsmensagem || vschar || 'Numero de itens (' || p_contitensvalidos || ') menor que o#';
        vsmensagem         := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpag.codplpag || ';';
        p_regpedido.valido := FALSE;
      END IF;

      IF ( ((p_vltotped + nvl(p_regpedido.vlfrete,0)) < p_regplpag.vlminpedido) AND
			(p_regpedido.orcamento = 'N') ) OR
			((p_vltotped < p_regplpag.vlminpedido) AND
			(p_regpedido.orcamento = 'S') AND
			(FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VALIDAVLMINIMOORCAMENTO','99','N') = 'S' ) )
	  THEN

        IF (integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'N') or
           (p_regfilial.bloquearpedidosabaixovlminimo = 'N')
        THEN
            p_regpedido.valido := FALSE;
        END IF;

        IF vsmensagem IS NOT NULL
        THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem := vsmensagem || vschar || 'Valor do pedido (' || p_vltotped || ') menor que o#';
        vsmensagem := vsmensagem || 'mínimo para o plano de pagamento: ' || p_regplpag.codplpag || ';';

      END IF;

    END IF;

    if nvl(p_vltotped,0) > 0 then
      --tarefa 193101
      SELECT round((((p_vltotped - p_vlcustofin) / p_vltotped) * 100),
                   integradora_comple.gregpcconsum.numcasasdecvenda)
        INTO vnperluc
        FROM dual;
    end if;

    -----------------------------------------------------------
    --Autor: Rodrigo Santos
    --Solicitação: HIS.00104.2015
    --Data: 07/04/2015
    --Descrição: Efetuar verificação do limite de venda por CNAE.

    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VALIDARLIMITECNAE',p_regpedido.codfilial,'N') = 'S' THEN

      IF VENDAS.VLLIMITECNAE(p_regcliente.codcli) < p_vltotped THEN
        p_regpedido.valido := FALSE;
        vsmensagem         := vsmensagem || vschar || 'LIMITE DE VENDA PARA ESTE CNAE EXCEDIDO.';
      END IF;

    END IF;
    -----------------------------------------------------------

    --DMAISNEG-18----------------------------------------------
    IF (p_regpedido.CODCOB = 'SUPP') THEN
	   IF p_regpedido.CONDVENDA <> 1 THEN
          p_regpedido.valido := FALSE;
          vsmensagem         := vsmensagem || vschar || 'Cobrança SUPP - Permitido apenas para condição de venda igual a 1.';	 
	   ELSIF p_regpedido.ORIGEMPED <> 'F' THEN
             p_regpedido.valido := FALSE;
             vsmensagem         := vsmensagem || vschar || 'Cobrança SUPP - Permitido apenas para origem do pedido igual a (F)orça de venda.';	 
	   END IF;
	   
	   BEGIN
	     SELECT NVL(PCCLIENT.CLIENTEMAISNEGOCIOS,'N')
		   INTO vsCLIENTEMAISNEGOCIOS 
		   FROM PCCLIENT
		  WHERE PCCLIENT.CODCLI = p_regcliente.codcli;
	   EXCEPTION
       WHEN NO_DATA_FOUND THEN
	   	  vsCLIENTEMAISNEGOCIOS := 'N' ;
	   END;
	   
	   IF vsCLIENTEMAISNEGOCIOS = 'N' THEN
          p_regpedido.valido := FALSE;
         vsmensagem         := vsmensagem || vschar || 'Cobrança SUPP - Permitido apenas para cliente marcado para trabalhar no "Mais negócio", verifique cadastro do cliente na rotina 302.';	 
	   END IF;	
	END IF;
    -----------------------------------------------------------
    	
    /*********  HIS.02142.2016  ***********/
    SELECT VENDAS.VALIDA_VLR_LIM_VENDA_MEI(p_regpedido.codcli,
                                           p_vltotped)
      INTO vsMsgTemp
      FROM DUAL;

    IF UPPER(VSMSGTEMP) <> 'OK' THEN
      vsmensagem         := vsmensagem || vschar || VSMSGTEMP;
      p_regpedido.valido := FALSE;
    END IF;
     /*********  HIS.02142.2016  ***********/

    IF (FERRAMENTAS.VERIFICAR_FJ(P_REGPEDIDO.CODCLI) = 'PESSOA FISICA') AND
       (NVL(INTEGRADORA_COMPLE.GREGPCCONSUM.TRAVAVENDAPF, 'N') = 'S')
    THEN
      p_regpedido.valido := FALSE;
      vsmensagem         := vsmensagem || vschar || 'VENDA PARA PESSOA FISICA NAO PERMITIDA.';
    END IF;

    -- Alterado para considerar os parâmetros de permissão para venda PF de acordo
    -- com a filial NF, se informado.
    if nvl(p_regpedido.codfilialnf,'0') <> '0' then
      select f.uf
        into vUf
        from pcfilial f
       where f.codigo = p_regpedido.codfilialnf;

      select valor
        into vpermitirvendainterestadualpf
        from pcparamfilial
       where nome = 'FIL_PERMITIRVENDAINTERESTADUALPF'
         and codfilial = p_regpedido.codfilialnf;

      select valor
        into vpermitirvendaestadualpfcomie
        from pcparamfilial
       where nome = 'FIL_PERMITIRVENDAESTADUALPFCOMIE'
         and codfilial = p_regpedido.codfilialnf;

      select valor
        into vpermitirvendaestadualpfsemie
        from pcparamfilial
       where nome = 'FIL_PERMITIRVENDAESTADUALPFSEMIE'
         and codfilial = p_regpedido.codfilialnf;
    else
      vpermitirvendainterestadualpf := p_regfilial.permitirvendainterestadualpf;
      vpermitirvendaestadualpfcomie := p_regfilial.permitirvendaestadualpfcomie;
      vpermitirvendaestadualpfsemie := p_regfilial.permitirvendaestadualpfsemie;
      vUf := p_regfilial.uf;
    end if;

    IF (nvl(vpermitirvendainterestadualpf,
            'S') = 'N')
       AND ((p_regcliente.estent <> vUf) AND ((p_regcliente.tipofj = 'F' AND p_regcliente.contribuinte = 'N') OR (p_regcliente.CONSUMIDORFINAL = 'S') OR
       ((integradora_comple.gregpcconsum.CONSIDERAISENTOSCOMOPF = 'S') AND ((TRIM(p_regcliente.IEENT) = '') OR (p_regcliente.ieent IS NULL) OR
       (Upper(p_regcliente.IEENT) = 'ISENTA') OR (Upper(p_regcliente.ieent) = 'ISENTO')))))
    THEN
      p_regpedido.valido := FALSE;
      vsmensagem         := vsmensagem || vschar || 'VENDA INTERESTADUAL PARA PESSOA FISICA NAO PERMITIDA NESTA FILIAL';
    END IF;

    IF ((nvl(vpermitirvendaestadualpfcomie,
             'S') = 'N') AND (p_regcliente.estent = vUf) AND
       ((p_regcliente.tipofj = 'F') AND (p_regcliente.CONTRIBUINTE = 'N') AND
       (TRIM(upper(p_regcliente.ieent)) <> '' AND TRIM(upper(p_regcliente.ieent)) <> 'ISENTA' AND TRIM(upper(p_regcliente.ieent)) <> 'ISENTO')))
    THEN
      p_regpedido.valido := FALSE;
      vsmensagem         := vsmensagem || vschar || 'VENDA ESTADUAL PARA PESSOA FISICA COM INSC ESTADUAL NAO PERMITIDA NESTA FILIAL';
    END IF;

    IF (nvl(vpermitirvendaestadualpfsemie,
            'S') = 'N')
       AND (p_regcliente.estent = vUf)
       AND ( (FERRAMENTAS.VERIFICAR_FJ(p_regcliente.codcli) = 'PESSOA FISICA') AND
       (TRIM(upper(p_regcliente.ieent)) = '' OR TRIM(upper(p_regcliente.ieent)) = 'ISENTA' OR TRIM(upper(p_regcliente.ieent)) = 'ISENTO'))
    THEN
      p_regpedido.valido := FALSE;
      vsmensagem         := vsmensagem || vschar || 'VENDA ESTADUAL PARA PESSOA FISICA SEM/ISENTA INSC ESTADUAL NAO PERMITIDA NESTA FILIAL';
    END IF;
    IF nvl(p_regcliente.VALIDAMAXVENDAPF,
           'N') = 'S'
    THEN
      --Verificar venda p/ pessoa física

     IF FERRAMENTAS.VERIFICAR_FJ(p_regcliente.codcli) = 'PESSOA FISICA' THEN
        IF NOT funcoesvendas.verificarvalormaximovendapf(p_regcliente.codcli,
                                                         p_vltotped,
                                                         0,
                                                         p_regpedido.percvenda,
                                                         nvl(integradora_comple.gregpcconsum.ACEITAVENDAPF,
                                                             'S'),
                                                         nvl(integradora_comple.gregpcconsum.VERIFICARLIMVENDAPF,
                                                             'N'),
                                                         NVL(p_regfilial.VLMAXVENDAPF ,integradora_comple.gregpcconsum.VLMAXVENDAPF),
                                                         NVL(p_regfilial.PERLIMVENDAPF, integradora_comple.gregpcconsum.PERLIMVENDAPF),
                                                         integradora_comple.gregpcconsum.VLMAXPEDIDOPF,
                                                         integradora_comple.gregpcconsum.CONSIDERAISENTOSCOMOPF,
                                                         p_regpedido.codfilial,
                                                         vsMensagem_vendapf)
        THEN
          IF vsMensagem_vendapf IS NOT NULL
          THEN
            p_regpedido.valido := FALSE;
            vsmensagem         := vsmensagem || vschar || vsmensagem_vendapf;
          END IF;
        END IF;
      END IF;
    END IF;

    IF p_regpedido.origemped <> 'R'
       OR (p_regpedido.origemped = 'R' AND p_regfilial.validavlminvendabalcao = 'S')
    THEN

      IF p_regpedido.condvenda IN (1, 7, 13)
         AND p_regfilial.vlminvendafv > 0
      THEN

        IF p_vltotped < p_regfilial.vlminvendafv
        THEN

          IF vsmensagem IS NOT NULL
          THEN
            vschar := '#';
          ELSE
            vschar := NULL;
          END IF;
          vsmensagem := vsmensagem || vschar || 'Valor do pedido (' || p_vltotped || ') menor que o #';
          vsmensagem := vsmensagem || 'mínimo para o pedido (' || p_regfilial.vlminvendafv || ');';

          IF integradora_comple.gregpcconsum.aceitavendabloq = 'S'
          THEN
            p_regpedido.posicao       := 'B';
            p_regpedido.codmotivo     := 11;
            p_regpedido.motivoposicao := 'Valor do pedido menor que minimo para pedido';
          ELSE
            p_regpedido.valido := FALSE;
          END IF;


        END IF;

      END IF;

    END IF;

    IF p_regpedido.condvenda = 11
    THEN

      SELECT SUM (ROUND(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0),2)) VLATEND
        INTO vnVLATEND
        FROM PCPEDI
       WHERE PCPEDI.NUMPED = p_regpedido.numped;

      IF vnVLATEND < 0
      THEN

        IF p_regcliente.aceitatrocanegativa = 'N'
        THEN

          vsmensagem     := vsmensagem || vschar || 'Valor do pedido não pode ser negativo!#';
          vsmensagem     := vsmensagem || 'O Valor a recolher do pedido é maior do que o valor a enviar';
          p_regpedido.valido := FALSE;

        ELSE

          SELECT COUNT(1)
            INTO qtITENS
            FROM PCPEDI
           WHERE PCPEDI.NUMPED = p_regpedido.numped
             AND PCPEDI.QT > 0;

          IF qtITENS = 0
          THEN

            vsmensagem     := vsmensagem || vschar || 'Pedido de troca não possui itens a enviar#';
            p_regpedido.valido := FALSE;

          END IF;

        END IF;
      END IF;
    END IF;

    -- HIS.02660.2015
    if (P_REGFILIAL.validarAlvaraVenda = 'S')
    THEN
      BEGIN
        FOR DADOS IN (SELECT I.NUMPED, I.CODPROD, I.NUMSEQ, I.QT
                        FROM PCPEDI I
                       WHERE I.NUMPED = P_REGPEDIDO.NUMPED)
        LOOP
          PRC_MED_VALIDA_CONTROLE_VENDA('G',
                                        P_REGPEDIDO.CODCLI,
                                        P_REGCLIENTE.TIPOFJ,
                                        DADOS.CODPROD,
                                        DADOS.QT,
                                        P_REGPEDIDO.NUMPED,
                                        DADOS.NUMSEQ,
                                        VSPODECOMPRAR,
                                        VSMSGTEMP,
                                        VNQTDTEMP);

          IF VSPODECOMPRAR = 'N' THEN
            IF integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'S' THEN
              P_REGPEDIDO.POSICAO       := 'B';
              P_REGPEDIDO.CODMOTIVO     := 19;
              P_REGPEDIDO.MOTIVOPOSICAO := substr('Quant.de venda maior que a permitida para itens restritos',1,60);
              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,19,substr('Quant.de venda maior que a permitida para itens restritos',1,200),'C');

            ELSE
              P_REGPEDIDO.VALIDO := FALSE;

              VSMENSAGEM         := VSMENSAGEM || VSCHAR || 'Existe controle de venda ' ||
                                    VSCHAR || VSMSGTEMP;
            END IF;
            EXIT;
          END IF;
        END LOOP;
      EXCEPTION
        WHEN OTHERS THEN
          VSMENSAGEM              := VSMENSAGEM || VSCHAR || 'Erro ao validar controle de venda #;' || SQLCODE || '-' ||
                                     SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';';

          P_REGPEDIDO.VALIDO      := FALSE;
      END;
    END IF;
    -- fim HIS.02660.2015


    -----------------------------------------------------------
    --Autor: Guilherme Freitas
    --Solicitação: HIS.00698.2015
    --Data: 28/06/2016
    --Descrição: Implementação do desconto de simulador.
    /******************************************************************************************************/
    FOR ITENS IN (SELECT DISTINCT I.CODPROD, I.CODUSUR, I.CODDESCONTOSIMULADOR
                    FROM PCPEDI I
                   WHERE I.NUMPED = P_REGPEDIDO.NUMPED
                     AND NVL(I.CODDESCONTOSIMULADOR, 0) <> 0)
    LOOP
      VNQTDTEMP := 0;
      SELECT COUNT(1) QT
        INTO VNQTDTEMP
        FROM TABLE(VENDAS.DESCONTO_CAB_VENDA_SIMUL(P_REGPEDIDO.CODCLI,
                                                   P_REGPEDIDO.CODPLPAG,
                                                   coalesce(itens.codusur, p_regpedido.CODUSUR),
                                                   P_REGPEDIDO.NUMPED,
                                                   'F',
                                                   '',
                                                   P_REGPEDIDO.CODFILIAL,
                                                   P_REGPEDIDO.CODFILIALNF,
                                                   P_REGPEDIDO.DATA)) D
       WHERE D.PERCATING = 100
         AND INSTR(D.PRODATEND,'-'||ITENS.CODPROD||'-') <> 0;


        IF vnQtdTemp <= 0 THEN
          IF p_regfilial.aceitadesctmkfv = 'S' THEN
                            p_Regpedido.posicao := 'B';
                            p_regpedido.codmotivo     := 5;
                            p_Regpedido.motivoposicao := substr(ITENS.codprod || '- Item com desconto acima do permitido',1,60);
                            PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(p_regpedido.numped,5,substr('Item com desconto acima do permitido :' || ITENS.codprod,1,200),'C');


                    ELSIF p_regfilial.aceitadesctmkfv = 'RP' THEN
                          VSMENSAGEM := VSMENSAGEM || VSCHAR || 'Existe(m) item(s) com desconto de simulador inválido.';
                          p_regpedido.valido := FALSE;

                    ELSE
                      VSMENSAGEM := VSMENSAGEM || VSCHAR || 'Existe(m) item(s) com desconto de simulador inválido. Código do Produto : '||itens.codprod;
                      p_regpedido.valido        := FALSE;

          END IF;

          EXIT;
        END IF;
    END LOOP;
    /******************************************************************************************************/

    /******************************************************************************************************/
    BEGIN
      FOR DADOS IN (SELECT R.CODFILIALRETIRA, R.CODFILIALVENDA
                      FROM PCUSURFILRETIRA R
                     WHERE ((R.CODUSUR = p_regpedido.CODUSUR) OR (R.CODUSUR IS NULL))
                       AND ((R.CODFUNC = p_regpedido.codemitente) OR (R.CODFUNC IS NULL))
                       AND R.ORIGEMPED = 'F')
      LOOP
        IF (DADOS.CODFILIALVENDA IS NOT NULL) AND
           (DADOS.CODFILIALVENDA <> P_REGPEDIDO.CODFILIAL)
        THEN
          VSMENSAGEM              := VSMENSAGEM || VSCHAR || 'Usuário sem permissão para digitação de pedidos para a filial ' ||
                                     p_regpedido.codfilial;
          P_REGPEDIDO.VALIDO      := FALSE;
        END IF;

        IF ((DADOS.CODFILIALVENDA IS NOT NULL) or
            (DADOS.CODFILIALRETIRA IS NOT  NULL)) AND
           (P_REGPEDIDO.CODFILIAL <> NVL(P_REGPEDIDO.codfilialnf, P_REGPEDIDO.CODFILIAL))
        THEN
          VSMENSAGEM              := VSMENSAGEM || VSCHAR || 'Não é permitido digitar pedidos com Filial NF diferente da Filial de Venda';
          P_REGPEDIDO.VALIDO      := FALSE;
        END IF;
      END LOOP;
    EXCEPTION
      WHEN OTHERS THEN
        VSMENSAGEM              := VSMENSAGEM || VSCHAR || 'Erro ao buscar dados das filiais permitidas para o usuário. ' ||
                                   SQLCODE || ' - ' || SQLERRM;
        P_REGPEDIDO.VALIDO      := FALSE;
    END;

    if p_regpedido.CODCOB NOT IN ('SUPP')  THEN	
      if (integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'N') then

        /* OBTER O VLATEND PARA VALIDAR O LIMITE DO CLIENTE */
        SELECT SUM (ROUND(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0),2)) VLATEND
          INTO vnVLATEND
          FROM PCPEDI
        WHERE PCPEDI.NUMPED = p_regpedido.numped;

	    IF NOT
            integradora_comple.func_existelimitecliente(p_regpedido,
                                                        p_regcliente,
                                                        p_regfilial,
                                                        vnVLATEND,
                                                        vnsaldodisponivel_LimCred) THEN

          VSMENSAGEM         := VSMENSAGEM || VSCHAR ||
                                'Pedido ultrapassa credito disponível do cliente.' ||
                                chr(13) || 'Valor do Pedido : ' ||
                                p_regpedido.vlatend || chr(13) ||
                                'Credito disponivel: ' ||
                                vnsaldodisponivel_LimCred || ';';
           P_REGPEDIDO.VALIDO := FALSE;

        END IF;

        if (p_regcliente.dtvenclimcred < trunc(sysdate)) and
           (p_regcliente.dtvenclimcred is not null) then

          VSMENSAGEM := VSMENSAGEM || VSCHAR ||
                        'Limite de crédito vencido, verifique 1203. ';
          P_REGPEDIDO.VALIDO := FALSE;

        end if;
      end if;
    end if;

    /******************************************************************************************************/
    -- registra log
    IF (vsmensagem IS NOT NULL)
    THEN
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       vsmensagem,
                       NULL,
                       null);
    END IF;

  EXCEPTION
    WHEN OTHERS THEN
      p_regpedido.valido := FALSE;
      integradora_comple.proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.cgccli,
                       NULL,
                       NULL,
                       NULL,
                       p_regpedido.CODUSUR,
                       p_Regpedido.dtaberturapedpalm,
                       NULL,
                       '2',
                       SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                       NULL,
                       null);

  END proc_validacaofinalcab;

  PROCEDURE enviarmensagensrca_int IS
  BEGIN
    BEGIN

      FOR c_pcmens IN (SELECT pcmens.ROWID id,
                              pcmens.data,
                              pcmens.codfuncemite,
                              pcempr.nome,
                              pcmens.mens1,
                              pcmens.mens2,
                              pcmens.mens3,
                              pcmens.mens4,
                              pcmens.mens5,
                              pcmens.mens6,
                              pcmens.mens7,
                              pcmens.mens8,
                              pcmens.codusur
                         FROM pcmens,
                              pcempr
                        WHERE NVL(enviado,
                                  'N') = 'N'
                          AND pcmens.codfuncemite = pcempr.matricula
                          and pcmens.data between sysdate - 30 and sysdate)
      LOOP

        INSERT INTO pcmensfv
          (retorno, --1
           codusur, --2
           data, --3
           mens1, --4
           mens2, --5
           mens3, --6
           mens4, --7
           mens5, --8
           mens6, --9
           mens7, --10
           mens8, --11
           codfuncemite, --12
           dtinclusao --13
           )
        VALUES
          (2, --1
           c_pcmens.codusur, --2
           nvl(c_pcmens.data, sysdate), --3
           nvl(c_pcmens.mens1, 'Mensagem 1 não informada no Winthor'), --4
           c_pcmens.mens2, --5
           c_pcmens.mens3, --6
           c_pcmens.mens4, --7
           c_pcmens.mens5, --8
           c_pcmens.mens6, --9
           c_pcmens.mens7, --10
           c_pcmens.mens8, --11
           c_pcmens.codfuncemite, --12
           SYSDATE --13
           );


        UPDATE pcmens
           SET enviado = 'S'
         WHERE ROWID = c_pcmens.id;

   --     COMMIT;


      END LOOP;


    EXCEPTION
      WHEN OTHERS THEN
 --       ROLLBACK;
          null;
    END;
  END enviarmensagensrca_int;

  PROCEDURE proc_processaretornotab(p_existerro IN BOOLEAN, p_faixa IN NUMBER DEFAULT -1) IS

    vncontlog           NUMBER;
    vncontped           NUMBER;
    vicontador          NUMBER;
    vnqtatend           pcpedi.qt%TYPE;
    vsobservacaopedcab  VARCHAR2(32767) := NULL;
    vsobservacaopedcorp VARCHAR2(32767) := NULL;
    vnnumpedrca      pcpedc.numpedrca%TYPE;
    vscliente        pcclient.cliente%TYPE;
    vnqtpedida       NUMBER;
    vsobsfinalpedido VARCHAR2(1000);
    vsatendido       pcpedcfv.atendido%TYPE;
    viexistecorte    NUMBER;
    vnqtatendtotped  NUMBER;
    vscorte          VARCHAR2(1);
    vnvltotgeral   NUMBER;
    vsaux               VARCHAR2(30);
    vsrestricaotranspitem pcprodut.restricaotransp%TYPE;
    viexisteitem          NUMBER;
    vncontitem            NUMBER;
    vnnumpednovo      pcpedc.numped%TYPE;
    vbatualizoupedido BOOLEAN;
    virejeitado       NUMBER;

    vnnumitensgeral NUMBER;
    vnInicioloop number := 0;

  BEGIN
    -- Retorna erros genericos tiporeg = 1
    IF p_existerro = TRUE
    THEN

      if (p_faixa > -1 ) then
         vnInicioloop :=   p_faixa;
         vncontlog    :=   p_faixa;
      else
         vncontlog := integradora_comple.gvetregistralog.COUNT;
      end if;

      FOR i IN vnInicioloop .. vncontlog
      LOOP
        IF integradora_comple.gvetregistralog(i).tiporeg = 1
        THEN
          -- Gravar log de processamento de pedidos
          BEGIN
            INSERT INTO pclogfv
              (arquivo,
               codcli,
               DATA,
               motivo,
               numped,
               numpedcli,
               numpedrca,
               status)
            VALUES
              ('PCPEDCFV/PCPEDIFV',
               NULL,
               SYSDATE,
               SUBSTR(REPLACE(REPLACE(integradora_comple.gvetregistralog(i).erro,
                                      '#',
                                      ' '),
                              ';',
                              CHR(13)),
                      1,
                      100),
               NULL,
               NULL,
               NULL,
               'N');

--            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvetregistralog(i).numpedrca;
              integradora_comple.vLog.CODUSUR            := integradora_comple.gvetregistralog(i).CODUSUR;
              integradora_comple.vLog.CGCCLI             := integradora_comple.gvetregistralog(i).CGCENT;
              integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvetregistralog(i).data;
              integradora_comple.vLog.TipoLog            := 'C';
              integradora_comple.vLog.MSG                := 'Erro na gravação do PCLOGFV' || chr(13) ||
                                         SQLCODE  || ' - ' ||  SQLERRM  ;

              PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
              --ROLLBACK;  Não descomentar!! Pode dar erro na reserva do estoque
          END;
        END IF;
      END LOOP;
    END IF;

    -----------------INICIO PEDIDOS -------------------------

    vncontlog := integradora_comple.gvetregistralog.COUNT;

    FOR i IN 1 .. vncontlog
    LOOP
      IF integradora_comple.gvetregistralog(i).tiporeg = 3
      THEN

        BEGIN
          SELECT p.numped
            INTO vnnumpednovo
            FROM pcpedc   p,
                 pcclient c,
                 pcpedi   i
           WHERE p.numpedrca = integradora_comple.gvetregistralog(i).numpedrca
             AND p.codusur = integradora_comple.gvetregistralog(i).codusur
             AND p.dtaberturapedpalm = integradora_comple.gvetregistralog(i).data
             AND p.codcli = c.codcli
             AND trim(regexp_replace(c.cgcent, '[./-]', '')) = trim(regexp_replace(integradora_comple.gvetregistralog(i).cgcent, '[./-]', ''))
             AND p.numped = i.numped
             AND i.codprod = integradora_comple.gvetregistralog(i).codprod;
        EXCEPTION
          WHEN OTHERS THEN
            vnnumpednovo := NULL;

        END;


        integradora_comple.gvetregistralog(i).numrecadofv := vnnumpednovo;


      END IF;
    END LOOP;

    vncontped  := integradora_comple.gvet_regpedido.COUNT;
    vncontitem := integradora_comple.gvet_regitem.COUNT;

    --verifica se teve algum item com restrição cortado e que não gerou o pedido
    FOR i IN 1 .. vncontped
    LOOP

      FOR regped IN (SELECT numped,
                            restricaotransp
                       FROM pcpedc p
                      WHERE p.numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                                 0,
                                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                                 integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
						--DDVENDAS-21600
                        and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND  p.codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
                        --AND p.codusur = integradora_comple.gvet_regpedido(i).codusur
                        AND p.dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                        AND p.codcli = integradora_comple.gvet_regpedido(i).codcli)
      LOOP




        FOR aux IN 1 .. vncontitem
        LOOP

          IF integradora_comple.gvet_regpedido(i).numpedrca = integradora_comple.gvet_regitem(aux).numpedrca
             AND integradora_comple.gvet_regpedido(i).codusur = integradora_comple.gvet_regitem(aux).codusur
             AND integradora_comple.gvet_regpedido(i).cgccli = integradora_comple.gvet_regitem(aux).cgccli
             AND integradora_comple.gvet_regpedido(i).dtaberturapedpalm = integradora_comple.gvet_regitem(aux).dtaberturapedpalm
          THEN


            BEGIN
              SELECT nvl(pcprodut.restricaotransp,
                         'N')
                INTO vsrestricaotranspitem
                FROM pcprodut
               WHERE codprod = integradora_comple.gvet_regitem(aux).codprod;
            EXCEPTION
              WHEN OTHERS THEN
                vsrestricaotranspitem := 'N';

            END;

            IF vsrestricaotranspitem <> regped.restricaotransp
            THEN

              SELECT COUNT(*)
                INTO viexisteitem
                FROM pcpedi
               WHERE pcpedi.codprod = integradora_comple.gvet_regitem(aux).codprod
                 AND EXISTS (SELECT 'x'
                        FROM pcpedc
                       WHERE pcpedc.numpedorigem = integradora_comple.gvet_regpedido(i).numped
                         AND pcpedc.numpedrca = vnnumpedrca
                         AND nvl(pcpedc.restricaotransp,
                                 'N') <> regped.restricaotransp
                         AND pcpedi.numped = pcpedc.numped);

              IF viexisteitem = 0
              THEN

                integradora_comple.gvet_regitem(aux).restricaotransp := regped.restricaotransp;
              END IF;

            END IF;
          END IF;
        END LOOP;
      END LOOP;
    END LOOP;


    -- Retorna pedidos gravados com sucesso
    vncontped := integradora_comple.gvet_regpedido.COUNT;


    FOR i IN 1 .. vncontped
    LOOP

      vbatualizoupedido := FALSE;

      IF integradora_comple.gvet_regpedido(i).valido = TRUE
      THEN
        -- recupera critica do cabecalho.
        vncontlog          := integradora_comple.gvetregistralog.COUNT;
        vsobservacaopedcab := '';

        vsatendido := 'T';


        IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
        THEN

          BEGIN
            SELECT SUM(numitens),
                   SUM(vltotal)
              INTO vnqtatendtotped,
                   vnvltotgeral
              FROM pcorcavendac
             WHERE numorca IN (SELECT numorca
                                 FROM pcorcavendac
                                WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                                  AND codusur = integradora_comple.gvet_regpedido(i).codusur
                                  AND codcli = integradora_comple.gvet_regpedido(i).codcli
                                  AND data = trunc(SYSDATE));
          EXCEPTION
            WHEN OTHERS THEN

              vnqtatendtotped := 0;

          END;


          viexistecorte := 0;




        ELSE

          -- tarefa 154935
          BEGIN
            SELECT SUM(numitens)
              INTO vnqtatendtotped
              FROM pcpedc
             WHERE numped IN (SELECT numped
                                FROM pcpedc
                               WHERE numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                                        0,
                                                        integradora_comple.gvet_regpedido(i).numpedrca,
                                                        integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
								 --DDVENDAS-21600
								 and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
                                 --AND codusur = integradora_comple.gvet_regpedido(i).codusur
                                 AND codcli = integradora_comple.gvet_regpedido(i).codcli
                                 AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm);
          EXCEPTION
            WHEN OTHERS THEN

              vnqtatendtotped := 0;

          END;

          BEGIN

            select count(*) into viexistecorte
            from pcpedifv i
           where i.numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig, 0,integradora_comple.gvet_regpedido(i).numpedrca, integradora_comple.gvet_regpedido(i).numpedorig)
             --DDVENDAS-21600
             and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND i.codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
			 --and i.codusur   = integradora_comple.gvet_regpedido(i).codusur
--             and i.codcli    = integradora_comple.gvet_regpedido(i).codcli
             and i.dtaberturapedpalm   = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
             and i.qt_faturada < i.qt;
          EXCEPTION
            WHEN OTHERS THEN

              viexistecorte := 0;

          END;
        END IF;

        vnqtpedida := integradora_comple.gvet_regpedido(i).numitens;


        IF vnqtpedida > vnqtatendtotped
        THEN
          -- se teve corte de itens
          vsatendido := 'P';

        END IF;

        IF nvl(viexistecorte,
               0) > 0
        THEN
          vsatendido := 'P';

        END IF;




        IF nvl(integradora_comple.gvet_regpedido(i).orcamento,
               'N') = 'N'
        THEN

          SELECT SUM(vltotal),
                 SUM(numitens)
            INTO vnvltotgeral,
                 vnnumitensgeral
            FROM pcpedc p
           WHERE p.numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                      0,
                                      integradora_comple.gvet_regpedido(i).numpedrca,
                                      integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
             --DDVENDAS-21600
			 and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND p.codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
			 --AND p.codusur = integradora_comple.gvet_regpedido(i).codusur
             AND p.dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
             AND p.codcli = integradora_comple.gvet_regpedido(i).codcli;

        ELSE

          vnnumitensgeral := vnqtatendtotped;

        END IF;

        SELECT cliente
          INTO vscliente
          FROM pcclient
         WHERE codcli = integradora_comple.gvet_regpedido(i).codcli;


        vsobsfinalpedido := '>>PEDIDO      : ' || integradora_comple.gvet_regpedido(i).numpedrca || CHR(13) || integradora_comple.gvet_regpedido(i)
                           .codcli || ' - ' || vscliente || CHR(13) || 'Total        : ' || vnvltotgeral || CHR(13) || '--------------------------------------------' || CHR(13);


        FOR regped IN (SELECT p.numped,
                              p.numpedrca,
                              p.codcli,
                              p.codusur,
                              p.vltotal,
                              p.numitens,
                              p.vlatend,
                              p.posicao,
                              c.cliente,
                              p.restricaotransp,
                              decode(p.restricaotransp,
                                     'N',
                                     'Normal',
                                     'com Restricao Transporte') vsaux,
                              p.condvenda,
                              p.brinde
                         FROM pcpedc   p,
                              pcclient c
                        WHERE p.numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                                   0,
                                                   integradora_comple.gvet_regpedido(i).numpedrca,
                                                   integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
                          --DDVENDAS-21600
						  and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND  p.codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
						  --AND p.codusur = integradora_comple.gvet_regpedido(i).codusur
                          AND p.dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                          AND p.codcli = integradora_comple.gvet_regpedido(i).codcli
                          AND p.codcli = c.codcli
                          AND nvl(P.BRINDE,'N') = 'N'
                       UNION
                       SELECT o.numorca numped,
                              o.numpedrca,
                              o.codcli,
                              o.codusur,
                              o.vltotal,
                              o.numitens,
                              o.vlatend,
                              o.posicao,
                              cl.cliente,
                              o.restricaotransp,
                              NULL vsaux,
                              o.condvenda,
                              null brinde
                         FROM pcorcavendac o,
                              pcclient     cl
                        WHERE o.numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                          AND o.codusur = integradora_comple.gvet_regpedido(i).codusur
                          AND o.codcli = integradora_comple.gvet_regpedido(i).codcli
                          AND o.data = trunc(SYSDATE)
                          AND o.codcli = cl.codcli
                          AND integradora_comple.gvet_regpedido(i).orcamento = 'S'
                        ORDER BY numped)
        LOOP

          BEGIN
            vncontitem := integradora_comple.gvet_regitem.COUNT;
            vnqtatend  := regped.numitens;

            -- Reconta os itens totais do pedido e o total de itens atendidos
			IF nvl(integradora_comple.gvet_regpedido(i).orcamento,
               'N') = 'N' THEN
               select count(*) into vnqtatend from pcpedi where numped = regped.numped;
			ELSE
			   select count(*) into vnqtatend from pcorcavendac oc
                                                 , pcorcavendai oi
                                             where oc.numorca = oi.numorca
                                               and oc.numpedrca = integradora_comple.gvet_regpedido(i).numpedrca;
			END IF;

            select count(*) into vnnumitensgeral
              from pcpedifv
             where numpedrca         = integradora_comple.gvet_regpedido(i).numpedrca
               and codusur           = integradora_comple.gvet_regpedido(i).codusur
               and cgccli            = integradora_comple.gvet_regpedido(i).cgccli
               and dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
            --

            IF vbatualizoupedido = FALSE
            THEN
              vnqtatend := vnqtatend;
              --Comentado aprtir da solicitação 907.143058.2014 vnqtatend := vnnumitensgeral - vnqtpedida + regped.numitens; -- tarefa: 2517.110878.2014
            ELSE
              vnqtatend := regped.numitens;
            END IF;

            if regped.condvenda = 5 and regped.brinde = 'S' then
              -- tarefa: 2517.110878.2014
              vsobsfinalpedido := vsobsfinalpedido || 'Pedido Brinde Winthor  ' || regped.vsaux || ' : ' || regped.numped || CHR(13)
                                                   || 'Vlr. Total    : '        || regped.vltotal || CHR(13)
                                                   || 'Vlr. Atendido : '        || regped.vlatend || CHR(13)
                                                   || 'Qt Itens Atend: '        || vnqtatend || CHR(13); --(vnqtpedida - nvl(vnqtatendrest,0)- nvl(vnqtatendrest2,0) )||CHR(13)||
            else
              -- tarefa: 2517.110878.2014
              vsobsfinalpedido := vsobsfinalpedido || 'Pedido Winthor  '        || regped.vsaux || ' : ' || regped.numped || CHR(13)
                                                   || 'Vlr. Total    : '        || regped.vltotal || CHR(13)
                                                   || 'Vlr. Atendido : '        || regped.vlatend || CHR(13)
                                                   || 'Qt Tot.Itens(Ped.Principal): ' || vnnumitensgeral || CHR(13)
                                                   || 'Qt Itens Atend: '        || vnqtatend || CHR(13); --(vnqtpedida - nvl(vnqtatendrest,0)- nvl(vnqtatendrest2,0) )||CHR(13)||
            END IF;


          END;


          FOR j IN 1 .. vncontlog
          LOOP
            IF (integradora_comple.gvetregistralog(j).tiporeg = 2)
               AND (integradora_comple.gvetregistralog(j).numped = regped.numped)
               AND (integradora_comple.gvetregistralog(j).numpedrca = integradora_comple.gvet_regpedido(i).numpedrca)
               AND (integradora_comple.gvetregistralog(j).cgcent = integradora_comple.gvet_regpedido(i).cgccli)
               AND (integradora_comple.gvetregistralog(j).codusur = integradora_comple.gvet_regpedido(i).codusur)
               AND (integradora_comple.gvetregistralog(j).data = integradora_comple.gvet_regpedido(i).dtaberturapedpalm)
            THEN

              IF length(vsobservacaopedcab) <= 3000
                 OR vsobservacaopedcab IS NULL
              THEN

                IF TRIM(integradora_comple.gvetregistralog(j).erro) <> ';'
                THEN

                  vsobservacaopedcab := vsobservacaopedcab || REPLACE(REPLACE(integradora_comple.gvetregistralog(j).erro,
                                                                              '#',
                                                                              ' '),
                                                                      ';',
                                                                      CHR(13));
                END IF;
              END IF;

            END IF;
          END LOOP;


          IF vbatualizoupedido = FALSE
          THEN

            BEGIN
              --- atualiza cabecalho do pedido.
              UPDATE pcpedcfv
                 SET importado     = 2,
                     retorno       = 2,
                     numped        = regped.numped,
                     observacao_pc = substr(vsobsfinalpedido || CHR(13) || vsobservacaopedcab,
                                            1,
                                            4000),
                     posicao_atual = integradora_comple.gvet_regpedido(i).posicao,
                     geroubrinde   = integradora_comple.gvet_regpedido(i).geroubrinde,
                     atendido      = vsatendido
               WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                 AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                 AND codusur = integradora_comple.gvet_regpedido(i).codusur
                 AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;

              vbatualizoupedido := TRUE;

--              COMMIT;
            EXCEPTION
              WHEN OTHERS THEN
                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).cgccli;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDCFV(IMPORTADO)' || chr(13) ||
                                           SQLCODE  || ' - ' ||  SQLERRM  ;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                ROLLBACK;
            END;



            -- Gravar log de processamento de pedidos
            BEGIN
              INSERT INTO pclogfv
                (arquivo,
                 codcli,
                 DATA,
                 motivo,
                 numped,
                 numpedcli,
                 numpedrca,
                 status)
              VALUES
                ('PCPEDCFV/PCPEDIFV',
                 integradora_comple.gvet_regpedido(i).codcli,
                 SYSDATE,
                 SUBSTR(vsobservacaopedcab,
                        1,
                        100),
                 integradora_comple.gvet_regpedido(i).numped,
                 integradora_comple.gvet_regpedido(i).numpedcli,
                 integradora_comple.gvet_regpedido(i).numpedrca,
                 integradora_comple.gvet_regpedido(i).posicao);

--              COMMIT;
            EXCEPTION
              WHEN OTHERS THEN
                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Erro inserir PCLOGFV' || chr(13) ||
                                           SQLCODE  || ' - ' ||  SQLERRM  ;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                ROLLBACK;
            END;

          ELSE

            BEGIN
              --- atualiza cabecalho do pedido.
              UPDATE pcpedcfv
                 SET observacao_pc = substr(vsobsfinalpedido || CHR(13) || vsobservacaopedcab,
                                            1,
                                            4000)
               WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                 AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                 AND codusur = integradora_comple.gvet_regpedido(i).codusur
                 AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;


--              COMMIT;
            EXCEPTION
              WHEN OTHERS THEN
                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDCFV' || chr(13) ||
                                           SQLCODE  || ' - ' ||  SQLERRM  ;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                ROLLBACK;
            END;


          END IF;

          FOR cr_pedcorp IN (SELECT pcpedifv.codprod,
                                    nvl(pcpedifv.codauxiliar,
                                        pcprodut.codauxiliar) codauxiliar,
                                    pcpedifv.qt * CASE pcprodut.tipoestoque
                                                   WHEN 'FR' THEN -- 7431.108773.2017
                                                    case pcpedifv.unidade_frios
                                                      when pcprodut.unidademaster then
                                                       GET_PRODUTO_PESO(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial)
                                                      when 'PC' then
                                                       GET_PRODUTO_PECA(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial)
                                                      else
                                                       1
                                                    END
                                                   ELSE
                                                    1
                                                 END as qt,
                                    pcprodut.restricaotransp,
                                    pcpedifv.numseq
                               FROM pcpedifv,
                                    pcprodut
                              WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                                AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                                AND codusur = integradora_comple.gvet_regpedido(i).codusur
                                AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                                AND pcpedifv.codprod = pcprodut.codprod(+)
                                --AND pcprodut.restricaotransp = regped.restricaotransp
                             UNION
                             SELECT pcpedifv.codprod,
                                    nvl(pcpedifv.codauxiliar,
                                        pcprodut.codauxiliar) codauxiliar,
                                    pcpedifv.qt * CASE pcprodut.tipoestoque
                                                   WHEN 'FR' THEN -- 7431.108773.2017
                                                    case pcpedifv.unidade_frios
                                                      when pcprodut.unidademaster then
                                                       GET_PRODUTO_PESO(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial)
                                                      when 'PC' then
                                                       GET_PRODUTO_PECA(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial)
                                                      else
                                                       1
                                                    END
                                                   ELSE
                                                    1
                                                 END as qt,
                                    pcprodut.restricaotransp,
                                    pcpedifv.numseq
                               FROM pcpedifv,
                                    pcprodut
                              WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                                AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                                AND codusur = integradora_comple.gvet_regpedido(i).codusur
                                AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                                AND pcpedifv.codprod = pcprodut.codprod(+)
                                AND NOT EXISTS (SELECT 'x'
                                       FROM pcpedi,
                                            pcpedc
                                      WHERE pcpedc.numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                                                      0,
                                                                      integradora_comple.gvet_regpedido(i).numpedrca,
                                                                      integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
										--DDVENDAS-21600
										and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND  pcpedc.codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
                                        --AND pcpedc.codusur = integradora_comple.gvet_regpedido(i).codusur
                                        AND pcpedc.codcli = integradora_comple.gvet_regpedido(i).codcli
                                        AND pcpedc.numpedorigem = regped.numped
                                        AND pcpedc.numped = pcpedi.numped
                                        AND pcpedi.codprod = pcpedifv.codprod
                                        AND pcpedi.numseq  = pcpedifv.numseq
                                        AND pcpedi.codauxiliar = nvl(pcpedifv.codauxiliar,
                                                                     pcprodut.codauxiliar))

                             )
          LOOP

            -- recupera critica do item
            vncontlog           := integradora_comple.gvetregistralog.COUNT;
            vsobservacaopedcorp := '';


            FOR j IN 1 .. vncontlog
            LOOP

              IF (integradora_comple.gvetregistralog(j).tiporeg = 3)
                 AND ((integradora_comple.gvetregistralog(j).numrecadofv = regped.numped) OR (integradora_comple.gvetregistralog(j).numrecadofv IS NULL))
                 AND (integradora_comple.gvetregistralog(j).numpedrca = integradora_comple.gvet_regpedido(i).numpedrca)
                 AND (integradora_comple.gvetregistralog(j).cgcent = integradora_comple.gvet_regpedido(i).cgccli)
                 AND (integradora_comple.gvetregistralog(j).codusur = integradora_comple.gvet_regpedido(i).codusur)
                 AND (integradora_comple.gvetregistralog(j).data = integradora_comple.gvet_regpedido(i).dtaberturapedpalm)
                 AND (integradora_comple.gvetregistralog(j).codprod = cr_pedcorp.codprod)
                 AND (integradora_comple.gvetregistralog(j).numseq  = cr_pedcorp.numseq)
                 AND (integradora_comple.gvetregistralog(j).codauxiliar IS NULL OR integradora_comple.gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar) --AND
              --cr_pedcorp.restricaotransp     =  regped.restricaotransp
              THEN

                IF length(vsobservacaopedcorp) <= 3000
                   OR vsobservacaopedcorp IS NULL
                THEN

                  IF TRIM(integradora_comple.gvetregistralog(j).erro) <> ';'
                  THEN

                    vsobservacaopedcorp := vsobservacaopedcorp || REPLACE(REPLACE(integradora_comple.gvetregistralog(j).erro,
                                                                                  '#',
                                                                                  ' '),
                                                                          ';',
                                                                          CHR(13));

                  END IF;
                END IF;
              END IF;
            END LOOP;

            vnqtatend := 0;

            IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
            THEN

              SELECT COUNT(*)
                INTO vicontador
                FROM pcorcavendai,pcorcavendac
               WHERE pcorcavendac.numpedrca = regped.numpedrca
                 AND pcorcavendac.codcli = regped.codcli
                 AND pcorcavendac.codusur = regped.codusur
                 AND pcorcavendai.numorca = pcorcavendac.numorca
                 AND pcorcavendai.codprod = cr_pedcorp.codprod
                 AND (pcorcavendai.codauxiliar = cr_pedcorp.codauxiliar OR pcorcavendai.codauxiliar IS NULL);

            ELSE

              SELECT COUNT(*)
                INTO vicontador
                FROM pcpedi,pcpedc
               WHERE pcpedc.numpedrca = regped.numpedrca
                 AND pcpedi.numped = pcpedc.numped
                 AND pcpedi.codcli = regped.codcli
                 AND pcpedi.codusur = regped.codusur
                 AND pcpedi.codprod = cr_pedcorp.codprod
                 AND (pcpedi.codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL);

            END IF;

            IF vicontador > 0
            THEN

              IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
              THEN

                BEGIN

                  SELECT qt / nvl(qtunitemb,
                                  1)
                  INTO vnqtatend
                   FROM pcorcavendai,pcorcavendac
                  WHERE pcorcavendac.numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                     AND pcorcavendac.codcli = regped.codcli
                     AND pcorcavendac.codusur = regped.codusur
                     AND pcorcavendai.numorca = pcorcavendac.numorca
                     AND pcorcavendai.codprod = cr_pedcorp.codprod
                     AND pcorcavendai.numseq  = cr_pedcorp.numseq
                     AND (pcorcavendai.codauxiliar = cr_pedcorp.codauxiliar OR pcorcavendai.codauxiliar IS NULL)
                     AND rownum = 1;
			      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
				  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
				  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
				  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
				  integradora_comple.vLog.TipoLog            := 'C';
				  integradora_comple.vLog.MSG                := 'Contagem qt faturada codprod ' || cr_pedcorp.codprod || chr(13) ||
																'numseq ' || cr_pedcorp.numseq || chr(13) ||
																'codauxiliar ' || cr_pedcorp.codauxiliar || chr(13) ||
																'codcli ' || regped.codcli || chr(13) ||
																'codusur ' || regped.codusur || chr(13);

				  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                EXCEPTION
                WHEN OTHERS THEN
                  vnqtatend := 0;
				  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
				  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
				  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
				  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
				  integradora_comple.vLog.TipoLog            := 'C';
				  integradora_comple.vLog.MSG                := 'Falha contagem qt faturada codprod ' || cr_pedcorp.codprod || chr(13) ||
																'numseq ' || cr_pedcorp.numseq || chr(13) ||
																'codauxiliar ' || cr_pedcorp.codauxiliar || chr(13) ||
																'codcli ' || regped.codcli || chr(13) ||
																'codusur ' || regped.codusur || chr(13) ||
																SQLCODE || '-' || SQLERRM;

				  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                END;

              ELSE

                BEGIN

                  SELECT qt / nvl(i.qtunitemb,1)
                    INTO vnqtatend
                    FROM pcpedi i inner join pcpedipcpedifv it
                                          on it.numped  = i.numped
                                         and it.numseq  = i.numseq
                                         and it.codprod = i.codprod
                                         and it.codusur = i.codusur
                   WHERE it.numpedrcafv = integradora_comple.gvet_regpedido(i).numpedrca
                     AND it.numseqfv    = cr_pedcorp.numseq
                     AND i.numped       = regped.numped
                     AND i.codcli       = regped.codcli
                     AND i.codusur      = regped.codusur
                     AND i.codprod      = cr_pedcorp.codprod
                     AND (i.codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL)
                     AND rownum = 1;

                EXCEPTION
                 WHEN OTHERS THEN
                  BEGIN
                    SELECT qt / nvl(i.qtunitemb,1)
                    INTO vnqtatend
                    FROM pcpedi i inner join pcpedipcpedifv it
                                          on it.numped  = i.numped
                                         and it.numseq  = i.numseq
                                         and it.codprod = i.codprod
                                         and it.codusur = i.codusur
                   WHERE it.numpedrcafv = integradora_comple.gvet_regpedido(i).numpedrca
                     AND it.numseqfv    = cr_pedcorp.numseq
                     AND i.codcli       = regped.codcli
                     AND i.codusur      = regped.codusur
                     AND i.codprod      = cr_pedcorp.codprod
                     AND (i.codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL)
                     AND it.dtaberturapedpalmfv = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                     AND rownum = 1;
                   EXCEPTION
                     WHEN OTHERS THEN
                       vnqtatend := 0;
                  END;
                END;

              END IF;
            END IF;

            vscorte := 'N';

            IF cr_pedcorp.qt > vnqtatend
            THEN
              vscorte := 'S';

            END IF;

			integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
			integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
			integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
			integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
			integradora_comple.vLog.TipoLog            := 'C';
			integradora_comple.vLog.MSG                := 'Atualizar qt faturada codprod ' || cr_pedcorp.codprod || chr(13) ||
			                                              'vnqtatend ' || vnqtatend || chr(13) ||
			                                              'vicontador ' || vicontador || chr(13) ||
			                                              'cr_pedcorp.qt ' || cr_pedcorp.qt || chr(13) ||
			                                              'orcamento ' || integradora_comple.gvet_regpedido(i).orcamento || chr(13) ||
			                                              'vscorte ' || vscorte || chr(13);

			PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

            IF vicontador > 0
            THEN


              BEGIN
                UPDATE pcpedifv
                   SET observacao_pc   = SUBSTR(vsobservacaopedcorp,
                                                1,
                                                4000),
                       qt_faturada     = nvl(vnqtatend,0),-- estava dobrando o valor de qt_faturada nvl(qt_faturada,0) + vnqtatend, -- tarefa: 2517.110878.2014
                       corte           = vscorte,
                       restricaotransp = cr_pedcorp.restricaotransp,
                       numped          = regped.numped
                 WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                   AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                   AND codusur = integradora_comple.gvet_regpedido(i).codusur
                   AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                   AND codprod = cr_pedcorp.codprod
                   AND numseq  = cr_pedcorp.numseq
                   AND (codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL);

--                COMMIT;
              EXCEPTION
                WHEN OTHERS THEN
                  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
                  integradora_comple.vLog.TipoLog            := 'C';
                  integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDIFV' || chr(13) ||
                                             SQLCODE  || ' - ' ||  SQLERRM  ;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                  ROLLBACK;
              END;


            ELSE

              SELECT COUNT(*)
                INTO virejeitado
                FROM pcpedi i
               WHERE EXISTS (SELECT 'x'
                        FROM pcpedc p
                       WHERE numpedrca = decode(integradora_comple.gvet_regpedido(i).numpedorig,
                                                0,
                                                integradora_comple.gvet_regpedido(i).numpedrca,
                                                integradora_comple.gvet_regpedido(i).numpedorig) --integradora_comple.gvet_regpedido(i).numpedrca
						 --DDVENDAS-21600
						 and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND codusur     = integradora_comple.gvet_regpedido(i).codusur) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
                         --AND codusur = integradora_comple.gvet_regpedido(i).codusur
                         AND codcli = integradora_comple.gvet_regpedido(i).codcli
                         AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                         AND p.numped = i.numped)
                 AND i.codprod = cr_pedcorp.codprod
                 AND (i.codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL);

              IF virejeitado = 0
              THEN

                BEGIN
                  UPDATE pcpedifv
                     SET observacao_pc   = SUBSTR(vsobservacaopedcorp,
                                                  1,
                                                  4000),
                         qt_faturada     = 0,
                         corte           = 'S',
                         restricaotransp = cr_pedcorp.restricaotransp
                   WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                     AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                     AND codusur = integradora_comple.gvet_regpedido(i).codusur
                     AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                     AND codprod = cr_pedcorp.codprod
                     AND numseq  = cr_pedcorp.numseq
                     AND (codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL);

--                  COMMIT;
                EXCEPTION
                  WHEN OTHERS THEN
                    integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                    integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                    integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
                    integradora_comple.vLog.TipoLog            := 'C';
                    integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDCFV(IMPORTADO)' || chr(13) ||
                                               SQLCODE  || ' - ' ||  SQLERRM  ;

                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                    ROLLBACK;
                END;


              END IF;

            END IF;

          END LOOP;



        END LOOP;


      END IF;
    END LOOP;

    -- Retorna pedidos nao gravados
    vncontped := integradora_comple.gvet_regpedido.COUNT;

    FOR i IN 1 .. vncontped
    LOOP

      IF integradora_comple.gvet_regpedido(i).valido = FALSE
      THEN
        -- recupera critica do cabecalho.
        vncontlog          := integradora_comple.gvetregistralog.COUNT;
        vsobservacaopedcab := '';



        FOR j IN 1 .. vncontlog
        LOOP
          IF (integradora_comple.gvetregistralog(j).tiporeg = 2)
             AND ((integradora_comple.gvetregistralog(j).numped = integradora_comple.gvet_regpedido(i).numped) OR (integradora_comple.gvetregistralog(j).numped IS NULL))
             AND (integradora_comple.gvetregistralog(j).numpedrca = integradora_comple.gvet_regpedido(i).numpedrca)
             AND (integradora_comple.gvetregistralog(j).cgcent = integradora_comple.gvet_regpedido(i).cgccli)
             AND (integradora_comple.gvetregistralog(j).codusur = integradora_comple.gvet_regpedido(i).codusur)
             AND (integradora_comple.gvetregistralog(j).data = integradora_comple.gvet_regpedido(i).dtaberturapedpalm)

          THEN

            IF length(vsobservacaopedcab) <= 3000
               OR vsobservacaopedcab IS NULL
            THEN

              IF TRIM(integradora_comple.gvetregistralog(j).erro) <> ';'
              THEN

                vsobservacaopedcab := vsobservacaopedcab || REPLACE(REPLACE(integradora_comple.gvetregistralog(j).erro,
                                                                            '#',
                                                                            ' '),
                                                                    ';',
                                                                    CHR(13));
              END IF;
            END IF;
          END IF;
        END LOOP;



        BEGIN

          --- atualiza cabecalho do pedido.
          UPDATE pcpedcfv
             SET importado     = 3,
                 retorno       = 2,
                 numped        = NULL,
                 observacao_pc = substr(vsobservacaopedcab,
                                        1,
                                        4000),
                 posicao_atual = 'R'
           WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
             AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
             AND codusur = integradora_comple.gvet_regpedido(i).codusur
             AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;

--          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
            integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
            integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
            integradora_comple.vLog.TipoLog            := 'C';
            integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDCFV' || chr(13) ||
                                       SQLCODE  || ' - ' ||  SQLERRM  ;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
            ROLLBACK;
        END;

        -- Gravar log de processamento de pedidos
        BEGIN
          INSERT INTO pclogfv
            (arquivo,
             codcli,
             DATA,
             motivo,
             numped,
             numpedcli,
             numpedrca,
             status)
          VALUES
            ('PCPEDCFV/PCPEDIFV',
             integradora_comple.gvet_regpedido(i).codcli,
             SYSDATE,
             SUBSTR(vsobservacaopedcab,
                    1,
                    100),
             integradora_comple.gvet_regpedido(i).numped,
             integradora_comple.gvet_regpedido(i).numpedcli,
             integradora_comple.gvet_regpedido(i).numpedrca,
             'R');

--          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
            integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
            integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
            integradora_comple.vLog.TipoLog            := 'C';
            integradora_comple.vLog.MSG                := 'Erro ao inserir a PCLOGFV' || chr(13) ||
                                       SQLCODE  || ' - ' ||  SQLERRM  ;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
            ROLLBACK;
        END;

        FOR cr_pedcorp IN (SELECT pcpedifv.codprod,
                                  nvl(pcpedifv.codauxiliar,
                                      pcprodut.codauxiliar) codauxiliar,
                                      pcpedifv.numseq
                             FROM pcpedifv,
                                  pcprodut
                            WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                              AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                              AND codusur = integradora_comple.gvet_regpedido(i).codusur
                              AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                              AND pcpedifv.codprod = pcprodut.codprod(+))
        LOOP

          -- recupera critica do item
          vncontlog           := integradora_comple.gvetregistralog.COUNT;
          vsobservacaopedcorp := '';


          FOR j IN 1 .. vncontlog
          LOOP
            IF (integradora_comple.gvetregistralog(j).tiporeg = 3)
               AND ((integradora_comple.gvetregistralog(j).numped = integradora_comple.gvet_regpedido(i).numped) OR (integradora_comple.gvetregistralog(j).numped IS NULL))
               AND (integradora_comple.gvetregistralog(j).numpedrca = integradora_comple.gvet_regpedido(i).numpedrca)
               AND (integradora_comple.gvetregistralog(j).cgcent = integradora_comple.gvet_regpedido(i).cgccli)
               AND (integradora_comple.gvetregistralog(j).codusur = integradora_comple.gvet_regpedido(i).codusur)
               AND (integradora_comple.gvetregistralog(j).data = integradora_comple.gvet_regpedido(i).dtaberturapedpalm)
               AND (integradora_comple.gvetregistralog(j).codprod = cr_pedcorp.codprod)
               AND (integradora_comple.gvetregistralog(j).numseq  = cr_pedcorp.numseq)
               AND (integradora_comple.gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar OR integradora_comple.gvetregistralog(j).codauxiliar IS NULL)
            THEN

              IF length(vsobservacaopedcorp) <= 3000
                 OR vsobservacaopedcorp IS NULL
              THEN

                IF TRIM(integradora_comple.gvetregistralog(j).erro) <> ';'
                THEN

                  vsobservacaopedcorp := vsobservacaopedcorp || REPLACE(REPLACE(integradora_comple.gvetregistralog(j).erro,
                                                                                '#',
                                                                                ' '),
                                                                        ';',
                                                                        CHR(13));

                END IF;
              END IF;
            END IF;
          END LOOP;

          BEGIN
            UPDATE pcpedifv
               SET observacao_pc = SUBSTR(vsobservacaopedcorp,
                                          1,
                                          4000),
                   qt_faturada   = 0
             WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
               AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
               AND codusur = integradora_comple.gvet_regpedido(i).codusur
               AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
               AND codprod = cr_pedcorp.codprod
               AND numseq  = cr_pedcorp.numseq
               AND (codauxiliar = cr_pedcorp.codauxiliar OR codauxiliar IS NULL);

--            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
              integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
              integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
              integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).dtaberturapedpalm;
              integradora_comple.vLog.TipoLog            := 'C';
              integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDIFV' || chr(13) ||
                                         SQLCODE  || ' - ' ||  SQLERRM  ;

              PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
              ROLLBACK;
          END;
        END LOOP;
      END IF;
    END LOOP;

    -- Retorna pedidos rejeitados durante a leitura
    vncontlog := integradora_comple.gvetregistralog.COUNT;

    FOR i IN 1 .. vncontlog
    LOOP
      IF (integradora_comple.gvetregistralog(i).tiporeg = 2)
         AND (integradora_comple.gvetregistralog(i).linhareg IS NOT NULL)
      THEN
        BEGIN
          --- atualiza cabecalho do pedido.
          UPDATE pcpedcfv
             SET importado     = 3,
                 retorno       = 2,
                 numped        = NULL,
                 observacao_pc = SUBSTR(REPLACE(REPLACE(integradora_comple.gvetregistralog(i).erro,
                                                        '#',
                                                        ' '),
                                                ';',
                                                CHR(13)),
                                        1,
                                        4000),
                 posicao_atual = 'R'
           WHERE numpedrca = integradora_comple.gvetregistralog(i).numpedrca
             AND cgccli = integradora_comple.gvetregistralog(i).cgcent
             AND codusur = integradora_comple.gvetregistralog(i).codusur
             AND dtaberturapedpalm = integradora_comple.gvetregistralog(i).data;


--          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvetregistralog(i).numpedrca;
            integradora_comple.vLog.CODUSUR            := integradora_comple.gvetregistralog(i).CODUSUR;
            integradora_comple.vLog.CGCCLI             := integradora_comple.gvetregistralog(i).CGCENT;
            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvetregistralog(i).data;
            integradora_comple.vLog.TipoLog            := 'C';
            integradora_comple.vLog.MSG                := 'Erro ao atualizar PCPEDCFV(REJEITADO)' || chr(13) ||
                                       SQLCODE  || ' - ' ||  SQLERRM  ;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
            ROLLBACK;
        END;

        -- Gravar log de processamento de pedidos
        BEGIN
          INSERT INTO pclogfv
            (arquivo,
             codcli,
             DATA,
             motivo,
             numped,
             numpedcli,
             numpedrca,
             status)
          VALUES
            ('PCPEDCFV/PCPEDIFV',
             NULL,
             SYSDATE,
             SUBSTR(REPLACE(REPLACE(integradora_comple.gvetregistralog(i).erro,
                                    '#',
                                    ' '),
                            ';',
                            CHR(13)),
                    1,
                    100),
             integradora_comple.gvetregistralog(i).numped,
             NULL,
             integradora_comple.gvetregistralog(i).numpedrca,
             'N');

--          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvetregistralog(i).numpedrca;
            integradora_comple.vLog.CODUSUR            := integradora_comple.gvetregistralog(i).CODUSUR;
            integradora_comple.vLog.CGCCLI             := integradora_comple.gvetregistralog(i).CGCENT;
            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvetregistralog(i).data;
            integradora_comple.vLog.TipoLog            := 'C';
            integradora_comple.vLog.MSG                := 'Erro ao atualizar gravar LOG(PCLOGFV)' || chr(13) ||
                                       SQLCODE  || ' - ' ||  SQLERRM  ;

            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
            ROLLBACK;
        END;
      END IF;
    END LOOP;

    IF integradora_comple.vngtiporeg IS NULL
       OR integradora_comple.vngtiporeg = 8
    THEN

      enviarmensagensrca_int;
    END IF;

  EXCEPTION
    WHEN OTHERS THEN
      NULL;
  END proc_processaretornotab;

