    vCursorEstoque     integradora_comple.T_CURSOR_ESTOQUE_LOCK;
    vnPvendaTemp      PCPEDI.PVENDA%TYPE := 0;
    vnPtabelaTemp     PCPEDI.PTABELA%TYPE := 0;
    vnPerDescTemp     PCPEDI.PERDESC%TYPE := 0;
	  vsMultiplicouPeso  VARCHAR2(1);
    vnVLCREDDISPONIVELTOTAL PCCLIENT.LIMCRED%TYPE;
    vsDADOSLIMCRED   VARCHAR2(4000);

    FUNCTION EXTRAIR_PROX_NUMPED(LISTA IN OUT INTEGRADORA_COMPLE.T_NUMPED_PED%TYPE)
      RETURN NUMBER IS
      NUMPEDTEMP PCPEDI.NUMPED%TYPE;
    BEGIN
      IF LISTA.COUNT <= 0
      THEN
        RETURN 0;
      END IF;

      FOR I IN LISTA.FIRST .. LISTA.LAST
      LOOP
        NUMPEDTEMP := LISTA(I);
        LISTA.DELETE(I);
        RETURN NUMPEDTEMP;
      END LOOP;
    END;

    PROCEDURE PROC_VALIDARQUEBRA_PEDIDO(PINDICEPEDIDO IN NUMBER) IS
      ITENTATIVA       NUMBER;
      VNCOUNTPEDIDOS   NUMBER := 0;
      VNCOUNTPEDIDOS_1 NUMBER := 0;
      VNCOUNTPEDIDOS_2 NUMBER := 0;
    BEGIN
      IF REGFILIAL.SEPARARPRODCOMST = 'S'
      THEN
        SELECT COUNT(1)
          INTO VNCOUNTPEDIDOS
          FROM PCPEDI
         WHERE NUMPED = INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO).NUMPED
           AND (NVL(PCPEDI.ST, 0) > 0)
           AND (NVL(PCPEDI.BASEICST, 0) > 0);

        SELECT COUNT(1)
          INTO VNCOUNTPEDIDOS_1
          FROM PCPEDI
         WHERE NUMPED = INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO).NUMPED
           AND (PCPEDI.ST = 0)
           AND (NVL(PCPEDI.BASEICST, 0) = 0);

        IF (VNCOUNTPEDIDOS > 0) AND (VNCOUNTPEDIDOS_1 > 0)
        THEN
          ITENTATIVA := 0;
          INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := 0;
          WHILE ITENTATIVA < 50 AND
                INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) = 0
          LOOP
            INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := FERRAMENTAS.F_PROX_NUMPED(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO)
                                                                                           .CODUSUR);
            IF INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) > 0
            THEN
              EXIT;
            END IF;
            ITENTATIVA := ITENTATIVA + 1;
          END LOOP;
          VNCOUNTPEDIDOS_2 := VNCOUNTPEDIDOS_2 + 1;
        END IF;
      END IF;

      VNCOUNTPEDIDOS   := 0;
      VNCOUNTPEDIDOS_1 := 0;

      vbPossuiMaisDeUmaRestricao := FALSE;
      IF REGFILIAL.SEPARARPRODCOMRESTRICAOTRANSP = 'S'
      THEN
      SELECT COUNT(DISTINCT(PCPRODUT.RESTRICAOTRANSP))
          INTO VNCOUNTPEDIDOS
          FROM PCPEDI, PCPRODUT
         WHERE PCPEDI.NUMPED = INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO).NUMPED
           AND PCPEDI.CODPROD = PCPRODUT.CODPROD
           AND NVL(PCPRODUT.RESTRICAOTRANSP,'N') <> 'N';

        IF (VNCOUNTPEDIDOS >= 1)
        THEN
          vbPossuiMaisDeUmaRestricao := vnCountPedidos >= 2;

          WHILE VNCOUNTPEDIDOS >= 1
          LOOP
            ITENTATIVA := 0;
            INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := 0;
            WHILE ITENTATIVA < 50 AND
                  INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) = 0
            LOOP
              INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := FERRAMENTAS.F_PROX_NUMPED(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO)
                                                                                             .CODUSUR);
              IF INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) > 0
              THEN
                EXIT;
              END IF;
              ITENTATIVA := ITENTATIVA + 1;
            END LOOP;
            VNCOUNTPEDIDOS_2 := VNCOUNTPEDIDOS_2 + 1;
            VNCOUNTPEDIDOS   := VNCOUNTPEDIDOS - 1;
          END LOOP;
        END IF;

        IF (NVL(VNNUMPEDBRINDE, 0) > 0)
        THEN
          SELECT COUNT(DISTINCT(PCPRODUT.RESTRICAOTRANSP))
            INTO VNCOUNTPEDIDOS
            FROM PCPEDI, PCPRODUT
           WHERE PCPEDI.NUMPED = VNNUMPEDBRINDE
             AND PCPEDI.CODPROD = PCPRODUT.CODPROD
               AND NVL(PCPRODUT.RESTRICAOTRANSP,'N') <> 'N';

          IF (VNCOUNTPEDIDOS >= 1)
          THEN
            vbPossuiMaisDeUmaRestricaoBnf := vnCountPedidos >= 2;

            WHILE VNCOUNTPEDIDOS >= 1
            LOOP
              ITENTATIVA := 0;
              INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := 0;
              WHILE ITENTATIVA < 50 AND
                    INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) = 0
              LOOP
                INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := FERRAMENTAS.F_PROX_NUMPED(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO)
                                                                                               .CODUSUR);
                IF INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) > 0
                THEN
                  EXIT;
                END IF;
                ITENTATIVA := ITENTATIVA + 1;
              END LOOP;
              VNCOUNTPEDIDOS_2 := VNCOUNTPEDIDOS_2 + 1;
              VNCOUNTPEDIDOS   := VNCOUNTPEDIDOS - 1;
            END LOOP;
          END IF;
        END IF;
      END IF;

      VNCOUNTPEDIDOS   := 0;
      VNCOUNTPEDIDOS_1 := 0;

      IF NVL(REGFILIAL.NUMMAXITENSNFE, 0) > 0 AND
         NVL(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO).ORCAMENTO,
             'N') = 'N' AND INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO).CONDVENDA <> 7
      THEN
        VNCOUNTPEDIDOS := CEIL(NVL(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO)
                                   .NUMITENS,
                                   0) / NVL(REGFILIAL.NUMMAXITENSNFE, 0));
        WHILE VNCOUNTPEDIDOS > 1
        LOOP
          ITENTATIVA := 0;
          INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := 0;
          WHILE ITENTATIVA < 50 AND
                INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) = 0
          LOOP
            INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) := FERRAMENTAS.F_PROX_NUMPED(INTEGRADORA_COMPLE.GVET_REGPEDIDO(PINDICEPEDIDO)
                                                                                           .CODUSUR);
            IF INTEGRADORA_COMPLE.T_NUMPED_PED(VNCOUNTPEDIDOS_2) > 0
            THEN
              EXIT;
            END IF;
            ITENTATIVA := ITENTATIVA + 1;
          END LOOP;
          VNCOUNTPEDIDOS_2 := VNCOUNTPEDIDOS_2 + 1;
          VNCOUNTPEDIDOS   := VNCOUNTPEDIDOS - 1;
        END LOOP;
      END IF;
    END PROC_VALIDARQUEBRA_PEDIDO;

  BEGIN
    vncontped := integradora_comple.gvet_regpedido.COUNT;
    vValido      := TRUE;

    IF vncontped > 0
    THEN

      FOR i IN 1 .. vncontped
      LOOP
        vscoddistrib := NULL;

        BEGIN
          integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regpedido(i).numpedrca;
          integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
          integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regpedido(i).CGCCLI;
          integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
          integradora_comple.vLog.TIPOLOG           := 'G';
          integradora_comple.vLog.MSG               := 'Inicio proc_validarcabped';

          PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

          IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('GERARLOCKPRODFILESTPEDFV',integradora_comple.gvet_regpedido(i).codfilial,'S') = 'S'
           THEN
            integradora_comple.proc_lockestoque( integradora_comple.gvet_regpedido(i).CGCCLI,
                                             integradora_comple.vngdatainicio,
                                            integradora_comple.vngdatafim ,
                                            --integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM,
                                            integradora_comple.gvet_regpedido(i).codfilial,
                                           -- integradora_comple.vngtiporeg,
                                            integradora_comple.gvet_regpedido(i).CODUSUR,
                                            integradora_comple.gvet_regpedido(i).numpedrca,
                                            vMensagem,
                                            vValido,
                                            vCursorEstoque);
          END IF;
		if vValido then
          proc_validarcabped(integradora_comple.gvet_regpedido(i),
                             regcliente,
                             regrca,
                             regregiao,
                             regplpag,
                             regplpagetico,
                             regplpaggenerico,
                             regcob,
                             regfilial);

          IF integradora_comple.gvet_regpedido(i).valido = TRUE
          THEN

            vncontitem         := integradora_comple.gvet_regitem.COUNT;
            vncontitematual    := 0;
            vnnumseq           := 0;
            vnmaxnumseq        := 0;
            vncontitensvalidos := 0;
            vnvltotped         := 0;
            vnvltottab         := 0;
            vnvltotbaserca     := 0;
            vntotpesoped       := 0;
            vntotvolumeped     := 0;
            vnvlcustocontped   := 0;
            vnvlcustofinped    := 0;
            vnvlcustorealped   := 0;
            vnvlcustorepped    := 0;
            vnvlverbacmv       := 0;
            vnvlverbacmvcli    := 0;
            vnqtinicial        := 0;

            IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                   0) <> 0
            THEN

              SELECT SUM(pcpedi.qt * pcpedi.pvenda),
                     SUM(pcpedi.qt * pcpedi.ptabela),
                     SUM(pcpedi.qt * pcpedi.pbaserca),
                     MAX(numseq),
                     COUNT(*)
                INTO vnvltotped_ant,
                     vnvltottab_ant,
                     vnvltotbaserca_ant,
                     vnnumseq,
                     vnqtinicial
                FROM pcpedi
               WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

              BEGIN
                SELECT POSICAO
                  INTO integradora_comple.gvet_regpedido(I).POSICAOORIG
                  FROM PCPEDC
                 WHERE NUMPED = integradora_comple.gvet_regpedido(I).NUMPED;
              EXCEPTION
                WHEN OTHERS THEN
                  integradora_comple.gvet_regpedido(I).POSICAOORIG := NULL;
              END;

              vnsaldo_ant := vnvltotped_ant - nvl(vnvltotbaserca_ant,
                                                  vnvltottab_ant);
              vnnumseq    := nvl(vnnumseq,
                                 0);
              vnmaxnumseq := nvl(vnnumseq,
                                 0);

            END IF;

            -- 4041.120884.2015
            if nvl(vncontitem, 0) = 0 then
              integradora_comple.gvet_regpedido(i).valido := FALSE;
              integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                               integradora_comple.gvet_regpedido(i).numpedrca,
                               null,
                               null,
                               null,
                               integradora_comple.gvet_regpedido(i).cgccli,
                               NULL,
                               NULL,
                               NULL,
                               integradora_comple.gvet_regpedido(i).CODUSUR,
                               integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                               NULL,
                               '2',
                               'Nenhum Item encontrado para processamento -' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                               NULL,
                               null);
            end if;

            FOR j IN 1 .. vncontitem
            LOOP

              vnpercdesccom := 0;
              vnpercdescrca := 0;

			  IF integradora_comple.gvet_regpedido(i).orcamento = 'N' THEN
			    --Ajuste numseq do item no pedido
				vnnumseq                                  := vnnumseq + 1;

				integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regpedido(i).numpedrca;
				integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
				integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regpedido(i).CGCCLI;
				integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
				integradora_comple.vLog.TIPOLOG           := 'G';
				integradora_comple.vLog.MSG               := 'Ajustar numseq de pedido ' || integradora_comple.gvet_regitem(j).codprod;

				PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
			  ELSE
			    --Não tem uma tabela auxiliar de vínculo, então se mudar o numseq perde a referência com o item importado
			    vnnumseq                                  := integradora_comple.gvet_regitem(j).numseqfv;

			    integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regpedido(i).numpedrca;
				integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
				integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regpedido(i).CGCCLI;
				integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
				integradora_comple.vLog.TIPOLOG           := 'G';
				integradora_comple.vLog.MSG               := 'Ajustar numseq de orçamento ' || integradora_comple.gvet_regitem(j).codprod;

				PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
			  END IF;

              integradora_comple.gvet_regitem(j).numseq        := vnnumseq;
              integradora_comple.gvet_regorigempreco(j).numseq := vnnumseq;
              integradora_comple.gvet_regorigemcomiss(j).numseq:= vnnumseq;
              integradora_comple.gvet_regorigemdesc(j).numseq  := vnnumseq;

              -- Calcula o valor do simples nacional para abater no pvenda
              begin
                SELECT VALOR_REDUCAO_SIMPLES_NACIONAL
                 INTO vlredsimplesnac_pvenda
                 FROM TABLE(PKG_TRIBUTACAO.CALCULAR_RED_SIMPLES_NACIONAL(integradora_comple.gvet_regpedido(i).codfilial,
                                                                        integradora_comple.gvet_regpedido(i).codfilialnf,
                                                                        integradora_comple.gvet_regitem(j).codfilialretira,
                                                                        integradora_comple.gvet_regpedido(i).codcli,
                                                                        integradora_comple.gvet_regpedido(i).codplpag,
                                                                        integradora_comple.gvet_regitem(j).codprod,
                                                                        integradora_comple.gvet_regitem(j).codauxiliar,
                                                                        integradora_comple.gvet_regpedido(i).condvenda,
                                                                        'N',
                                                                        integradora_comple.gvet_regitem(j).pvenda,
                                                                        integradora_comple.gvet_regitem(j).pvenda
                                                                        ));
                exception
                  when others then
                     vlredsimplesnac_pvenda := 0;
                     integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                     integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                     integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                     integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                     integradora_comple.vLog.TipoLog            := 'I';
                     integradora_comple.vLog.MSG                := 'Erro ao recuperar descont do Simples Nacional ' || integradora_comple.gvet_regitem(j).codprod || chr(13) ||
                                                'Msg Original: ' || SQLCODE || ' - ' || SQLERRM;
                     PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                end;

              BEGIN

                IF (integradora_comple.gvet_regpedido(i).numpedrca = integradora_comple.gvet_regitem(j).numpedrca
                   AND integradora_comple.gvet_regpedido(i).cgccli = integradora_comple.gvet_regitem(j).cgccli
                   --AND integradora_comple.gvet_regpedido(i).codusur = integradora_comple.gvet_regitem(j).codusur (VEN-963)
                   AND integradora_comple.gvet_regpedido(i).dtaberturapedpalm = integradora_comple.gvet_regitem(j).dtaberturapedpalm
                   AND ((nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) = 0)
                   OR (nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) <> 0
                   AND (integradora_comple.gvet_regpedido(i).numpedorig = integradora_comple.gvet_regitem(j).numpedorig))))
                THEN


                  integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regitem(j).numpedrca;
                  integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regitem(j).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regitem(j).DTABERTURAPEDPALM;
                  integradora_comple.vLog.TIPOLOG           := 'G';
                  integradora_comple.vLog.MSG               := 'Iniciando validações do item ' || integradora_comple.gvet_regitem(j).codprod;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  BEGIN
                    proc_validaritemped('N',
                                        integradora_comple.gvet_regitem(j),
                                        integradora_comple.gvet_regorigempreco(j),
                                        integradora_comple.gvet_regorigemcomiss(j),
                                        integradora_comple.gvet_regorigemdesc(j),
                                        integradora_comple.gvet_regpedido(i),
                                        regcliente,
                                        regrca,
                                        regregiao,
                                        regplpag,
                                        regplpagetico,
                                        regplpaggenerico,
                                        regfilial,
                                        regproduto,
                                        regprecos,
                                        vscoddistrib,
                                        vsmensagemitem,
                                        vnpermaxdesc,
										vsMultiplicouPeso);
                  EXCEPTION
                    WHEN ERRO_VALIDARPRECONULOOUZERADO THEN
                      IF regfilial.tipoimportacaovenda = 'RI' THEN
                        NULL;
                      ELSE
                        RAISE;
                      END IF;
                  END;

                  IF integradora_comple.gvet_regitem(j).valido = TRUE then
					IF (integradora_comple.gvet_regitem(j).qt > 0) THEN
                       vnvltotped := vnvltotped +  ROUND((integradora_comple.gvet_regitem(j).qt * integradora_comple.gvet_regitem(j).pvenda  ), 2);
					END IF;
                  ELSE
					  SELECT tipoestoque,
								 UNIDADEMASTER,
								 GET_PRODUTO_PESO(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial) PESOBRUTOMASTER,
								 GET_PRODUTO_PECA(pcprodut.codprod, integradora_comple.gvet_regpedido(i).codfilial) PESOPECA,
								 UNIDADE
							INTO VStipoestoque,
								 VSUNIDADEMASTER,
								 VFPESOBRUTOMASTER,
								 VFPESOPECA,
								 VSUNIDADE
							FROM PCPRODUT
							WHERE CODPROD = integradora_comple.gvet_regitem(j).codprod;

						  IF VStipoestoque = 'FR'  AND
							((FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_UTILIZAFRIOSEMBALAGEM', integradora_comple.gvet_regpedido(I).CODFILIAL, 'N') = 'S'
							   AND regfilial.utilizavendaporembalagem = 'S')  OR
							 (regfilial.utilizavendaporembalagem = 'N'))
						  THEN

							IF upper(TRIM(integradora_comple.gvet_regitem(j).unidadevenda)) = upper(TRIM(VSUNIDADEMASTER)) and (vsMultiplicouPeso = 'N')
							THEN
							  vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * VFPESOBRUTOMASTER * (integradora_comple.gvet_regitem(j).pvenda - nvl(vlredsimplesnac_pvenda,0))), 2), 0);

							ELSIF upper(TRIM(integradora_comple.gvet_regitem(j).unidadevenda)) = 'PC' and (vsMultiplicouPeso = 'N')
							THEN
							  vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * VFPESOPECA * (integradora_comple.gvet_regitem(j).pvenda - nvl(vlredsimplesnac_pvenda,0))), 2), 0);
							ELSE
							  integradora_comple.gvet_regitem(j).vsunidadeVenda := VSUNIDADE; --5896.111382.2017 - Rafael Soares
							  vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * (integradora_comple.gvet_regitem(j).pvenda - nvl(vlredsimplesnac_pvenda,0))), 2), 0);
							END IF;

						  ELSE
							 vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * (integradora_comple.gvet_regitem(j).pvenda - nvl(vlredsimplesnac_pvenda,0))), 2), 0);
						  END IF;

						IF ( integradora_comple.gregpedido.pvendasemimposto = 'S') then --3790.147867.2017
							 vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * (nvl(integradora_comple.gvet_regitem(j).st,0) + nvl(integradora_comple.gvet_regitem(j).vlipi, 0) + nvl(integradora_comple.gvet_regitem(j).VLFECP, 0))), 2), 0);
						END IF;

						IF ( nvl(integradora_comple.gvet_regitem(j).VLICMSPART,0) > 0) then --2001.136302.2017
							 vnvltotped := vnvltotped + NVL(ROUND((integradora_comple.gvet_regitem(j).qt * (nvl(integradora_comple.gvet_regitem(j).VLICMSPART,0)  )), 2), 0);
						END IF;
                  END IF;

                  IF integradora_comple.gvet_regitem(j).valido = TRUE
                  THEN

                    --HIS.02141.2017
                    IF (regfilial.CALCCOMISSAOPORITEM = 'S') THEN
                      integradora_comple.GVET_REGITEM(j).CODEMITENTEITEMPEDIDO := integradora_comple.gvet_regpedido(i).codemitente;
                    ELSE
                      integradora_comple.GVET_REGITEM(j).CODEMITENTEITEMPEDIDO := NULL;
                    END IF;

                    vsTIPOST := UPPER(FERRAMENTAS.VERIFICAR_TIPOST(regcliente.codcli,
                                                                   regprecos.codst));

                    IF (vsTIPOST = 'ST FONTE') THEN
                       integradora_comple.gvet_regitem(j).origemst := 'F';
                    ELSIF (vsTIPOST = 'ST NORMAL') THEN
                       integradora_comple.gvet_regitem(j).origemst := 'N';
                    ELSE
                       integradora_comple.gvet_regitem(j).origemst := 'X';
                    END IF;

                    vnVLREDPVENDASIMPLESNA := nvl(integradora_comple.gvet_regitem(j).vlredpvendasimplesna,0);
                    --integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := nvl(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac,0);
                    vnvlredcmvsimplesnac := nvl(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac,0);

                    --tarefa 173597
                    IF regprecos.usaaliqicmssimplesnacional = 'S'
                       AND (regfilial.uf = regcliente.estent)
                       AND regcliente.simplesnacional = 'S'
                       AND regproduto.revenda = 'S'
                       AND regprecos.ALIQSTSIMPLESNACIONAL > 0
                       AND (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC', integradora_comple.gvet_regpedido(i).codfilial, 'N') = 'N')
                    THEN

                      regprecos.aliqicms2 := regprecos.ALIQSTSIMPLESNACIONAL;

                    END IF;

                    vncontitematual := vncontitematual + 1;

                    BEGIN
                      SELECT pcfilial.uf
                        INTO vsuffilialnf
                        FROM pcfilial
                       WHERE pcfilial.codigo = integradora_comple.gvet_regpedido(i).codfilialnf;
                    EXCEPTION
                      WHEN OTHERS THEN
                        vsuffilialnf := NULL;
                    END;

                    IF regprecos.codicmtabpf IS NULL
                    THEN
                      vbcodicmtabpf := TRUE;
                    ELSE
                      vbcodicmtabpf := FALSE;
                    END IF;

                    --Buscar Percentuais de desconto
                    vnpercdesccom := integradora_comple.func_calcularperdescitem(integradora_comple.gvet_regitem(j).ptabela,integradora_comple.gvet_regitem(j).pvenda);
                    vnpercdescrca := integradora_comple.func_calcularperdescitem(integradora_comple.gvet_regitem(j).ptabela,integradora_comple.gvet_regitem(j).pbaserca);


                    /* Marcos Garcia verificar este ponto*/
                    IF regprecos.tipocalculognre = 'C'
                    THEN
                      integradora_comple.gvet_regitem(j).stclientegnre := integradora_comple.gvet_regitem(j).st;
                      integradora_comple.gvet_regitem(j).st := 0;
                    END IF;

                    integradora_comple.gvet_regorigempreco(j).vlst := integradora_comple.gvet_regitem(j).st;
                    integradora_comple.gvet_regorigempreco(j).vlipi := integradora_comple.gvet_regitem(j).vlipi;
                    integradora_comple.gvet_regorigempreco(j).VLFECP := integradora_comple.gvet_regitem(j).VLFECP;

                    -- calcula o percentual de desconto
                    integradora_comple.gvet_regitem(j).perdesc := integradora_comple.func_calcularperdescitem(integradora_comple.gvet_regitem(j).ptabela,integradora_comple.gvet_regitem(j).pvenda);

                    --114903

                    IF regprecos.codicmtabpf IS NULL
                    THEN
                      vbcodicmtabpf := TRUE;
                    ELSE
                      vbcodicmtabpf := FALSE;
                    END IF;


                    -- CMV sem comissao
                    BEGIN
                      --53 parâmetros
                      funcoesvendas.calcularcmv(FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('IMPOSTOCOMISSAORCA',integradora_comple.gvet_regpedido(i).codfilial,'A'),
                                                integradora_comple.gregpcconsum.aplicarindicecmv,
                                                integradora_comple.gregpcconsum.INCLUIRCOMISSAOCMVVENDA,
                                                nvl(integradora_comple.gregpcconsum.txvenda,0),
                                                regcliente.tipofj,
                                                regcliente.utilizaiesimplificada,
                                                regcliente.ieent,
                                                regproduto.freteespecial,
                                                CASE
                                                  WHEN ((integradora_comple.gvet_regpedido(i).origemped = 'B') or
                                                        (integradora_comple.gvet_regpedido(i).origemped = 'R')) AND
                                                        (paramfilial.obtercomovarchar2('RETIRARCMVDOFRETETERCEIROPEDBALCAO', integradora_comple.gvet_regpedido(i).codfilial) = 'S') THEN
                                                    0
                                                  ELSE
                                                    regregiao.perfreteterceiros
                                                END
                                                ,
                                                regregiao.perfreteespecial,
                                                regprecos.custofin,
                                                regprecos.custoreal,
                                                regprecos.perdesccusto,
                                                regprecos.codicmtab,
                                                vbcodicmtabpf,
                                                regprecos.codicmtabpf,
                                                integradora_comple.gvet_regpedido(i).percvenda,
                                                --integradora_comple.gvet_regitem(j).pvenda,
                                                integradora_comple.gvet_regitem(j).pvenda - nvl(integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA,0),
                                                0,
                                                integradora_comple.gvet_regitem(j).st,
                                                integradora_comple.gvet_regitem(j).VLFECP,
                                                integradora_comple.gvet_regitem(j).vlipi,
                                                0,
                                                regcliente.contribuinte,
                                                0,
                                                0,
                                                regcliente.consumidorfinal,
                                                nvl(integradora_comple.gregpcconsum.consideraisentoscomopf,'N'),
                                                integradora_comple.gvet_regitem(j).perfretecmv,
                                                integradora_comple.gvet_regitem(j).CUSTOFINEST,
                                                integradora_comple.gvet_regitem(j).txvenda,
                                                integradora_comple.gvet_regitem(j).perdesccusto,
                                                integradora_comple.gvet_regitem(j).CODICMTAB,
                                                integradora_comple.gvet_regitem(j).VLCUSTOREAL,
                                                integradora_comple.gvet_regitem(j).VLCUSTOFIN,
                                                integradora_comple.gvet_regitem(j).VLDESCCUSTOCMV,
                                                regcliente.codcli,
                                                regprecos.custoprecific,
                                                false,
                                                case when (integradora_comple.gvet_regpedido(i).condvenda = 5
                                                     or integradora_comple.gvet_regitem(j).bonific <> 'N') then true else false end,
                                                regprecos.codst,
                                                0,
                                                regprecos.CODICMTABSIMPNASC,
                                                0,
                                                nvl(integradora_comple.gvet_regitem(j).codfilialretira, integradora_comple.gvet_regpedido(i).codfilial),
                                                regprecos.CodIcmDifer,
                                                regprecos.custofinsemst,
                                                0,
                                                0,
                                                0,
                                                integradora_comple.gvet_regpedido(i).Numped,
                                                integradora_comple.gvet_regitem(j).Numseq,
                                                integradora_comple.gvet_regitem(j).Codprod
                                                );

                      IF NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0) > 0
                         AND (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('ACRESCICMSPARTILHAPRECO',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')  THEN
                        integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regitem(j).numpedrca;
                        integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regitem(j).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regitem(j).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TIPOLOG           := 'G';
                        integradora_comple.vLog.MSG               := 'ACRESCICMSPARTILHAPRECO ' || integradora_comple.gvet_regitem(j).codprod
                                                                     || ' VLCUSTOFIN = ' || integradora_comple.gvet_regitem(j).VLCUSTOFIN
                                                                     || ' VLICMSPART = ' || integradora_comple.gvet_regitem(j).VLICMSPART;
                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                        integradora_comple.gvet_regitem(j).VLCUSTOFIN := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0) + NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) + NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0);
                      END IF;

                      IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAREDPVENDASIMPLESNACMV','99','N') = 'S' THEN
                         integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA;
                      ELSE
                         --Aplica desconto do simples nacional após fazer a chamada do "calcularCMV" (1)
                        IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')
                          AND (nvl(regcliente.simplesnacional,'N') = 'S')
                        THEN

                          integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := ((regprecos.custofin * regprecos.percdescsimplesnac) / 100);

                        ELSIF (nvl(regcliente.simplesnacional,'N') = 'S' )  and nvl(integradora_comple.gvet_regitem(j).st,0) = 0
                        THEN
                          integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := nvl(integradora_comple.gvet_regitem(j).custofinest * (nvl(((nvl(integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA,0) / integradora_comple.gvet_regitem(j).pvenda) * 100),0) / 100),0);
                        END IF;
                      END IF;

                      IF NVL(INTEGRADORA_COMPLE.GVET_REGITEM(J).CODPRECOFIXO,0) > 0 THEN
                         SELECT NVL(APLICADESCONTOSIMPLES, 'S')
                           INTO VSAPLICADESCONTOSIMPLES
                           FROM PCPRECOPROM
                          WHERE CODPRECOPROM =
                                INTEGRADORA_COMPLE.GVET_REGITEM(J).CODPRECOFIXO;

                         IF VSAPLICADESCONTOSIMPLES  = 'N' THEN
                          INTEGRADORA_COMPLE.GVET_REGITEM(J).VLREDPVENDASIMPLESNA := 0;
                         END IF;

                      END IF;

                      IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')
                          AND (nvl(regcliente.simplesnacional,'N') = 'S')
                      THEN
                        integradora_comple.gvet_regitem(j).VLCUSTOFIN := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0); /*((NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) * regprecos.percredpvendasimplesnac) / 100)*/ -- VEN-10345
                      ELSIF (nvl(regcliente.simplesnacional,'N') = 'S' )  and nvl(integradora_comple.gvet_regitem(j).st,0) = 0
                      THEN
                        integradora_comple.gvet_regitem(j).VLCUSTOFIN  := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0)  - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);

                      END IF;

                    EXCEPTION
                      WHEN OTHERS THEN
                        integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                        integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TipoLog            := 'I';
                        integradora_comple.vLog.MSG                := 'Erro ao calcular CMV do produto ' || integradora_comple.gvet_regitem(j).codprod || chr(13) ||
                                                   'Msg Original: ' || SQLCODE || ' - ' || SQLERRM;
                        /** PRECOS **/
                        integradora_comple.vLog.ptabela            := integradora_comple.gvet_regitem(j).ptabela;
                        integradora_comple.vLog.PVENDA             := integradora_comple.gvet_regitem(j).pvenda;
                        integradora_comple.vLog.PBASE              := integradora_comple.gvet_regitem(j).pbaserca;

                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                         integradora_comple.gvet_regpedido(i).numpedrca,
                                         integradora_comple.gvet_regitem(j).codprod,
                                         integradora_comple.gvet_regitem(j).numseq,
                                         integradora_comple.gvet_regitem(j).codauxiliar,
                                         integradora_comple.gvet_regitem(j).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         integradora_comple.gvet_regpedido(i).CODUSUR,
                                         integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                         NULL,
                                         '3',
                                         'Erro ao calcular cmv. ' || SQLCODE || ' ' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                         NULL,
                                         integradora_comple.gvet_regitem(j).numseqfv);

                    END;

                    vnperluc := ((integradora_comple.gvet_regitem(j).pvenda - integradora_comple.gvet_regitem(j).vlcustofin) / integradora_comple.gvet_regitem(j).pvenda) * 100;


                    -- busca percentual de comissao
                    vsmensagem_comiss := NULL;

                    SELECT COUNT(*)
                      INTO vicont
                      FROM pctabcomiss p;

                    IF vicont <> 0
                    THEN
                      vbUsaPcTabComiss := TRUE;
                    ELSE
                      vbUsaPcTabComiss := FALSE;
                    END IF;

                    SELECT COUNT(*)
                      INTO vicont
                      FROM pccomissaousur p;

                    IF vicont <> 0
                    THEN
                      vbUsaPcComissaoUsur := TRUE;
                    ELSE
                      vbUsaPcComissaoUsur := FALSE;
                    END IF;


                    SELECT COUNT(*)
                      INTO vicont
                      FROM pccomissaoplpag p;

                    IF vicont <> 0
                    THEN
                      vbUsaPcComissaoplpag := TRUE;
                    ELSE
                      vbUsaPCComissaoPlPag := FALSE;
                    END IF;


                    SELECT COUNT(*)
                      INTO vicont
                      FROM pccomissaoregiao p;

                    IF vicont <> 0
                    THEN
                      vbUsaPcComissaoregiao := TRUE;
                    ELSE
                      vbUsaPcComissaoregiao := FALSE;
                    END IF;

                    IF regfilial.broker = 'S'
                    THEN
                      vbUsaPCComissaofilial := TRUE;
                    ELSE
                      vbUsaPCComissaofilial := FALSE;
                    END IF;

                    -- 0.015514.2015 - Não permitir comissão para itens bonificados. - Guilherme Freitas
                    if integradora_comple.gvet_regitem(j).percom is null then
                      integradora_comple.gvet_regitem(j).percom := 0;
                    end if;

					IF integradora_comple.gvet_regitem(J).CODCOMBO > 0 THEN
                      BEGIN
                        SELECT NVL(UTILIZACODPRODPRINC, 'N'), TIPOCAMPANHA
                          INTO VSUTILIZACODPRODPRINC, VSTIPOCAMPANHA
                          FROM PCDESCONTOC
                         WHERE CODIGO = integradora_comple.gvet_regitem(J)
                              .CODCOMBO;
                      EXCEPTION
                        WHEN OTHERS THEN
                          VSUTILIZACODPRODPRINC := 'N';
                      END;

                      IF VSTIPOCAMPANHA <> 'SQP' THEN
                        IF VSUTILIZACODPRODPRINC = 'S' THEN
                            SELECT SUM(NVL(QT, 0))
                              INTO VNQTTOTAL
                              FROM PCPEDIFV I, PCPRODUT P
                             WHERE I.CODPROD = P.CODPROD
                               AND I.NUMPEDRCA = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                  .NUMPEDRCA
                               AND I.CODUSUR = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                  .CODUSUR
                               AND I.DTABERTURAPEDPALM = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                  .DTABERTURAPEDPALM
                               AND P.CODPRODPRINC IN
                                   (SELECT NVL(CODPRODPRINC, CODPROD)
                                      FROM PCPRODUT
                                     WHERE PCPRODUT.CODPROD = INTEGRADORA_COMPLE.GVET_REGITEM(J).CODPROD);
                        ELSE
                          SELECT SUM(NVL(QT, 0))
                            INTO VNQTTOTAL
                            FROM PCPEDIFV
                           WHERE NUMPEDRCA = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                .NUMPEDRCA
                             AND CODUSUR = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                .CODUSUR
                             AND DTABERTURAPEDPALM = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                .DTABERTURAPEDPALM
                             AND CODPROD = INTEGRADORA_COMPLE.GVET_REGITEM(J)
                                .CODPROD;
                        END IF;

                        BEGIN
                          SELECT NAODEBITCCRCA,
                                 CREDITAPOLITICA,
                                 Alterarptabela,
                                 PERDESC
                            INTO P_VSNAODEBITACCRCA,
                                 P_VSCREDITACCRCA,
                                 p_vsAlterarPtabela,
                                 P_VDPERCDESCPOLITICA
                            FROM (SELECT NVL(C.NAODEBITCCRCA, 'S') NAODEBITCCRCA,
                                         NVL(C.CREDITAPOLITICA, 'N') CREDITAPOLITICA,
                                         NVL(C.Alterarptabela, 'N') Alterarptabela,
                                         NVL(I.PERDESC, 0) PERDESC
                                    FROM PCDESCONTOC C, PCDESCONTOI I
                                   WHERE C.CODIGO = I.CODIGO
                                     AND C.CODIGO = integradora_comple.gvet_regitem(J)
                                        .CODCOMBO
                                     AND ((I.CODPROD = integradora_comple.gvet_regitem(J)
                                         .CODPROD AND
                                         NVL(C.UTILIZACODPRODPRINC, 'N') = 'N') OR

                                         (I.CODPROD =
                                         (SELECT PCPRODUT.CODPRODPRINC
                                              FROM PCPRODUT
                                             WHERE CODPROD = integradora_comple.gvet_regitem(J)
                                                  .CODPROD) AND
                                         NVL(C.UTILIZACODPRODPRINC, 'N') = 'S'))
                                     AND CASE C.TIPOCAMPANHA
                                           WHEN 'MIQ' THEN
                                            DECODE(VNQTTOTAL,
                                                   0,
                                                   INTEGRADORA_COMPLE.GVET_REGITEM(J).QT,
                                                   VNQTTOTAL)
                                           ELSE
                                            999999
                                         END BETWEEN I.QTMINIMA AND
                                         DECODE(NVL(I.QTMAXIMA, 0),
                                                0,
                                                999999,
                                                I.QTMAXIMA)
                                   ORDER BY NVL(I.PERDESC, 0) DESC)
                           WHERE ROWNUM = 1;

                        EXCEPTION
                          WHEN OTHERS THEN
                            begin
                              SELECT NVL(C.NAODEBITCCRCA, 'S'),
                                     NVL(C.CREDITAPOLITICA, 'N'),
                                     NVL(C.Alterarptabela, 'N')
                                INTO P_VSNAODEBITACCRCA,
                                     P_VSCREDITACCRCA,
                                     p_vsAlterarPtabela
                                FROM PCDESCONTOC C
                               WHERE C.CODIGO = integradora_comple.gvet_regitem(J)
                                    .CODCOMBO;

                              vnDescComboCODCOMBO    := integradora_comple.gvet_regitem(J)
                                                        .CODCOMBO;
                              vnDescComboCODCAMPANHA := 0;

                              P_VDPERCDESCPOLITICA := PKG_CAMPANHACOMBO.BUSCACAMPANHADESCONTO(integradora_comple.gvet_regpedido(i)
                                                                                              .CODFILIAL,
                                                                                              integradora_comple.gvet_regitem(J)
                                                                                              .CODPROD,
                                                                                              integradora_comple.gvet_regpedido(i)
                                                                                              .CODCLI,
                                                                                              integradora_comple.gvet_regpedido(i)
                                                                                              .numped,
                                                                                              CASE
                                                                                                WHEN regfilial.utilizavendaporembalagem = 'S' THEN
                                                                                                 integradora_comple.gvet_regitem(J).CODAUXILIAR
                                                                                                ELSE
                                                                                                 0
                                                                                              END,
                                                                                              'N',
                                                                                              vnDescComboCODCOMBO,
                                                                                              vnDescComboCODCAMPANHA);
                            EXCEPTION
                              WHEN OTHERS THEN
                                P_VSNAODEBITACCRCA   := 'S';
                                P_VSCREDITACCRCA     := 'N';
                                p_vsAlterarPtabela   := 'N';
                                P_VDPERCDESCPOLITICA := 0;
                            end;
                        END;

                      ELSE

                        begin
                          SELECT NVL(C.NAODEBITCCRCA, 'S'),
                                 NVL(C.CREDITAPOLITICA, 'N'),
                                 NVL(C.Alterarptabela, 'N')
                            INTO P_VSNAODEBITACCRCA,
                                 P_VSCREDITACCRCA,
                                 p_vsAlterarPtabela
                            FROM PCDESCONTOC C
                           WHERE C.CODIGO = integradora_comple.gvet_regitem(J)
                                .CODCOMBO;

                          P_VDPERCDESCPOLITICA := 0;

                          P_VDPERCDESCPOLITICA := INTEGRADORA_COMPLE.F_RETORNARDESCFAIXACAMPANHASQP(integradora_comple.gvet_regpedido(i)
                                                                                                   .NUMPEDRCA,
                                                                                                   integradora_comple.gvet_regpedido(i)
                                                                                                   .CODUSUR,
                                                                                                   integradora_comple.gvet_regpedido(i)
                                                                                                   .DTABERTURAPEDPALM,
                                                                                                   integradora_comple.gvet_regpedido(i)
                                                                                                   .CODFILIAL,
                                                                                                   integradora_comple.gvet_regitem  (J)
                                                                                                   .CODCOMBO,
                                                                                                   vsMsgRetornoFaixa,
                                                                                                   vnDescComboCODCAMPANHA,
                                                                                                   integradora_comple.gvet_regitem(j).CODPROD);
                        EXCEPTION
                          WHEN OTHERS THEN
                            P_VSNAODEBITACCRCA   := 'S';
                            P_VSCREDITACCRCA     := 'N';
                            p_vsAlterarPtabela   := 'N';
                            P_VDPERCDESCPOLITICA := 0;
                        end;

                      END IF;

                      IF (p_vsAlterarPtabela = 'S') THEN
                        integradora_comple.gvet_regitem(J).PTABELA := integradora_comple.gvet_regitem(J)
                                                                      .PTABELA * (1 -
                                                                                  (P_VDPERCDESCPOLITICA / 100));
                        integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                       .PTABELA;

                        integradora_comple.gvet_regitem(j).perdesc := integradora_comple.func_calcularperdescitem(integradora_comple.gvet_regitem(j).ptabela,integradora_comple.gvet_regitem(j).pvenda);


                      ELSIF (P_VSNAODEBITACCRCA = 'S') AND
                            (P_VSCREDITACCRCA = 'S') THEN
                        integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                       .PTABELA * (1 -
                                                                                   (P_VDPERCDESCPOLITICA / 100));
                      ELSIF (P_VSNAODEBITACCRCA = 'S') THEN
                        IF (integradora_comple.gvet_regitem(j).perdesc <= 0) THEN
                          integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                         .PTABELA;
                        ELSIF (integradora_comple.gvet_regitem(j)
                              .perdesc > 0) THEN
                          integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                         .PVENDA;
                        ELSE
                          integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                         .PTABELA;
                        END IF;
                      ELSE
                        integradora_comple.gvet_regitem(J).PBASERCA := integradora_comple.gvet_regitem(J)
                                                                       .PTABELA;
                      END IF;

                      integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regpedido(i)
                                                                   .numpedrca;
                      integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i)
                                                                   .CODUSUR;
                      integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regpedido(i)
                                                                   .CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regpedido(i)
                                                                   .DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog           := 'I';
                      integradora_comple.vLog.MSG               := 'Produto ' || integradora_comple.gvet_regitem(j)
                                                                  .codprod ||
                                                                   chr(13) ||
                                                                   'Combo: ' || integradora_comple.gvet_regitem(J)
                                                                  .CODCOMBO ||
                                                                   chr(13) ||
                                                                   'Perc. Desc. Combo  : ' || integradora_comple.gvet_regitem(j)
                                                                  .perdesc ||
                                                                   chr(13) ||
                                                                   'Debita RCA  : ' ||
                                                                   P_VSNAODEBITACCRCA ||
                                                                   'Credita RCA  : ' ||
                                                                   P_VSCREDITACCRCA ||
                                                                   chr(13) ||
                                                                   'Altera Preço Tabela  : ' ||
                                                                   p_vsAlterarPtabela ||
                                                                   chr(13) ||
                                                                   'Preço Tabela S/I : ' || integradora_comple.gvet_regitem(j)
                                                                  .ptabela ||
                                                                   chr(13) ||
                                                                   'Preço Venda S/I  : ' || integradora_comple.gvet_regitem(j)
                                                                  .pvenda ||
                                                                   chr(13) ||
                                                                   'Preço Base RCA S/I  : ' || integradora_comple.gvet_regitem(j)
                                                                  .pbaserca ||
                                                                   chr(13) ||
                                                                   'Perc. Desc. Política  : ' ||
                                                                   P_VDPERCDESCPOLITICA;
                      /** PRECOS **/
                      integradora_comple.vLog.ptabela := integradora_comple.gvet_regitem(j)
                                                         .ptabela;
                      integradora_comple.vLog.PVENDA  := integradora_comple.gvet_regitem(j)
                                                         .pvenda;
                      integradora_comple.vLog.PBASE   := integradora_comple.gvet_regitem(j)
                                                         .pbaserca;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog,
                                          (CASE WHEN integradora_comple.vLog.MSG LIKE
                                           '%ORA-%' THEN
                                           DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE
                                           TO_CHAR($$PLSQL_LINE) END));
                    END IF;

                    vnPvendaTemp := round(integradora_comple.gvet_regitem(j).pvenda,integradora_comple.gregpcconsum.numcasasdecvenda);
                    vnPtabelaTemp := round(integradora_comple.gvet_regitem(j).ptabela,integradora_comple.gregpcconsum.numcasasdecvenda);
                    vnPerDescTemp := nvl(ROUND((integradora_comple.func_calcularperdescitem(vnPtabelaTemp, vnPvendaTemp)),2),
                                         ROUND(integradora_comple.gvet_regitem(j).perdesc, 2));

                    IF integradora_comple.gvet_regitem(j).bonific = 'N'
                    THEN
                      BEGIN

                    if (integradora_comple.gvet_regpedido(i).condvenda not in (4, 5, 8, 10, 13, 11, 20) or
                       (integradora_comple.gvet_regpedido(i).condvenda = 9 and ferramentas.F_BUSCARPARAMETRO_ALFA('CON_CALCULACOMISSTV9',integradora_comple.gvet_regpedido(i).codfilial, 'N') = 'S')) and
                       NVL(integradora_comple.gvet_regitem(j).percom,0) = 0
                    then
                        integradora_comple.gvet_regitem(j).percom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido(regregiao.numregiao,
                                                                                              vnperluc,
                                                                                              vnPerDescTemp,
                                                                                              vbUsaPcTabComiss,
                                                                                              vbUsaPcComissaoUsur,
                                                                                              vbUsaPCComissaoPlPag,
                                                                                              vbUsaPCComissaoRegiao,
                                                                                              vbUsaPCComissaofilial,
                                                                                              integradora_comple.gregpcconsum.usacomissaoporrca,
                                                                                              integradora_comple.gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                                                                              integradora_comple.gregpcconsum.usacomissaoporcliente,
                                                                                              integradora_comple.gregpcconsum.USACOMISSAOPORLINHAPROD,
                                                                                              integradora_comple.gregpcconsum.comissaorcatipovenda,
                                                                                              regrca.tipovend,
                                                                                              regrca.percent,
                                                                                              regrca.percent2,
                                                                                              regproduto.codprod,
                                                                                              regproduto.pcomint1,
                                                                                              regproduto.PCOMEXT1,
                                                                                              regproduto.PCOMREP1,
                                                                                              regproduto.codlinhaprod,
                                                                                              regproduto.tipocomissao,
                                                                                              regproduto.codepto,
                                                                                              regproduto.codsec,
                                                                                              regproduto.classe,
                                                                                              integradora_comple.gvet_regitem(j).tipovenda,
                                                                                              integradora_comple.gvet_regitem(j).codplpag,
                                                                                              integradora_comple.gvet_regpedido(i).data,
                                                                                              integradora_comple.gvet_regpedido(i).codfilial,
                                                                                              coalesce(integradora_comple.GVET_REGITEM(j).codusur, integradora_comple.gvet_regpedido(i).CODUSUR),
                                                                                              regfilial.considerarcomissaozero,
                                                                                              regfilial.tipoavaliacaocomissao,
                                                                                              regcliente.percomcli,
                                                                                              regcliente.codcli,
                                                                                              integradora_comple.gvet_regitem(j).coddesconto,
                                                                                              integradora_comple.gvet_regorigemcomiss(j).codcomis,
                                                                                              integradora_comple.gvet_regorigemcomiss(j).codrotinacomis,
                                                                                              integradora_comple.gvet_regitem(j).LetraComiss,
                                                                                              vsmensagem_comiss,
                                                                                              integradora_comple.gvet_regitem(i).codauxiliar,
                                                                                              regprecos.pcomint1_emb,
                                                                                              regprecos.PCOMEXT1_emb,
                                                                                              regprecos.PCOMREP1_emb,
                                                                                              regfilial.utilizavendaporembalagem,
                                                                                              vnPtabelaTemp,
                                                                                              vnPvendaTemp,
                                                                                              integradora_comple.gregpcconsum.numcasasdecvenda);
                      end if;
                      EXCEPTION
                        WHEN OTHERS THEN
                          integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                          integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                          integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                          integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                          integradora_comple.vLog.TipoLog            := 'I';
                          integradora_comple.vLog.MSG                := 'Erro ao calcular comissão do produto ' || integradora_comple.gvet_regitem(j).codprod || chr(13) ||
                                                     'Msg Original: ' || SQLCODE || ' - ' || SQLERRM;
                          /** PRECOS **/
                          integradora_comple.vLog.ptabela            := integradora_comple.gvet_regitem(j).ptabela;
                          integradora_comple.vLog.PVENDA             := integradora_comple.gvet_regitem(j).pvenda;
                          integradora_comple.vLog.PBASE              := integradora_comple.gvet_regitem(j).pbaserca;

                          PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           integradora_comple.gvet_regitem(j).codprod,
                                           integradora_comple.gvet_regitem(j).numseq,
                                           integradora_comple.gvet_regitem(j).codauxiliar,
                                           integradora_comple.gvet_regitem(j).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).CODUSUR,
                                           integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                           NULL,
                                           '3',
                                           'Erro ao calcular comissão. ' || SQLCODE || ' ' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                           NULL,
                                           integradora_comple.gvet_regitem(j).numseqfv);

                      END;

                      integradora_comple.gvet_regorigemcomiss(j).percom := integradora_comple.gvet_regitem(j).percom;
                      integradora_comple.gvet_regorigemcomiss(j).perdesc := integradora_comple.gvet_regitem(j).perdesc;
                      integradora_comple.gvet_regorigemcomiss(j).tipocomissao := regproduto.tipocomissao;
                      integradora_comple.gvet_regorigemcomiss(j).codlinhaprod := regproduto.codlinhaprod;
                      integradora_comple.gvet_regorigemcomiss(j).ordemavaliacaocomissaorca := integradora_comple.gregpcconsum.ordemavaliacaocomissaorca;
                      integradora_comple.gvet_regorigemcomiss(j).usacomissaoporrca := integradora_comple.gregpcconsum.usacomissaoporrca;
                      integradora_comple.gvet_regorigemcomiss(j).usacomissaoporcliente := integradora_comple.gregpcconsum.usacomissaoporcliente;
                      integradora_comple.gvet_regorigemcomiss(j).usacomissaoporlinhaprod := integradora_comple.gregpcconsum.usacomissaoporlinhaprod;
                      integradora_comple.gvet_regorigemcomiss(j).comissaorcatipovenda := integradora_comple.gregpcconsum.comissaorcatipovenda;


                      IF vsmensagem_comiss IS NOT NULL
                      THEN
                        integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                        integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TipoLog            := 'I';
                        integradora_comple.vLog.MSG                := 'Produto ' || integradora_comple.gvet_regitem(j).codprod || chr(13) ||
                                                   'Msg: ' || vsmensagem_comiss;
                        /** PRECOS **/
                        integradora_comple.vLog.ptabela            := integradora_comple.gvet_regitem(j).ptabela;
                        integradora_comple.vLog.PVENDA             := integradora_comple.gvet_regitem(j).pvenda;
                        integradora_comple.vLog.PBASE              := integradora_comple.gvet_regitem(j).pbaserca;

                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                         integradora_comple.gvet_regpedido(i).numpedrca,
                                         integradora_comple.gvet_regitem(j).codprod,
                                         integradora_comple.gvet_regitem(j).numseq,
                                         integradora_comple.gvet_regitem(j).codauxiliar,
                                         integradora_comple.gvet_regitem(j).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         integradora_comple.gvet_regpedido(i).CODUSUR,
                                         integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                         NULL,
                                         '3',
                                         vsmensagem_comiss,
                                         NULL,
                                         integradora_comple.gvet_regitem(j).numseqfv);
                      END IF;



                      --207034 Comissão por Profissionais

                      IF integradora_comple.gvet_regpedido(i).codusur2 IS NOT NULL
                      THEN

                        BEGIN

                          funcoesvendas.Definir_Comissao_Profissional(integradora_comple.gvet_regitem(j).codprod,
                                                                      integradora_comple.gvet_regpedido(i).codcli,
                                                                      integradora_comple.gvet_regpedido(i).codusur2,
                                                                      integradora_comple.gvet_regitem(j).tipovenda,
                                                                      integradora_comple.gvet_regpedido(i).codfilial,
                                                                      regfilial.considerarcomissaozero,
                                                                      integradora_comple.gregpcconsum.comissaorcatipovenda,
                                                                      integradora_comple.gvet_regitem(j).percom2);
                        EXCEPTION
                          WHEN OTHERS THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             integradora_comple.gvet_regitem(j).codprod,
                                             integradora_comple.gvet_regitem(j).numseq,
                                             integradora_comple.gvet_regitem(j).codauxiliar,
                                             integradora_comple.gvet_regitem(j).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Erro ao calcular comissao para RCA 2',
                                             NULL,
                                             integradora_comple.gvet_regitem(j).numseqfv);
                        END;

                      END IF;

                      IF integradora_comple.gvet_regpedido(i).codusur3 IS NOT NULL
                      THEN

                        BEGIN

                          funcoesvendas.Definir_Comissao_Profissional(integradora_comple.gvet_regitem(j).codprod,
                                                                      integradora_comple.gvet_regpedido(i).codcli,
                                                                      integradora_comple.gvet_regpedido(i).codusur3,
                                                                      integradora_comple.gvet_regitem(j).tipovenda,
                                                                      integradora_comple.gvet_regpedido(i).codfilial,
                                                                      regfilial.considerarcomissaozero,
                                                                      integradora_comple.gregpcconsum.comissaorcatipovenda,
                                                                      integradora_comple.gvet_regitem(j).percom3);
                        EXCEPTION
                          WHEN OTHERS THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             integradora_comple.gvet_regitem(j).codprod,
                                             integradora_comple.gvet_regitem(j).numseq,
                                             integradora_comple.gvet_regitem(j).codauxiliar,
                                             integradora_comple.gvet_regitem(j).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Erro ao calcular comissao para RCA 3',
                                             NULL,
                                             integradora_comple.gvet_regitem(j).numseqfv);
                        END;

                      END IF;

                      IF integradora_comple.gvet_regpedido(i).codusur4 IS NOT NULL
                      THEN

                        BEGIN

                          funcoesvendas.Definir_Comissao_Profissional(integradora_comple.gvet_regitem(j).codprod,
                                                                      integradora_comple.gvet_regpedido(i).codcli,
                                                                      integradora_comple.gvet_regpedido(i).codusur4,
                                                                      integradora_comple.gvet_regitem(j).tipovenda,
                                                                      integradora_comple.gvet_regpedido(i).codfilial,
                                                                      regfilial.considerarcomissaozero,
                                                                      integradora_comple.gregpcconsum.comissaorcatipovenda,
                                                                      integradora_comple.gvet_regitem(j).percom4);
                        EXCEPTION
                          WHEN OTHERS THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             integradora_comple.gvet_regitem(j).codprod,
                                             integradora_comple.gvet_regitem(j).numseq,
                                             integradora_comple.gvet_regitem(j).codauxiliar,
                                             integradora_comple.gvet_regitem(j).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Erro ao calcular comissao para RCA 4',
                                             NULL,
                                             integradora_comple.gvet_regitem(j).numseqfv);
                        END;

                      END IF;
                    END IF;


                    IF integradora_comple.gvet_regpedido(i).condvenda = 20
                    THEN

                      integradora_comple.gvet_regitem(j).percom := 0;

                    END IF;

                    IF nvl(integradora_comple.gregpcconsum.incluircomissaocmvvenda,
                           'S') = 'N'
                    THEN
                      vnpercom := 0;
                    ELSE
                      vnpercom := integradora_comple.gvet_regitem(j).percom;
                    END IF;



                    BEGIN
                      -- 53 parâmetros
                      funcoesvendas.calcularcmv(FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('IMPOSTOCOMISSAORCA',integradora_comple.gvet_regpedido(i).codfilial,'A'),
                                                integradora_comple.gregpcconsum.aplicarindicecmv,
                                                integradora_comple.gregpcconsum.INCLUIRCOMISSAOCMVVENDA,
                                                nvl(integradora_comple.gregpcconsum.txvenda,0),
                                                regcliente.tipofj,
                                                regcliente.utilizaiesimplificada,
                                                regcliente.ieent,
                                                regproduto.freteespecial,
                                                CASE
                                                  WHEN ((integradora_comple.gvet_regpedido(i).origemped = 'B') or
                                                        (integradora_comple.gvet_regpedido(i).origemped = 'R')) AND
                                                        (paramfilial.obtercomovarchar2('RETIRARCMVDOFRETETERCEIROPEDBALCAO', integradora_comple.gvet_regpedido(i).codfilial) = 'S') THEN
                                                    0
                                                  ELSE
                                                    regregiao.perfreteterceiros
                                                END,
                                                regregiao.perfreteespecial,
                                                regprecos.custofin,
                                                regprecos.custoreal,
                                                regprecos.perdesccusto,
                                                regprecos.codicmtab,
                                                vbcodicmtabpf,
                                                regprecos.codicmtabpf,
                                                integradora_comple.gvet_regpedido(i).percvenda,
                                                integradora_comple.gvet_regitem(j).pvenda,
                                                --integradora_comple.gvet_regitem(j).pvenda - nvl(integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA,0),
                                                vnpercom,
                                                integradora_comple.gvet_regitem(j).st,
                                                integradora_comple.gvet_regitem(j).VLFECP,
                                                integradora_comple.gvet_regitem(j).vlipi,
                                                0,
                                                regcliente.contribuinte,
                                                0,
                                                0,
                                                regcliente.consumidorfinal,
                                                nvl(integradora_comple.gregpcconsum.consideraisentoscomopf,'N'),
                                                integradora_comple.gvet_regitem(j).perfretecmv,
                                                integradora_comple.gvet_regitem(j).CUSTOFINEST,
                                                integradora_comple.gvet_regitem(j).txvenda,
                                                integradora_comple.gvet_regitem(j).perdesccusto,
                                                integradora_comple.gvet_regitem(j).CODICMTAB,
                                                integradora_comple.gvet_regitem(j).VLCUSTOREAL,
                                                integradora_comple.gvet_regitem(j).VLCUSTOFIN,
                                                integradora_comple.gvet_regitem(j).VLDESCCUSTOCMV,
                                                regcliente.codcli,
                                                regprecos.custoprecific,
                                                false,
                                                case when (integradora_comple.gvet_regpedido(i).condvenda = 5
                                                     or integradora_comple.gvet_regitem(j).bonific <> 'N') then true else false end,
                                                regprecos.codst,
                                                0,
                                                regprecos.CODICMTABSIMPNASC,
                                                0,
                                                nvl(integradora_comple.gvet_regitem(j).codfilialretira, integradora_comple.gvet_regpedido(i).codfilial),
                                                regprecos.CodIcmDifer,
                                                regprecos.custofinsemst,
                                                0,
                                                0,
                                                0,
                                                integradora_comple.gvet_regpedido(i).Numped,
                                                integradora_comple.gvet_regitem(j).Numseq,
                                                integradora_comple.gvet_regitem(j).Codprod);

					  IF NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0) > 0
                         AND (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('ACRESCICMSPARTILHAPRECO',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')  THEN
                        integradora_comple.vLog.NUMPEDRCA         := integradora_comple.gvet_regitem(j).numpedrca;
                        integradora_comple.vLog.CODUSUR           := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI            := integradora_comple.gvet_regitem(j).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM := integradora_comple.gvet_regitem(j).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TIPOLOG           := 'G';
                        integradora_comple.vLog.MSG               := 'ACRESCICMSPARTILHAPRECO ' || integradora_comple.gvet_regitem(j).codprod
                                                                     || ' VLCUSTOFIN = ' || integradora_comple.gvet_regitem(j).VLCUSTOFIN
                                                                     || ' VLICMSPART = ' || integradora_comple.gvet_regitem(j).VLICMSPART;
                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                        integradora_comple.gvet_regitem(j).VLCUSTOFIN := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0) + NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) + NVL(integradora_comple.gvet_regitem(j).VLICMSPART, 0);
                      END IF;

                      IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAREDPVENDASIMPLESNACMV','99','N') = 'S')
                      THEN
                        integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA;
                      ELSE
                        --Aplica desconto do simples nacional após fazer a chamada do "calcularCMV" (2)
                        IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')
                          AND (nvl(regcliente.simplesnacional,'N') = 'S')
                        THEN

                          integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := ((regprecos.custofin * regprecos.percredpvendasimplesnac) / 100);
                        --integradora_comple.gvet_regitem(j).VLCUSTOFIN := integradora_comple.gvet_regitem(j).VLCUSTOFIN - integradora_comple.gvet_regitem(j).vlredcmvsimplesnac;
                          --integradora_comple.gvet_regitem(j).VLCUSTOREAL := integradora_comple.gvet_regitem(j).CUSTOFINEST - integradora_comple.gvet_regitem(j).vlredcmvsimplesnac;
                        --integradora_comple.gvet_regitem(j).VLCUSTOREAL := integradora_comple.gvet_regitem(j).VLCUSTOREAL - ((integradora_comple.gvet_regitem(j).VLCUSTOREAL * regprecos.percredpvendasimplesnac) / 100);

                        ELSIF (nvl(regcliente.simplesnacional,'N') = 'S' )
                        THEN
                           if nvl(integradora_comple.gvet_regitem(j).st,0) = 0
                           THEN
                              --integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := nvl(integradora_comple.gvet_regitem(j).custofinest * (nvl(integradora_comple.gvet_regitem(j).vlredpvendasimplesna,0) / 100),0);
                              integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := nvl(integradora_comple.gvet_regitem(j).custofinest * (nvl(((nvl(integradora_comple.gvet_regitem(j).VLREDPVENDASIMPLESNA,0) / integradora_comple.gvet_regitem(j).pvenda) * 100),0) / 100),0);

                            --integradora_comple.gvet_regitem(j).VLCUSTOFIN := integradora_comple.gvet_regitem(j).VLCUSTOFIN - integradora_comple.gvet_regitem(j).vlredcmvsimplesnac;
                            --integradora_comple.gvet_regitem(j).VLCUSTOREAL := integradora_comple.gvet_regitem(j).VLCUSTOREAL - integradora_comple.gvet_regitem(j).vlredcmvsimplesnac;
                           else
                                integradora_comple.gvet_regitem(j).vlredcmvsimplesnac := 0;
                           end if;
                        END IF;
                      END IF;

                      IF (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('USADESCSIMPLESNAC',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S')
                        AND (nvl(regcliente.simplesnacional,'N') = 'S')
                      THEN
                        integradora_comple.gvet_regitem(j).VLCUSTOFIN := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);/* - ((NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) * regprecos.percredpvendasimplesnac) / 100);  */
                      ELSIF (nvl(regcliente.simplesnacional,'N') = 'S' ) THEN
                        integradora_comple.gvet_regitem(j).VLCUSTOFIN  := NVL(integradora_comple.gvet_regitem(j).VLCUSTOFIN, 0)  - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);
                        integradora_comple.gvet_regitem(j).VLCUSTOREAL := NVL(integradora_comple.gvet_regitem(j).VLCUSTOREAL, 0) - NVL(integradora_comple.gvet_regitem(j).vlredcmvsimplesnac, 0);
                      END IF;

                    EXCEPTION
                      WHEN OTHERS THEN
                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                         integradora_comple.gvet_regpedido(i).numpedrca,
                                         integradora_comple.gvet_regitem(j).codprod,
                                         integradora_comple.gvet_regitem(j).numseq,
                                         integradora_comple.gvet_regitem(j).codauxiliar,
                                         integradora_comple.gvet_regitem(j).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         integradora_comple.gvet_regpedido(i).codusur,
                                         integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                         NULL,
                                         '3',
                                         'Erro ao calcular comissão. ' || SQLCODE || ' ' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                         NULL,
                                         integradora_comple.gvet_regitem(j).numseqfv);

                    END;
                    -----------------------------------------------------------------------------------

                    vnpercverbacmv := NULL;

                    vbvalidoverbacmv := funcoesvendas.calcularpercverbacmv(integradora_comple.gvet_regitem(j).codprod,
                                                                           regproduto.codsec,
                                                                           regproduto.codepto,
                                                                           integradora_comple.gvet_regpedido(i).data,
                                                                           integradora_comple.gvet_regpedido(i).codcli,
                                                                           integradora_comple.gregpcconsum.numcasasdecvenda,
                                                                           vsmensagemverbacmv,
                                                                           vnpercverbacmv,
                                                                           regcliente.codrede);

                    IF vsmensagemverbacmv IS NOT NULL
                    THEN

                      IF substr(vsmensagemverbacmv,1,1) IN ('S','N')
                      THEN

                        vsalteracontacorrente := substr(vsmensagemverbacmv,1,1);

                      ELSE

                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                         integradora_comple.gvet_regpedido(i).numpedrca,
                                         integradora_comple.gvet_regitem(j).codprod,
                                         integradora_comple.gvet_regitem(j).numseq,
                                         integradora_comple.gvet_regitem(j).codauxiliar,
                                         integradora_comple.gvet_regitem(j).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         integradora_comple.gvet_regpedido(i).codusur,
                                         integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                         NULL,
                                         '3',
                                         vsmensagemverbacmv,
                                         NULL,
                                         integradora_comple.gvet_regitem(j).numseqfv);
                      END IF;

                    END IF;

                    IF nvl(vnpercverbacmv,
                           0) <> 0
                    THEN

                      integradora_comple.gvet_regitem(j).vlverbacmvcli := integradora_comple.gvet_regitem(j).pvenda * (vnpercverbacmv / 100);

                      integradora_comple.gvet_regitem(j).vlcustofin := integradora_comple.gvet_regitem(j).vlcustofin + integradora_comple.gvet_regitem(j).vlverbacmvcli;

                      integradora_comple.gvet_regitem(j).vlcustoreal := integradora_comple.gvet_regitem(j).vlcustoreal + integradora_comple.gvet_regitem(j).vlverbacmvcli;


                      IF vsalteracontacorrente = 'S'
                      THEN

                        integradora_comple.gvet_regitem(j).pbaserca := round(integradora_comple.gvet_regitem(j).pbaserca + integradora_comple.gvet_regitem(j).vlverbacmvcli,
                                                          integradora_comple.gregpcconsum.numcasasdecvenda);

                      END IF;

                    END IF;

                    -----------------------------------------------------------
                    --Autor: Rodrigo Santos
                    --Solicitação: HIS.05072.2014
                    --Data: 12/12/2014
                    --Descrição: Implementação referente a item BNF no pedido TV1.

                    IF integradora_comple.gvet_regitem(j).bonific <> 'N' THEN
                      integradora_comple.gvet_regitem(j).pbonific := integradora_comple.gvet_regitem(j).pvenda;
                    END IF;

                -----------------------------------------------------------
                    --Autor: Rodrigo Santos
                    --Solicitação: HIS.04878.2014
                    --Data: 10/12/2014
                    --Descrição: Verificar margem mínima de lucratividade cadastrada
                    --           na rotina 238.
                    vnMargemItem := 0;
                    vnMargemMinItem := 0;

                    IF integradora_comple.RetornarMargemMinimaItem(integradora_comple.gvet_regitem(j).codprod,
                                                              integradora_comple.gvet_regpedido(i).codfilial,
                                                              vnMargemMinItem)
                    THEN
                      vnMargemItem := round((((integradora_comple.gvet_regitem(j).pvenda - integradora_comple.gvet_regitem(j).vlcustofin) / integradora_comple.gvet_regitem(j).pvenda) * 100),
                                            integradora_comple.gregpcconsum.numcasasdecvenda);

                      IF vnMargemItem < vnMargemMinItem THEN

                        vsmensagem := vsmensagem || 'Margem mínima de lucratividade do item não alcançada(Rotina 238).';
                        vsmensagem := vsmensagem || 'Margem mínima: ' || ROUND(vnMargemMinItem, integradora_comple.gregpcconsum.numcasasdecvenda) || ' ';
                        vsmensagem := vsmensagem || 'Margem praticada: ' || ROUND(vnMargemItem, integradora_comple.gregpcconsum.numcasasdecvenda) || ';';

                        IF (regfilial.tipoimportacaovenda = 'RP') THEN
                          integradora_comple.gvet_regpedido(i).valido := FALSE;
                        ELSE
                          integradora_comple.gvet_regitem(j).valido := FALSE;
                        END IF;

                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                         integradora_comple.gvet_regpedido(i).numpedrca,
                                         integradora_comple.gvet_regitem(j).codprod,
                                         integradora_comple.gvet_regitem(j).numseq,
                                         integradora_comple.gvet_regitem(j).codauxiliar,
                                         integradora_comple.gvet_regitem(j).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         integradora_comple.gvet_regpedido(i).codusur,
                                         integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                         NULL,
                                         '3',
                                         vsmensagem || ';',
                                         NULL,
                                         integradora_comple.gvet_regitem(j).numseqfv);

                      END IF;
                    END IF;

                    -- Recalcular PBASERCA dos itens da cesta --------------------------------------------------------------
                    IF integradora_comple.GVET_REGITEM(J).CESTA = 'S' AND  integradora_comple.GVET_REGITEM(J).PBASERCA <>  integradora_comple.GVET_REGITEM(J).PTABELA THEN

                        P_VDPERCDESCPOLITICA := integradora_comple.func_calcularperdescitem(integradora_comple.GVET_REGITEM(J).PTABELA,
                                                                                            integradora_comple.GVET_REGITEM(J).PBASERCA);

                        vncount := integradora_comple.gvet_regitenscesta.COUNT;
                        vnPVENDAMAIOR := 0;
                        vnsubtotal    := 0;

                        FOR x IN 1 .. vncount
                        LOOP

                          IF integradora_comple.gvet_regpedido(i).numped = integradora_comple.gvet_regitenscesta(x).numped
                             AND integradora_comple.GVET_REGITEM(J).codprod = integradora_comple.gvet_regitenscesta(x).codprodcesta
                          THEN

                            integradora_comple.gvet_regitenscesta(x).PBASERCA := round(integradora_comple.gvet_regitenscesta(x).PTABELA - (integradora_comple.gvet_regitenscesta(x).PTABELA * (P_VDPERCDESCPOLITICA/100)),
                                                                    integradora_comple.gregpcconsum.numcasasdecvenda);


                            vnsubtotal := vnsubtotal + (integradora_comple.gvet_regitenscesta(x).PBASERCA * integradora_comple.gvet_regitenscesta(x).qt);

                            IF integradora_comple.gvet_regitenscesta(x).PBASERCA > vnpvendamaior
                            THEN
                              vnpvendamaior := integradora_comple.gvet_regitenscesta(x).PBASERCA;
                              vnreg         := x;

                            END IF;

                          END IF;


                        END LOOP;

                        IF vnsubtotal <> (integradora_comple.GVET_REGITEM(J).PBASERCA - NVL(integradora_comple.GVET_REGITEM(J).VLREPASSE,0))
                        THEN

                          vndif := (integradora_comple.GVET_REGITEM(J).PBASERCA - vnsubtotal) / integradora_comple.gvet_regitenscesta(vnreg).qt;

                          integradora_comple.gvet_regitenscesta(vnreg).PBASERCA := round(integradora_comple.gvet_regitenscesta(vnreg).PBASERCA + vndif,
                                                                    integradora_comple.gregpcconsum.numcasasdecvenda);


                        END IF;

                    END IF;
                    -- Fim recalculo pbaserca itens da cesta ----------------------------------------------------------------

                    -----------------------------------------------------------

                    IF integradora_comple.gvet_regitem(j).valido = TRUE
                    THEN

                      IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
                      THEN

                       IF ferramentas.F_BUSCARPARAMETRO_ALFA('FIL_MONTARKITAUTOMATICAMENTE', integradora_comple.gvet_regpedido(i).codfilial, 'N') = 'S'
                        THEN

                          SELECT COUNT(*)
                                INTO vnexistecesta
                                FROM pcpedifv,
                                     pcprodut
                               WHERE pcpedifv.numpedrca  = integradora_comple.gvet_regpedido(i).numpedrca
                                 AND pcpedifv.codusur    = coalesce(integradora_comple.GVET_REGITEM(j).codusur, integradora_comple.gvet_regpedido(i).CODUSUR)
                                 AND pcpedifv.dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                                 AND pcpedifv.codprod = pcprodut.codprod
                                 AND nvl(pcprodut.tipomerc,
                                         'X') = 'CB';

                          IF vnexistecesta > 0
                          THEN

                            vendas.montar_cb(integradora_comple.gvet_regitem(j).codprod
                                            ,integradora_comple.gvet_regpedido(i).codfilial
                                            ,integradora_comple.gvet_regitem(j).qt
                                            ,vsmensagemkit
                                            ,integradora_comple.gvet_regpedido(i).codfilialretira
                                            ,integradora_comple.gvet_regpedido(i).codfilialnf);

                            IF not ((vsmensagemkit = 'OK') or
                                    ((trim(vsmensagemkit) = 'PRODUTOS QUE COMPÕEM O KIT CESTA NÃO TEM ESTOQUE.') and
                                     (NVL(regfilial.aceitavendasemestfv,'N') = 'S')))
                            THEN
                              integradora_comple.gvet_regpedido(i).valido := FALSE;
                              integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                               integradora_comple.gvet_regpedido(i).numpedrca,
                                               NULL,
                                               NULL,
                                               NULL,
                                               integradora_comple.gvet_regpedido(i).cgccli,
                                               NULL,
                                               NULL,
                                               NULL,
                                               integradora_comple.gvet_regpedido(i).codusur,
                                               integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                               NULL,
                                               '2',
                                               vsmensagemkit || ';',
                                               NULL,
                                               null);
                            END IF;
                          END IF;
                        END IF;

                          IF regfilial.broker = 'N'
                          THEN

                            IF (integradora_comple.gvet_regpedido(i).condvenda <> 7)
                               or (regfilial.RESERVARESTOQUETV7 = 'S')
                            THEN

                              IF Regfilial.utilizavendaporembalagem = 'S' then
                               BEGIN
                                 if (FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('UTILIZAEMBALAGEMFILIALRETIRA',integradora_comple.gvet_regpedido(i).codfilial,'N') = 'N' ) then

                                   select nvl(qtunit, 1)
                                     into regprecos.qtunit
                                     from pcembalagem e
                                    where e.codprod = integradora_comple.gvet_regitem(j).codprod
                                      and e.codfilial = integradora_comple.gvet_regpedido(i).codfilial
                                      and e.codauxiliar = integradora_comple.gvet_regitem(j).codauxiliar;
                                 else
                                   select nvl(qtunit, 1)
                                     into regprecos.qtunit
                                     from pcembalagem e
                                    where e.codprod = integradora_comple.gvet_regitem(j).codprod
                                      and e.codfilial = integradora_comple.gvet_regitem(j).codfilialretira
                                      and e.codauxiliar = integradora_comple.gvet_regitem(j).codauxiliar;
                                 end if;
                               exception
                                 when others then
                                   regprecos.qtunit := 1;
                               end;

                             END IF;

                              proc_verificaCorte(integradora_comple.gvet_regpedido(i),
                                                 integradora_comple.gvet_regitem(j),
                                                 regfilial,
                                                 regcliente,
                                                 regprecos.qtunit);

                            END IF;
                          END IF;
                      END IF;

                      --tarefa 136584

                      IF regproduto.tipomerc IN ('M', 'MA')
                         AND nvl(integradora_comple.gvet_regitem(j).poriginal,
                                 0) <> 0
                      THEN

                        integradora_comple.gvet_regitem(j).descprecofab := ((integradora_comple.gvet_regitem(j).poriginal - integradora_comple.gvet_regitem(j).pvenda) / (integradora_comple.gvet_regitem(j).poriginal * 100));

                      END IF;


                      -- insere item do pedido
                      vntotpesoped := vntotpesoped + (regproduto.pesobruto * GREATEST(NVL(integradora_comple.gvet_regitem(j).qt,0),0)); -- Não pega QT < 0.
                      vntotvolumeped := vntotvolumeped + (regproduto.volume * integradora_comple.gvet_regitem(j).qt);

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'G';
                      integradora_comple.vLog.MSG                := 'Inserindo produto ' || integradora_comple.gvet_regitem(j).codprod ||
                                                                    ' . integradora_comple.gvet_regpedido(i).orcamento = ' || integradora_comple.gvet_regpedido(i).orcamento;
                      /** PRECOS **/
                      integradora_comple.vLog.ptabela            := integradora_comple.gvet_regitem(j).ptabela;
                      integradora_comple.vLog.PTABELA_SEMIMPOSTO := 0;
                      integradora_comple.vLog.PVENDA             := integradora_comple.gvet_regitem(j).pvenda;
                      integradora_comple.vLog.PVENDA_SEMIMPOSTO  := 0;
                      integradora_comple.vLog.PBASE              := integradora_comple.gvet_regitem(j).pbaserca;
                      integradora_comple.vLog.PBASE_SEMIMPOSTO   := 0;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                      IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
                      THEN

                        integradora_comple.gvet_regitem(j).valido := func_inseriritemorcamento(integradora_comple.gvet_regpedido(i),
                                                                            integradora_comple.gvet_regitem(j),
                                                                            regprecos,
                                                                            regproduto,
                                                                            regrca,
                                                                            regcliente,
                                                                            regfilial,
                                                                            regregiao,
                                                                            integradora_comple.gvet_regorigempreco(j));

                      ELSE
                        integradora_comple.gvet_regitem(j).valido := func_inseriritempedido(integradora_comple.gvet_regpedido(i),
                                                                         integradora_comple.gvet_regitem(j),
                                                                         regprecos,
                                                                         regproduto,
                                                                         integradora_comple.gvet_regorigempreco(j),
                                                                         integradora_comple.gvet_regorigemcomiss(j),
                                                                         integradora_comple.gvet_regorigemdesc(j),
                                                                         regrca,
                                                                         regcliente,
                                                                         regfilial,
                                                                         regregiao);
                      END IF;

                    END IF;
                  END IF;
                END IF;

              EXCEPTION
                WHEN OTHERS THEN

                  integradora_comple.gvet_regpedido(i).valido := FALSE;
                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                   integradora_comple.gvet_regpedido(i).numpedrca,
                                   integradora_comple.gvet_regitem(j).codprod,
                                   integradora_comple.gvet_regitem(j).numseq,
                                   integradora_comple.gvet_regitem(j).codauxiliar,
                                   integradora_comple.gvet_regitem(j).cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   integradora_comple.gvet_regpedido(i).codusur,
                                   integradora_comple.gvet_regitem(j).dtaberturapedpalm,
                                   NULL,
                                   '3',
                                   SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                                   NULL,
                                   integradora_comple.gvet_regitem(j).numseqfv);
                  EXIT;
              END;
            END LOOP; -- FOR j IN 1 .. vncontitem

            IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
            THEN


              FOR reg_combos IN (SELECT DISTINCT pcpedi.codcombo
                                   FROM pcpedi
                                  WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                    AND codcombo IS NOT NULL)
              LOOP

                 vbvalidodescontocombo := False;
                --Verifica sé combo continuo
                BEGIN
                  SELECT PCDESCONTOC.COMBOCONTINUO
                    INTO VSCOMBOCONTINUO
                    FROM PCDESCONTOC
                   WHERE PCDESCONTOC.CODIGO = REG_COMBOS.CODCOMBO;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    VSCOMBOCONTINUO := 'N';
                END;
                --HIS.03255.2016
                --(vsComboContinuo = 'S')then
                  --Verifica o desconto produto a produto
                  FOR reg_combos_grupo IN (SELECT PVENDA, PTABELA, CODPROD,PERDESC, NUMSEQ FROM PCPEDI WHERE NUMPED = integradora_comple.gvet_regpedido(i).numped
                                                                              AND CODCOMBO = reg_combos.codcombo
                                                                              AND PERDESC > 0)
                                                                              LOOP

                    VNPERDESCOMBOCALC :=   PKG_CAMPANHACOMBO.BUSCADESCONTO(integradora_comple.gvet_regpedido(I).CODFILIAL,
                                                   REG_COMBOS_GRUPO.CODPROD,
                                                   integradora_comple.gvet_regpedido(I).CODCLI,
                                                   integradora_comple.gvet_regpedido(I).NUMPED,
                                                   0,
                                                   'N',
                                                   reg_combos.codcombo);


                    VNPERDESCOMBOCALC :=  ((reg_combos_grupo.Ptabela -  round(reg_combos_grupo.Ptabela *(1-  VNPERDESCOMBOCALC/100),integradora_comple.gregpcconsum.numcasasdecvenda))/
                                          reg_combos_grupo.Ptabela)*100;
                    --Verifica se o desconto informado é maior do que o da campanha
                    IF(trunc(REG_COMBOS_GRUPO.PERDESC,2) > round(VNPERDESCOMBOCALC,2))THEN
                      vbvalidodescontocombo := False;
                    ELSE
                      vbvalidodescontocombo := True;
                    END IF;

                    BEGIN
                      SELECT NVL(C.NAODEBITCCRCA, 'S'),
                           NVL(C.CREDITAPOLITICA, 'N'),
                           NVL(C.ALTERARPTABELA, 'N') ALTERARPTABELA,
                           NVL(tipocampanha, 'X') tipocampanha
                      INTO P_VSNAODEBITACCRCA,
                           P_VSCREDITACCRCA,
                           p_vsAlterarPtabela,
                           P_tipocampanhacombo
                      FROM PCDESCONTOC C
                      WHERE C.CODIGO = reg_combos.codcombo;
                    EXCEPTION
                      WHEN OTHERS THEN
                      P_VSNAODEBITACCRCA := 'S';
                      P_VSCREDITACCRCA :=  'N';
                      p_vsAlterarPtabela := 'N';
                    END;

                    /*VEN-2048*/
                    if (p_vsAlterarPtabela = 'S') and (P_tipocampanhacombo = 'SQP') then
                    /*  update pcpedi
                         set ptabela = pvenda,
							 pbaserca = pvenda,
                             perdesc = 0
                       where numped = integradora_comple.gvet_regpedido(i).numped
                         and codcombo = reg_combos.codcombo
                         and codprod = REG_COMBOS_GRUPO.Codprod
                         and numseq = REG_COMBOS_GRUPO.numseq;*/

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'C';
                      integradora_comple.vLog.MSG                := 'Prod: ' || REG_COMBOS_GRUPO.Codprod || ' teve preço de tabela igualado ao pvenda devido à flag ALTERARPTABELA do combo SQP : ' || reg_combos.codcombo || '.';
                      integradora_comple.vLog.ptabela            := null;
                      integradora_comple.vLog.PVENDA             := null;
                      integradora_comple.vLog.PBASE              := null;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                    end if;



                  END LOOP;
                --END IF;

                  FOR reg_combos_grupo IN (SELECT PCPEDI.PVENDA, PCPEDI.PTABELA, PCPEDI.PBASERCA, PCPEDI.CODPROD, PCPEDI.PERDESC, PCPEDI.NUMSEQ
				                             FROM PCPEDI
											WHERE PCPEDI.NUMPED = integradora_comple.gvet_regpedido(i).numped
                                              AND PCPEDI.CODCOMBO = reg_combos.codcombo
											  AND NVL(PCPEDI.BONIFIC, 'N') = 'N')LOOP

                    BEGIN
                      SELECT NVL(C.NAODEBITCCRCA, 'S'),
                           NVL(C.CREDITAPOLITICA, 'N'),
                           NVL(C.ALTERARPTABELA, 'N') ALTERARPTABELA,
                           NVL(tipocampanha, 'X') tipocampanha
                      INTO P_VSNAODEBITACCRCA,
                           P_VSCREDITACCRCA,
                           p_vsAlterarPtabela,
                           P_tipocampanhacombo
                      FROM PCDESCONTOC C
                      WHERE C.CODIGO = reg_combos.codcombo;
                    EXCEPTION
                      WHEN OTHERS THEN
                      P_VSNAODEBITACCRCA := 'S';
                      P_VSCREDITACCRCA :=  'N';
                      p_vsAlterarPtabela := 'N';
                    END;

					if (P_VSNAODEBITACCRCA = 'S') AND (p_vsAlterarPtabela <> 'S')
                       AND (integradora_comple.gvet_regpedido(I).CONDVENDA IN (1, 14))
                       AND (reg_combos_grupo.PVENDA < reg_combos_grupo.PBASERCA) then
                      update pcpedi
                         set pbaserca = pvenda
                       where numped = integradora_comple.gvet_regpedido(i).numped
                         and codcombo = reg_combos.codcombo
                         and codprod = REG_COMBOS_GRUPO.Codprod
                         and numseq = REG_COMBOS_GRUPO.numseq;

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'C';
                      integradora_comple.vLog.MSG                := 'Prod: ' || REG_COMBOS_GRUPO.Codprod || ' teve preço base de RCA igualado ao pvenda devido à flag P_VSNAODEBITACCRCA do combo : ' || reg_combos.codcombo || '.';
                      integradora_comple.vLog.ptabela            := reg_combos_grupo.PTABELA;
                      integradora_comple.vLog.PVENDA             := reg_combos_grupo.PVENDA;
                      integradora_comple.vLog.PBASE              := reg_combos_grupo.PBASERCA;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                    end if;

					if (P_VSNAODEBITACCRCA = 'S') AND (P_VSCREDITACCRCA = 'N') AND (p_vsAlterarPtabela <> 'S')
                       AND (integradora_comple.gvet_regpedido(I).CONDVENDA IN (1, 14))
                       AND (reg_combos_grupo.PVENDA > reg_combos_grupo.PBASERCA) then
                      update pcpedi
                         set pbaserca = pvenda
                       where numped = integradora_comple.gvet_regpedido(i).numped
                         and codcombo = reg_combos.codcombo
                         and codprod = REG_COMBOS_GRUPO.Codprod
                         and numseq = REG_COMBOS_GRUPO.numseq;

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'C';
                      integradora_comple.vLog.MSG                := 'Prod: ' || REG_COMBOS_GRUPO.Codprod || ' teve preço base de RCA igualado ao pvenda devido à flag P_VSNAODEBITACCRCA do combo : ' || reg_combos.codcombo || '.';
                      integradora_comple.vLog.ptabela            := reg_combos_grupo.PTABELA;
                      integradora_comple.vLog.PVENDA             := reg_combos_grupo.PVENDA;
                      integradora_comple.vLog.PBASE              := reg_combos_grupo.PBASERCA;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                    end if;



                  END LOOP;

                IF NOT vbvalidodescontocombo THEN

                vbvalidodescontocombo := funcoesvendas.verificacampanhasdesconto(integradora_comple.gvet_regpedido(i).numped,
                                                                                 integradora_comple.gvet_regpedido(i).codfilial,
                                                                                 regregiao.numregiao,
                                                                                 integradora_comple.gvet_regpedido(i).codcli,
                                                                                 regcliente.codatv1,
                                                                                 regcliente.codcliprinc,
                                                                                 integradora_comple.gvet_regpedido(i).codusur,
                                                                                 regrca.codsupervisor,
                                                                                 regrca.coddistrib,
                                                                                 regplpag.pertxfim,
                                                                                 reg_combos.codcombo,
                                                                                 vsmensagemdescontocombo,
                                                                                 integradora_comple.gvet_regpedido(i).codplpag);
                END IF;

                IF vbvalidodescontocombo = FALSE
                THEN
                  FOR reg IN (SELECT codprod,
                                     qt,
                                     numseq,
                                     codauxiliar
                                FROM pcpedi
                               WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                 AND codcombo = reg_Combos.Codcombo)
                  LOOP

                    integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                 reg.codprod,
                                 reg.numseq,
                                 reg.codauxiliar,
                                 integradora_comple.gvet_regpedido(i).cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).CODUSUR,
                                 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                 NULL,
                                 '3',
                                 'Prod: ' || reg.codprod || ' cortado por fazer parte do combo : ' || reg_combos.codcombo || ' que foi rejeitado.' || ';',
                                 NULL,
                                 null);

                    DELETE FROM pcorigempreco
                     WHERE numped = integradora_comple.gvet_regpedido(i).numped
                       AND numseq = reg.numseq
                       AND codprod = reg.codprod;

                    DELETE FROM pcpedi
                     WHERE numped = integradora_comple.gvet_regpedido(i).numped
                       AND codcombo = reg_Combos.Codcombo
                       AND codprod = reg.codprod;

                    integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                     integradora_comple.gvet_regpedido(i).numpedrca,
                                     NULL,
                                     NULL,
                                     NULL,
                                     integradora_comple.gvet_regpedido(i).cgccli,
                                     NULL,
                                     NULL,
                                     NULL,
                                     integradora_comple.gvet_regpedido(i).codusur,
                                     integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                     NULL,
                                     '2',
                                     'Prod: ' || reg.codprod || ' cortado por fazer parte do combo : ' || reg_combos.codcombo || ' que foi rejeitado.' || ';',
                                     NULL,
                                     null);
                  END LOOP;

                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                   integradora_comple.gvet_regpedido(i).numpedrca,
                                   NULL,
                                   NULL,
                                   NULL,
                                   integradora_comple.gvet_regpedido(i).cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   integradora_comple.gvet_regpedido(i).codusur,
                                   integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                   NULL,
                                   '2',
                                   vsmensagemdescontocombo || ';',
                                   NULL,
                                   null);
                END IF;

              END LOOP;

            END IF;

            IF integradora_comple.gvet_regpedido(i).valido = TRUE
            THEN
              integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
              integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
              integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
              integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
              integradora_comple.vLog.TipoLog            := 'C';
              integradora_comple.vLog.MSG                := 'Totalizando pedido/orcamento ' || integradora_comple.gvet_regpedido(i).numped;
              integradora_comple.vLog.ptabela            := null;
              integradora_comple.vLog.PVENDA             := null;
              integradora_comple.vLog.PBASE              := null;

              PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));



              IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
              THEN

                SELECT COUNT(*),
                       SUM(qt * ptabela),
                       SUM(qt * pbaserca),
                       SUM(qt * vlcustocont),
                       SUM(qt * vlcustofin),
                       SUM(qt * vlcustoreal),
                       SUM(qt * vlcustorep)
                       --SUM(qt * pvenda)
                  INTO vncontitensvalidos,
                       vnvltottab,
                       vnvltotbaserca,
                       vnvlcustocontped,
                       vnvlcustofinped,
                       vnvlcustorealped,
                       vnvlcustorepped
                       --vnvltotped
                  FROM pcorcavendai
                 WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

              ELSE

                SELECT COUNT(*),
                       --SUM(ROUND(pcpedi.qt * pcpedi.pvenda, 2)),
                       SUM(pcpedi.qt * pcpedi.ptabela),
                       SUM(pcpedi.qt * pcpedi.pbaserca),
                       SUM(pcpedi.qt * pcpedi.vlcustocont),
                       SUM(pcpedi.qt * pcpedi.vlcustofin),
                       SUM(pcpedi.qt * pcpedi.vlcustoreal),
                       SUM(pcpedi.qt * pcpedi.vlcustorep),
                       SUM(pcpedi.qt * pcpedi.vlverbacmv),
                       SUM(pcpedi.qt * pcpedi.vlverbacmvcli)
                  INTO vncontitensvalidos,
                       --vnvltotped,
                       vnvltottab,
                       vnvltotbaserca,
                       vnvlcustocontped,
                       vnvlcustofinped,
                       vnvlcustorealped,
                       vnvlcustorepped,
                       vnvlverbacmv,
                       vnvlverbacmvcli

                  FROM pcpedi
               inner join pcpedipcpedifv
                  on pcpedipcpedifv.numped = pcpedi.numped
                 and pcpedipcpedifv.numseq = pcpedi.numseq
                 and pcpedipcpedifv.codprod = pcpedi.codprod
               WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

              END IF;

              IF vncontitensvalidos > 0
                AND integradora_comple.gvet_regpedido(i).valido = TRUE
              THEN

                IF regfilial.broker = 'N' and nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) = 0
                THEN


                  -- faz validacao final do cabecalho
                  proc_validacaofinalcab(integradora_comple.gvet_regpedido(i),
                                         regcliente,
                                         regplpag,
                                         regplpagetico,
                                         regplpaggenerico,
                                       --  regcob,
                                         regfilial,
                                        -- regrca,
                                         vncontitensvalidos,
                                         vnvltotped,
                                         --vnvltotped_ant,
                                         vnvltottab,
                                         vnvlcustofinped);
                ELSE
                  IF (FERRAMENTAS.VERIFICAR_FJ(regcliente.codcli) = 'PESSOA FISICA') and
                     (nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) <> 0) THEN
                    IF NOT funcoesvendas.verificarvalormaximovendapf(regcliente.codcli,
                                                                     vnvltottab,
                                                                     0,
                                                                     integradora_comple.gvet_regpedido(i).percvenda,
                                                                     nvl(integradora_comple.gregpcconsum.ACEITAVENDAPF,
                                                                         'S'),
                                                                     nvl(integradora_comple.gregpcconsum.VERIFICARLIMVENDAPF,
                                                                         'N'),
                                                                     NVL(regfilial.VLMAXVENDAPF ,integradora_comple.gregpcconsum.VLMAXVENDAPF),
                                                                     NVL(regfilial.PERLIMVENDAPF, integradora_comple.gregpcconsum.PERLIMVENDAPF),
                                                                     integradora_comple.gregpcconsum.VLMAXPEDIDOPF,
                                                                     integradora_comple.gregpcconsum.CONSIDERAISENTOSCOMOPF,
                                                                     integradora_comple.gvet_regpedido(i).codfilial,
                                                                     vsMensagem_vendapf)
                    THEN
                      IF vsMensagem_vendapf IS NOT NULL
                      THEN
                        integradora_comple.gvet_regpedido(i).valido := FALSE;
                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).codusur,
                                 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                 NULL,
                                 '2',
                                 vsmensagem_vendapf,
                                 NULL,
                                 null);
                      END IF;
                    END IF;
                  END IF;

                END IF;


              ELSE

                integradora_comple.gvet_regpedido(i).valido := FALSE;
                integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).codusur,
                                 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                 NULL,
                                 '2',
                                 'Nenhum item gravado;',
                                 NULL,
                                 null);
              END IF;

            END IF;

            IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
            THEN

              -- verifica se ha itens no pedido
              SELECT COUNT(*),
                     --SUM(pcpedi.qt * pcpedi.pvenda),
                     SUM(pcpedi.qt * pcpedi.ptabela),
                     SUM(pcpedi.qt * pcpedi.pbaserca),
                     SUM(pcpedi.qt * pcpedi.vlcustocont),
                     SUM(pcpedi.qt * pcpedi.vlcustofin),
                     SUM(pcpedi.qt * pcpedi.vlcustoreal),
                     SUM(pcpedi.qt * pcpedi.vlcustorep)
                INTO vncontitensvalidos,
                     --vnvltotped,
                     vnvltottab,
                     vnvltotbaserca,
                     vnvlcustocontped,
                     vnvlcustofinped,
                     vnvlcustorealped,
                     vnvlcustorepped
                FROM pcpedi
              inner join pcpedipcpedifv
                 on pcpedipcpedifv.numped = pcpedi.numped
                and pcpedipcpedifv.numseq = pcpedi.numseq
                and pcpedipcpedifv.codprod = pcpedi.codprod
              WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
               AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

              -----------------------------------------------------------
              --Autor: Rodrigo Santos
              --Solicitação: HIS.05072.2014
              --Data: 12/12/2014
              --Descrição: Implementação referente a item BNF no pedido TV1.
              IF (NOT integradora_comple.ValidarTV1comBNF(integradora_comple.gvet_regpedido(i),
                                       vsMsgTV1BNF))
                AND integradora_comple.gvet_regpedido(i).valido
              THEN

                vsmensagem         := vsmensagem  || vsMsgTV1BNF;
                integradora_comple.gvet_regpedido(i).valido := FALSE;

                integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,  ---RAFAEL TV1
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           vsmensagem || ';',
                                           NULL,
                                           null);

              END IF;
              -----------------------------------------------------------
              proc_validarquebra_pedido(i);

              IF vncontitensvalidos <> 0 and
                 FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VERIFICAESTOQUEPEDBLOQUEADO', integradora_comple.gvet_regpedido(i).codfilial,'N') = 'S' --VEN-9319 // Alterado de 'N' para 'S' para não rejeitar o pedido integralmente.
              THEN

                IF regfilial.broker = 'N'
                THEN

                  IF (integradora_comple.gvet_regpedido(i).condvenda <> 7 )
                     or (regfilial.RESERVARESTOQUETV7 = 'S')
                  THEN
                    integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                    integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                    integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                    integradora_comple.vLog.TipoLog            := 'C';
                    integradora_comple.vLog.MSG                := 'Efetuando Movimentação do Estoque';
                    integradora_comple.vLog.ptabela            := null;
                    integradora_comple.vLog.PVENDA             := null;
                    integradora_comple.vLog.PBASE              := null;

                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                      --valida estoque (LL)
                      proc_gravaestoque(integradora_comple.gvet_regpedido(i),
                                        vnmaxnumseq,
                                        regfilial,
                                  --      regcliente,
                                        regrca,
                                        regplpag,
                                        vnvlatendped,
                                        vntotpesoped,
                                        vntotvolumeped,
                                        vnvltotped);

                  END IF;
                END IF;

              IF integradora_comple.gvet_regpedido(i).valido = TRUE
              THEN

                  vnvlsaldoped := 0;

                  -----------------------------------------------------------
                    --Autor:Rafael Soares
                    --Solicitação: 0.032567.2016
                    --Data: 21/03/2016
                    --Descrição: Ajustado para que a rotina 2500 respeite os mesmos críterios de validação de conta corrente
                    --           que a rotina 316, esta são, O CLIENTE deve movimentar a conta corrente, o RCA deve movimentar a conta
                    --           corrente e o parametor da 132 deve movimentar a conta corrente.
                    --           Caso alguma dessas opções esteja nula, o valor do NVL é o que esta no parametro da 132
                    -----------------------------------------------------------


                   SELECT NVL(USADEBCREDRCA, integradora_comple.gregpcconsum.usacredrca)
                    INTO vsUSACCRCAUSUR
                    FROM PCUSUARI
                   WHERE PCUSUARI.CODUSUR = integradora_comple.gvet_regpedido(i).CODUSUR;

                  SELECT NVL(usadebcredrca, integradora_comple.gregpcconsum.usacredrca)
                    INTO vsUSACCRCACLIENT
                    FROM PCCLIENT
                   WHERE PCCLIENT.CODCLI = integradora_comple.gvet_regpedido(i).CODCLI;

                  SELECT CASE
                           WHEN COUNT(*) = 0 THEN 'S'
                           ELSE 'N'
                         END CASE
                    INTO vsTV5MOVRCA
                    FROM pcbrindeex b
                   WHERE b.codbrex = integradora_comple.gvet_regpedido(i).codbrex
                     AND b.movccrca = 'N'
                     AND integradora_comple.gvet_regpedido(i).condvenda = 5;

                  vsUSADEBCREDRCA := (((integradora_comple.gregpcconsum.usacredrca = 'S') AND
                                     (vsUSACCRCAUSUR = 'S')) or
                                     FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'S') AND
                                     vsUSACCRCACLIENT = 'S'  AND vsTV5MOVRCA = 'S';

                  IF NOT vsUSADEBCREDRCA THEN

                     integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                     integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                     integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                     integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                     integradora_comple.vLog.TipoLog            := 'C';
                     integradora_comple.vLog.MSG                := 'PEDIDO NÃO MOVIMENTA CC RCA';
                     integradora_comple.vLog.ptabela            := null;
                     integradora_comple.vLog.PVENDA             := null;
                     integradora_comple.vLog.PBASE              := null;

                     PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  END IF;

                  IF integradora_comple.gvet_regpedido(i).condvenda <> 13 and vsUSADEBCREDRCA
                  THEN

                    -----------------------------------------------------------
                    --Autor: Rodrigo Santos
                    --Solicitação: HIS.03499.2014
                    --Data: 21/10/2014
                    --Descrição: Implementação das chamadas para C/C como desconto financeiro.
                    -----------------------------------------------------------
                    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USASALDOCONTACORRENTEDESCFIN','99','N') = 'N' THEN

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'C';
                      integradora_comple.vLog.MSG                := 'CCRCA: Validacao 01 Movimentando Conta Corrente vnmaxnumseq ' || vnmaxnumseq;
                      integradora_comple.vLog.ptabela            := null;
                      integradora_comple.vLog.PVENDA             := null;
                      integradora_comple.vLog.PBASE              := null;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


                      IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'N' THEN

                        FOR reg_itens IN (SELECT codprod,
                                                 numseq,
                                                 qt,
                                                 codauxiliar,
                                                 pcpedi.pvenda,
                                                 pcpedi.ptabela,
                                                 pcpedi.pbaserca,
                                                 pcpedi.codusur,
                                                 pc_pkg_controlarsaldorca.ccrca_saldo_item(integradora_comple.gregpcconsum.usacredrca,
                                                                                           integradora_comple.gvet_regpedido(i).usadebcredrca,
                                                                                           'N',
                                                                                           integradora_comple.gvet_regpedido(i).origemped,
                                                                                           --integradora_comple.gregpcconsum.bonificaltdebcredrca,
                                                                                           nvl(integradora_comple.gvet_regpedido(i).bonificaltdebcredrca,integradora_comple.gregpcconsum.bonificaltdebcredrca),
                                                                                           integradora_comple.gregpcconsum.trocaaltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.crmaltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.brokeraltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.tipomovccrca,
                                                                                           integradora_comple.gvet_regpedido(i).condvenda,
                                                                                           'N',
                                                                                           coalesce(pcpedi.codusur, integradora_comple.gvet_regpedido(i).CODUSUR),
                                                                                           'V',
                                                                                           -- VEN-5760
                                                                                           -- Arredondando as casas decimais dos preços para 3, pois o conta corrente é somente
                                                                                           -- 2 casas decimais.
                                                                                           ROUND(pcpedi.pvenda,3),
                                                                                           ROUND(pcpedi.ptabela,3),
                                                                                           ROUND(pcpedi.pbaserca,3),
                                                                                           (pcpedi.qt /*- decode(integradora_comple.gvet_regpedido(i).posicao,
                                                                                                               'B',
                                                                                                               0,
                                                                                                               nvl(pcpedi.qtfalta,
                                                                                                                   0))*/),-- 1880.057447.2015, comentado pois neste ponto o corte já foi feito,
                                                                                                                          -- ao subtrair qt - qtfalta, o resultado seria qt original - (2xqtfalta)
                                                                                                                          -- causando erro no cálculo da cc do rca.
                                                                                           'N',
                                                                                           pcpedi.movimentacontacorrenterca,
                                                                                           pcpedi.bonific) saldo
                                            FROM pcpedi
                                           WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                             AND pcpedi.numseq > vnmaxnumseq
                                           ORDER BY saldo DESC)
                        LOOP

                          if integradora_comple.gvet_regpedido(i).tipocontacorrente = 'G' then
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccger_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODGERENTE);
                             vsOperador := 'Gerente';
                          elsif integradora_comple.gvet_regpedido(i).tipocontacorrente = 'S' then
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccsup_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODSUPERVISOR);
                             vsOperador := 'Supervisor';
                          else
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccrca_checar_disponivel_atual(coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).CODUSUR));
                             vsOperador := 'RCA';
                          end if;

						  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
						  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
						  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
						  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
						  integradora_comple.vLog.TipoLog            := 'C';
						  integradora_comple.vLog.MSG                := 'CCRCA: Validacao 01 Movimentando Conta Corrente ' || vsOperador;
						  integradora_comple.vLog.ptabela            := null;
						  integradora_comple.vLog.PVENDA             := null;
						  integradora_comple.vLog.PBASE              := null;

						  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                          IF (vnvldisponivel + reg_itens.saldo + vnvlsaldoped) < 0 AND reg_itens.saldo < 0 THEN

                            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
							integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
							integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
							integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
							integradora_comple.vLog.TipoLog            := 'C';
							integradora_comple.vLog.MSG                := 'CCRCA: Validacao 01 Movimentando Conta Corrente ' || vsOperador || ' - sem credito disponivel - ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;
							integradora_comple.vLog.ptabela            := null;
							integradora_comple.vLog.PVENDA             := null;
							integradora_comple.vLog.PBASE              := null;

							PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

							integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             reg_itens.codprod,
                                             reg_itens.numseq,
                                             reg_itens.codauxiliar,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).CODUSUR,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             vsOperador || ' sem credito disponivel' || ';',
                                             NULL,
                                             null);

                            IF regfilial.aceitavendarcasemsaldofv = 'S'
                            THEN

                              integradora_comple.gvet_regpedido(i).posicao := 'B';
                              integradora_comple.gvet_regpedido(i).motivoposicao := substr(vsOperador || ' sem saldo disponivel',1,60);
                              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22,substr(vsOperador || ' Sem Saldo Disponível CC' || vsOperador,1,200), 'C');
                              integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || vsOperador || ' sem saldo disponivel';
                            /*907.101980.2016*/
                            ELSIF regfilial.tipoimportacaovenda = 'RP' then
                              integradora_comple.gvet_regpedido(i).valido := false;
                            ELSE
                              integradora_comple.proc_pcpedimov(integradora_comple.gvet_regpedido(i),
                                           reg_itens.codprod,
                                           reg_itens.numseq,
                                           0,
                                             'N');
                            END IF;

                          ELSE

                            vnvlsaldoped := vnvlsaldoped + reg_itens.saldo;

                          END IF;
                        END LOOP;

                      ELSE
                       FOR validarCC IN (SELECT coalesce(i.codusur, c.codusur) codusur,
                                                 c.numped,
                                                 p.codfornec,
                                                 i.codprod,
                                                 i.numseq,
                                                 i.pvenda,
                                                 i.pbaserca,
                                                 i.qt,
                                                 p.codfilial
                                            FROM pcpedi i, pcpedc c, pcprodut p
                                           WHERE i.numped = c.numped
                                             AND i.codprod = p.codprod
                                             AND c.numped = integradora_comple.gvet_regpedido(i).numped
                                           ORDER BY numseq)
                        LOOP
                          vsMensagemcc_fornec := 'OK';
                          PC_PKG_CONTROLASALDORCAFORNEC.PRC_VALIDAITEMSALDORCAFORNEC(validarCC.Codusur,
                                                                                     validarCC.Numped,
                                                                                     validarCC.Codfornec,
                                                                                     validarCC.Codprod,
                                                                                     validarCC.Numseq,
                                                                                     validarCC.numseq,
                                                                                     validarCC.Pvenda,
                                                                                     validarCC.Pbaserca,
                                                                                     validarCC.Qt,
                                                                                     2596,
                                                                                     integradora_comple.gvet_regpedido(i).codemitente,
                                                                                     integradora_comple.gvet_regpedido(i).codfilial,
                                                                                     vsMensagemcc_fornec);
                         if vsMensagemcc_fornec <> 'OK' then
                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             0,
                                             0,
                                             0,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Rca sem credito disponivel(C/C Fornec.)' || ';',
                                             NULL,
                                             null);
                              integradora_comple.gvet_regpedido(i).posicao := 'B';
                              integradora_comple.gvet_regpedido(i).motivoposicao := substr('Rca sem saldo disponivel',1,60);
                              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22,substr('RCA Sem Saldo Disponível CC/FORNEC',1,200), 'C');
                              integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || 'Rca sem saldo disponivel';
                          END IF;
                        END LOOP;

                          PC_PKG_CONTROLASALDORCAFORNEC.PRC_MOVIMENTASALDORCAFORNEC(integradora_comple.gvet_regpedido(i).codusur,
                                                                                    integradora_comple.gvet_regpedido(i).numped,
                                                                                    2596,
                                                                                    integradora_comple.gvet_regpedido(i).codemitente,
                                                                                    integradora_comple.gvet_regpedido(i).codfilial,
                                                                                    vsmensagemccfornec);

                         if vsmensagemccfornec <> 'OK' then
                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             0,
                                             0,
                                             0,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Rca sem credito disponivel(C/C Fornec.)' || ';',
                                             NULL,
                                             null);


                              integradora_comple.gvet_regpedido(i).posicao := 'B';
                              integradora_comple.gvet_regpedido(i).motivoposicao := substr('Rca sem saldo disponivel',1,60);
                              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22,substr('RCA Sem Saldo Disponível CC/FORNEC',1,200), 'C');
                              integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || 'Rca sem saldo disponivel';
                         END IF;
                          /*END LOOP;*/

                      END IF;
                    ELSE

                      FOR reg_itens IN (SELECT codprod,
                                               numseq,
                                               numped,
                                               codusur,
                                               codauxiliar
                                          FROM pcpedi
                                         WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                         ORDER BY numseq)
                      LOOP

                        IF NOT (pc_pkg_controlarsaldorca.ccfinrca_incluir_item_pedido(integradora_comple.gvet_regpedido(i).codemitente,
                                                                                      2596,
                                                                                      reg_itens.codusur,
                                                                                      reg_itens.numped,
                                                                                      reg_itens.codprod,
                                                                                      reg_itens.numseq,
                                                                                      vsmensagemccfin))
                        THEN

                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           reg_itens.codprod,
                                           reg_itens.numseq,
                                           reg_itens.codauxiliar,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '3',
                                           vsmensagemccfin || ';',
                                           NULL,
                                           null);

					        integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
							integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
							integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
							integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
							integradora_comple.vLog.TipoLog            := 'C';
							integradora_comple.vLog.MSG                := 'Rca sem saldo disponivel(C/C Fin) ' || ' - sem credito disponivel - ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;
							integradora_comple.vLog.ptabela            := null;
							integradora_comple.vLog.PVENDA             := null;
							integradora_comple.vLog.PBASE              := null;

							PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                          IF regfilial.aceitavendarcasemsaldofv = 'S'
                          THEN

                            integradora_comple.gvet_regpedido(i).posicao := 'B';
                            integradora_comple.gvet_regpedido(i).motivoposicao := substr('Rca sem saldo disponivel(C/C Fin)',1,60);
                            PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22, substr('RCA Sem Saldo Disponível CC/FIN',1,200), 'C');
                            integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || 'Rca sem saldo disponivel';
                          ELSE

                            integradora_comple.proc_pcpedimov(integradora_comple.gvet_regpedido(i)
                                          ,reg_itens.codprod
                                          ,reg_itens.numseq
                                          ,0
                                          ,'N');
                          END IF;
                        END IF;

                      END LOOP;

                    END IF;
                    -------------------------------------------------------------------------

                    SELECT COUNT(*)
                      INTO VICONTADOR
                      FROM pcpedi
                     inner join pcpedipcpedifv
                        on pcpedipcpedifv.numped = pcpedi.numped
                       and pcpedipcpedifv.numseq = pcpedi.numseq
                       and pcpedipcpedifv.codprod = pcpedi.codprod
                     WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                      AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

                    IF VICONTADOR = 0 THEN
                        integradora_comple.gvet_regpedido(i).valido := FALSE;
                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           'Nenhum item gravado;',
                                           NULL,
                                           null);

                    END IF;

                  END IF;

                END IF;

                --Processo de Abatimento
                IF regfilial.usaabatimento = 'S'
                   AND (nvl(integradora_comple.gvet_regpedido(i).percdescabatimento,
                            0) > 0 OR nvl(integradora_comple.gvet_regpedido(i).vldescabatimento,
                                               0) > 0)
                THEN

                  integradora_comple.proc_processarabatimento(integradora_comple.gvet_regpedido(i),
                                           regcliente,
                                           regregiao,
                                           regfilial,
                                           regrca,
                                           regplpag,
                                           vnvltotped);

                END IF;
              END IF;

            END IF;


            --Processo de distribuição por produto
            IF nvl(integradora_comple.gregpcconsum.pedidopordistrib,'N') = 'S' THEN

               SELECT MAX(PCPRODUT.Coddistrib)
                INTO VSDISTRIBPRODUT
                FROM PCPRODUT, PCPEDI
                 inner join pcpedipcpedifv
                  on pcpedipcpedifv.numped = pcpedi.numped
                 and pcpedipcpedifv.numseq = pcpedi.numseq
                 and pcpedipcpedifv.codprod = pcpedi.codprod
               WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                     AND pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca
                     AND PCPRODUT.codprod =  PCPEDI.codprod;

               integradora_comple.gvet_regpedido(i).coddistrib := VSDISTRIBPRODUT;
            END IF;

             -- Validação dos valores do cabeçalho do pedido. VEN-9946
            SELECT COUNT(*),
                   SUM(DECODE(NVL(pcpedi.bonific, 'N'), 'F', 0, 'S', 0, Round(pcpedi.qt * pcpedi.pvenda, 2))),
                   SUM(pcpedi.qt * pcpedi.pbaserca),
                   SUM(pcpedi.qt * pcpedi.vlcustocont),
                   SUM(pcpedi.qt * pcpedi.vlcustofin),
                   SUM(pcpedi.qt * pcpedi.vlcustoreal),
                   SUM(pcpedi.qt * pcpedi.vlcustorep),
                   SUM(Round(pcpedi.qt * pcpedi.ptabela, 2))
              INTO vncontitensvalidos,
                   vnvlatend,
                   vnvltotbaserca,
                   vnvlcustocontped,
                   vnvlcustofinped,
                   vnvlcustorealped,
                   vnvlcustorepped,
                   vnvltottab
              FROM pcpedi
             inner join pcpedipcpedifv
                on pcpedipcpedifv.numped = pcpedi.numped
               and pcpedipcpedifv.numseq = pcpedi.numseq
               and pcpedipcpedifv.codprod = pcpedi.codprod
             WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
              AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

            IF integradora_comple.gvet_regpedido(i).valido = TRUE
            THEN

              IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
              THEN

                  SELECT COUNT(*),
                         SUM(Round(pcorcavendai.qt * pcorcavendai.pvenda, 2)),
                         SUM(pcorcavendai.qt * pcorcavendai.pbaserca),
                         SUM(pcorcavendai.qt * pcorcavendai.vlcustocont),
                         SUM(pcorcavendai.qt * pcorcavendai.vlcustofin),
                         SUM(pcorcavendai.qt * pcorcavendai.vlcustoreal),
                         SUM(pcorcavendai.qt * pcorcavendai.vlcustorep),
                         SUM(Round(pcorcavendai.qt * pcorcavendai.ptabela, 2))
                    INTO vncontitensvalidos,
                         vnvlatend,
                         vnvltotbaserca,
                         vnvlcustocontped,
                         vnvlcustofinped,
                         vnvlcustorealped,
                         vnvlcustorepped,
                         vnvltottab
                    FROM pcorcavendai
                   WHERE pcorcavendai.numorca = integradora_comple.gvet_regpedido(i).numped;

                integradora_comple.gvet_regpedido(i).valido := func_inserirorcamento(integradora_comple.gvet_regpedido(i),
                                                                  regplpag,
                                                                  regrca,
                                                                  regcliente,
                                                                  regregiao,
                                                                  regfilial,
                                                                  vncontitensvalidos,
                                                                  vnvltotped + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0),
                                                                  vnvlatend + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0),
                                                                  vnvltottab,
                                                                  vntotpesoped,
                                                                  vntotvolumeped,
                                                                  vnvlcustocontped,
                                                                  vnvlcustofinped,
                                                                  vnvlcustorealped,
                                                                  vnvlcustorepped);

              ELSE

                integradora_comple.gvet_regpedido(i).valido := func_inserircabpedido(integradora_comple.gvet_regpedido(i),
                                                                  regplpag,
                                                                  regrca,
                                                                  regcliente,
                                                                  regregiao,
                                                                  regfilial,
                                                                  vncontitensvalidos,
                                                                  vnvltotped + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0),
                                                                  CASE WHEN  integradora_comple.gvet_regpedido(i).condvenda in(5,11) THEN
                                                                         0
                                                                       ELSE
                                                                         vnvlatend + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0)
                                                                  END,
                                                                  vnvltottab,
                                                                  vntotpesoped,
                                                                  vntotvolumeped,
                                                                  vnvlcustocontped,
                                                                  vnvlcustofinped,
                                                                  vnvlcustorealped,
                                                                  vnvlcustorepped,
                                                                  vnvlverbacmv,
                                                                  vnvlverbacmvcli);

              END IF;
  			  
			  IF (NVL(integradora_comple.gvet_regpedido(i).vlfrete,0) > 0) THEN
				  IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FIL_INCLUIFRETEOUTRASDESPBASEST',integradora_comple.gvet_regpedido(i).codfilial, 'N' ) = 'S' THEN
					 IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FORMARETEIOFRETE_OUTRASDESP_VENDA',integradora_comple.gvet_regpedido(i).codfilial, 'F' ) = 'G' THEN
						FATURAMENTO.RATEAR_FRETE_OUTRASDESPESAS(integradora_comple.gvet_regpedido(i).numped, 0,0, vMensagem );
					 elsif FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('FORMARETEIOFRETE_OUTRASDESP_VENDA',integradora_comple.gvet_regpedido(i).codfilial, 'F') = 'Q' THEN
     				   IF integradora_comple.GVET_REGITEM(i).RESPQUESTFRETE = 'S' THEN
					      FATURAMENTO.RATEAR_FRETE_OUTRASDESPESAS(integradora_comple.gvet_regpedido(i).numped, 0, 0, vMensagem );
					   END IF;
					 END IF;
				  END IF;
              END IF;

			  
              IF nvl(integradora_comple.gvet_regpedido(i).numpedtv1 ,0) > 0
              AND nvl(integradora_comple.gvet_regpedido(i).codbrex,0) > 0 THEN

                vMSGVALIDATV5 := PKG_BRINDEEX.VALIDARTV5(integradora_comple.gvet_regpedido(i).numpedtv1, integradora_comple.gvet_regpedido(i).numped, integradora_comple.gvet_regpedido(i).codbrex);

                IF vMSGVALIDATV5 <> 'OK' THEN

                 integradora_comple.gvet_regpedido(i).valido := FALSE;

                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                                      integradora_comple.gvet_regpedido(i).numpedrca,
                                                      NULL,
                                                      NULL,
                                                      NULL,
                                                      integradora_comple.gvet_regpedido(i).cgccli,
                                                      NULL,
                                                      NULL,
                                                      NULL,
                                                      integradora_comple.gvet_regpedido(i).codusur,
                                                      integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                                      NULL,
                                                      '2',
                                                      'Pedido inválido para a campanha: ' || nvl(integradora_comple.gvet_regpedido(i).codbrex,0) || chr(13) ||
                                                      vMSGVALIDATV5,
                                                      NULL,
                                                      null);
                END IF;

              END IF;

              IF (regfilial.VLBNFMAXTV1 > 0)
                AND (regfilial.VLBNFMAXTV1) < (integradora_comple.GVET_REGPEDIDO(I).vlbonific)
                AND (integradora_comple.GVET_REGPEDIDO(I).vlatend > 0)
                AND (integradora_comple.GVET_REGPEDIDO(I).vlbonific > 0)
                AND (integradora_comple.GVET_REGPEDIDO(I).condvenda = 1) THEN

                  integradora_comple.gvet_regpedido(i).valido := FALSE;

                  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                  integradora_comple.vLog.TipoLog            := 'C';
                  integradora_comple.vLog.MSG                := 'O valor total em itens bonificados é maior que o valor máximo permitido.'
                                                                || CHR(13) ||  'Verifique o parâmetro 3046 da Rotina 132.'
                                                                || CHR(13) ||  'Valor máximo: ' || regfilial.vlbnfmaxtv1 || ' Valor bonificado: ' || (integradora_comple.GVET_REGPEDIDO(I).vlbonific) || '.';
                  integradora_comple.vLog.ptabela            := null;
                  integradora_comple.vLog.PVENDA             := null;
                  integradora_comple.vLog.PBASE              := null;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).codusur,
                                 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                 NULL,
                                 '2',
                                 'O valor total em itens bonificados é maior que o valor máximo permitido.'
                                  || CHR(13) ||  'Verifique o parâmetro 3046 da Rotina 132.'
                                  || CHR(13) ||  'Valor máximo: ' || regfilial.vlbnfmaxtv1 || ' Valor bonificado: ' || (integradora_comple.GVET_REGPEDIDO(I).vlbonific) || '.',
                                 NULL,
                                 null);

              END IF;

              IF (regfilial.VLMINTV1BNF > 0)
                and (regfilial.VLMINTV1BNF) > (integradora_comple.GVET_REGPEDIDO(I).vlatend)
                and (integradora_comple.GVET_REGPEDIDO(I).vlatend > 0)
                and (integradora_comple.GVET_REGPEDIDO(I).vlbonific > 0)
                AND (integradora_comple.GVET_REGPEDIDO(I).condvenda = 1) THEN

                  integradora_comple.gvet_regpedido(i).valido := FALSE;

                  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                  integradora_comple.vLog.TipoLog            := 'C';
                  integradora_comple.vLog.MSG                := 'O valor total em itens vendidos (TV1) é menor que o valor mínimo para venda com itens bonificados.'
                                                                || CHR(13) ||  'Verifique o parâmetro 3048 da Rotina 132.'
                                                                || CHR(13) ||  'Valor mínimo: ' || regfilial.vlmintv1bnf || ' Valor Atendido(TV1): ' || (integradora_comple.GVET_REGPEDIDO(I).vlatend);
                  integradora_comple.vLog.ptabela            := null;
                  integradora_comple.vLog.PVENDA             := null;
                  integradora_comple.vLog.PBASE              := null;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                 integradora_comple.gvet_regpedido(i).numpedrca,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).cgccli,
                                 NULL,
                                 NULL,
                                 NULL,
                                 integradora_comple.gvet_regpedido(i).codusur,
                                 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                 NULL,
                                 '2',
                                 'O valor total em itens vendidos (TV1) é menor que o valor mínimo para venda com itens bonificados.'
                                  || CHR(13) ||  'Verifique o parâmetro 3048 da Rotina 132.'
                                  || CHR(13) ||  'Valor mínimo: ' || regfilial.vlmintv1bnf || ' Valor Atendido(TV1): ' || (integradora_comple.GVET_REGPEDIDO(I).vlatend),
                                 NULL,
                                 null);

              END IF;

              -- Carregamento de Pedido Balcao Reserva
              IF (integradora_comple.gvet_regpedido(i).origemped = 'R')
                 AND (integradora_comple.gvet_regpedido(i).posicao = 'L')
              THEN

                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Gerando Carregamento Balcão reserva.';

                PRC_LOG_INTEGRADORA(integradora_comple.vlog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


                integradora_comple.gerarcarregbalcaoreserva(integradora_comple.gvet_regpedido(i).numped,
                                                            integradora_comple.gvet_regpedido(i).numpedrca,
                                                            integradora_comple.gvet_regpedido(i).CODUSUR,
                                                            integradora_comple.gvet_regpedido(i).cgccli,
                                                            integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                                            NULL,
                                                            vnnumcar);

                IF vnnumcar > 0
                THEN
                  integradora_comple.gvet_regpedido(i).posicao := 'M';
                else
                  integradora_comple.gvet_regpedido(i).valido := FALSE;

                  integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                                      integradora_comple.gvet_regpedido(i).numpedrca,
                                                      NULL,
                                                      NULL,
                                                      NULL,
                                                      integradora_comple.gvet_regpedido(i).cgccli,
                                                      NULL,
                                                      NULL,
                                                      NULL,
                                                      integradora_comple.gvet_regpedido(i).codusur,
                                                      integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                                      NULL,
                                                      '2',
                                                      'Não foi possível obter nº de carregamento. Tente reprocessar o pedido mais tarde.',
                                                      NULL,
                                                      null);
                END IF;

              END IF;

              proc_bloqvenda  ( regfilial, integradora_comple.gvet_regpedido(i) );

              --Para resolver o problema do cliente CONSTRUJÁ, colocado para quando não tiver desconto usar o mesmo parametro da 316/336
              IF (integradora_comple.GVET_REGPEDIDO(I).condvenda <> 5) AND --Se for diferente de bonificação o pedido
                paramfilial.obtercomovarchar2('TIPOCONTACORRENTEFV') <> paramfilial.obtercomovarchar2('TIPOCONTACORRENTE') THEN
                 BEGIN --Se tiver algum desconto mantem o parametro: TIPOCONTACORRENTEFV
                   SELECT COUNT(1)
                     into vnvldisponivel
                     FROM PCPEDI
                    WHERE PCPEDI.NUMPED = integradora_comple.GVET_REGPEDIDO(I).NUMPED
                      AND ROUND(NVL(PCPEDI.PTABELA,0),2) <> ROUND(NVL(PCPEDI.PVENDA,0),2);

                 EXCEPTION
                   WHEN NO_DATA_FOUND THEN
                      vnvldisponivel := 0; --Se não tiver desconto muda para o parametro TIPOCONTACORRENTE
                 END;

                 IF vnvldisponivel = 0 then
                  UPDATE PCPEDC
                     SET PCPEDC.TIPOCONTACORRENTE = paramfilial.obtercomovarchar2('TIPOCONTACORRENTE')
                   WHERE PCPEDC.NUMPED = integradora_comple.GVET_REGPEDIDO(I).NUMPED;

                 END IF;
              END IF;

              IF integradora_comple.gvet_regpedido(i).orcamento = 'N' and
                 vncontitensvalidos <> 0 and
                 FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('VERIFICAESTOQUEPEDBLOQUEADO', integradora_comple.gvet_regpedido(i).codfilial,'N') = 'N'
              THEN

                IF regfilial.broker = 'N'
                THEN

                  IF integradora_comple.gvet_regpedido(i).condvenda <> 7
                  THEN
                    integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                    integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                    integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                    integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                    integradora_comple.vLog.TipoLog            := 'C';
                    integradora_comple.vLog.MSG                := 'Efetuando Movimentação do Estoque';
                    integradora_comple.vLog.ptabela            := null;
                    integradora_comple.vLog.PVENDA             := null;
                    integradora_comple.vLog.PBASE              := null;

                    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                      --valida estoque (LL)
                      proc_gravaestoque(integradora_comple.gvet_regpedido(i),
                                        vnmaxnumseq,
                                        regfilial,
                                  --      regcliente,
                                        regrca,
                                        regplpag,
                                        vnvlatendped,
                                        vntotpesoped,
                                        vntotvolumeped,
                                        vnvltotped);

                   IF integradora_comple.gregpcconsum.validarvlminvendaaposcorte = 'S'
                        AND nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) = 0
                     THEN
                      proc_bloqvenda  ( regfilial, integradora_comple.gvet_regpedido(i) );
                     END IF;

                  END IF;
                END IF;

			   	SELECT COUNT(*),
					 SUM(DECODE(NVL(pcpedi.bonific, 'N'), 'F', 0, 'S', 0, Round(pcpedi.qt * pcpedi.pvenda, 2)))
				INTO vncontitensvalidos,
					 vnvlatend
				FROM pcpedi
			   inner join pcpedipcpedifv
				  on pcpedipcpedifv.numped = pcpedi.numped
				 and pcpedipcpedifv.numseq = pcpedi.numseq
				 and pcpedipcpedifv.codprod = pcpedi.codprod
			   WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
				AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

				SELECT COUNT(*)
				INTO vncontitenstodos
				FROM pcpedifv
			   WHERE pcpedifv.numpedrca  = integradora_comple.gvet_regpedido(i).numpedrca
			     and pcpedifv.DTABERTURAPEDPALM = integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;

			   IF (vncontitensvalidos <> vncontitenstodos) and (vncontitensvalidos > 0) THEN
				integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
				integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
				integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
				integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
				integradora_comple.vLog.TipoLog            := 'C';
				integradora_comple.vLog.MSG                := 'Atualizando vlatend após corte.' || chr(13)
															   || 'Valor Total: ' || to_char(vnvltotped + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0)) || '.' || chr(13)
															   || 'Valor Atendido: ' || to_char(vnvlatend + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0)) || '.' || chr(13)
															   || 'Qtd FV: ' || to_char(vncontitenstodos) || '.' || chr(13)
															   || 'Qtd Validos: ' || to_char(vncontitensvalidos) || '.' || chr(13);

				PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
				update pcpedc c
				   SET c.vlatend     = vnvlatend + nvl(integradora_comple.gvet_regpedido(i).vlfrete,0)
					  ,c.NUMITENS    = vncontitensvalidos
				where c.numped       = integradora_comple.gvet_regpedido(i).numped;
			  END IF;

              IF integradora_comple.gvet_regpedido(i).valido = TRUE
              THEN

                  vnvlsaldoped := 0;

                  -----------------------------------------------------------
                    --Autor:Rafael Soares
                    --Solicitação: 0.032567.2016
                    --Data: 21/03/2016
                    --Descrição: Ajustado para que a rotina 2500 respeite os mesmos críterios de validação de conta corrente
                    --           que a rotina 316, esta são, O CLIENTE deve movimentar a conta corrente, o RCA deve movimentar a conta
                    --           corrente e o parametor da 132 deve movimentar a conta corrente.
                    --           Caso alguma dessas opções esteja nula, o valor do NVL é o que esta no parametro da 132
                    -----------------------------------------------------------


                   SELECT NVL(USADEBCREDRCA, integradora_comple.gregpcconsum.usacredrca)
                    INTO vsUSACCRCAUSUR
                    FROM PCUSUARI
                   WHERE PCUSUARI.CODUSUR = integradora_comple.gvet_regpedido(i).CODUSUR;

                  SELECT NVL(usadebcredrca, integradora_comple.gregpcconsum.usacredrca)
                    INTO vsUSACCRCACLIENT
                    FROM PCCLIENT
                   WHERE PCCLIENT.CODCLI = integradora_comple.gvet_regpedido(i).CODCLI;

                  vsUSADEBCREDRCA := (((integradora_comple.gregpcconsum.usacredrca = 'S') AND
                                     (vsUSACCRCAUSUR = 'S')) or
                                     FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'S') AND
                                     (vsUSACCRCACLIENT = 'S');

                  IF integradora_comple.gvet_regpedido(i).condvenda <> 13 and vsUSADEBCREDRCA
                  THEN

                    -----------------------------------------------------------
                    --Autor: Rodrigo Santos
                    --Solicitação: HIS.03499.2014
                    --Data: 21/10/2014
                    --Descrição: Implementação das chamadas para C/C como desconto financeiro.
                    -----------------------------------------------------------
                    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USASALDOCONTACORRENTEDESCFIN','99','N') = 'N' THEN

                      integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                      integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                      integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                      integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                      integradora_comple.vLog.TipoLog            := 'C';
                      integradora_comple.vLog.MSG                := 'CCRCA: Validacao 02 Movimentando Conta Corrente vnmaxnumseq ' || vnmaxnumseq;
                      integradora_comple.vLog.ptabela            := null;
                      integradora_comple.vLog.PVENDA             := null;
                      integradora_comple.vLog.PBASE              := null;

                      PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


                      IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'N' THEN

                        FOR reg_itens IN (SELECT codprod,
                                                 numseq,
                                                 qt,
                                                 codauxiliar,
                                                 pcpedi.pvenda,
                                                 pcpedi.ptabela,
                                                 pcpedi.pbaserca,
                                                 pcpedi.codusur,
                                                 pc_pkg_controlarsaldorca.ccrca_saldo_item(integradora_comple.gregpcconsum.usacredrca,
                                                                                           integradora_comple.gvet_regpedido(i).usadebcredrca,
                                                                                           'N',
                                                                                           integradora_comple.gvet_regpedido(i).origemped,
                                                                                           --integradora_comple.gregpcconsum.bonificaltdebcredrca,
                                                                                           nvl(integradora_comple.gvet_regpedido(i).bonificaltdebcredrca,integradora_comple.gregpcconsum.bonificaltdebcredrca),
                                                                                           integradora_comple.gregpcconsum.trocaaltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.crmaltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.brokeraltdebcredrca,
                                                                                           integradora_comple.gregpcconsum.tipomovccrca,
                                                                                           integradora_comple.gvet_regpedido(i).condvenda,
                                                                                           'N',
                                                                                           coalesce(pcpedi.codusur, integradora_comple.gvet_regpedido(i).CODUSUR),
                                                                                           'V',
                                                                                           -- VEN-5760
                                                                                           -- Arredondando as casas decimais dos preços para 3, pois o conta corrente é somente
                                                                                           -- 2 casas decimais.
                                                                                           ROUND(pcpedi.pvenda,3),
                                                                                           ROUND(pcpedi.ptabela,3),
                                                                                           ROUND(pcpedi.pbaserca,3),
                                                                                           (pcpedi.qt /*- decode(integradora_comple.gvet_regpedido(i).posicao,
                                                                                                               'B',
                                                                                                               0,
                                                                                                               nvl(pcpedi.qtfalta,
                                                                                                                   0))*/),-- 1880.057447.2015, comentado pois neste ponto o corte já foi feito,
                                                                                                                          -- ao subtrair qt - qtfalta, o resultado seria qt original - (2xqtfalta)
                                                                                                                          -- causando erro no cálculo da cc do rca.
                                                                                           'N',
                                                                                           pcpedi.movimentacontacorrenterca,
                                                                                           pcpedi.bonific) saldo
                                            FROM pcpedi
                                           WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                             AND pcpedi.numseq > vnmaxnumseq
                                           ORDER BY saldo DESC)
                        LOOP

                     --     pc_pkg_controlarsaldorca.ccrca_bloquear_registro_rca(coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).CODUSUR));
                          if integradora_comple.gvet_regpedido(i).tipocontacorrente = 'G' then
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccger_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODGERENTE);
                             vsOperador := 'Gerente';
                          elsif integradora_comple.gvet_regpedido(i).tipocontacorrente = 'S' then
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccsup_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODSUPERVISOR);
                             vsOperador := 'Supervisor';
                          else
                             vnvldisponivel := pc_pkg_controlarsaldorca.ccrca_checar_disponivel_atual(coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).CODUSUR));
                             vsOperador := 'RCA';
                          end if;



                          IF (vnvldisponivel + reg_itens.saldo + vnvlsaldoped) < 0
                             AND reg_itens.saldo < 0
                          THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             reg_itens.codprod,
                                             reg_itens.numseq,
                                             reg_itens.codauxiliar,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             vsOperador || ' sem credito disponivel' || ';',
                                             NULL,
                                             null);

							integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
							integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
							integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
							integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
							integradora_comple.vLog.TipoLog            := 'C';
							integradora_comple.vLog.MSG                := 'CCRCA: Validacao 02 Movimentando Conta Corrente ' || vsOperador || ' - sem credito disponivel - ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;
							integradora_comple.vLog.ptabela            := null;
							integradora_comple.vLog.PVENDA             := null;
							integradora_comple.vLog.PBASE              := null;

							PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                            IF regfilial.aceitavendarcasemsaldofv = 'S'
                            THEN

                              integradora_comple.gvet_regpedido(i).posicao := 'B';
                              integradora_comple.gvet_regpedido(i).motivoposicao := substr(vsOperador || ' sem saldo disponivel',1,60);
                              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22, substr(vsOperador || ' Sem Saldo Disponível CC' || vsOperador,1,200) , 'C');
                              integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || vsOperador || ' sem saldo disponivel';
                            /*907.101980.2016*/
                            ELSIF regfilial.tipoimportacaovenda = 'RP' then
                              integradora_comple.gvet_regpedido(i).valido := false;
                            ELSE
                              integradora_comple.proc_pcpedimov(integradora_comple.gvet_regpedido(i),
                                           reg_itens.codprod,
                                           reg_itens.numseq,
                                           0,
                                             'N');
                            END IF;

                          ELSE

                            vnvlsaldoped := vnvlsaldoped + reg_itens.saldo;

                          END IF;
                        END LOOP;

                      ELSE

                          PC_PKG_CONTROLASALDORCAFORNEC.PRC_MOVIMENTASALDORCAFORNEC(integradora_comple.gvet_regpedido(i).CODUSUR,
                                                                                    integradora_comple.gvet_regpedido(i).numped,
                                                                                    2596,
                                                                                    integradora_comple.gvet_regpedido(i).codemitente,
                                                                                    integradora_comple.gvet_regpedido(i).codfilial,
                                                                                    vsmensagemccfornec);

                         if vsmensagemccfornec <> 'OK' then
                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             0,
                                             0,
                                             0,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             'Rca sem credito disponivel(C/C Fornec.)' || ';',
                                             NULL,
                                             null);


                              integradora_comple.gvet_regpedido(i).posicao := 'B';
                              integradora_comple.gvet_regpedido(i).motivoposicao := substr('Rca sem saldo disponivel',1,60);
                              PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22,substr('RCA Sem Saldo Disponível CC/FORNEC',1,200), 'C');
                              integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || 'Rca sem saldo disponivel';
                         END IF;
                         -- END LOOP;

                      END IF;
                    ELSE

                      FOR reg_itens IN (SELECT codprod,
                                               numseq,
                                               numped,
                                               codusur,
                                               codauxiliar
                                          FROM pcpedi
                                         WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                         ORDER BY numseq)
                      LOOP

                        IF NOT (pc_pkg_controlarsaldorca.ccfinrca_incluir_item_pedido(integradora_comple.gvet_regpedido(i).codemitente,
                                                                                      2596,
                                                                                      reg_itens.codusur,
                                                                                      reg_itens.numped,
                                                                                      reg_itens.codprod,
                                                                                      reg_itens.numseq,
                                                                                      vsmensagemccfin))
                        THEN

                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           reg_itens.codprod,
                                           reg_itens.numseq,
                                           reg_itens.codauxiliar,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '3',
                                           vsmensagemccfin || ';',
                                           NULL,
                                           null);

                          IF regfilial.aceitavendarcasemsaldofv = 'S'
                          THEN

                            integradora_comple.gvet_regpedido(i).posicao := 'B';
                            integradora_comple.gvet_regpedido(i).motivoposicao := substr('Rca sem saldo disponivel(C/C Fin)',1,60);
                            PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(integradora_comple.gvet_regpedido(i).numped, 22, substr('RCA Sem Saldo Disponível CC/FIN',1,200), 'C');
                            integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i).log || CHR(13) || 'Rca sem saldo disponivel';
                          ELSE

                            integradora_comple.proc_pcpedimov(integradora_comple.gvet_regpedido(i)
                                          ,reg_itens.codprod
                                          ,reg_itens.numseq
                                          ,0
                                          ,'N');

                          END IF;
                        END IF;

                      END LOOP;

                    END IF;
                    -------------------------------------------------------------------------

                    SELECT COUNT(*)
                      INTO VICONTADOR
                      FROM pcpedi
                     inner join pcpedipcpedifv
                        on pcpedipcpedifv.numped = pcpedi.numped
                       and pcpedipcpedifv.numseq = pcpedi.numseq
                       and pcpedipcpedifv.codprod = pcpedi.codprod
                     WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                      AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

                    IF VICONTADOR = 0 THEN
                        integradora_comple.gvet_regpedido(i).valido := FALSE;
                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           'Nenhum item gravado;',
                                           NULL,
                                           null);

                    END IF;

                  END IF;

                END IF;

                --Processo de Abatimento
                IF regfilial.usaabatimento = 'S'
                   AND (nvl(integradora_comple.gvet_regpedido(i).percdescabatimento,
                            0) > 0 OR nvl(integradora_comple.gvet_regpedido(i).vldescabatimento,
                                               0) > 0)
                THEN

                  integradora_comple.proc_processarabatimento(integradora_comple.gvet_regpedido(i),
                                           regcliente,
                                           regregiao,
                                           regfilial,
                                           regrca,
                                           regplpag,
                                           vnvltotped);

                END IF;
              END IF;


              IF integradora_comple.gvet_regpedido(i).valido = TRUE
              THEN

                IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
                THEN

                     -- verifica se ha itens no pedido
                      SELECT COUNT(*),
                             SUM(DECODE(NVL(pcpedi.bonific, 'N'), 'F', 0, 'S', 0, Round(pcpedi.qt * pcpedi.pvenda, 2))),
                             SUM(pcpedi.qt * pcpedi.pbaserca),
                             SUM(pcpedi.qt * pcpedi.vlcustocont),
                             SUM(pcpedi.qt * pcpedi.vlcustofin),
                             SUM(pcpedi.qt * pcpedi.vlcustoreal),
                             SUM(pcpedi.qt * pcpedi.vlcustorep),
                             SUM(Round(pcpedi.qt * pcpedi.ptabela, 2))
                        INTO vncontitensvalidos,
                             vnvlatend,
                             vnvltotbaserca,
                             vnvlcustocontped,
                             vnvlcustofinped,
                             vnvlcustorealped,
                             vnvlcustorepped,
                             vnvltottab
                        FROM pcpedi
                       inner join pcpedipcpedifv
                          on pcpedipcpedifv.numped = pcpedi.numped
                         and pcpedipcpedifv.numseq = pcpedi.numseq
                         and pcpedipcpedifv.codprod = pcpedi.codprod
                       WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                        AND  pcpedipcpedifv.numpedrcafv  = integradora_comple.gvet_regpedido(i).numpedrca;

                     IF vnvltotped <> vnvlatend
                        AND integradora_comple.gregpcconsum.validarvlminvendaaposcorte = 'S'
                        AND nvl(integradora_comple.gvet_regpedido(i).numpedorig,0) = 0
                     THEN
                        proc_validacaofinalcabposcorte(integradora_comple.gvet_regpedido(i),
                                                       regplpag,
                                                       regrca,
                                                       vnvltotped,
                                                       vnvlatend,
                                                       vncontitensvalidos);
                     END IF;


                  IF (integradora_comple.gvet_regpedido(i).condvenda = 5) AND
                      (integradora_comple.gvet_regpedido(i).numpedtv1 is not null) AND
                      (NVL(regcliente.validarlimbonific,'N') = 'S') then

                    vnPERCLIMITEVLTV5 := ferramentas.F_BUSCARPARAMETRO_NUM('PERCLIMITEVLTV5', integradora_comple.gvet_regpedido(i).codfilial, 0);

                    DECLARE
                        vtotalpedido PCPEDC.Vltotal%TYPE;
                    BEGIN
                       select Vltotal
                       into vtotalpedido
                       from pcpedc
                       where numped = integradora_comple.gvet_regpedido(i).numped;

                      IF NOT integradora_comple.validarValorTv1Tv5(integradora_comple.gvet_regpedido(i).numpedtv1,
                                 integradora_comple.gvet_regpedido(i).numped,
                                 vtotalpedido,
                                 vnPERCLIMITEVLTV5,
                                 vsMsgTv1Tv5)
                                  THEN

                      integradora_comple.gvet_regpedido(i).valido := FALSE;

                      integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                           integradora_comple.gvet_regpedido(i).numpedrca,
                           NULL,
                           NULL,
                           NULL,
                           integradora_comple.gvet_regpedido(i).cgccli,
                           NULL,
                           NULL,
                           NULL,
                           integradora_comple.gvet_regpedido(i).codusur,
                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                           NULL,
                           '2',
                           'Erro ao validar percentual limite de TV5:' || CHR(13) || vsMsgTv1Tv5 ,
                           NULL,
                           null);

                      END IF;
                    END;
                  END IF;

                  IF integradora_comple.gvet_regpedido(i).valido = TRUE
                  THEN
                    --DDVENDAS-21600
                    IF integradora_comple.gvet_regpedido(i).condvenda = 7
					and ((integradora_comple.gvet_regpedido(i).vendaassistida = 'N' AND integradora_comple.gvet_regpedido(i).numpedorig = 0) OR  (integradora_comple.gvet_regpedido(i).vendaassistida = 'S'))
                    --AND integradora_comple.gvet_regpedido(i).numpedorig = 0
                    THEN

                      IF regfilial.RESERVARESTOQUETV7 = 'S'
                      THEN

                        integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                        integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TipoLog            := 'C';
                        integradora_comple.vLog.MSG                := 'Gerando pedido TV8 automático.' || chr(13);

                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                        prc_gerarpedtv8(integradora_comple.gvet_regpedido(i).numped,
                                        vsmensagempedidotv8,
                                        vnnumpedtv8,
                                        vsposicaotv8,
                                        vnmotivotv8);



                        IF TRIM(vsmensagempedidotv8) IS NOT NULL AND
                           (vsmensagempedidotv8 like '%Erro%') THEN
                          integradora_comple.gvet_regpedido(i).valido := FALSE;
                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i)
                                                              .numped,
                                                              integradora_comple.gvet_regpedido(i)
                                                              .numpedrca,
                                                              NULL,
                                                              NULL,
                                                              NULL,
                                                              integradora_comple.gvet_regpedido(i)
                                                              .cgccli,
                                                              NULL,
                                                              NULL,
                                                              NULL,
                                                              integradora_comple.gvet_regpedido(i)
                                                              .codusur,
                                                              integradora_comple.gvet_regpedido(i)
                                                              .dtaberturapedpalm,
                                                              NULL,
                                                              '2',
                                                              vsmensagempedidotv8 || ';',
                                                              NULL,
                                                              null);

                          --DDVENDAS-21598: Não deve gravar o TV7 se não existir o TV8 na venda assistida.
                          if integradora_comple.gvet_regpedido(i).vendaassistida = 'S' THEN

                            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                            integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                            integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                            integradora_comple.vLog.TipoLog            := 'C';
                            integradora_comple.vLog.MSG                := 'Retorno ao gerar pedido TV8 ' || vsmensagempedidotv8 || ';';

                            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                            UPDATE pcpedcfv
                               SET observacao_pc = substr(observacao_pc || CHR(13) || integradora_comple.vLog.MSG, 1, 4000)
                             WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                               AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                               AND codusur = integradora_comple.gvet_regpedido(i).codusur
                               AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;

                            integradora_comple.gvet_regpedido(i).valido := FALSE;
                            p_existerro := TRUE;
                            RAISE_APPLICATION_ERROR(-20000, integradora_comple.vLog.MSG);
                          end if;

                        ELSE

                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           'Pedido TV8 gerado : ' || vnnumpedtv8 || ' na posicao : ' || vsposicaotv8 || ';',
                                           NULL,
                                           null);



                        END IF;

                        integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                        integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                        integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                        integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                        integradora_comple.vLog.TipoLog            := 'C';
                        integradora_comple.vLog.MSG                := 'Retorno gerar pedido TV8: '
                                                                      || vsmensagempedidotv8 || chr(13) ||
                                                                      case  when vnnumpedtv8 > 0 then  'Pedido TV8 gerado : ' || vnnumpedtv8 || ' na posicao: ' || vsposicaotv8 || ';'
                                                                       else ''
                                                                         end;

                        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                      END IF;

                    END IF;

                    IF regfilial.broker = 'N'
                    THEN


                      IF integradora_comple.gvet_regpedido(i).condvenda = 1
                         AND nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                                 0) = 0
                      THEN


                        integradora_comple.gvet_regpedido(i).geroubrinde := 'N';

                        IF (nvl(regcliente.validarcampanhabrinde,
                               'S') = 'S') and (integradora_comple.gvet_regpedido(i).gerabrinde = 'S')
                        THEN
                          integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                          integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                          integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                          integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                          integradora_comple.vLog.TipoLog            := 'C';
                          integradora_comple.vLog.MSG                := 'Apurando Brindes para o pedido ' || integradora_comple.gvet_regpedido(i).numped;

                          PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                          -- apuracao de brindes.
                          apurarcampanhasbrindes.proc_apurarcampanha(integradora_comple.gvet_regpedido(i).numped,
                                                                     /*  VEN-6547
                                                                         Conforme combinado com Rafael Soares, a filial será passada nula para que o comportamento
                                                                         da integradora fique igual ao da 316.
                                                                     */
                                                                     null,
                                                                     integradora_comple.gvet_regpedido(i).cgccli,
                                                                     vnnumseq,
                                                                     'S',
                                                                     vsmensagembrinde,
                                                                     vsgeroubrinde);

                          IF vsmensagembrinde IS NOT NULL
                          THEN
                            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                            integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                            integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                            integradora_comple.vLog.TipoLog            := 'C';
                            integradora_comple.vLog.MSG                := SUBSTR('Retorno apurar campanha brindes : ' || vsmensagembrinde,1,2000);

                            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '2',
                                             vsmensagembrinde,
                                             NULL, null);

                          END IF;

                          IF vsgeroubrinde = 'S'
                          THEN
                            integradora_comple.gvet_regpedido(i).geroubrinde := 'S';

                            update pcpedc c
                               set c.obsentrega1 = regcliente.obsentrega1
                                  ,c.obsentrega2 = regcliente.obsentrega2
                                  ,c.obsentrega3 = regcliente.obsentrega3
                                  ,c.obsentrega4 = regcliente.obsentrega4
                             where c.numpedtv1   = integradora_comple.gvet_regpedido(i).numped
                               and c.condvenda   = 5;

                          END IF;

                          -- Deyvid Costa - Deixando pedido pendente se houver algum item brinde sem estoque
                          DECLARE
                            VNCONTITEM     NUMBER;
                            VNNUMPEDLOCAL  PCPEDC.NUMPED%TYPE;
                            VSPOSICAOLOCAL PCPEDC.POSICAO%TYPE;
                          BEGIN

                            BEGIN
                              SELECT COUNT(PCPEDI.CODPROD) CONTAITEMPENDENTE
                                INTO VNCONTITEM
                              FROM PCPEDI,
                                     TABLE(VENDAS.ESTOQUE_DISPONIVEL(PCPEDI.CODPROD,
                                                                     NVL(PCPEDI.CODFILIALRETIRA, integradora_comple.gvet_regpedido(i).codfilial))) EST_DISP
                               WHERE PCPEDI.CODPROD = EST_DISP.CODPROD
                                 AND NVL(PCPEDI.CODFILIALRETIRA, integradora_comple.gvet_regpedido(i).codfilial) = EST_DISP.CODFILIAL
                                 AND PCPEDI.QT > EST_DISP.QTDISP
                                 AND PCPEDI.NUMPED = INTEGRADORA_COMPLE.GVET_REGPEDIDO(I).NUMPED
                                 AND NVL(PCPEDI.BRINDE, 'N') = 'S';
                              EXCEPTION
                               WHEN NO_DATA_FOUND THEN
                                VNCONTITEM := 0;
                              END;

                              IF VNCONTITEM = 0 THEN
                                 BEGIN
                                    SELECT COUNT(PCPEDI.CODPROD) CONTAITEMPENDENTE
                                    INTO VNCONTITEM
                                  FROM PCPEDC,
                                       PCPEDI,
                                         TABLE(VENDAS.ESTOQUE_DISPONIVEL(PCPEDI.CODPROD,
                                                                         NVL(PCPEDI.CODFILIALRETIRA, integradora_comple.gvet_regpedido(i).codfilial))) EST_DISP
                                   WHERE PCPEDI.CODPROD = EST_DISP.CODPROD
                                     AND NVL(PCPEDI.CODFILIALRETIRA, integradora_comple.gvet_regpedido(i).codfilial) = EST_DISP.CODFILIAL
                                     AND PCPEDI.QT > EST_DISP.QTDISP
                                     AND PCPEDC.NUMPED = PCPEDI.NUMPED
									 AND PCPEDI.POSICAO NOT IN ('L','M')
                                     AND PCPEDC.NUMPEDTV1 = INTEGRADORA_COMPLE.GVET_REGPEDIDO(I).NUMPED
                                     AND NVL(PCPEDI.BRINDE, 'N') = 'S';
                                  EXCEPTION
                                   WHEN NO_DATA_FOUND THEN
                                    VNCONTITEM := 0;
                                  END;
                                END IF;


                            IF VNCONTITEM > 0 THEN
								IF (integradora_comple.gregpcconsum.ACEITAVENDABLOQ = 'S') THEN
								  VNNUMPEDLOCAL := integradora_comple.gvet_regpedido(i).numped;
								  integradora_comple.gvet_regpedido(i).posicao := 'B';
								  VSPOSICAOLOCAL := integradora_comple.gvet_regpedido(i).POSICAO;

								  UPDATE PCPEDC
									 SET POSICAO = VSPOSICAOLOCAL
								   WHERE NUMPED = VNNUMPEDLOCAL;

								  UPDATE PCPEDI
									 SET POSICAO = VSPOSICAOLOCAL
								   WHERE NUMPED = VNNUMPEDLOCAL;

								  PKG_MOTIVOBLOQUEIO.INSERTMOTIVO(VNNUMPEDLOCAL,
																  22,
																  substr('Item brinde sem estoque ' ||
																  vsmensagembrindE,1,200),
																  'C');
								  integradora_comple.gvet_regpedido(i).motivoposicao := substr('Item brinde sem estoque. ' ||
																								vsmensagembrinde,1,60);
								  integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i)
																			  .log || CHR(13) ||
																			   'Item brinde sem estoque. ' ||
																			   vsmensagembrinde;
								ELSE 
								  VNNUMPEDLOCAL := integradora_comple.gvet_regpedido(i).numped;
								  integradora_comple.gvet_regpedido(i).posicao := 'P';
								  VSPOSICAOLOCAL := integradora_comple.gvet_regpedido(i).POSICAO;

								  UPDATE PCPEDC
								   SET POSICAO = VSPOSICAOLOCAL
								   WHERE NUMPED = VNNUMPEDLOCAL;

								  UPDATE PCPEDI
								   SET POSICAO = VSPOSICAOLOCAL
								   WHERE NUMPED = VNNUMPEDLOCAL;
								  integradora_comple.gvet_regpedido(i).motivoposicao := substr('Item brinde sem estoque. ' ||
																								vsmensagembrinde,1,60);
								  integradora_comple.gvet_regpedido(i).log := integradora_comple.gvet_regpedido(i)
																			  .log || CHR(13) ||
																			   'Item brinde sem estoque. ' ||
																			   vsmensagembrinde;
								   
								END IF;
                            END IF;
                          END;



                        END IF;
                      END IF;
                    END IF;

                    -----------------------------------------------------------
                    --Autor:Rafael Soares
                    --Solicitação: 0.032567.2016
                    --Data: 21/03/2016
                    --Descrição: Ajustado para que a rotina 2500 respeite os mesmos críterios de validação de conta corrente
                    --           que a rotina 316, esta são, O CLIENTE deve movimentar a conta corrente, o RCA deve movimentar a conta
                    --           corrente e o parametor da 132 deve movimentar a conta corrente.
                    --           Caso alguma dessas opções esteja nula, o valor do NVL é o que esta no parametro da 132
                    -----------------------------------------------------------


                    SELECT NVL(USADEBCREDRCA,integradora_comple.gregpcconsum.usacredrca)
                     INTO vsUSACCRCAUSUR
                     FROM PCUSUARI
                    WHERE PCUSUARI.CODUSUR = integradora_comple.gvet_regpedido(i).CODUSUR;


                    SELECT NVL(usadebcredrca,integradora_comple.gregpcconsum.usacredrca)
                       INTO vsUSACCRCACLIENT
                       FROM PCCLIENT
                      WHERE PCCLIENT.CODCLI =  integradora_comple.gvet_regpedido(i).CODCLI;

                    vsUSADEBCREDRCA := (((integradora_comple.gregpcconsum.usacredrca = 'S') AND
                                       (vsUSACCRCAUSUR = 'S')) or
                                       FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'S') AND
                                       (vsUSACCRCACLIENT = 'S');

                    IF integradora_comple.gvet_regpedido(i).condvenda <> 13 and vsUSADEBCREDRCA
                    THEN
                      -----------------------------------------------------------
                      --Autor: Rodrigo Santos
                      --Solicitação: HIS.03499.2014
                      --Data: 21/10/2014
                      --Descrição: Implementação das chamadas para C/C como desconto financeiro.
                      -----------------------------------------------------------
                      IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USASALDOCONTACORRENTEDESCFIN','99','N') = 'N' THEN

                        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_USACREDRCAFORNEC','99','N') = 'N' THEN

                          FOR reg_itens IN (SELECT codprod,
                                                   numseq,
                                                   qt,
												   ROUND(nvl(pcpedi.pbaserca, 0), 3) pbaserca,
                                                   pc_pkg_controlarsaldorca.ccrca_saldo_item(integradora_comple.gregpcconsum.usacredrca,
                                                                                             integradora_comple.gvet_regpedido(i).usadebcredrca,
                                                                                             'N',
                                                                                             integradora_comple.gvet_regpedido(i).origemped,
                                                                                             --integradora_comple.gregpcconsum.bonificaltdebcredrca,
                                                                                             nvl(integradora_comple.gvet_regpedido(i).bonificaltdebcredrca,integradora_comple.gregpcconsum.bonificaltdebcredrca),
                                                                                             integradora_comple.gregpcconsum.trocaaltdebcredrca,
                                                                                             integradora_comple.gregpcconsum.crmaltdebcredrca,
                                                                                             integradora_comple.gregpcconsum.brokeraltdebcredrca,
                                                                                             integradora_comple.gregpcconsum.tipomovccrca,
                                                                                             integradora_comple.gvet_regpedido(i).condvenda,
                                                                                             'N',
                                                                                             coalesce(pcpedi.codusur, integradora_comple.gvet_regpedido(i).codusur),
                                                                                             'V',
                                                                                             -- VEN-5760
                                                                                             -- Arredondando as casas decimais dos preços para 3, pois o conta corrente é somente
                                                                                             -- 2 casas decimais.
                                                                                             ROUND(pcpedi.pvenda,3),
                                                                                             ROUND(pcpedi.ptabela,3),
                                                                                             ROUND(pcpedi.pbaserca,3),
                                                                                             pcpedi.qt,
                                                                                             'N',
                                                                                             pcpedi.movimentacontacorrenterca) saldo,
                                                                                             pcpedi.codusur
                                              FROM pcpedi
                                             WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                               AND numseq > vnmaxnumseq
                                             ORDER BY saldo DESC)
                          LOOP

                            pc_pkg_controlarsaldorca.ccrca_bloquear_registro_rca(coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).CODUSUR));
                            if integradora_comple.gvet_regpedido(i).tipocontacorrente = 'G' then
                              vnvldisponivel := pc_pkg_controlarsaldorca.ccger_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODGERENTE);
                              vsOperador := 'Gerente';
                            elsif integradora_comple.gvet_regpedido(i).tipocontacorrente = 'S' then
                              vnvldisponivel := pc_pkg_controlarsaldorca.ccsup_checar_disponivel_atual(integradora_comple.gvet_regpedido(i).CODSUPERVISOR);
                              vsOperador := 'Supervisor';
                            else
                              vnvldisponivel := pc_pkg_controlarsaldorca.ccrca_checar_disponivel_atual(coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).CODUSUR));
                              vsOperador := 'RCA';
                            end if;

                            integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                            integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                            integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                            integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                            integradora_comple.vLog.TipoLog            := 'C';
                            integradora_comple.vLog.MSG                := 'CCRCA: Validacao 03 Movimentando Conta Corrente ' || vsOperador
                                                                           || ' vnvldisponivel ' || vnvldisponivel || CHR(13)
                                                                           || ' saldoitem ' || reg_itens.saldo;

                            PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

							IF (reg_itens.pbaserca = 0) THEN
							   integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
							   integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
							   integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
							   integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
							   integradora_comple.vLog.TipoLog            := 'C';
							   integradora_comple.vLog.MSG                := 'CCRCA: Validacao 03 Movimentando Conta Corrente ' || vsOperador || ' Base RCA zerado e inválido';

                               PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
							   integradora_comple.gvet_regpedido(i).log := vsOperador || ' Base RCA zerado e inválido';
							   integradora_comple.gvet_regpedido(i).valido := FALSE;
                 p_existerro := TRUE;
                 RAISE ERRO_CCRCA_FINAL;
							END IF;

              IF (vnvldisponivel + reg_itens.saldo) < 0 AND reg_itens.saldo < 0 THEN

                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'CCRCA: Validacao 03 Movimentando Conta Corrente ' || vsOperador || ' - sem credito disponivel - ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                IF regfilial.aceitavendarcasemsaldofv = 'S'
                THEN

							   vbsaldorca := pc_pkg_controlarsaldorca.ccrca_incluir_item_pedido(integradora_comple.gvet_regpedido(i).codemitente,
                                                                                  2596,
                                                                                  coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).codusur),
                                                                                  integradora_comple.gvet_regpedido(i).numped,
                                                                                  reg_itens.codprod,
                                                                                  reg_itens.numseq);

                   integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                   integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                   integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                   integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                   integradora_comple.vLog.TipoLog            := 'C';
                   integradora_comple.vLog.MSG                := 'CCRCA: Movimentando Conta Corrente ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;
                   if vbsaldorca then
                     integradora_comple.vLog.MSG                := integradora_comple.vLog.MSG || ' - Resultado TRUE';
                   else
                     integradora_comple.vLog.MSG                := integradora_comple.vLog.MSG || ' - Resultado FALSE';
                   end if;
                   integradora_comple.vLog.ptabela            := null;
                   integradora_comple.vLog.PVENDA             := null;
                   integradora_comple.vLog.PBASE              := null;

                   PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
                  ELSE
							    integradora_comple.gvet_regpedido(i).log := vsOperador || ' sem saldo disponivel';
							    p_existerro := TRUE;
                  RAISE ERRO_CCRCA_FINAL;
                END IF;
							ELSE
							  vbsaldorca := pc_pkg_controlarsaldorca.ccrca_incluir_item_pedido(integradora_comple.gvet_regpedido(i).codemitente,
                                                                                 2596,
                                                                                 coalesce(reg_itens.codusur, integradora_comple.gvet_regpedido(i).codusur),
                                                                                 integradora_comple.gvet_regpedido(i).numped,
                                                                                 reg_itens.codprod,
                                                                                 reg_itens.numseq);

                  integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                  integradora_comple.vLog.TipoLog            := 'C';
                  integradora_comple.vLog.MSG                := 'CCRCA: Movimentando Conta Corrente ACEITAVENDARCASEMSALDOFV ' || regfilial.aceitavendarcasemsaldofv;
                  if vbsaldorca then
                    integradora_comple.vLog.MSG                := integradora_comple.vLog.MSG || ' - Resultado TRUE';
                  else
                    integradora_comple.vLog.MSG                := integradora_comple.vLog.MSG || ' - Resultado FALSE';
                  end if;
                  integradora_comple.vLog.ptabela            := null;
                  integradora_comple.vLog.PVENDA             := null;
                  integradora_comple.vLog.PBASE              := null;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));
							END IF;

                          END LOOP;

                        END IF;

                      ELSE

                        FOR reg_itens IN (SELECT codprod,
                                                 numseq,
                                                 numped,
                                                 codusur,
                                                 codauxiliar
                                            FROM pcpedi
                                           WHERE numped = integradora_comple.gvet_regpedido(i).numped
                                           ORDER BY numseq)
                        LOOP

                          IF NOT (pc_pkg_controlarsaldorca.ccfinrca_incluir_item_pedido(integradora_comple.gvet_regpedido(i).codemitente,
                                                                                        2596,
                                                                                        reg_itens.codusur,
                                                                                        reg_itens.numped,
                                                                                        reg_itens.codprod,
                                                                                        reg_itens.numseq,
                                                                                        vsmensagemccfin))
                          THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             reg_itens.codprod,
                                             reg_itens.numseq,
                                             reg_itens.codauxiliar,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '3',
                                             vsmensagemccfin || ';',
                                             NULL,
                                             null);

                          END IF;

                        END LOOP;

                      END IF;
                    END IF;

                    IF integradora_comple.gregpcconsum.CODCONTAREBAIXACMV IS NOT NULL
                       OR integradora_comple.gregpcconsum.codcontarebaixacmvaapurar IS NOT NULL
                    THEN
                      integradora_comple.proc_RebaixarCMV(integradora_comple.gvet_regpedido(i).numped,
                                       integradora_comple.gvet_regpedido(i).data,
                                       integradora_comple.gvet_regpedido(i).codfilial,
                                       integradora_comple.gvet_regpedido(i).CONDVENDA);


                      SELECT SUM(pcpedi.qt * pcpedi.vlcustofin),
                             SUM(pcpedi.qt * pcpedi.vlcustoreal)
                        INTO vnvlcustofinped,
                             vnvlcustorealped
                        FROM pcpedi
                       WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
					   AND pcpedi.QT > 0;

                      BEGIN

                        UPDATE pcpedc
                           SET vlcustofin  = decode(integradora_comple.gvet_regpedido(i).condvenda,
                                                    20,
                                                    0,
                                                    vnvlcustofinped),
                               vlcustoreal = decode(integradora_comple.gvet_regpedido(i).condvenda,
                                                    20,
                                                    0,
                                                    vnvlcustorealped)
                         WHERE numped = integradora_comple.gvet_regpedido(i).numped;
                      EXCEPTION
                        WHEN OTHERS THEN

                          integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                           integradora_comple.gvet_regpedido(i).numpedrca,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).cgccli,
                                           NULL,
                                           NULL,
                                           NULL,
                                           integradora_comple.gvet_regpedido(i).codusur,
                                           integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                           NULL,
                                           '2',
                                           'Erro ao atualizar pedido apos rebaixa de cmv :' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                           NULL,
                                           null);


                      END;

                    END IF;

--                    COMMIT;

                    --verifica se teve pedido de brinde gerado
                    SELECT COUNT(*)
                      INTO viexistebrinde
                      FROM pcpedc
                     WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                       AND codusur   = integradora_comple.gvet_regpedido(i).codusur
                       AND dtaberturapedpalm   = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                       AND brinde = 'S';


                    IF viexistebrinde >= 1
                    THEN

                    BEGIN
                      FOR PED_BRINDE IN(
                      SELECT numped
                        FROM pcpedc
                       WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                         AND codusur   = integradora_comple.gvet_regpedido(i).codusur
                         AND dtaberturapedpalm   = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                         AND brinde = 'S')
                         LOOP

                      --rebaixar cmv para itens do pedido de brinde
                      IF integradora_comple.gregpcconsum.CODCONTAREBAIXACMV IS NOT NULL
                      THEN

                        integradora_comple.proc_RebaixarCMV(ped_brinde.numped,
                                         integradora_comple.gvet_regpedido(i).data,
                                         integradora_comple.gvet_regpedido(i).codfilial,
                                         5);



                        SELECT SUM(pcpedi.qt * pcpedi.vlcustofin),
                               SUM(pcpedi.qt * pcpedi.vlcustoreal)
                          INTO vnvlcustofinped,
                               vnvlcustorealped
                          FROM pcpedi
                         WHERE pcpedi.numped = ped_brinde.numped;

                        BEGIN

                          UPDATE pcpedc
                             SET vlcustofin  = vnvlcustofinped,
                                 vlcustoreal = vnvlcustorealped
                           WHERE numped = ped_brinde.numped;
                        EXCEPTION
                          WHEN OTHERS THEN

                            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                                             integradora_comple.gvet_regpedido(i).numpedrca,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).cgccli,
                                             NULL,
                                             NULL,
                                             NULL,
                                             integradora_comple.gvet_regpedido(i).codusur,
                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                             NULL,
                                             '2',
                                             'Erro ao atualizar pedido apos rebaixa de cmv para pedido de brinde :' || SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE,
                                             NULL,
                                             null);


                        END;

                      END IF;
                      END LOOP;

                      END;
                    END IF;

--                 COMMIT;

                    SELECT nvl(vlcorrente,
                               0) + nvl(vllimcred,
                                        0)
                      INTO vnvlsaldorca
                      FROM pcusuari
                     WHERE codusur = integradora_comple.gvet_regpedido(i).codusur;


                    UPDATE pcpedcfv
                       SET pcpedcfv.saldoatualrca = vnvlsaldorca
                     WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                       AND cgccli = integradora_comple.gvet_regpedido(i).cgccli
                       AND codusur = integradora_comple.gvet_regpedido(i).codusur
                       AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm;


                    IF integradora_comple.gvet_regpedido(i).valido = TRUE
                      THEN

                      integradora_comple.PROC_TOTALIZARPEDIDO(integradora_comple.gvet_regpedido(i).numped);

                    END IF;

                  ELSE

                    ROLLBACK;

                    IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                           0) = 0
                    THEN

                      DELETE FROM pcpedi
                       WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

                      DELETE FROM pcorigempreco
                       WHERE numped = integradora_comple.gvet_regpedido(i).numped;

                      DELETE FROM pcpedc
                       WHERE pcpedc.numped = integradora_comple.gvet_regpedido(i).numped;

--                      COMMIT;
                    END IF;

                  END IF;

                /*ELSE

                  COMMIT;   */

                END IF;

              ELSE

                ROLLBACK;

                IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                       0) = 0
                THEN

                  IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
                  THEN

                    DELETE FROM pcorcavendai
                     WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

                    DELETE FROM pcorcavendac
                     WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

        --            COMMIT;

                  ELSE

                    DELETE FROM pcpedi
                     WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

                    DELETE FROM pcorigempreco
                     WHERE numped = integradora_comple.gvet_regpedido(i).numped;

                    DELETE FROM pcpedc
                     WHERE pcpedc.numped = integradora_comple.gvet_regpedido(i).numped;

--                    COMMIT;
                  END IF;
                END IF;
              END IF;
            ELSE
              -- rejeitado na validacao final do cabecalho
              ROLLBACK;

              IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                     0) = 0
              THEN

                IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
                THEN

                  DELETE FROM pcorcavendai
                   WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

--                  COMMIT;

                ELSE

                  DELETE FROM pcpedi
                   WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

                  DELETE FROM pcorigempreco
                   WHERE numped = integradora_comple.gvet_regpedido(i).numped;

--                  COMMIT;
                END IF;

              END IF;

            END IF;
          END IF; -- pedido valido (integradora_comple.gvet_regpedido (i).valido)

          -----------------------------------------------------------
          FOR itemped IN
          (SELECT NUMPED, NUMSEQ, CODPROD
             FROM PCPEDI
            WHERE NUMPED = integradora_comple.gvet_regpedido(i).numped
            UNION ALL
           SELECT NUMPED, NUMSEQ, CODPROD
             FROM PCPEDI
            WHERE NUMPED IN (SELECT NUMPEDBNF FROM PCPEDC WHERE NUMPED = integradora_comple.gvet_regpedido(i).numped))
           LOOP

             VENDAS.APLICAR_VERBACAMPANHA(itemped.numped,
                                          itemped.codprod,
                                          itemped.numseq,
										  integradora_comple.gvet_regpedido(i).codfilial);

           END LOOP;
           -----------------------------------------------------------

          IF integradora_comple.gvet_regpedido(i).condvenda NOT IN(7) THEN
            reservarestoque(integradora_comple.gvet_regpedido(i));
          END IF;

          proc_processaretornotab(p_existerro, i);

          --COMMIT;

          /* Autor: Rafael Braga
             Solicitação: 2550.083969.2016
             Data: 03/08/2016
             Descrição: Comitando antes de separar os pedidos; caso isso não seja feito,
                        diversas tabelas estarão com lock, pois o pedido original não vai
                        ter sido finalizado. É necessário o commit para concluir o processamento
                        do pedido original e em seguida processar o pedido de restrição.
          */
          integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
          integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
          integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
          integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
          integradora_comple.vLog.TipoLog            := 'C';
          integradora_comple.vLog.MSG                := 'Efetuando COMMIT para geração dos novos pedidos(TV8, RESTRIÇÃO TRANSP, ST)';

          PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

          VNCOUNTPEDIDOS_2 := 0;

          IF integradora_comple.gvet_regpedido(i).valido = TRUE
          THEN
            IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
               -- AND integradora_comple.gvet_regpedido(i).numpedorig = 0 -- Solicitação: 907.058478.2015
               AND integradora_comple.gvet_regpedido(i).condvenda NOT IN (7)
            THEN

              BEGIN
                SELECT COUNT(DISTINCT(PCPRODUT.RESTRICAOTRANSP))
                  INTO VNCOUNTPEDIDOS_TRANSP
                  FROM PCPEDI, PCPRODUT
                  WHERE PCPEDI.NUMPED = integradora_comple.gvet_regpedido(i).numped
                  AND PCPEDI.CODPROD = PCPRODUT.CODPROD
                  AND NVL(PCPRODUT.RESTRICAOTRANSP,'N') <> 'N';
              EXCEPTION
                WHEN OTHERS THEN
                  VNCOUNTPEDIDOS_TRANSP := 0;
              END;

              BEGIN
                SELECT COUNT(DISTINCT(PCPRODUT.RESTRICAOTRANSP))
                  INTO VNCOUNTPEDIDOS_TRANSP_BRINDE
                  FROM PCPEDI, PCPRODUT
                  WHERE PCPEDI.NUMPED = vnnumpedbrinde
                  AND PCPEDI.CODPROD = PCPRODUT.CODPROD
                  AND NVL(PCPRODUT.RESTRICAOTRANSP,'N') <> 'N';
              EXCEPTION
                WHEN OTHERS THEN
                  VNCOUNTPEDIDOS_TRANSP_BRINDE := 0;
              END;

              IF regfilial.separarprodcomrestricaotransp = 'S'
              THEN

                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Verificação da geração de pedidos com restrição de transporte para pedido ' || vsmensagembrinde;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                IF (VNCOUNTPEDIDOS_TRANSP > 0) THEN

                prc_gerarpedidorestricaotransp(integradora_comple.gvet_regpedido(i).numped,
                                               vsauxpedido,
                                               vsmensagem,
                                               CASE
                                                 WHEN REGFILIAL.SEPARARPRODCOMRESTRICAOTRANSP = 'S' THEN
                                                   EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED)
                                               ELSE
                                                 0
                                               END,
                                               CASE
                                                 WHEN REGFILIAL.SEPARARPRODCOMRESTRICAOTRANSP = 'S' AND
                                                      vbPossuiMaisDeUmaRestricao THEN
                                                   EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED)
                                               ELSE
                                                 0
                                               END
                                                 );
                  IF vsmensagem IS NOT NULL and
                       (vsmensagem not like ('%sucesso%'))

                     THEN
                      integradora_comple.gvet_regpedido(i).valido := FALSE;
                      integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i)
                                                          .numped,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .numpedrca,
                                                          NULL,
                                                          NULL,
                                                          NULL,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .cgccli,
                                                          NULL,
                                                          NULL,
                                                          NULL,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .codusur,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .dtaberturapedpalm,
                                                          NULL,
                                                          '2',
                                                          vsmensagem || ';',
                                                          NULL,
                                                          null);

                      RAISE ERRO_PROC_FINAL;
                  END IF;


                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Retorno geração pedido com restrição de transporte : ' || vsmensagem || chr(13) ||
                                           'Pedido gerado : ' || vsauxpedido;

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

               -- COMMIT;  VEN-9145 - Ajustado o lugar do Commit para que não ocorra Deadlock na Ferramentas.
                END IF;

                IF (nvl(vnnumpedbrinde,0) > 0) then

                 IF (VNCOUNTPEDIDOS_TRANSP_BRINDE > 0) THEN

                  prc_gerarpedidorestricaotransp(vnnumpedbrinde,
                                                 vsauxpedido,
                                                 vsmensagem,
                                                 CASE
                                                   WHEN REGFILIAL.SEPARARPRODCOMRESTRICAOTRANSP = 'S' THEN
                                                     EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED)
                                                 ELSE
                                                   0
                                                 END,
                                                 CASE
                                                   WHEN REGFILIAL.SEPARARPRODCOMRESTRICAOTRANSP = 'S' AND
                                                        vbPossuiMaisDeUmaRestricaoBnf THEN
                                                     EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED)
                                                 ELSE
                                                   0
                                                 END);

                    IF vsmensagem IS NOT NULL and
                       (vsmensagem not like ('%sucesso%'))

                     THEN
                      integradora_comple.gvet_regpedido(i).valido := FALSE;
                      integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i)
                                                          .numped,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .numpedrca,
                                                          NULL,
                                                          NULL,
                                                          NULL,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .cgccli,
                                                          NULL,
                                                          NULL,
                                                          NULL,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .codusur,
                                                          integradora_comple.gvet_regpedido(i)
                                                          .dtaberturapedpalm,
                                                          NULL,
                                                          '2',
                                                          vsmensagem || ';',
                                                          NULL,
                                                          null);

                      RAISE ERRO_PROC_FINAL;
                    END IF;

                  integradora_comple.vLog.NUMPEDRCA          := vnnumpedbrinde;
                  integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                  integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                  integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                  integradora_comple.vLog.TipoLog            := 'C';
                  integradora_comple.vLog.MSG                := 'Retorno geração pedido brinde com restrição de transporte : ' || vsmensagem || chr(13) ||
                                           'Pedido gerado : ' || vsauxpedido;

                  PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                END IF;

               END IF;

              ELSE

                integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
                integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
                integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
                integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
                integradora_comple.vLog.TipoLog            := 'C';
                integradora_comple.vLog.MSG                := 'Não separou pedidos com restrição de transporte.';

                PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

                SELECT COUNT(*)
                  INTO viexisterest
                  FROM pcpedi,
                       pcprodut
                 WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                   AND pcpedi.codprod = pcprodut.codprod
                   AND nvl(pcprodut.restricaotransp,
                           'N') = 'S';

                SELECT COUNT(*)
                  INTO viexisterestref
                  FROM pcpedi,
                       pcprodut
                 WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped
                   AND pcpedi.codprod = pcprodut.codprod
                   AND nvl(pcprodut.restricaotransp,
                           'N') = 'R';


                IF viexisterestref > 0
                THEN

                  UPDATE pcpedc
                     SET pcpedc.restricaotransp = 'R'
                   WHERE numped = integradora_comple.gvet_regpedido(i).numped;


                ELSE

                  IF viexisterest > 0
                  THEN

                    UPDATE pcpedc
                       SET pcpedc.restricaotransp = 'S'
                     WHERE numped = integradora_comple.gvet_regpedido(i).numped;


                  END IF;
                END IF;

                --COMMIT; Commit adicionado pelo mesmo motivo (pesquisar 2550.083969.2016)

              END IF;

            END IF;

            --tarefa 194518
            IF regfilial.separarprodcomst = 'S'
            THEN

              IF integradora_comple.gvet_regpedido(i).orcamento = 'N'
                 AND integradora_comple.gvet_regpedido(i).numpedorig = 0
                 AND integradora_comple.gvet_regpedido(i).condvenda NOT IN (7)
              THEN

                FOR reg IN (SELECT numped
                              FROM pcpedc p
                             WHERE p.numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                               AND p.dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                               AND p.codusur = integradora_comple.gvet_regpedido(i).codusur
                               AND p.codcli = integradora_comple.gvet_regpedido(i).codcli)
                LOOP

               integradora_comple.vLog.NUMPEDRCA          := integradora_comple.gvet_regpedido(i).numpedrca;
               integradora_comple.vLog.CODUSUR            := integradora_comple.gvet_regpedido(i).CODUSUR;
               integradora_comple.vLog.CGCCLI             := integradora_comple.gvet_regpedido(i).CGCCLI;
               integradora_comple.vLog.DTABERTURAPEDPALM  := integradora_comple.gvet_regpedido(i).DTABERTURAPEDPALM;
               integradora_comple.vLog.TipoLog            := 'C';
               integradora_comple.vLog.MSG                := 'Separando itens com ST. PEDIDO : ' || reg.numped;

               PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


               prc_gerarpedidoitemcomst(reg.numped,
                                        vnpedidorestst,
                                        vsmensagemrestst,
                                        EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED));

                   IF vsmensagemrestst IS NOT NULL and
                         (vsmensagemrestst not like ('%sucesso%'))

                       THEN
                        integradora_comple.gvet_regpedido(i).valido := FALSE;
                        integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i)
                                                            .numped,
                                                            integradora_comple.gvet_regpedido(i)
                                                            .numpedrca,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            integradora_comple.gvet_regpedido(i)
                                                            .cgccli,
                                                            NULL,
                                                            NULL,
                                                            NULL,
                                                            integradora_comple.gvet_regpedido(i)
                                                            .codusur,
                                                            integradora_comple.gvet_regpedido(i)
                                                            .dtaberturapedpalm,
                                                            NULL,
                                                            '2',
                                                            vsmensagemrestst || ';',
                                                            NULL,
                                                            null);

                      RAISE ERRO_PROC_FINAL;
                   END IF;

                END LOOP;

              END IF;
            END IF;

            IF nvl(regfilial.nummaxitensnfe,
                           0) > 0
                       AND nvl(integradora_comple.gvet_regpedido(i).orcamento,
                               'N') = 'N'
                       AND integradora_comple.gvet_regpedido(i).condvenda <> 7
                    THEN

                      vicontador := 1;

                      WHILE vicontador > 0
                      LOOP

                        -- Verifica se tem algum pedido com numero de itens superior ao parametrizado na pcparamfilial.nummaxitensnfe
                        SELECT COUNT(*)
                          INTO vicontador
                          FROM pcpedc
                         WHERE numpedrca = integradora_comple.gvet_regpedido(i).numpedrca
                           AND codusur = integradora_comple.gvet_regpedido(i).codusur
                           AND codcli = integradora_comple.gvet_regpedido(i).codcli
                           AND dtaberturapedpalm = integradora_comple.gvet_regpedido(i).dtaberturapedpalm
                           AND pcpedc.numitens > nvl(regfilial.nummaxitensnfe,
                                                     0);

                        IF vicontador > 0
                        THEN
                          integradora_comple.proc_divide_numitensnfe(integradora_comple.gvet_regpedido(i).numpedrca,
                                                             integradora_comple.gvet_regpedido(i).codusur,
                                                             integradora_comple.gvet_regpedido(i).codcli,
                                                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                                                             regfilial,
                                                             vsmensagemdividenfe,
                                                             integradora_comple.gvet_regpedido(i).pedidodivididonfe,
                                                             EXTRAIR_PROX_NUMPED(integradora_comple.T_NUMPED_PED));

                           IF vsmensagemdividenfe IS NOT NULL and
                             (vsmensagemdividenfe not like ('%sucesso%'))

                               THEN
                                integradora_comple.gvet_regpedido(i).valido := FALSE;
                                integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i)
                                                                    .numped,
                                                                    integradora_comple.gvet_regpedido(i)
                                                                    .numpedrca,
                                                                    NULL,
                                                                    NULL,
                                                                    NULL,
                                                                    integradora_comple.gvet_regpedido(i)
                                                                    .cgccli,
                                                                    NULL,
                                                                    NULL,
                                                                    NULL,
                                                                    integradora_comple.gvet_regpedido(i)
                                                                    .codusur,
                                                                    integradora_comple.gvet_regpedido(i)
                                                                    .dtaberturapedpalm,
                                                                    NULL,
                                                                    '2',
                                                                    vsmensagemdividenfe || ';',
                                                                    NULL,
                                                                    null);

                              RAISE ERRO_PROC_FINAL;
                           END IF;

                        END IF;
                      END LOOP;
                    END IF;
          END IF;
			IF REGFILIAL.utilizaroteirizacao = 'S'
			   AND REGFILIAL.atualizarotanomomentovenda = 'S'
			THEN
				  DECLARE
					  vsmensagematurota VARCHAR2(1000);
					  vbjustvalida      BOOLEAN;
				  BEGIN

				  PRC_ATUALIZA_ROTA(REGFILIAL.utilizaroteirizacao,
									REGFILIAL.atualizarotanomomentovenda,
									integradora_comple.gvet_regpedido(i).codcli,
									integradora_comple.gvet_regpedido(i).CODUSUR,
									'PED',
									integradora_comple.gvet_regpedido(i).numped,
									trunc(integradora_comple.gvet_regpedido(i).dtaberturapedpalm),
									integradora_comple.gvet_regpedido(i).codrota,
									NULL,
									NULL,
									vsmensagematurota,
									vbjustvalida);

				  IF vsmensagematurota IS NOT NULL
				  THEN


					integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
									 integradora_comple.gvet_regpedido(i).numpedrca,
									 NULL,
									 NULL,
									 NULL,
									 integradora_comple.gvet_regpedido(i).cgccli,
									 NULL,
									 NULL,
									 NULL,
									 integradora_comple.gvet_regpedido(i).CODUSUR,
									 integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
									 NULL,
									 '2',
									 vsmensagematurota || ';',
									 NULL,
									 null);

				  END IF;
				  END;


			END IF;

          COMMIT;

          INTEGRADORA_COMPLE.T_NUMPED_PED.DELETE();

          commit; -- Commit inserido para evitar lock. //DDVENDAS-729

          IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('GERARLOCKPRODFILESTPEDFV',integradora_comple.gvet_regpedido(i).codfilial,'S') = 'S'
           THEN
            integradora_comple.proc_liberaestoque(vCursorEstoque);
          END IF;

        END IF;
        EXCEPTION
          WHEN ERRO_PROC_FINAL THEN

            ROLLBACK;

            INTEGRADORA_COMPLE.T_NUMPED_PED.DELETE();
            integradora_comple.gvet_regpedido(i).valido := FALSE;

            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                             integradora_comple.gvet_regpedido(i).numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             integradora_comple.gvet_regpedido(i).cgccli,
                             NULL,
                             NULL,
                             NULL,
                             integradora_comple.gvet_regpedido(i).codusur,
                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                             NULL,
                             '2',
                             SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                             NULL,
                             null);

            IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                   0) = 0
            THEN

              IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
              THEN

                DELETE FROM pcorcavendai
                 WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcorcavendac
                 WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

--                COMMIT;

              ELSE

                DELETE FROM pcpedi
                 WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcorigempreco
                 WHERE numped = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcpedc
                 WHERE pcpedc.numped = integradora_comple.gvet_regpedido(i).numped;

--                COMMIT;
              END IF;

              EXIT;

            END IF;

          WHEN ERRO_CCRCA_FINAL THEN

            ROLLBACK;

            INTEGRADORA_COMPLE.T_NUMPED_PED.DELETE();

            INTEGRADORA_comple.gvet_regpedido(i).valido := FALSE;

            INTEGRADORA_comple.proc_registralog(INTEGRADORA_comple.gvet_regpedido(i)
                                                .numped,
                                                INTEGRADORA_comple.gvet_regpedido(i)
                                                .numpedrca,
                                                NULL,
                                                NULL,
                                                NULL,
                                                INTEGRADORA_comple.gvet_regpedido(i)
                                                .cgccli,
                                                NULL,
                                                NULL,
                                                NULL,
                                                INTEGRADORA_comple.gvet_regpedido(i)
                                                .codusur,
                                                INTEGRADORA_comple.gvet_regpedido(i)
                                                .dtaberturapedpalm,
                                                NULL,
                                                '2',
                                                INTEGRADORA_comple.gvet_regpedido(i).log || chr(13) ||
                                                INTEGRADORA_comple.vLog.MSG || chr(13) ||
                                                SQLCODE || '-' ||
                                                SQLERRM || '-' ||
                                                DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                                                NULL,
                                                null);


            IF nvl(INTEGRADORA_comple.gvet_regpedido(i).numpedorig, 0) = 0 THEN

              IF INTEGRADORA_comple.gvet_regpedido(i).orcamento = 'S' THEN

                DELETE FROM pcorcavendai
                 WHERE numorca = INTEGRADORA_comple.gvet_regpedido(i)
                .numped;

                DELETE FROM pcorcavendac
                 WHERE numorca = INTEGRADORA_comple.gvet_regpedido(i)
                .numped;

                --                COMMIT;

              ELSE

                DELETE FROM pcpedi
                 WHERE pcpedi.numped =
                       INTEGRADORA_comple.gvet_regpedido(i)
                .numped;

                DELETE FROM pcorigempreco
                 WHERE numped = INTEGRADORA_comple.gvet_regpedido(i)
                .numped;

                DELETE FROM pcpedc
                 WHERE pcpedc.numped =
                       INTEGRADORA_comple.gvet_regpedido(i)
                .numped;

                --                COMMIT;
              END IF;

              EXIT;

            END IF;

          WHEN OTHERS THEN

            ROLLBACK;

            INTEGRADORA_COMPLE.T_NUMPED_PED.DELETE();

            integradora_comple.gvet_regpedido(i).valido := FALSE;

            integradora_comple.proc_registralog(integradora_comple.gvet_regpedido(i).numped,
                             integradora_comple.gvet_regpedido(i).numpedrca,
                             NULL,
                             NULL,
                             NULL,
                             integradora_comple.gvet_regpedido(i).cgccli,
                             NULL,
                             NULL,
                             NULL,
                             integradora_comple.gvet_regpedido(i).codusur,
                             integradora_comple.gvet_regpedido(i).dtaberturapedpalm,
                             NULL,
                             '2',
                             SQLCODE || '-' || SQLERRM || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ';',
                             NULL,
                             null);

            IF nvl(integradora_comple.gvet_regpedido(i).numpedorig,
                   0) = 0
            THEN

              IF integradora_comple.gvet_regpedido(i).orcamento = 'S'
              THEN

                DELETE FROM pcorcavendai
                 WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcorcavendac
                 WHERE numorca = integradora_comple.gvet_regpedido(i).numped;

--                COMMIT;

              ELSE

                DELETE FROM pcpedi
                 WHERE pcpedi.numped = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcorigempreco
                 WHERE numped = integradora_comple.gvet_regpedido(i).numped;

                DELETE FROM pcpedc
                 WHERE pcpedc.numped = integradora_comple.gvet_regpedido(i).numped;

--             COMMIT;
              END IF;

              EXIT;

            END IF;
        END;

      END LOOP; -- FOR i IN 1 .. vncontped

    END IF; -- vncontped > 0

  END proc_processarpedidos;

 PROCEDURE importarpedido
  (
    p_tipoleitura IN NUMBER DEFAULT 1,
    p_datainicial IN DATE DEFAULT TRUNC(SYSDATE),
    p_datafinal   IN DATE DEFAULT TRUNC(SYSDATE),
    p_codfilial   IN VARCHAR2 DEFAULT '99',
    p_tiporeg     IN NUMBER DEFAULT NULL,
    p_codusur     IN NUMBER DEFAULT NULL,
    p_numpedrca   IN NUMBER DEFAULT NULL
  ) IS
    vbexisterro     BOOLEAN;
    vscodfilial     pcfilial.codigo%TYPE;
    vnnumpedrca     pcpedc.numpedrca%TYPE;

  BEGIN
    --Identificar na sessão a execução da package
    BEGIN
      DBMS_APPLICATION_INFO.read_client_info(integradora_comple.G_TITULO_TRANSACAO);

      DBMS_APPLICATION_INFO.SET_CLIENT_INFO('INTEGRADORA');
    END;
    ---------------------------------------------

    -- Remove todos os elementos das tabelas.
    integradora_comple.gvetregistralog.DELETE;
    integradora_comple.gvet_regpedido.DELETE;
    integradora_comple.gvet_regitem.DELETE;
    integradora_comple.gvet_regitenscesta.DELETE;
    integradora_comple.gvet_regprodconvestoque.DELETE;
    integradora_comple.gvet_regorigempreco.DELETE;
    integradora_comple.gvet_regorigemcomiss.DELETE;
    integradora_comple.gvet_regorigemdesc.DELETE;
    integradora_comple.vLog      := NULL;

    vscodfilial := nvl(p_codfilial,'99');

    integradora_comple.vngcontador := 0;

    integradora_comple.vngtipoleitura := p_tipoleitura;
    integradora_comple.vngtiporeg     := p_tiporeg;

    vbexisterro := FALSE;

    integradora_comple.vLog.CODUSUR           := p_codusur;
    integradora_comple.vLog.NUMPEDRCA         := p_numpedrca;
    integradora_comple.vLog.MSG               := 'Iniciando processamento de pedidos. Parâmetros de entrada..: ' || chr(13) ||
                               '| p_tipoleitura  - ' || p_tipoleitura  || chr(13) ||
                               '| p_datainicial  - ' || p_datainicial  || chr(13) ||
                               '| p_datafinal - '    || p_datafinal    || chr(13) ||
                               '| p_codfilial - '    || p_codfilial    || chr(13) ||
                               '| p_tiporeg - '      || p_tiporeg      || chr(13) ||
                               '| p_codusur - '      || p_codusur      || chr(13) ||
                               '| p_numpedrca - '    || p_numpedrca;

    PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));

    -- leitura dos parametros do sistema (PCCONSUM).
    IF NOT vbexisterro
    THEN
      integradora_comple.proc_lerparametros(vbexisterro);
    END IF;

     --VEN-3180
    IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('IMPORTARCLIENTEFVAUTOMATICO',
                                          '99',
                                          'S') = 'S'
    THEN
      IF NOT vbexisterro
      THEN
        integradora_comple.vLog.CODUSUR           := p_codusur;
        integradora_comple.vLog.NUMPEDRCA         := p_numpedrca;
        integradora_comple.vLog.MSG               := 'Efetuando chamada da IMPORTARCADASTROS para importar cadastros de clientes AUTOMATICAMENTE. Parametros: ' || chr(13) ||
                                                      ' p_tipoleitura : ' || p_tipoleitura || chr(13) ||
                                                      ' p_datainicial : ' || p_datainicial || chr(13) ||
                                                      ' p_datafinal   : ' || p_datafinal   || chr(13) ||
                                                      ' p_tiporeg     : ' || p_tiporeg        || chr(13) ||
                                                      ' p_codusur     : ' || p_codusur ;

        PRC_LOG_INTEGRADORA(integradora_comple.vLog, (CASE WHEN integradora_comple.vLog.MSG LIKE '%ORA-%' THEN DBMS_UTILITY.FORMAT_ERROR_BACKTRACE ELSE TO_CHAR($$PLSQL_LINE) END));


        importarcadastros.importar(p_tipoleitura,
                                   p_datainicial,
                                   p_datafinal,
                                   p_tiporeg,
                                   p_codusur);
      END IF;
    END IF;

    -- leitura dos pedidos
    IF NOT vbexisterro
    THEN
      -- leitura de tabelas contendo os pedidos.
      proc_processarleitura(vbexisterro,
                            p_tipoleitura,
                            p_datainicial,
                            p_datafinal,
                            vscodfilial,
                            p_tiporeg,
                            p_codusur,
                            p_numpedrca);
    END IF;

    /*IF p_tipoleitura = 1
    THEN
      vddatainicial := TRUNC(SYSDATE) - 365;
      vddatafinal   := TRUNC(SYSDATE);
    ELSE
      vddatainicial := p_datainicial;
      vddatafinal   := p_datafinal;
    END IF;*/


    -- processamento dos pedidos.
    proc_processarpedidos(vbexisterro);

    -- processamento do retorno.
    proc_processaretornotab(vbexisterro);

	-- A posição do cabeçalho deve ser a mesma dos itens
    DECLARE
      VSPOSICAO VARCHAR2(1);
    BEGIN
      FOR PED IN (SELECT NUMPEDRCA, CODCLI, CODUSUR, NUMPED
                    FROM PCPEDC
                   WHERE NUMPEDRCA = p_numpedrca
                     AND CODUSUR = p_codusur) LOOP
        BEGIN
		  VSPOSICAO := '';
          SELECT POSICAO
            INTO VSPOSICAO
            FROM PCPEDI
           WHERE NUMPED = PED.NUMPED
             AND ROWNUM = 1;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            VSPOSICAO := '';
        end;

        IF VSPOSICAO <> '' THEN
          UPDATE PCPEDC SET POSICAO = VSPOSICAO WHERE NUMPED = PED.NUMPED;
        END IF;

      END LOOP;
    END;

    commit;

    IF NOT vbexisterro
    THEN

      vnnumpedrca := NULL;

      IF p_tiporeg = 9
         AND p_numpedrca IS NOT NULL
      THEN
        vnnumpedrca := p_numpedrca;
      END IF;

      -- processamento das notas.
      IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('INTEGRADORAIMPORTATV14', '99', 'S') <> 'N' THEN
        importarprontaentrega.importarpedido(p_tipoleitura,
                                             p_datainicial,
                                             p_datafinal,
                                             p_codfilial,
                                             p_tiporeg,
                                             p_codusur,
                                             vnnumpedrca);
      END IF;
    END IF;

    IF NOT vbexisterro
    THEN
      -- processamento das notas.
      importarindenizacoes.importarpedido(p_tipoleitura,
                                          p_datainicial,
                                          p_datafinal,
                                          p_codfilial,
                                          p_tiporeg,
                                          p_codusur);
    END IF;

    -- Verifica se existe registros com status 4 - Processando
    proc_unlockpedidos;

    --Remove todos os elementos das tabelas.
    integradora_comple.gvetregistralog.DELETE;
    integradora_comple.gvet_regpedido.DELETE;
    integradora_comple.gvet_regitem.DELETE;
    integradora_comple.gvetregistralog.DELETE;
    integradora_comple.gvet_regitenscesta.DELETE;
    integradora_comple.gvet_regprodconvestoque.DELETE;
    integradora_comple.gvet_regorigempreco.DELETE;
    integradora_comple.gvet_regorigemcomiss.DELETE;
    integradora_comple.gvet_regorigemdesc.DELETE; --

    --Devolver título original para a transação corrente
    BEGIN
      DBMS_APPLICATION_INFO.SET_CLIENT_INFO(integradora_comple.G_TITULO_TRANSACAO);
    END;
    ---------------------------------------------

  END importarpedido;

END; -- INTEGRADORA

